function getDocClassifications() {
  const data = localStorage.getItem('psva_doc_classifications');
  return data ? JSON.parse(data) : JSON.parse(JSON.stringify(DEFAULT_DOC_CLASSIFICATIONS));
}

function saveDocClassifications(classifications) {
  localStorage.setItem('psva_doc_classifications', JSON.stringify(classifications));
}

function getDocStatusInfo(docType, statusId) {
  const cls = getDocClassifications();
  const typeCls = cls[docType];
  if (!typeCls) return { id: statusId || 'draft', label: statusId || 'Draft', classification: 'internal', color: '#6B7280' };
  return typeCls.statuses.find(s => s.id === statusId) || typeCls.statuses[0];
}

function isDocInternal(docType, statusId) {
  const info = getDocStatusInfo(docType, statusId);
  return info.classification === 'internal';
}

