// ============================================================
// DATA ACCESS LAYER
// ============================================================
function loadState() {
  try {
    const theme = localStorage.getItem('psva_theme');
    if (theme === 'light') isDarkMode = false;
    const pdfTheme = localStorage.getItem('psva_pdf_theme');
    if (pdfTheme) selectedThemeId = pdfTheme;
    const pdfMode = localStorage.getItem('psva_pdf_dark_mode');
    if (pdfMode !== null) pdfDarkMode = pdfMode === 'true';
  } catch(e) {}
}

function getCompany() {
  try {
    const saved = localStorage.getItem('psva_company');
    if (saved) return { ...DEFAULT_COMPANY, ...JSON.parse(saved) };
  } catch(e) {}
  return { ...DEFAULT_COMPANY };
}

function saveCompany(data) {
  localStorage.setItem('psva_company', JSON.stringify(data));
}

function getDocuments(type) {
  try {
    const key = 'psva_' + type;
    const data = localStorage.getItem(key);
    return data ? JSON.parse(data) : [];
  } catch(e) { return []; }
}

function saveDocument(type, doc) {
  const docs = getDocuments(type);
  const idx = docs.findIndex(d => d.id === doc.id);
  if (idx >= 0) docs[idx] = doc;
  else docs.push(doc);
  localStorage.setItem('psva_' + type, JSON.stringify(docs));
}

function deleteDocument(type, id) {
  const docs = getDocuments(type).filter(d => d.id !== id);
  localStorage.setItem('psva_' + type, JSON.stringify(docs));
}

function getJobs() { return getDocuments('jobs'); }
function getEstimates() { return getDocuments('estimates'); }
function getTimesheets() { return getDocuments('timesheets'); }
function getTravelEntries() { return getDocuments('travel'); }
function getReceipts() { return getDocuments('receipts'); }
function getPnlStatements() { return getDocuments('pnl'); }

function getJobById(id) { return getJobs().find(j => j.id === id) || null; }

function generateId() { return Date.now().toString(36) + Math.random().toString(36).substr(2, 6); }
function generateNumber(prefix) {
  const year = new Date().getFullYear();
  const rand = Math.floor(1000 + Math.random() * 9000);
  return `${prefix}-${year}-${rand}`;
}

// ============================================================
// TOAST NOTIFICATIONS
// ============================================================
function showToast(message, type = 'success') {
  const el = document.getElementById('toast');
  el.textContent = message;
  el.className = 'toast ' + type;
  setTimeout(() => el.classList.add('show'), 10);
  setTimeout(() => el.classList.remove('show'), 3000);
}

// ============================================================
// THEME & UI
// ============================================================
function toggleTheme() {
  isDarkMode = !isDarkMode;
  document.body.classList.toggle('light-mode', !isDarkMode);
  document.getElementById('themeToggle').classList.toggle('active', !isDarkMode);
  localStorage.setItem('psva_theme', isDarkMode ? 'dark' : 'light');
  updateSidebarLogo();
}

function updateSidebarLogo() {
  const company = getCompany();
  const logo = document.getElementById('sidebarLogo');
  if (!logo) return;
  if (!isDarkMode && company.logoLight) logo.src = company.logoLight;
  else if (isDarkMode && company.logoDark) logo.src = company.logoDark;
  else if (!isDarkMode) logo.src = 'public/placeholder-logo-light.png';
  else logo.src = 'public/placeholder-logo-dark.png';
  // Also update sidebar company name text
  const nameEl = document.getElementById('sidebarCompanyName');
  if (nameEl) nameEl.textContent = company.tagline || 'Document Manager';
}

// ============================================================
// FORMAT HELPERS
// ============================================================
function formatCurrency(amount) {
  return '$' + parseFloat(amount || 0).toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
}

function formatDate(dateStr) {
  if (!dateStr) return '';
  const d = new Date(dateStr + 'T00:00:00');
  return d.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
}

function formatDateShort(dateStr) {
  if (!dateStr) return '';
  const d = new Date(dateStr + 'T00:00:00');
  return d.toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
}

function todayStr() {
  const d = new Date();
  return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
}

function escapeHtml(str) {
  if (!str) return '';
  return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}

function getStatusBadge(status) {
  const s = JOB_STATUSES.find(st => st.id === status) || JOB_STATUSES[0];
  return `<span class="status-badge" style="background:${s.color}20; color:${s.color}; border:1px solid ${s.color}40;">${s.label}</span>`;
}

// Build a job selector dropdown HTML snippet
function buildJobSelector(fieldId, selectedJobId, includeAutoCreate) {
  const jobs = getJobs();
  let html = `<select class="form-select" id="${fieldId}">`;
  html += `<option value="">— No Job —</option>`;
  if (includeAutoCreate) {
    html += `<option value="__auto_create__">+ Auto-Create New Job</option>`;
  }
  jobs.forEach(j => {
    html += `<option value="${j.id}" ${selectedJobId === j.id ? 'selected' : ''}>${escapeHtml(j.jobNumber)} — ${escapeHtml(j.name)}</option>`;
  });
  html += `</select>`;
  return html;
}

// Auto-create a job from document data and return the new job id
function autoCreateJobFromDoc(docType, data) {
  const job = getDefaultJob();
  job.name = data.projectName || data.subject || docType + ' - ' + (data.docNumber || data.estimateNumber || '');
  job.customer = {
    name: data.customerName || data.recipientName || '',
    company: data.customerCompany || data.vendorCompany || data.recipientCompany || '',
    phone: data.customerPhone || data.vendorPhone || '',
    email: data.customerEmail || data.vendorEmail || '',
    address: data.customerAddress || data.vendorAddress || data.recipientAddress || '',
  };
  job.status = 'estimate';
  saveDocument('jobs', job);
  showToast('Job "' + job.jobNumber + '" auto-created!');
  return job.id;
}

// Resolve jobId from a selector — handles auto-create logic
function resolveJobId(selectorId, docType, data) {
  const val = document.getElementById(selectorId)?.value || '';
  if (val === '__auto_create__') {
    return autoCreateJobFromDoc(docType, data);
  }
  return val;
}

// ============================================================
// NAVIGATION
// ============================================================
function showPage(page, jobId) {
  currentPage = page;
  if (jobId !== undefined) currentJobId = jobId;
  editingDocId = null;
  document.querySelectorAll('.nav-item').forEach(el => el.classList.remove('active'));
  const navEl = document.querySelector(`.nav-item[data-page="${page}"]`);
  if (navEl) navEl.classList.add('active');
  renderPage();
}

function renderPage() {
  switch(currentPage) {
    case 'jobs': renderJobsList(); break;
    case 'job-dashboard': renderJobDashboard(); break;
    case 'estimates': renderDocumentList('estimate'); break;
    case 'quotes': renderDocumentList('quote'); break;
    case 'invoices': renderDocumentList('invoice'); break;
    case 'po': renderDocumentList('po'); break;
    case 'letterhead': renderDocumentList('letterhead'); break;
    case 'timesheets': renderTimesheetsList(); break;
    case 'travel': renderTravelList(); break;
    case 'receipts': renderReceiptsList(); break;
    case 'test-reports': renderTestReportsList(); break;
    case 'pnl': renderPnlList(); break;
    case 'equipment': renderEquipmentList(); break;
    case 'inventory': renderInventoryList(); break;
    case 'purchase-orders': renderDocumentList('po'); break;
    case 'tax-summary': renderTaxSummary(); break;
    case 'customers': renderCustomersList(); break;
    case 'technicians': renderTechniciansList(); break;
    case 'calendar': renderCalendarView(); break;
    case 'kpi-dashboard': renderKPIDashboard(); break;
    case 'rate-sheet': renderRateSheetPage(); break;
    case 'themes': renderThemes(); break;
    case 'settings': renderSettings(); break;
    case 'work-orders': renderDocumentList('workorder'); break;
    case 'change-orders': renderDocumentList('changeorder'); break;
    case 'proposals': renderDocumentList('proposal'); break;
    case 'contracts': renderDocumentList('contracts'); break;
    case 'credit-memos': renderDocumentList('creditmemo'); break;
    case 'payment-receipts': renderDocumentList('paymentreceipt'); break;
    case 'statements': renderDocumentList('statements'); break;
    case 'certificates': renderDocumentList('certificates'); break;
    case 'asset-transfers': renderDocumentList('assettransfers'); break;
    case 'safety-reports': renderDocumentList('safetyreports'); break;
    case '1099-tracking': render1099Tracking(); break;
    case 'quarterly-taxes': renderQuarterlyTaxes(); break;
    case 'tax-package': renderYearEndTaxPackage(); break;
    case 'employee-hr': renderEmployeeHR(); break;
    default: renderJobsList();
  }
}


// ============================================================
// JOBS SYSTEM
// ============================================================
function getDefaultJob() {
  return {
    id: generateId(),
    jobNumber: generateNumber('JOB'),
    name: '',
    customer: { name: '', company: '', phone: '', email: '', address: '' },
    status: 'estimate',
    startDate: todayStr(),
    endDate: '',
    estimateIds: [],
    quoteIds: [],
    invoiceIds: [],
    poIds: [],
    timesheetIds: [],
    travelIds: [],
    receiptIds: [],
    pnlId: null,
    notes: '',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
}

function renderJobsList() {
  const main = document.querySelector('.main-content');
  let jobs = getJobs();
  const prefs = getDashboardPrefs('jobs');
  const viewMode = prefs.viewMode || 'grid';

  // Search filter
  if (prefs.searchQuery) {
    const q = prefs.searchQuery.toLowerCase();
    jobs = jobs.filter(j => {
      return (j.jobNumber || '').toLowerCase().includes(q) || (j.name || '').toLowerCase().includes(q) || (j.customer?.company || '').toLowerCase().includes(q) || (j.customer?.name || '').toLowerCase().includes(q);
    });
  }

  // Status filter
  if (prefs.filterStatus && prefs.filterStatus !== 'all') {
    jobs = jobs.filter(j => j.status === prefs.filterStatus);
  }

  // Sort
  const sortDir = prefs.sortDir === 'asc' ? 1 : -1;
  jobs.sort((a, b) => {
    switch (prefs.sortBy) {
      case 'number': return (a.jobNumber || '').localeCompare(b.jobNumber || '') * sortDir;
      case 'name': return (a.name || '').localeCompare(b.name || '') * sortDir;
      case 'status': return (a.status || '').localeCompare(b.status || '') * sortDir;
      case 'customer': return (a.customer?.company || a.customer?.name || '').localeCompare(b.customer?.company || b.customer?.name || '') * sortDir;
      default: return (a.startDate || '').localeCompare(b.startDate || '') * sortDir;
    }
  });

  main.innerHTML = `
    <div class="page-header">
      <h1>Jobs</h1>
      <div class="page-header-actions">
        <button class="btn btn-primary" onclick="createNewJob()">+ New Job</button>
      </div>
    </div>
    <div class="card" style="margin-bottom:12px;">
      <div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;">
        <input class="form-input" style="width:200px;" placeholder="Search jobs..." value="${escapeHtml(prefs.searchQuery || '')}" oninput="updateDocListPref('jobs','searchQuery',this.value); renderJobsList();">
        <select class="form-select" style="width:160px;" onchange="updateDocListPref('jobs','filterStatus',this.value); renderJobsList();">
          <option value="all">All Statuses</option>
          ${JOB_STATUSES.map(s => '<option value="' + s.id + '"' + (prefs.filterStatus === s.id ? ' selected' : '') + '>' + s.label + '</option>').join('')}
        </select>
        <select class="form-select" style="width:140px;" onchange="updateDocListPref('jobs','sortBy',this.value); renderJobsList();">
          <option value="date" ${prefs.sortBy==='date'?'selected':''}>Sort by Date</option>
          <option value="number" ${prefs.sortBy==='number'?'selected':''}>Sort by Number</option>
          <option value="name" ${prefs.sortBy==='name'?'selected':''}>Sort by Name</option>
          <option value="status" ${prefs.sortBy==='status'?'selected':''}>Sort by Status</option>
          <option value="customer" ${prefs.sortBy==='customer'?'selected':''}>Sort by Customer</option>
        </select>
        <button class="btn btn-secondary btn-sm" onclick="const p=getDashboardPrefs('jobs'); p.sortDir=p.sortDir==='asc'?'desc':'asc'; saveDashboardPrefs('jobs',p); renderJobsList();">${prefs.sortDir === 'asc' ? '\u25b2 Asc' : '\u25bc Desc'}</button>
        <div style="margin-left:auto;display:flex;gap:4px;">
          <button class="btn btn-secondary btn-sm ${viewMode==='grid'?'active':''}" onclick="updateDocListPref('jobs','viewMode','grid'); renderJobsList();" title="Grid View">\u25a6</button>
          <button class="btn btn-secondary btn-sm ${viewMode==='list'?'active':''}" onclick="updateDocListPref('jobs','viewMode','list'); renderJobsList();" title="List View">\u2630</button>
        </div>
      </div>
    </div>
    ${jobs.length === 0 ? '<p class="intro-text">No jobs found.</p>' : ''}
    ${viewMode === 'list' ? `
      ${jobs.map(job => {
        const estimates = getEstimates().filter(e => e.jobId === job.id);
        const timesheets = getTimesheets().filter(t => t.jobId === job.id);
        const totalEstimated = estimates.reduce((sum, e) => sum + (e.totalCustomerPrice || 0), 0);
        return `
        <div class="doc-row" onclick="openJobDashboard('${job.id}')">
          <div class="doc-row-info">
            <div class="doc-row-number">${escapeHtml(job.jobNumber)} ${getJobHealthBadge(job.id)} ${getStatusBadge(job.status)}</div>
            <div class="doc-row-meta">${escapeHtml(job.name || 'Untitled')} \u00b7 ${escapeHtml(job.customer?.company || job.customer?.name || '')} \u00b7 ${formatDateShort(job.startDate)}</div>
          </div>
          <div class="doc-row-actions">
            <span class="doc-row-total">${totalEstimated > 0 ? formatCurrency(totalEstimated) : ''}</span>
            <button class="btn-icon" onclick="event.stopPropagation(); confirmDeleteJob('${job.id}','${escapeHtml(job.name || job.jobNumber)}')" title="Delete">\ud83d\uddd1</button>
          </div>
        </div>`;
      }).join('')}
    ` : `
    <div class="jobs-grid">
      ${jobs.map(job => {
        const estimates = getEstimates().filter(e => e.jobId === job.id);
        const timesheets = getTimesheets().filter(t => t.jobId === job.id);
        const receipts = getReceipts().filter(r => r.jobId === job.id);
        const totalEstimated = estimates.reduce((sum, e) => sum + (e.totalCustomerPrice || 0), 0);
        return `
        <div class="job-card" onclick="openJobDashboard('${job.id}')">
          <div class="job-card-header">
            <div>
              <div class="job-card-number">${escapeHtml(job.jobNumber)}</div>
              <div class="job-card-name">${escapeHtml(job.name) || 'Untitled Job'}</div>
            </div>
            <div style="display:flex;align-items:center;gap:6px;">
              ${getJobHealthBadge(job.id)}
              ${getStatusBadge(job.status)}
            </div>
          </div>
          <div class="job-card-customer">${escapeHtml(job.customer?.company || job.customer?.name || 'No customer')}</div>
          <div class="job-card-meta">
            <span>${formatDateShort(job.startDate)}</span>
            ${totalEstimated > 0 ? '<span>' + formatCurrency(totalEstimated) + '</span>' : ''}
          </div>
          <div class="job-card-stats">
            ${estimates.length > 0 ? '<span class="stat-pill">\ud83d\udccb ' + estimates.length + ' Est</span>' : ''}
            ${timesheets.length > 0 ? '<span class="stat-pill">\u23f1 ' + timesheets.length + ' TS</span>' : ''}
            ${receipts.length > 0 ? '<span class="stat-pill">\ud83e\uddfe ' + receipts.length + ' Rcpt</span>' : ''}
          </div>
          <div class="job-card-delete">
            <button class="btn-icon" onclick="event.stopPropagation(); confirmDeleteJob('${job.id}','${escapeHtml(job.name || job.jobNumber)}')" title="Delete Job">\ud83d\uddd1</button>
          </div>
        </div>`;
      }).join('')}
    </div>
    `}
  `;
}

function createNewJob() {
  editingDocId = null;
  renderJobEditor(getDefaultJob());
}

function openJobDashboard(jobId) {
  currentJobId = jobId;
  currentPage = 'job-dashboard';
  editingDocId = null;
  renderPage();
}

function renderJobEditor(job) {
  const main = document.querySelector('.main-content');
  const isNew = !getJobs().find(j => j.id === job.id);
  window._currentJob = job;
  main.innerHTML = `
    <div class="page-header">
      <div style="display:flex;align-items:center;gap:12px;">
        <button class="btn-icon" onclick="showPage('jobs')" title="Back">←</button>
        <h1>${isNew ? 'New Job' : 'Edit Job'}</h1>
      </div>
      <div class="page-header-actions">
        <button class="btn btn-secondary" onclick="saveCurrentJob()">Save Job</button>
        ${!isNew ? `<button class="btn btn-primary" onclick="saveCurrentJob(); openJobDashboard('${job.id}')">Save & View Dashboard</button>` : ''}
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Job Information</div>
      <div class="form-grid">
        <div class="form-group"><label class="form-label">Job Number</label><input class="form-input" id="job-number" value="${escapeHtml(job.jobNumber)}"></div>
        <div class="form-group"><label class="form-label">Status</label>
          <select class="form-select" id="job-status">
            ${JOB_STATUSES.map(s => `<option value="${s.id}" ${job.status === s.id ? 'selected' : ''}>${s.label}</option>`).join('')}
          </select>
        </div>
        <div class="form-group"><label class="form-label">Start Date</label><input class="form-input" type="date" id="job-startDate" value="${job.startDate}"></div>
        <div class="form-group"><label class="form-label">End Date</label><input class="form-input" type="date" id="job-endDate" value="${job.endDate}"></div>
        <div class="form-group full-width"><label class="form-label">Job Name / Description</label><input class="form-input" id="job-name" value="${escapeHtml(job.name)}" placeholder="e.g. Main St Switchgear Replacement"></div>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Customer Information</div>
      <div class="form-grid">
        <div class="form-group"><label class="form-label">Contact Name</label><input class="form-input" id="job-custName" value="${escapeHtml(job.customer.name)}"></div>
        <div class="form-group"><label class="form-label">Company</label><input class="form-input" id="job-custCompany" value="${escapeHtml(job.customer.company)}"></div>
        <div class="form-group"><label class="form-label">Phone</label><input class="form-input" id="job-custPhone" value="${escapeHtml(job.customer.phone)}"></div>
        <div class="form-group"><label class="form-label">Email</label><input class="form-input" id="job-custEmail" value="${escapeHtml(job.customer.email)}"></div>
        <div class="form-group full-width"><label class="form-label">Address</label><input class="form-input" id="job-custAddress" value="${escapeHtml(job.customer.address)}"></div>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Notes</div>
      <textarea class="form-textarea" id="job-notes" rows="4" placeholder="Internal notes about this job...">${escapeHtml(job.notes)}</textarea>
    </div>
  `;
}

function collectJobData() {
  const job = window._currentJob || getDefaultJob();
  job.jobNumber = document.getElementById('job-number').value;
  job.name = document.getElementById('job-name').value;
  job.status = document.getElementById('job-status').value;
  job.startDate = document.getElementById('job-startDate').value;
  job.endDate = document.getElementById('job-endDate').value;
  job.customer = {
    name: document.getElementById('job-custName').value,
    company: document.getElementById('job-custCompany').value,
    phone: document.getElementById('job-custPhone').value,
    email: document.getElementById('job-custEmail').value,
    address: document.getElementById('job-custAddress').value,
  };
  job.notes = document.getElementById('job-notes').value;
  job.updatedAt = new Date().toISOString();
  return job;
}

function saveCurrentJob() {
  const job = collectJobData();
  saveDocument('jobs', job);
  editingDocId = job.id;
  window._currentJob = job;
  showToast('Job saved!');
}

// ============================================================
// JOB DASHBOARD
// ============================================================
function renderJobDashboard() {
  const main = document.querySelector('.main-content');
  const job = getJobById(currentJobId);
  if (!job) { showPage('jobs'); return; }

  const estimates = getEstimates().filter(e => e.jobId === job.id);
  const quotes = getDocuments('quote').filter(q => q.jobId === job.id);
  const invoices = getDocuments('invoice').filter(i => i.jobId === job.id);
  const pos = getDocuments('po').filter(p => p.jobId === job.id);
  const timesheets = getTimesheets().filter(t => t.jobId === job.id);
  const travel = getTravelEntries().filter(t => t.jobId === job.id);
  const receipts = getReceipts().filter(r => r.jobId === job.id);
  const testReports = getTestReports().filter(t => t.jobId === job.id);
  const pnl = getPnlStatements().find(p => p.jobId === job.id);
  const workorders = getDocuments('workorder').filter(d => d.jobId === job.id);
  const changeorders = getDocuments('changeorder').filter(d => d.jobId === job.id);
  const proposals = getDocuments('proposal').filter(d => d.jobId === job.id);
  const contracts = getDocuments('contracts').filter(d => d.jobId === job.id);
  const creditmemos = getDocuments('creditmemo').filter(d => d.jobId === job.id);
  const paymentreceipts = getDocuments('paymentreceipt').filter(d => d.jobId === job.id);
  const certificates = getDocuments('certificates').filter(d => d.jobId === job.id);
  const assettransfers = getDocuments('assettransfers').filter(d => d.jobId === job.id);
  const safetyreports = getDocuments('safetyreports').filter(d => d.jobId === job.id);

  const totalEstRevenue = estimates.reduce((s, e) => s + (e.totalCustomerPrice || 0), 0);
  const totalEstCost = estimates.reduce((s, e) => s + (e.totalCost || 0), 0);
  const totalLabor = timesheets.reduce((s, t) => s + (t.totalCost || 0), 0);
  const totalTravel = travel.reduce((s, t) => s + (t.totalCost || 0), 0);
  const totalReceipts = receipts.reduce((s, r) => s + (r.amount || 0), 0);
  const totalHours = timesheets.reduce((s, t) => s + getTimesheetTotalHours(t), 0);
  const totalMiles = travel.reduce((s, t) => s + (t.mileage || 0), 0);

  main.innerHTML = `
    <div class="page-header">
      <div style="display:flex;align-items:center;gap:12px;">
        <button class="btn-icon" onclick="showPage('jobs')" title="Back to Jobs">←</button>
        <div>
          <h1>${escapeHtml(job.name) || 'Untitled Job'}</h1>
          <div style="font-size:13px;color:var(--text-secondary);margin-top:2px;">${escapeHtml(job.jobNumber)} · ${escapeHtml(job.customer.company || job.customer.name || '')}</div>
        </div>
      </div>
      <div class="page-header-actions">
        ${getStatusBadge(job.status)}
        <button class="btn btn-secondary" onclick="exportJobPackagePDF('${job.id}')">\u2193 Job Package PDF</button>
        <button class="btn btn-secondary" onclick="editJobFromDashboard('${job.id}')">Edit Job</button>
        <button class="btn btn-danger" onclick="confirmDeleteJob('${job.id}','${escapeHtml(job.name || job.jobNumber)}')">Delete Job</button>
      </div>
    </div>

    <!-- Summary Cards -->
    <div class="dashboard-stats">
      <div class="stat-card">
        <div class="stat-label">Est. Revenue</div>
        <div class="stat-value">${formatCurrency(totalEstRevenue)}</div>
      </div>
      <div class="stat-card">
        <div class="stat-label">Est. Cost</div>
        <div class="stat-value">${formatCurrency(totalEstCost)}</div>
      </div>
      <div class="stat-card">
        <div class="stat-label">Actual Costs</div>
        <div class="stat-value">${formatCurrency(totalLabor + totalTravel + totalReceipts)}</div>
      </div>
      <div class="stat-card">
        <div class="stat-label">Hours Logged</div>
        <div class="stat-value">${totalHours.toFixed(1)}</div>
      </div>
      <div class="stat-card">
        <div class="stat-label">Miles</div>
        <div class="stat-value">${totalMiles.toFixed(0)}</div>
      </div>
      <div class="stat-card">
        <div class="stat-label">Receipts</div>
        <div class="stat-value">${formatCurrency(totalReceipts)}</div>
      </div>
    </div>

    <!-- Job Overview -->
    ${renderJobOverviewSection(job.id)}

    <!-- Estimates -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Estimates
        <button class="btn btn-sm btn-primary" style="margin-left:auto;" onclick="createEstimateForJob('${job.id}')">+ New Estimate</button>
      </div>
      ${estimates.length === 0 ? '<p class="intro-text">No estimates yet.</p>' :
        `<div class="mini-table">${estimates.map(e => `
          <div class="mini-row" onclick="editEstimate('${e.id}')">
            <span class="mini-primary">${escapeHtml(e.estimateNumber)}</span>
            <span class="mini-secondary">${formatDateShort(e.date)}</span>
            <span class="mini-amount">${formatCurrency(e.totalCustomerPrice)}</span>
          </div>`).join('')}</div>`
      }
    </div>

    <!-- Quotes -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Quotes
        <button class="btn btn-sm btn-secondary" style="margin-left:auto;" onclick="createDocForJob('quote','${job.id}')">+ New Quote</button>
      </div>
      ${quotes.length === 0 ? '<p class="intro-text">No quotes yet. Create an estimate first, then generate a quote from it.</p>' :
        `<div class="mini-table">${quotes.map(q => `
          <div class="mini-row" onclick="editDocFromDashboard('quote','${q.id}')">
            <span class="mini-primary">${escapeHtml(q.docNumber)}</span>
            <span class="mini-secondary">${formatDateShort(q.date)}</span>
            <span class="mini-amount">${formatCurrency(q.total)}</span>
          </div>`).join('')}</div>`
      }
    </div>

    <!-- Invoices -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Invoices
        <button class="btn btn-sm btn-secondary" style="margin-left:auto;" onclick="createDocForJob('invoice','${job.id}')">+ New Invoice</button>
      </div>
      ${invoices.length === 0 ? '<p class="intro-text">No invoices yet.</p>' :
        `<div class="mini-table">${invoices.map(i => `
          <div class="mini-row" onclick="editDocFromDashboard('invoice','${i.id}')">
            <span class="mini-primary">${escapeHtml(i.docNumber)}</span>
            <span class="mini-secondary">${formatDateShort(i.date)}</span>
            <span class="mini-amount">${formatCurrency(i.total)}</span>
          </div>`).join('')}</div>`
      }
    </div>

    <!-- Timesheets -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Timesheets
        <button class="btn btn-sm btn-primary" style="margin-left:auto;" onclick="createTimesheetForJob('${job.id}')">+ Add Entry</button>
      </div>
      ${timesheets.length === 0 ? '<p class="intro-text">No timesheet entries yet.</p>' :
        `<div class="mini-table">${timesheets.slice(-10).reverse().map(t => `
          <div class="mini-row" onclick="editTimesheet('${t.id}')">
            <span class="mini-primary">${escapeHtml(getTimesheetTechnicians(t).join(', ') || t.employeeName || 'Unnamed')}</span>
            <span class="mini-secondary">${formatDateShort(t.date)} · ${getTimesheetTotalHours(t).toFixed(1)}h</span>
            <span class="mini-amount">${getTimesheetTotalHours(t).toFixed(1)} hrs</span>
          </div>`).join('')}</div>`
      }
    </div>

    <!-- Travel & Mileage -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Travel & Mileage
        <button class="btn btn-sm btn-primary" style="margin-left:auto;" onclick="createTravelForJob('${job.id}')">+ Add Entry</button>
      </div>
      ${travel.length === 0 ? '<p class="intro-text">No travel entries yet.</p>' :
        `<div class="mini-table">${travel.slice(-10).reverse().map(t => `
          <div class="mini-row" onclick="editTravel('${t.id}')">
            <span class="mini-primary">${escapeHtml(t.fromLocation)} → ${escapeHtml(t.toLocation)}</span>
            <span class="mini-secondary">${formatDateShort(t.date)} · ${t.mileage} mi</span>
            <span class="mini-amount">${formatCurrency(t.totalCost)}</span>
          </div>`).join('')}</div>`
      }
    </div>

    <!-- Receipts -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Receipts
        <button class="btn btn-sm btn-primary" style="margin-left:auto;" onclick="createReceiptForJob('${job.id}')">+ Add Receipt</button>
      </div>
      ${receipts.length === 0 ? '<p class="intro-text">No receipts yet.</p>' :
        `<div class="mini-table">${receipts.map(r => `
          <div class="mini-row" onclick="editReceipt('${r.id}')">
            <span class="mini-primary">${escapeHtml(r.vendor)} — ${escapeHtml(r.description)}</span>
            <span class="mini-secondary">${formatDateShort(r.date)} · ${escapeHtml(r.category)}</span>
            <span class="mini-amount">${formatCurrency(r.amount)}</span>
          </div>`).join('')}</div>`
      }
    </div>

    <!-- Test Reports -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Test Reports
        <div style="margin-left:auto;display:flex;gap:8px;">
          ${testReports.length > 0 ? `<button class="btn btn-sm btn-secondary" onclick="exportCompiledTestReportsPDF('${job.id}')">Export All as PDF</button>` : ''}
          <button class="btn btn-sm btn-primary" onclick="createTestReportForJob('${job.id}')">+ New Test Report</button>
        </div>
      </div>
      ${testReports.length === 0 ? '<p class="intro-text">No test reports yet.</p>' :
        `<div class="mini-table">${testReports.map(t => {
          const enabledCount = Object.values(t.sections).filter(s => s.enabled).length;
          return `
          <div class="mini-row" onclick="editTestReport('${t.id}')">
            <span class="mini-primary">${escapeHtml(t.reportNumber)} — ${escapeHtml(t.title || t.equipmentTested || 'Untitled')}</span>
            <span class="mini-secondary">${formatDateShort(t.date)} · ${enabledCount} test${enabledCount !== 1 ? 's' : ''}</span>
            <span class="status-badge" style="background:${t.overallResult === 'pass' ? '#22c55e20;color:#22c55e' : t.overallResult === 'investigate' ? '#f59e0b20;color:#f59e0b' : '#ef444420;color:#ef4444'};">${t.overallResult === 'pass' ? 'PASS' : t.overallResult === 'investigate' ? 'INVESTIGATE' : 'FAIL'}</span>
          </div>`;
        }).join('')}</div>`
      }
    </div>

    <!-- P&L -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Profit & Loss
        <button class="btn btn-sm btn-primary" style="margin-left:auto;" onclick="openPnlForJob('${job.id}')">${pnl ? 'View P&L' : 'Generate P&L'}</button>
      </div>
      ${pnl ? `
        <div class="dashboard-stats" style="margin-top:8px;">
          <div class="stat-card"><div class="stat-label">Est. Profit</div><div class="stat-value">${formatCurrency(pnl.estimatedProfit)}</div></div>
          <div class="stat-card"><div class="stat-label">Actual Profit</div><div class="stat-value" style="color:${(pnl.actualProfit||0) >= 0 ? 'var(--success)' : 'var(--accent)'};">${formatCurrency(pnl.actualProfit)}</div></div>
          <div class="stat-card"><div class="stat-label">Margin</div><div class="stat-value">${((pnl.profitMargin||0)*100).toFixed(1)}%</div></div>
        </div>
      ` : '<p class="intro-text">No P&L statement yet. Generate one from the estimate data.</p>'}
    </div>

    <!-- Purchase Orders -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Purchase Orders
        <button class="btn btn-sm btn-secondary" style="margin-left:auto;" onclick="createDocForJob('po','${job.id}')">+ New PO</button>
      </div>
      ${pos.length === 0 ? '<p class="intro-text">No purchase orders yet.</p>' :
        `<div class="mini-table">${pos.map(p => `
          <div class="mini-row" onclick="editDocFromDashboard('po','${p.id}')">
            <span class="mini-primary">${escapeHtml(p.docNumber)}</span>
            <span class="mini-secondary">${formatDateShort(p.date)}</span>
            <span class="mini-amount">${formatCurrency(p.total)}</span>
          </div>`).join('')}</div>`
      }
    </div>

    <!-- Work Orders -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Work Orders
        <button class="btn btn-sm btn-secondary" style="margin-left:auto;" onclick="createDocForJob('workorder','${job.id}')">+ New Work Order</button>
      </div>
      ${workorders.length === 0 ? '<p class="intro-text">No work orders yet.</p>' :
        `<div class="mini-table">${workorders.map(d => `
          <div class="mini-row" onclick="editDocFromDashboard('workorder','${d.id}')">
            <span class="mini-primary">${escapeHtml(d.docNumber)}</span>
            <span class="mini-secondary">${formatDateShort(d.date)} · ${escapeHtml(d.status || '')}</span>
            <span class="mini-amount">${formatCurrency(d.total || 0)}</span>
          </div>`).join('')}</div>`
      }
    </div>

    <!-- Change Orders -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Change Orders
        <button class="btn btn-sm btn-secondary" style="margin-left:auto;" onclick="createDocForJob('changeorder','${job.id}')">+ New Change Order</button>
      </div>
      ${changeorders.length === 0 ? '<p class="intro-text">No change orders yet.</p>' :
        `<div class="mini-table">${changeorders.map(d => `
          <div class="mini-row" onclick="editDocFromDashboard('changeorder','${d.id}')">
            <span class="mini-primary">${escapeHtml(d.docNumber)}</span>
            <span class="mini-secondary">${formatDateShort(d.date)} · ${escapeHtml(d.changeType || '')}</span>
            <span class="mini-amount">${formatCurrency(d.netCostChange || 0)}</span>
          </div>`).join('')}</div>`
      }
    </div>

    <!-- Proposals -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Proposals
        <button class="btn btn-sm btn-secondary" style="margin-left:auto;" onclick="createDocForJob('proposal','${job.id}')">+ New Proposal</button>
      </div>
      ${proposals.length === 0 ? '<p class="intro-text">No proposals yet.</p>' :
        `<div class="mini-table">${proposals.map(d => `
          <div class="mini-row" onclick="editDocFromDashboard('proposal','${d.id}')">
            <span class="mini-primary">${escapeHtml(d.docNumber)}</span>
            <span class="mini-secondary">${formatDateShort(d.date)}</span>
            <span class="mini-amount">${formatCurrency(d.total || 0)}</span>
          </div>`).join('')}</div>`
      }
    </div>

    <!-- Contracts -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Contracts
        <button class="btn btn-sm btn-secondary" style="margin-left:auto;" onclick="createDocForJob('contracts','${job.id}')">+ New Contract</button>
      </div>
      ${contracts.length === 0 ? '<p class="intro-text">No contracts yet.</p>' :
        `<div class="mini-table">${contracts.map(d => `
          <div class="mini-row" onclick="editDocFromDashboard('contracts','${d.id}')">
            <span class="mini-primary">${escapeHtml(d.docNumber)}</span>
            <span class="mini-secondary">${formatDateShort(d.startDate || d.date)} — ${formatDateShort(d.endDate || '')}</span>
            <span class="mini-amount">${formatCurrency(d.totalValue || 0)}</span>
          </div>`).join('')}</div>`
      }
    </div>

    <!-- Credit Memos -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Credit Memos
        <button class="btn btn-sm btn-secondary" style="margin-left:auto;" onclick="createDocForJob('creditmemo','${job.id}')">+ New Credit Memo</button>
      </div>
      ${creditmemos.length === 0 ? '<p class="intro-text">No credit memos yet.</p>' :
        `<div class="mini-table">${creditmemos.map(d => `
          <div class="mini-row" onclick="editDocFromDashboard('creditmemo','${d.id}')">
            <span class="mini-primary">${escapeHtml(d.docNumber)}</span>
            <span class="mini-secondary">${formatDateShort(d.date)} · ${escapeHtml(d.reason || '')}</span>
            <span class="mini-amount">${formatCurrency(d.total || 0)}</span>
          </div>`).join('')}</div>`
      }
    </div>

    <!-- Payment Receipts -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Payment Receipts
        <button class="btn btn-sm btn-secondary" style="margin-left:auto;" onclick="createDocForJob('paymentreceipt','${job.id}')">+ New Payment Receipt</button>
      </div>
      ${paymentreceipts.length === 0 ? '<p class="intro-text">No payment receipts yet.</p>' :
        `<div class="mini-table">${paymentreceipts.map(d => `
          <div class="mini-row" onclick="editDocFromDashboard('paymentreceipt','${d.id}')">
            <span class="mini-primary">${escapeHtml(d.docNumber)}</span>
            <span class="mini-secondary">${formatDateShort(d.date)} · ${escapeHtml(d.paymentMethod || '')}</span>
            <span class="mini-amount">${formatCurrency(d.amountReceived || 0)}</span>
          </div>`).join('')}</div>`
      }
    </div>

    <!-- Certificates of Completion -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Certificates of Completion
        <button class="btn btn-sm btn-secondary" style="margin-left:auto;" onclick="createDocForJob('certificates','${job.id}')">+ New Certificate</button>
      </div>
      ${certificates.length === 0 ? '<p class="intro-text">No certificates yet.</p>' :
        `<div class="mini-table">${certificates.map(d => `
          <div class="mini-row" onclick="editDocFromDashboard('certificates','${d.id}')">
            <span class="mini-primary">${escapeHtml(d.docNumber)}</span>
            <span class="mini-secondary">${formatDateShort(d.completionDate || d.date)}</span>
            <span class="status-badge" style="background:${d.status === 'completed' ? '#22c55e20;color:#22c55e' : '#f59e0b20;color:#f59e0b'};">${escapeHtml(d.status || 'draft')}</span>
          </div>`).join('')}</div>`
      }
    </div>

    <!-- Asset Transfers -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Asset Transfers
        <button class="btn btn-sm btn-secondary" style="margin-left:auto;" onclick="createDocForJob('assettransfers','${job.id}')">+ New Transfer</button>
      </div>
      ${assettransfers.length === 0 ? '<p class="intro-text">No asset transfers yet.</p>' :
        `<div class="mini-table">${assettransfers.map(d => `
          <div class="mini-row" onclick="editDocFromDashboard('assettransfers','${d.id}')">
            <span class="mini-primary">${escapeHtml(d.docNumber)} — ${escapeHtml(d.transferType || '')}</span>
            <span class="mini-secondary">${formatDateShort(d.date)}</span>
            <span class="status-badge" style="background:${d.signedDocumentData ? '#22c55e20;color:#22c55e' : '#f59e0b20;color:#f59e0b'};">${d.signedDocumentData ? 'Signed' : 'Pending'}</span>
          </div>`).join('')}</div>`
      }
    </div>

    <!-- Safety Reports -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Safety Reports / JSA
        <button class="btn btn-sm btn-secondary" style="margin-left:auto;" onclick="createDocForJob('safetyreports','${job.id}')">+ New Safety Report</button>
      </div>
      ${safetyreports.length === 0 ? '<p class="intro-text">No safety reports yet.</p>' :
        `<div class="mini-table">${safetyreports.map(d => `
          <div class="mini-row" onclick="editDocFromDashboard('safetyreports','${d.id}')">
            <span class="mini-primary">${escapeHtml(d.docNumber)} — ${escapeHtml(d.jobSiteName || '')}</span>
            <span class="mini-secondary">${formatDateShort(d.date)} · Risk: ${escapeHtml(d.overallRiskLevel || 'N/A')}</span>
            <span class="status-badge" style="background:${d.overallRiskLevel === 'low' ? '#22c55e20;color:#22c55e' : d.overallRiskLevel === 'medium' ? '#f59e0b20;color:#f59e0b' : '#ef444420;color:#ef4444'};">${escapeHtml((d.overallRiskLevel || 'N/A').toUpperCase())}</span>
          </div>`).join('')}</div>`
      }
    </div>
  `;
}

// ============================================================
// JOB OVERVIEW / HEALTH DASHBOARD
// ============================================================
function analyzeJobHealth(jobId) {
  const job = getJobById(jobId);
  if (!job) return { checklist: [], alerts: [], score: 0 };
  const company = getCompany();
  const estimates = getEstimates().filter(e => e.jobId === jobId);
  const quotes = getDocuments('quote').filter(q => q.jobId === jobId);
  const invoices = getDocuments('invoice').filter(i => i.jobId === jobId);
  const pos = getDocuments('po').filter(p => p.jobId === jobId);
  const timesheets = getTimesheets().filter(t => t.jobId === jobId);
  const travel = getTravelEntries().filter(t => t.jobId === jobId);
  const receipts = getReceipts().filter(r => r.jobId === jobId);
  const testReports = getTestReports().filter(t => t.jobId === jobId);
  const pnl = getPnlStatements().find(p => p.jobId === jobId);
  const workorders = getDocuments('workorder').filter(d => d.jobId === jobId);
  const changeorders = getDocuments('changeorder').filter(d => d.jobId === jobId);
  const proposals = getDocuments('proposal').filter(d => d.jobId === jobId);
  const contracts = getDocuments('contracts').filter(d => d.jobId === jobId);
  const creditmemos = getDocuments('creditmemo').filter(d => d.jobId === jobId);
  const paymentreceipts = getDocuments('paymentreceipt').filter(d => d.jobId === jobId);
  const certificates = getDocuments('certificates').filter(d => d.jobId === jobId);
  const assettransfers = getDocuments('assettransfers').filter(d => d.jobId === jobId);
  const safetyreports = getDocuments('safetyreports').filter(d => d.jobId === jobId);

  const totalHours = timesheets.reduce((s, t) => s + getTimesheetTotalHours(t), 0);
  const totalMiles = travel.reduce((s, t) => s + (t.mileage || 0), 0);
  const totalReceiptAmt = receipts.reduce((s, r) => s + (r.amount || 0), 0);
  const totalEstRevenue = estimates.reduce((s, e) => s + (e.totalCustomerPrice || 0), 0);
  const totalInvAmount = invoices.reduce((s, i) => s + (i.total || 0), 0);
  const totalPOAmount = pos.reduce((s, p) => s + (p.total || 0), 0);
  const hasLabor = estimates.some(e => (e.lineItems || []).some(li => li.category === 'labor'));
  const hasMaterials = estimates.some(e => (e.lineItems || []).some(li => li.category === 'materials'));
  const isActive = ['in-progress', 'approved'].includes(job.status);
  const isDone = ['completed', 'closed'].includes(job.status);
  const isEarly = ['estimate', 'quoted'].includes(job.status);

  // --- CHECKLIST ---
  const checklist = [];
  function addCheck(label, icon, done, detail, count) {
    checklist.push({ label, icon, done, detail: detail || '', count: count || 0 });
  }
  // Sales Tax check (calculated before checklist so it can be used in Phase 3)
  let taxOk = true;
  let taxDetail = 'N/A';
  if (invoices.length > 0) {
    const hasTaxableItems = invoices.some(i => (i.lineItems || []).some(li => li.taxable));
    const hasTaxApplied = invoices.some(i => (i.taxAmount || 0) > 0);
    if (hasTaxableItems && hasTaxApplied) { taxOk = true; taxDetail = 'Tax applied on taxable items'; }
    else if (hasTaxableItems && !hasTaxApplied) { taxOk = false; taxDetail = 'Taxable items found but $0 tax collected'; }
    else if (!hasTaxableItems) { taxOk = true; taxDetail = 'No taxable items on invoices'; }
  } else { taxDetail = 'No invoices yet'; }

  // --- CHECKLIST (ordered by natural job workflow) ---
  // Phase 1: Pre-Work (Planning & Approval)
  addCheck('Estimate', '', estimates.length > 0, estimates.length > 0 ? estimates.length + ' estimate' + (estimates.length > 1 ? 's' : '') + ' \u00b7 ' + formatCurrency(totalEstRevenue) : 'No estimates created', estimates.length);
  addCheck('Quote', '', quotes.length > 0, quotes.length > 0 ? quotes.map(q => (q.docNumber || 'Quote') + ' (' + (q.status || 'draft') + ')').join(', ') : 'No quotes generated', quotes.length);
  const acceptedQuotes = quotes.filter(q => q.status === 'accepted' || q.status === 'approved');
  addCheck('Quote Accepted', '', acceptedQuotes.length > 0, acceptedQuotes.length > 0 ? acceptedQuotes.length + ' accepted' : 'No quotes accepted yet', acceptedQuotes.length);
  addCheck('Proposals', '', true, proposals.length > 0 ? proposals.length + ' proposal' + (proposals.length > 1 ? 's' : '') : 'None', proposals.length);
  addCheck('Contracts', '', true, contracts.length > 0 ? contracts.length + ' contract' + (contracts.length > 1 ? 's' : '') : 'None', contracts.length);

  // Phase 2: Active Work (Execution)
  addCheck('Work Order', '', workorders.length > 0, workorders.length > 0 ? workorders.length + ' work order' + (workorders.length > 1 ? 's' : '') : 'No work orders issued', workorders.length);
  addCheck('Timesheets', '', timesheets.length > 0, timesheets.length > 0 ? timesheets.length + ' entries \u00b7 ' + totalHours.toFixed(1) + ' hrs' : 'No timesheets logged', timesheets.length);
  addCheck('Purchase Orders', '', pos.length > 0 || !hasMaterials, pos.length > 0 ? pos.length + ' PO' + (pos.length > 1 ? 's' : '') + ' \u00b7 ' + formatCurrency(totalPOAmount) : hasMaterials ? 'Materials in estimate but no POs' : 'N/A \u2014 no materials', pos.length);
  addCheck('Receipts', '', receipts.length > 0, receipts.length > 0 ? receipts.length + ' receipt' + (receipts.length > 1 ? 's' : '') + ' \u00b7 ' + formatCurrency(totalReceiptAmt) : 'No receipts', receipts.length);
  addCheck('Travel Logs', '', travel.length > 0, travel.length > 0 ? travel.length + ' entries \u00b7 ' + totalMiles.toFixed(0) + ' mi' : 'No travel logged', travel.length);
  addCheck('Safety Reports', '', safetyreports.length > 0, safetyreports.length > 0 ? safetyreports.length + ' report' + (safetyreports.length > 1 ? 's' : '') : 'No safety reports', safetyreports.length);
  addCheck('Test Reports', '', testReports.length > 0, testReports.length > 0 ? testReports.length + ' report' + (testReports.length > 1 ? 's' : '') + ' \u00b7 ' + testReports.filter(t => t.overallResult === 'pass').length + ' pass' : 'No test reports filed', testReports.length);
  addCheck('Change Orders', '', true, changeorders.length > 0 ? changeorders.length + ' change order' + (changeorders.length > 1 ? 's' : '') : 'None', changeorders.length);
  addCheck('Asset Transfers', '', assettransfers.length > 0 || true, assettransfers.length > 0 ? assettransfers.length + ' transfer' + (assettransfers.length > 1 ? 's' : '') : 'None needed', assettransfers.length);

  // Phase 3: Closeout & Billing (Financial Close)
  addCheck('Invoice', '', invoices.length > 0, invoices.length > 0 ? invoices.map(i => (i.docNumber || 'Invoice') + ' (' + (i.status || 'draft') + ') ' + formatCurrency(i.total)).join(', ') : 'No invoices created', invoices.length);
  const paidInvoices = invoices.filter(i => i.status === 'paid');
  addCheck('Invoice Paid', '', paidInvoices.length > 0 && paidInvoices.length === invoices.length, paidInvoices.length > 0 ? paidInvoices.length + '/' + invoices.length + ' paid' : invoices.length > 0 ? '0/' + invoices.length + ' paid' : 'No invoices to pay', paidInvoices.length);
  addCheck('Sales Tax', '', taxOk, taxDetail, 0);
  addCheck('P&L Statement', '', !!pnl, pnl ? 'Margin: ' + ((pnl.profitMargin || 0) * 100).toFixed(1) + '%' : 'No P&L generated', pnl ? 1 : 0);


  // --- ALERTS ---
  const alerts = [];
  function addAlert(severity, msg, action) {
    alerts.push({ severity, msg, action });
  }

  // Workflow sequence violations
  const draftQuotes = quotes.filter(q => !q.status || q.status === 'draft' || q.status === 'planning');
  if (draftQuotes.length > 0 && invoices.length > 0) {
    addAlert('critical', 'Quote still in Draft/Planning but Invoice already exists.', { label: 'Update Quote Status', type: 'editDoc', docType: 'quote', docId: draftQuotes[0].id });
  }
  const declinedQuotes = quotes.filter(q => q.status === 'declined');
  if (declinedQuotes.length > 0 && declinedQuotes.length === quotes.length && isActive) {
    addAlert('warning', 'All quotes have been Declined but job is still active.', { label: 'Close Job', type: 'updateJobStatus', status: 'closed' });
  }
  if (quotes.length > 0 && estimates.length === 0) {
    addAlert('warning', 'Quote exists but no Estimate was created first.', { label: 'Create Estimate', type: 'createDoc', docType: 'estimate' });
  }
  if (invoices.length > 0 && acceptedQuotes.length === 0 && quotes.length > 0) {
    addAlert('warning', 'Invoice created but no Quote has been marked Accepted.', { label: 'Update Quote', type: 'editDoc', docType: 'quote', docId: quotes[0].id });
  }
  if (isDone && invoices.length === 0) {
    addAlert('warning', 'Job is ' + job.status + ' but no Invoice has been created.', { label: 'Create Invoice', type: 'createDoc', docType: 'invoice' });
  }
  const unpaidInvoices = invoices.filter(i => i.status !== 'paid');
  if (isDone && unpaidInvoices.length > 0) {
    addAlert('warning', 'Job is ' + job.status + ' but ' + unpaidInvoices.length + ' invoice' + (unpaidInvoices.length > 1 ? 's are' : ' is') + ' still unpaid.', { label: 'View Invoice', type: 'editDoc', docType: 'invoice', docId: unpaidInvoices[0].id });
  }

  // Financial anomalies
  if (totalEstRevenue > 0 && totalInvAmount > 0) {
    const variance = Math.abs(totalEstRevenue - totalInvAmount) / totalEstRevenue;
    if (variance > 0.15) {
      addAlert('warning', 'Estimate total (' + formatCurrency(totalEstRevenue) + ') vs Invoice total (' + formatCurrency(totalInvAmount) + ') differ by ' + (variance * 100).toFixed(0) + '%.', { label: 'Review', type: 'compare' });
    }
  }
  invoices.forEach(inv => {
    const hasTaxable = (inv.lineItems || []).some(li => li.taxable);
    if (hasTaxable && (inv.taxAmount || 0) === 0) {
      addAlert('critical', 'Invoice ' + (inv.docNumber || '') + ' has taxable items but $0 tax collected.', { label: 'Edit Invoice', type: 'editDoc', docType: 'invoice', docId: inv.id });
    }
    if (hasTaxable && (inv.taxRate || 0) > 0 && company.taxRate > 0 && Math.abs(inv.taxRate - company.taxRate) > 0.01) {
      addAlert('warning', 'Invoice ' + (inv.docNumber || '') + ' tax rate (' + inv.taxRate + '%) differs from company default (' + company.taxRate + '%).', { label: 'Edit Invoice', type: 'editDoc', docType: 'invoice', docId: inv.id });
    }
  });
  if (pos.length > 0 && receipts.length === 0) {
    addAlert('info', 'Purchase Orders exist but no receipts have been logged.', { label: 'Add Receipt', type: 'createDoc', docType: 'receipt' });
  }
  if (totalReceiptAmt > 0 && totalPOAmount > 0 && totalReceiptAmt > totalPOAmount * 1.1) {
    addAlert('warning', 'Receipt total (' + formatCurrency(totalReceiptAmt) + ') exceeds PO total (' + formatCurrency(totalPOAmount) + ') by ' + ((totalReceiptAmt / totalPOAmount - 1) * 100).toFixed(0) + '%.', { label: 'Review POs', type: 'navigate', page: 'po' });
  }

  // Labor & time anomalies
  if (isActive && timesheets.length === 0) {
    addAlert('warning', 'Job is In Progress but no timesheets have been logged.', { label: 'Add Timesheet', type: 'createDoc', docType: 'timesheet' });
  }
  if (job.startDate || job.endDate) {
    timesheets.forEach(ts => {
      if (ts.date && job.startDate && ts.date < job.startDate) {
        addAlert('warning', 'Timesheet on ' + formatDateShort(ts.date) + ' is before job start date (' + formatDateShort(job.startDate) + ').', { label: 'View Timesheet', type: 'editTimesheet', docId: ts.id });
      }
      if (ts.date && job.endDate && ts.date > job.endDate) {
        addAlert('warning', 'Timesheet on ' + formatDateShort(ts.date) + ' is after job end date (' + formatDateShort(job.endDate) + ').', { label: 'View Timesheet', type: 'editTimesheet', docId: ts.id });
      }
    });
  }
  if (invoices.length > 0 && hasLabor && timesheets.length === 0) {
    addAlert('warning', 'Invoice exists with labor in estimate but no timesheets logged.', { label: 'Add Timesheet', type: 'createDoc', docType: 'timesheet' });
  }

  // Compliance & documentation
  if (isDone && testReports.length === 0) {
    addAlert('info', 'Job is completed but no test reports have been filed.', { label: 'Add Test Report', type: 'createDoc', docType: 'testreport' });
  }
  testReports.forEach(tr => {
    if (tr.overallResult === 'fail') {
      addAlert('critical', 'Test Report ' + (tr.reportNumber || '') + ' has a FAIL result.', { label: 'View Report', type: 'editTestReport', docId: tr.id });
    }
  });
  if (timesheets.length > 0 && safetyreports.length === 0) {
    addAlert('info', 'Timesheets logged but no safety report / JSA filed.', { label: 'Add Safety Report', type: 'createDoc', docType: 'safetyreport' });
  }
  if (isActive && workorders.length === 0) {
    addAlert('info', 'Job is active but no Work Order has been issued.', { label: 'Create Work Order', type: 'createDoc', docType: 'workorder' });
  }

  // Status consistency
  if (job.status === 'estimate' && acceptedQuotes.length > 0) {
    addAlert('warning', 'Job is still in Estimate status but a quote has been accepted.', { label: 'Update to Approved', type: 'updateJobStatus', status: 'approved' });
  }
  if (job.status === 'closed' && unpaidInvoices.length > 0) {
    addAlert('critical', 'Job is Closed but has ' + unpaidInvoices.length + ' unpaid invoice' + (unpaidInvoices.length > 1 ? 's' : '') + '.', { label: 'View Invoice', type: 'editDoc', docType: 'invoice', docId: unpaidInvoices[0].id });
  }
  if (isActive && !job.startDate) {
    addAlert('warning', 'Job is active but has no start date set.', { label: 'Edit Job', type: 'editJob' });
  }
  if (isDone && !pnl) {
    addAlert('info', 'Job is completed but no P&L statement has been generated.', { label: 'Generate P&L', type: 'createPnl' });
  }

  // Credit memos without paid invoice
  if (creditmemos.length > 0 && paidInvoices.length === 0) {
    addAlert('warning', 'Credit memo exists but no invoices have been paid.', { label: 'Review', type: 'navigate', page: 'credit-memos' });
  }

  // Unsigned asset transfers
  const unsignedTransfers = assettransfers.filter(at => !at.signedDocumentData);
  if (unsignedTransfers.length > 0) {
    addAlert('warning', unsignedTransfers.length + ' asset transfer' + (unsignedTransfers.length > 1 ? 's' : '') + ' pending signature.', { label: 'View Transfer', type: 'editDoc', docType: 'assettransfers', docId: unsignedTransfers[0].id });
  }

  // Score calculation
  const coreItems = checklist.filter(c => ['Estimate', 'Quote', 'Quote Accepted', 'Work Order', 'Timesheets', 'Invoice', 'Invoice Paid', 'Sales Tax'].includes(c.label));
  const doneCount = coreItems.filter(c => c.done).length;
  const score = coreItems.length > 0 ? Math.round((doneCount / coreItems.length) * 100) : 0;

  return { checklist, alerts, score, job, estimates, quotes, invoices, timesheets, travel, receipts, testReports, pnl, pos, workorders, changeorders, proposals, contracts, creditmemos, paymentreceipts, certificates, assettransfers, safetyreports };
}

function executeOverviewAction(action, jobId) {
  if (!action) return;
  switch (action.type) {
    case 'editDoc':
      editingDocId = action.docId;
      const doc = action.docType === 'estimate' ? getEstimates().find(e => e.id === action.docId) : getDocuments(action.docType).find(d => d.id === action.docId);
      if (doc) {
        switch (action.docType) {
          case 'quote': renderQuoteEditor(doc); break;
          case 'invoice': renderInvoiceEditor(doc); break;
          case 'po': renderPOEditor(doc); break;
          case 'estimate': renderEstimateEditor(doc); break;
          case 'workorder': renderWorkOrderEditor(doc); break;
          case 'changeorder': renderChangeOrderEditor(doc); break;
          case 'proposal': renderProposalEditor(doc); break;
          case 'contracts': renderContractEditor(doc); break;
          case 'creditmemo': renderCreditMemoEditor(doc); break;
          case 'paymentreceipt': renderPaymentReceiptEditor(doc); break;
          case 'certificates': renderCertificateEditor(doc); break;
          case 'assettransfers': renderAssetTransferEditor(doc); break;
          case 'safetyreports': renderSafetyReportEditor(doc); break;
        }
      }
      break;
    case 'createDoc':
      currentJobId = jobId;
      switch (action.docType) {
        case 'estimate': createEstimateForJob(jobId); break;
        case 'invoice': createDocForJob('invoice', jobId); break;
        case 'quote': createDocForJob('quote', jobId); break;
        case 'po': createDocForJob('po', jobId); break;
        case 'workorder': createDocForJob('workorder', jobId); break;
        case 'timesheet': createTimesheetForJob(jobId); break;
        case 'receipt': createReceiptForJob(jobId); break;
        case 'testreport': createTestReportForJob(jobId); break;
        case 'safetyreport': createDocForJob('safetyreports', jobId); break;
      }
      break;
    case 'editTimesheet':
      editTimesheet(action.docId);
      break;
    case 'editTestReport':
      editTestReport(action.docId);
      break;
    case 'editJob':
      editJobFromDashboard(jobId);
      break;
    case 'updateJobStatus':
      const job = getJobById(jobId);
      if (job) {
        job.status = action.status;
        job.updatedAt = new Date().toISOString();
        saveDocument('jobs', job);
        showToast('Job status updated to ' + (JOB_STATUSES.find(s => s.id === action.status)?.label || action.status));
        renderJobDashboard();
      }
      break;
    case 'createPnl':
      openPnlForJob(jobId);
      break;
    case 'navigate':
      showPage(action.page);
      break;
    case 'compare':
      // Just refresh the dashboard to show the comparison
      renderJobDashboard();
      break;
  }
}

function getHealthColor(score) {
  if (score >= 80) return '#22c55e';
  if (score >= 50) return '#f59e0b';
  return '#ef4444';
}

function getAlertIcon(severity) {
  switch (severity) {
    case 'critical': return '\ud83d\udd34';
    case 'warning': return '\ud83d\udfe1';
    case 'info': return '\ud83d\udfe2';
    default: return '\u2139\ufe0f';
  }
}

function getAlertBg(severity) {
  switch (severity) {
    case 'critical': return 'background:rgba(239,68,68,0.1);border-left:3px solid #ef4444;';
    case 'warning': return 'background:rgba(245,158,11,0.1);border-left:3px solid #f59e0b;';
    case 'info': return 'background:rgba(59,130,246,0.1);border-left:3px solid #3b82f6;';
    default: return '';
  }
}

function renderChecklistPhase(title, items) {
  if (!items || items.length === 0) return '';
  const doneCount = items.filter(c => c.done).length;
  const allDone = doneCount === items.length;
  return `
    <div style="margin-bottom:12px;">
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px;">
        <span style="font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:${allDone ? '#22c55e' : 'var(--text-secondary)'};">${title}</span>
        <span style="font-size:11px;color:var(--text-secondary);">${doneCount}/${items.length}</span>
        <div style="flex:1;height:1px;background:var(--border);"></div>
      </div>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:4px;">
        ${items.map(c => `
          <div style="display:flex;align-items:center;gap:8px;padding:5px 10px;border-radius:6px;background:var(--bg-secondary);font-size:13px;${c.done ? 'opacity:0.85;' : ''}">
            <span style="font-size:13px;color:${c.done ? '#22c55e' : '#6b7280'};">${c.done ? '\u2713' : '\u25cb'}</span>
            <span style="font-weight:600;min-width:100px;${c.done ? '' : 'color:var(--text-secondary);'}">${c.label}</span>
            <span style="color:var(--text-secondary);font-size:12px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${escapeHtml(c.detail)}</span>
          </div>
        `).join('')}
      </div>
    </div>
  `;
}

function renderJobOverviewSection(jobId) {
  const health = analyzeJobHealth(jobId);
  if (!health.job) return '';
  const criticalCount = health.alerts.filter(a => a.severity === 'critical').length;
  const warningCount = health.alerts.filter(a => a.severity === 'warning').length;
  const infoCount = health.alerts.filter(a => a.severity === 'info').length;
  const scoreColor = getHealthColor(health.score);

  // Store actions for onclick handlers
  window._jobOverviewActions = health.alerts.map(a => a.action);

  return `
    <div class="card" id="job-overview-card" style="border-top:3px solid ${scoreColor};">
      <div class="card-title" style="display:flex;align-items:center;gap:12px;">
        <div class="accent-bar" style="background:${scoreColor};"></div>
        <span>Job Overview</span>
        <div style="margin-left:auto;display:flex;align-items:center;gap:12px;">
          ${criticalCount > 0 ? '<span style="background:rgba(239,68,68,0.15);color:#ef4444;padding:2px 10px;border-radius:12px;font-size:12px;font-weight:600;">\ud83d\udd34 ' + criticalCount + ' Critical</span>' : ''}
          ${warningCount > 0 ? '<span style="background:rgba(245,158,11,0.15);color:#f59e0b;padding:2px 10px;border-radius:12px;font-size:12px;font-weight:600;">\ud83d\udfe1 ' + warningCount + ' Warning</span>' : ''}
          ${infoCount > 0 ? '<span style="background:rgba(59,130,246,0.15);color:#3b82f6;padding:2px 10px;border-radius:12px;font-size:12px;font-weight:600;">\ud83d\udfe2 ' + infoCount + ' Info</span>' : ''}
          ${health.alerts.length === 0 ? '<span style="background:rgba(34,197,94,0.15);color:#22c55e;padding:2px 10px;border-radius:12px;font-size:12px;font-weight:600;">\u2705 All Clear</span>' : ''}
          <div style="display:flex;align-items:center;gap:6px;">
            <div style="width:60px;height:8px;background:var(--bg-secondary);border-radius:4px;overflow:hidden;"><div style="width:${health.score}%;height:100%;background:${scoreColor};border-radius:4px;"></div></div>
            <span style="font-size:13px;font-weight:700;color:${scoreColor};">${health.score}%</span>
          </div>
        </div>
      </div>

      <!-- Checklist by Workflow Phase -->
      ${renderChecklistPhase('Planning & Approval', health.checklist.slice(0, 5))}
      ${renderChecklistPhase('Active Work', health.checklist.slice(5, 14))}
      ${renderChecklistPhase('Financial Close', health.checklist.slice(14))}

      <!-- Alerts -->
      ${health.alerts.length > 0 ? `
        <div style="border-top:1px solid var(--border);padding-top:12px;">
          <div style="font-weight:600;font-size:13px;margin-bottom:8px;color:var(--text-secondary);">\u26a1 Issues & Recommendations</div>
          <div style="display:flex;flex-direction:column;gap:6px;">
            ${health.alerts.map((a, idx) => `
              <div style="${getAlertBg(a.severity)}padding:8px 12px;border-radius:6px;display:flex;align-items:center;gap:10px;font-size:13px;">
                <span>${getAlertIcon(a.severity)}</span>
                <span style="flex:1;">${escapeHtml(a.msg)}</span>
                ${a.action ? '<button class="btn btn-sm btn-secondary" onclick="executeOverviewAction(window._jobOverviewActions[' + idx + '],\'' + jobId + '\')" style="white-space:nowrap;font-size:11px;padding:3px 10px;">' + escapeHtml(a.action.label) + '</button>' : ''}
              </div>
            `).join('')}
          </div>
        </div>
      ` : ''}
    </div>
  `;
}

// Compact overview for the Jobs Dashboard grid/list cards
function getJobHealthBadge(jobId) {
  const health = analyzeJobHealth(jobId);
  const criticals = health.alerts.filter(a => a.severity === 'critical').length;
  const warnings = health.alerts.filter(a => a.severity === 'warning').length;
  const infos = health.alerts.filter(a => a.severity === 'info').length;
  if (criticals > 0) return '<span title="' + criticals + ' critical issue' + (criticals > 1 ? 's' : '') + '" style="display:inline-flex;align-items:center;gap:3px;background:rgba(239,68,68,0.15);color:#ef4444;padding:1px 8px;border-radius:10px;font-size:11px;font-weight:600;cursor:default;">\ud83d\udd34 ' + criticals + '</span>';
  if (warnings > 0) return '<span title="' + warnings + ' warning' + (warnings > 1 ? 's' : '') + '" style="display:inline-flex;align-items:center;gap:3px;background:rgba(245,158,11,0.15);color:#f59e0b;padding:1px 8px;border-radius:10px;font-size:11px;font-weight:600;cursor:default;">\ud83d\udfe1 ' + warnings + '</span>';
  if (health.score >= 80) return '<span title="Job health: ' + health.score + '%" style="display:inline-flex;align-items:center;gap:3px;background:rgba(34,197,94,0.15);color:#22c55e;padding:1px 8px;border-radius:10px;font-size:11px;font-weight:600;cursor:default;">\u2705</span>';
  if (infos > 0) return '<span title="' + infos + ' suggestion' + (infos > 1 ? 's' : '') + '" style="display:inline-flex;align-items:center;gap:3px;background:rgba(59,130,246,0.15);color:#3b82f6;padding:1px 8px;border-radius:10px;font-size:11px;font-weight:600;cursor:default;">\ud83d\udfe2 ' + infos + '</span>';
  if (health.score < 50) return '<span title="Job health: ' + health.score + '%" style="display:inline-flex;align-items:center;gap:3px;background:rgba(245,158,11,0.15);color:#f59e0b;padding:1px 8px;border-radius:10px;font-size:11px;font-weight:600;cursor:default;">' + health.score + '%</span>';
  return '';
}

function editJobFromDashboard(jobId) {
  const job = getJobById(jobId);
  if (job) renderJobEditor(job);
}

function editDocFromDashboard(type, docId) {
  editingDocId = docId;
  const doc = getDocuments(type).find(d => d.id === docId);
  if (!doc) return;
  switch(type) {
    case 'quote': renderQuoteEditor(doc); break;
    case 'invoice': renderInvoiceEditor(doc); break;
    case 'po': renderPOEditor(doc); break;
    case 'letterhead': renderLetterheadEditor(doc); break;
  }
}

function createDocForJob(type, jobId) {
  const job = getJobById(jobId);
  currentJobId = jobId;
  editingDocId = null;
  let doc;
  switch(type) {
    case 'quote':
      doc = getDefaultQuote();
      if (job) {
        doc.jobId = jobId;
        doc.customerName = job.customer.name;
        doc.customerCompany = job.customer.company;
        doc.customerPhone = job.customer.phone;
        doc.customerEmail = job.customer.email;
        doc.customerAddress = job.customer.address;
        doc.projectName = job.name;
      }
      renderQuoteEditor(doc);
      break;
    case 'invoice':
      doc = getDefaultInvoice();
      if (job) {
        doc.jobId = jobId;
        doc.customerName = job.customer.name;
        doc.customerCompany = job.customer.company;
        doc.customerPhone = job.customer.phone;
        doc.customerEmail = job.customer.email;
        doc.customerAddress = job.customer.address;
        doc.projectName = job.name;
      }
      renderInvoiceEditor(doc);
      break;
    case 'po':
      doc = getDefaultPO();
      if (job) { doc.jobId = jobId; doc.projectName = job.name; }
      renderPOEditor(doc);
      break;
  }
}


// ============================================================
// ESTIMATE WORKSHEETS
// ============================================================
function getDefaultEstimate(jobId) {
  const company = getCompany();
  return {
    id: generateId(),
    jobId: jobId || '',
    estimateNumber: generateNumber('EST'),
    date: todayStr(),
    lineItems: [
      { id: generateId(), category: 'materials', description: '', quantity: 1, unit: 'Lot', unitCost: 0, markupPercent: 25 },
      { id: generateId(), category: 'labor', description: '', quantity: 1, unit: 'Hours', unitCost: company.regularRate, markupPercent: 30 },
    ],
    totalCost: 0,
    totalCustomerPrice: 0,
    estimatedProfit: 0,
    notes: '',
    status: 'draft',
  };
}

function createEstimateForJob(jobId) {
  editingDocId = null;
  currentJobId = jobId;
  const est = getDefaultEstimate(jobId);
  renderEstimateEditor(est);
}

function editEstimate(estId) {
  const est = getEstimates().find(e => e.id === estId);
  if (!est) return;
  editingDocId = estId;
  currentJobId = est.jobId;
  renderEstimateEditor(est);
}

function renderEstimateEditor(est) {
  window._currentEstimate = est;
  if (!est.lineItems) est.lineItems = [];
  window._estLineItems = est.lineItems.map(li => ({...li}));
  const main = document.querySelector('.main-content');
  const job = est.jobId ? getJobById(est.jobId) : null;

  main.innerHTML = `
    <div class="page-header">
      <div style="display:flex;align-items:center;gap:12px;">
        <button class="btn-icon" onclick="${est.jobId ? `openJobDashboard('${est.jobId}')` : `showPage('estimates')`}" title="Back">←</button>
        <h1>Estimate Worksheet</h1>
      </div>
      <div class="page-header-actions">
        <button class="btn btn-secondary" onclick="saveCurrentEstimate()">Save Estimate</button>
        <button class="btn btn-primary" onclick="generateQuoteFromEstimate()">Generate Quote</button>
        <button class="btn btn-secondary" onclick="exportEstimatePDF()">Export PDF</button>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Estimate Information</div>
      <div class="form-grid">
        <div class="form-group"><label class="form-label">Estimate Number</label><input class="form-input" id="est-number" value="${escapeHtml(est.estimateNumber)}"></div>
        <div class="form-group"><label class="form-label">Date</label><input class="form-input" type="date" id="est-date" value="${est.date}" onchange="checkEstimateDateHoliday(this.value)"></div>
        <div id="est-holiday-warning" class="holiday-warning" style="display:none;"></div>
        <div class="form-group"><label class="form-label">Job</label>${buildJobSelector('est-job', est.jobId, true)}</div>
        <div class="form-group"><label class="form-label">Status</label>
          <select class="form-select" id="est-status">
            ${(function(){
              const cls = getDocClassifications();
              const statuses = cls.estimate ? cls.estimate.statuses : [{id:'draft',label:'Draft'},{id:'review',label:'In Review'},{id:'approved',label:'Approved'},{id:'revised',label:'Revised'},{id:'final',label:'Final'}];
              return statuses.map(s => '<option value="'+s.id+'"'+(((est.status||'draft')===s.id)?' selected':'')+'>'+escapeHtml(s.label)+'</option>').join('');
            })()}
          </select>
        </div>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Cost Breakdown
        <span style="margin-left:auto;font-size:12px;color:var(--text-secondary);font-weight:400;">Internal costs + markup = customer price</span>
      </div>
      <div class="table-scroll">
        <table class="line-items-table" id="est-table">
          <thead>
            <tr>
              <th class="col-cat">Category</th>
              <th class="col-desc">Description</th>
              <th class="col-qty">Qty</th>
              <th class="col-unit">Unit</th>
              <th style="width:100px;">Unit Cost</th>
              <th style="width:80px;">Markup %</th>
              <th style="width:100px;text-align:right;">Ext. Cost</th>
              <th style="width:110px;text-align:right;">Customer Price</th>
              <th class="col-actions"></th>
            </tr>
          </thead>
          <tbody id="est-line-items"></tbody>
        </table>
      </div>
      <div style="margin-top:12px;display:flex;gap:8px;flex-wrap:wrap;">
        <button class="btn btn-secondary btn-sm" onclick="addEstLineItem()">+ Add Line Item</button>
        <button class="btn btn-secondary btn-sm" onclick="showEquipmentRoiPicker()">+ Add Equipment (ROI)</button>
        <button class="btn btn-secondary btn-sm" onclick="addEstLineItemFromRate()">+ Add from Rate Sheet</button>
        <button class="btn btn-secondary btn-sm" onclick="addEstLineItemFromEmpType()">+ Add by Employee Type</button>
      </div>
    </div>
    <div class="totals-section">
      <div class="totals-table">
        <div class="totals-row"><span class="label">Total Billed (Ext. Cost):</span><span class="value" id="est-totalCost">$0.00</span></div>
        <div class="totals-row"><span class="label">Total Customer Price (w/ Markup):</span><span class="value" id="est-totalPrice">$0.00</span></div>
        <div class="totals-row" style="display:none;"><span class="label">Actual Company Cost (Labor Pay Rates):</span><span class="value" id="est-actualCost" style="color:var(--text-secondary);">$0.00</span></div>
        <div class="totals-row total"><span class="label" id="est-profit-label">Estimated Profit (Markup Only):</span><span class="value" id="est-profit" style="color:var(--success);">$0.00</span></div>
      </div>
    </div>
    <div class="card" style="margin-top:20px;">
      <div class="card-title"><div class="accent-bar"></div>Notes</div>
      <textarea class="form-textarea" id="est-notes" rows="3" placeholder="Internal notes...">${escapeHtml(est.notes)}</textarea>
    </div>
  `;
  renderEstLineItems();
  recalcEstimate();
  // Check if estimate date falls on a holiday
  if (est.date) checkEstimateDateHoliday(est.date);
}

function renderEstLineItems() {
  const tbody = document.getElementById('est-line-items');
  if (!tbody) return;
  const rs = getRateSheet();
  const laborRates = rs.laborRates || [];
  const rosterNames = getEmployeeRosterNames();
  tbody.innerHTML = window._estLineItems.map((li, idx) => {
    const isLabor = li.category === 'labor';
    if (isLabor && !li.assignedTechnicians) li.assignedTechnicians = [];
    const techs = li.assignedTechnicians || [];
    const techRows = isLabor ? techs.map((t, ti) => {
      const emp = getEmployeeById(t.employeeId);
      const currentPayRate = emp ? emp.payRate : t.payRate;
      if (emp) t.payRate = currentPayRate; // keep in sync
      t.name = emp ? emp.name : t.name;
      return `<tr style="background:var(--card-bg);">
        <td style="padding:4px 6px;"><select class="form-select" style="font-size:12px;padding:3px 6px;color:var(--text-primary);background:var(--bg-input);" onchange="updateEstTech(${idx},${ti},'employeeId',this.value)">
          <option value="">— Select Technician —</option>
          ${rosterNames.map(e => `<option value="${e.id}" ${t.employeeId === e.id ? 'selected' : ''} style="color:var(--text-primary);background:var(--bg-input);">${escapeHtml(e.name)}${e.employeeType ? ' (' + escapeHtml(e.employeeType) + ')' : ''}</option>`).join('')}
        </select></td>
        <td style="padding:4px 6px;"><select class="form-select" style="font-size:12px;padding:3px 6px;color:var(--text-primary);background:var(--bg-input);" onchange="updateEstTech(${idx},${ti},'hourType',this.value)">
          ${laborRates.filter(r => !r.hidden).map(r => `<option value="${r.id}" ${t.hourType === r.id ? 'selected' : ''} style="color:var(--text-primary);background:var(--bg-input);">${escapeHtml(r.name)} (${r.multiplier}x)</option>`).join('')}
        </select></td>
        <td style="padding:4px 6px;"><input class="form-input" style="font-size:12px;padding:3px 6px;width:70px;" type="number" value="${t.hours}" min="0" step="0.5" onchange="updateEstTech(${idx},${ti},'hours',parseFloat(this.value)||0)"></td>
        <td style="padding:4px 6px;font-size:12px;color:var(--text-secondary);">${formatCurrency(currentPayRate)}/hr</td>
        <td style="padding:4px 6px;font-size:12px;font-weight:600;color:var(--text-secondary);" id="est-tech-cost-${idx}-${ti}">${formatCurrency(getEmployeeEffectivePayRate(currentPayRate, t.hourType) * t.hours)}</td>
        <td style="padding:4px 2px;"><button class="delete-btn" style="font-size:11px;" onclick="removeEstTech(${idx},${ti})" title="Remove">✕</button></td>
      </tr>`;
    }).join('') : '';

    const techPanel = isLabor ? `
    <tr id="est-tech-panel-${idx}" style="${techs.length > 0 || li._showTechPanel ? '' : 'display:none;'}">
      <td colspan="9" style="padding:0;">
        <div style="background:var(--bg);border:1px solid var(--border);border-radius:6px;margin:4px 8px 8px;padding:8px;">
          <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:6px;">
            <span style="font-size:12px;font-weight:600;color:var(--text-secondary);">👷 Assigned Technicians — Actual Company Cost</span>
            <button class="btn btn-secondary btn-sm" style="font-size:11px;padding:2px 8px;" onclick="addEstTech(${idx})">+ Add Technician</button>
          </div>
          ${techs.length > 0 ? `<table style="width:100%;border-collapse:collapse;font-size:12px;">
            <thead><tr style="color:var(--text-secondary);font-size:11px;text-transform:uppercase;">
              <th style="text-align:left;padding:2px 6px;">Technician</th>
              <th style="text-align:left;padding:2px 6px;">Hour Type</th>
              <th style="text-align:left;padding:2px 6px;">Hours</th>
              <th style="text-align:left;padding:2px 6px;">Base Pay</th>
              <th style="text-align:left;padding:2px 6px;">Eff. Cost</th>
              <th></th>
            </tr></thead>
            <tbody>${techRows}</tbody>
            <tfoot><tr style="border-top:1px solid var(--border);font-weight:600;font-size:12px;">
              <td colspan="2" style="padding:4px 6px;">Total Actual Cost:</td>
              <td style="padding:4px 6px;" id="est-tech-total-hrs-${idx}">0</td>
              <td></td>
              <td style="padding:4px 6px;color:var(--accent);" id="est-tech-total-cost-${idx}">$0.00</td>
              <td></td>
            </tr></tfoot>
          </table>` : '<p style="font-size:12px;color:var(--text-secondary);margin:4px 0;">No technicians assigned. Click "+ Add Technician" to calculate actual labor cost.</p>'}
        </div>
      </td>
    </tr>` : '';

    return `
    <tr>
      <td><select class="form-select" onchange="window._estLineItems[${idx}].category=this.value; renderEstLineItems(); recalcEstimate();">
        ${COST_CATEGORIES.map(c => `<option value="${c.id}" ${li.category === c.id ? 'selected' : ''}>${c.label}</option>`).join('')}
      </select></td>
      <td><input class="form-input" value="${escapeHtml(li.description)}" onchange="window._estLineItems[${idx}].description=this.value;"></td>
      <td><input class="form-input" type="number" value="${li.quantity}" min="0" step="0.5" onchange="window._estLineItems[${idx}].quantity=parseFloat(this.value)||0; recalcEstimate();"></td>
      <td><select class="form-select" onchange="window._estLineItems[${idx}].unit=this.value;">
        <option ${li.unit==='Hours'?'selected':''}>Hours</option>
        <option ${li.unit==='Each'?'selected':''}>Each</option>
        <option ${li.unit==='Lot'?'selected':''}>Lot</option>
        <option ${li.unit==='LF'?'selected':''}>LF</option>
        <option ${li.unit==='Day'?'selected':''}>Day</option>
        <option ${li.unit==='Week'?'selected':''}>Week</option>
        <option ${li.unit==='Month'?'selected':''}>Month</option>
      </select></td>
      <td><input class="form-input" type="number" value="${li.unitCost}" min="0" step="0.01" onchange="window._estLineItems[${idx}].unitCost=parseFloat(this.value)||0; recalcEstimate();"></td>
      <td><input class="form-input" type="number" value="${li.markupPercent}" min="0" step="1" onchange="window._estLineItems[${idx}].markupPercent=parseFloat(this.value)||0; recalcEstimate();"></td>
      <td style="text-align:right;font-weight:600;" id="est-ext-${idx}">$0.00</td>
      <td style="text-align:right;font-weight:600;color:var(--accent);" id="est-cust-${idx}">$0.00</td>
      <td style="display:flex;gap:4px;align-items:center;">
        ${isLabor ? `<button class="btn-icon" style="font-size:12px;padding:2px 4px;" onclick="toggleEstTechPanel(${idx})" title="Assign Technicians">👷</button>` : ''}
        <button class="delete-btn" onclick="removeEstLineItem(${idx})" title="Remove">✕</button>
      </td>
    </tr>
    ${techPanel}`;
  }).join('');
  recalcEstimate();
}

function toggleEstTechPanel(idx) {
  const li = window._estLineItems[idx];
  if (!li) return;
  const panel = document.getElementById('est-tech-panel-' + idx);
  if (panel) {
    const isHidden = panel.style.display === 'none';
    panel.style.display = isHidden ? '' : 'none';
    li._showTechPanel = isHidden;
  }
}

function addEstTech(lineIdx) {
  const li = window._estLineItems[lineIdx];
  if (!li || !li.assignedTechnicians) return;
  li.assignedTechnicians.push({ employeeId: '', name: '', hours: 0, payRate: 0, hourType: 'straight' });
  li._showTechPanel = true;
  renderEstLineItems();
}

function removeEstTech(lineIdx, techIdx) {
  const li = window._estLineItems[lineIdx];
  if (!li || !li.assignedTechnicians) return;
  li.assignedTechnicians.splice(techIdx, 1);
  renderEstLineItems();
}

function updateEstTech(lineIdx, techIdx, field, value) {
  const li = window._estLineItems[lineIdx];
  if (!li || !li.assignedTechnicians) return;
  const t = li.assignedTechnicians[techIdx];
  if (!t) return;
  if (field === 'employeeId') {
    t.employeeId = value;
    const emp = getEmployeeById(value);
    if (emp) {
      t.name = emp.name;
      t.payRate = emp.payRate || 0;
    }
    renderEstLineItems();
  } else if (field === 'hours') {
    t.hours = value;
    recalcEstimate();
  } else if (field === 'hourType') {
    t.hourType = value;
    recalcEstimate();
  }
}

function addEstLineItemFromRate() {
  const rs = getRateSheet();
  const rates = rs.laborRates.filter(r => !r.hidden && r.rate > 0);
  const specialty = rs.specialtyServices;
  let options = rates.map((r, i) => {
    let label = (i + 1) + '. ' + r.name;
    if (r.dualRate && r.rate2 > 0) {
      label += ' ($' + r.rate + '/hr ' + (r.dualRateLabel1 || 'first') + ' + $' + r.rate2 + '/hr ' + (r.dualRateLabel2 || 'after') + ')';
    } else {
      label += ' ($' + r.rate + '/hr)';
    }
    return label;
  }).join('\n');
  options += '\n' + specialty.map((s, i) => (rates.length + i + 1) + '. ' + s.name + ' ($' + s.rate + '/hr)').join('\n');
  const choice = prompt('Select a rate to add as a line item:\n\n' + options + '\n\nEnter number:');
  if (!choice) return;
  const idx = parseInt(choice) - 1;
  const allRates = [...rates, ...specialty];
  if (idx >= 0 && idx < allRates.length) {
    const r = allRates[idx];
    if (r.dualRate && r.rate2 > 0) {
      // Add two line items for dual-rate: one for threshold hours, one for remaining
      const thresholdHrs = r.dualRateThresholdHrs || 2;
      window._estLineItems.push({
        id: generateId(),
        category: 'labor',
        description: r.name + ' (' + (r.dualRateLabel1 || 'First ' + thresholdHrs + ' hrs') + ')',
        quantity: thresholdHrs,
        unit: 'Hours',
        unitCost: r.rate,
        markupPercent: 0,
      });
      window._estLineItems.push({
        id: generateId(),
        category: 'labor',
        description: r.name + ' (' + (r.dualRateLabel2 || 'After ' + thresholdHrs + ' hrs') + ')',
        quantity: Math.max(0, (rs.minimumHours || 4) - thresholdHrs),
        unit: 'Hours',
        unitCost: r.rate2,
        markupPercent: 0,
      });
      renderEstLineItems();
      recalcEstimate();
      showToast(r.name + ' added as dual-rate: $' + r.rate + '/hr + $' + r.rate2 + '/hr', 'success');
    } else {
      window._estLineItems.push({
        id: generateId(),
        category: 'labor',
        description: r.name + (r.description ? ' - ' + r.description.substring(0, 50) : ''),
        quantity: rs.minimumHours || 4,
        unit: 'Hours',
        unitCost: r.rate,
        markupPercent: 0,
      });
      renderEstLineItems();
      recalcEstimate();
      showToast(r.name + ' added at $' + r.rate + '/hr', 'success');
    }
  }
}

function checkEstimateDateHoliday(dateStr) {
  const warning = document.getElementById('est-holiday-warning');
  if (!warning) return;
  const hw = getHolidayRateWarning(dateStr);
  if (hw) {
    warning.style.display = 'flex';
    warning.innerHTML = '<span style="font-size:18px;">&#9888;</span><div><strong>Rate Alert: ' + escapeHtml(hw.holiday) + '</strong><br>Labor on this date should be billed at <strong>$' + hw.rate + '/hr</strong> per the company rate schedule. Please adjust labor line items accordingly.</div>';
  } else {
    warning.style.display = 'none';
  }
}

function addEstLineItemFromEmpType() {
  const empTypes = getEmployeeTypes();
  if (empTypes.length === 0) { showToast('No employee types defined. Add them in Settings.', 'error'); return; }
  const options = empTypes.map((t, i) => (i + 1) + '. ' + t.name + ' ($' + t.defaultRate.toFixed(2) + '/hr)').join('\n');
  const choice = prompt('Select an employee type to add as labor:\n\n' + options + '\n\nEnter number:');
  if (!choice) return;
  const idx = parseInt(choice) - 1;
  if (idx >= 0 && idx < empTypes.length) {
    const t = empTypes[idx];
    window._estLineItems.push({
      id: generateId(), category: 'labor',
      description: t.name + ' (' + (t.description || 'Labor') + ')',
      quantity: 4, unit: 'Hours', unitCost: t.defaultRate, markupPercent: 0,
    });
    renderEstLineItems();
    recalcEstimate();
    showToast(t.name + ' added at $' + t.defaultRate.toFixed(2) + '/hr', 'success');
  }
}

function addEstLineItem() {
  window._estLineItems.push({ id: generateId(), category: 'materials', description: '', quantity: 1, unit: 'Each', unitCost: 0, markupPercent: 25 });
  renderEstLineItems();
  recalcEstimate();
}

function removeEstLineItem(idx) {
  window._estLineItems.splice(idx, 1);
  renderEstLineItems();
  recalcEstimate();
}

function recalcEstimate() {
  let totalBilled = 0, totalActualCost = 0;
  let hasAnyTechs = false;
  window._estLineItems.forEach((li, idx) => {
    const ext = (li.quantity || 0) * (li.unitCost || 0);
    const cust = ext * (1 + (li.markupPercent || 0) / 100);
    li.extendedCost = ext;
    li.customerPrice = cust;
    totalBilled += cust;

    // For labor lines with assigned technicians, compute actual cost from pay rates
    const isLabor = li.category === 'labor';
    const techs = (isLabor && li.assignedTechnicians) ? li.assignedTechnicians : [];
    if (isLabor && techs.length > 0) {
      hasAnyTechs = true;
      let lineTechCost = 0;
      let lineTechHrs = 0;
      techs.forEach((t, ti) => {
        const effRate = getEmployeeEffectivePayRate(t.payRate || 0, t.hourType);
        const techCost = effRate * (t.hours || 0);
        lineTechCost += techCost;
        lineTechHrs += (t.hours || 0);
        const costEl = document.getElementById('est-tech-cost-' + idx + '-' + ti);
        if (costEl) costEl.textContent = formatCurrency(techCost);
      });
      li.actualLaborCost = lineTechCost;
      totalActualCost += lineTechCost;
      const totalHrsEl = document.getElementById('est-tech-total-hrs-' + idx);
      const totalCostEl = document.getElementById('est-tech-total-cost-' + idx);
      if (totalHrsEl) totalHrsEl.textContent = lineTechHrs.toFixed(1);
      if (totalCostEl) totalCostEl.textContent = formatCurrency(lineTechCost);
    } else {
      // Non-labor items or labor without techs: actual cost = extended cost
      li.actualLaborCost = isLabor ? ext : 0;
      totalActualCost += ext;
    }

    const extEl = document.getElementById('est-ext-' + idx);
    const custEl = document.getElementById('est-cust-' + idx);
    if (extEl) extEl.textContent = formatCurrency(ext);
    if (custEl) custEl.textContent = formatCurrency(cust);
  });
  const profit = totalBilled - totalActualCost;
  const billedEl = document.getElementById('est-totalPrice');
  const costEl = document.getElementById('est-totalCost');
  const actualCostEl = document.getElementById('est-actualCost');
  const profitEl = document.getElementById('est-profit');
  if (costEl) costEl.textContent = formatCurrency(window._estLineItems.reduce((s, li) => s + (li.extendedCost || 0), 0));
  if (billedEl) billedEl.textContent = formatCurrency(totalBilled);
  if (actualCostEl) {
    actualCostEl.textContent = formatCurrency(totalActualCost);
    actualCostEl.parentElement.style.display = hasAnyTechs ? '' : 'none';
  }
  if (profitEl) {
    profitEl.textContent = formatCurrency(profit);
    profitEl.style.color = profit >= 0 ? 'var(--success)' : 'var(--accent)';
  }
  // Update profit label to clarify what's being calculated
  const profitLabel = document.getElementById('est-profit-label');
  if (profitLabel) profitLabel.textContent = hasAnyTechs ? 'True Profit (Billed − Actual Cost):' : 'Estimated Profit (Markup Only):';
}

function collectEstimateData() {
  const est = window._currentEstimate;
  est.estimateNumber = document.getElementById('est-number').value;
  est.date = document.getElementById('est-date').value;
  est.lineItems = window._estLineItems.map(li => {
    const clean = {...li};
    delete clean._showTechPanel; // don't persist UI state
    return clean;
  });
  est.notes = document.getElementById('est-notes').value;
  const statusEl = document.getElementById('est-status');
  if (statusEl) est.status = statusEl.value;
  // Resolve job selector (may auto-create a job)
  est.jobId = resolveJobId('est-job', 'Estimate', est);
  let totalBilled = 0, totalActualCost = 0;
  est.lineItems.forEach(li => {
    totalBilled += li.customerPrice || 0;
    if (li.category === 'labor' && li.assignedTechnicians && li.assignedTechnicians.length > 0) {
      let lineCost = 0;
      li.assignedTechnicians.forEach(t => {
        lineCost += getEmployeeEffectivePayRate(t.payRate || 0, t.hourType) * (t.hours || 0);
      });
      totalActualCost += lineCost;
    } else {
      totalActualCost += li.extendedCost || 0;
    }
  });
  est.totalCost = est.lineItems.reduce((s, li) => s + (li.extendedCost || 0), 0);
  est.totalCustomerPrice = totalBilled;
  est.totalActualCost = totalActualCost;
  est.estimatedProfit = totalBilled - totalActualCost;
  return est;
}

function saveCurrentEstimate() {
  const est = collectEstimateData();
  saveDocument('estimates', est);
  editingDocId = est.id;
  showToast('Estimate saved!');
}

function generateQuoteFromEstimate() {
  const est = collectEstimateData();
  saveDocument('estimates', est);
  const job = est.jobId ? getJobById(est.jobId) : null;
  const quote = getDefaultQuote();
  quote.jobId = est.jobId;
  quote.projectName = job ? job.name : '';
  if (job) {
    quote.customerName = job.customer.name;
    quote.customerCompany = job.customer.company;
    quote.customerPhone = job.customer.phone;
    quote.customerEmail = job.customer.email;
    quote.customerAddress = job.customer.address;
  }
  // Convert estimate lines to quote lines (using customer prices)
  quote.lineItems = est.lineItems.map((li, idx) => ({
    item: idx + 1,
    description: li.description || COST_CATEGORIES.find(c => c.id === li.category)?.label || '',
    quantity: li.quantity,
    unit: li.unit,
    unitPrice: li.customerPrice / (li.quantity || 1),
    taxable: false,
  }));
  let sub = 0;
  quote.lineItems.forEach(li => { sub += (li.quantity || 0) * (li.unitPrice || 0); });
  quote.subtotal = sub;
  quote.taxAmount = 0;
  quote.total = sub;
  editingDocId = null;
  renderQuoteEditor(quote);
  showToast('Quote generated from estimate!');
}


// ============================================================
// GENERIC DOCUMENT LIST
// ============================================================
function renderDocumentList(type) {
  const main = document.querySelector('.main-content');
  const titles = { quote: 'Quotes', invoice: 'Invoices', po: 'Purchase Orders', letterhead: 'Letterhead', estimate: 'Estimates', workorder: 'Work Orders', changeorder: 'Change Orders', proposal: 'Proposals', contracts: 'Contracts', creditmemo: 'Credit Memos', paymentreceipt: 'Payment Receipts', statements: 'Statements', certificates: 'Certificates', assettransfers: 'Asset Transfers', safetyreports: 'Safety Reports' };
  let docs = type === 'estimate' ? getEstimates() : getDocuments(type);
  const prefs = getDashboardPrefs(type);
  const jobs = getJobs();

  // Determine available statuses for this doc type
  const hasStatuses = ['quote', 'invoice', 'estimate', 'po', 'workorder', 'proposal'].includes(type);
  let statusList = [];
  if (type === 'quote') statusList = QUOTE_STATUSES;
  else if (type === 'invoice') statusList = INVOICE_STATUSES;
  else {
    const cls = getDocClassifications();
    if (cls[type]) statusList = cls[type].statuses;
  }

  // Search filter
  if (prefs.searchQuery) {
    const q = prefs.searchQuery.toLowerCase();
    docs = docs.filter(d => {
      const num = (d.docNumber || d.estimateNumber || '').toLowerCase();
      const name = (d.customerName || d.vendorName || d.recipientName || '').toLowerCase();
      return num.includes(q) || name.includes(q);
    });
  }

  // Status filter
  if (prefs.filterStatus && prefs.filterStatus !== 'all' && hasStatuses) {
    docs = docs.filter(d => (d.status || 'draft') === prefs.filterStatus);
  }

  // Job filter
  if (prefs.filterJob && prefs.filterJob !== 'all') {
    docs = docs.filter(d => d.jobId === prefs.filterJob);
  }

  // Sort
  const sortDir = prefs.sortDir === 'asc' ? 1 : -1;
  docs.sort((a, b) => {
    let va, vb;
    switch (prefs.sortBy) {
      case 'number': va = a.docNumber || a.estimateNumber || ''; vb = b.docNumber || b.estimateNumber || ''; return va.localeCompare(vb) * sortDir;
      case 'name': va = a.customerName || a.vendorName || ''; vb = b.customerName || b.vendorName || ''; return va.localeCompare(vb) * sortDir;
      case 'total': va = a.total || a.totalCustomerPrice || 0; vb = b.total || b.totalCustomerPrice || 0; return (va - vb) * sortDir;
      case 'status': va = a.status || 'draft'; vb = b.status || 'draft'; return va.localeCompare(vb) * sortDir;
      default: va = a.date || ''; vb = b.date || ''; return va.localeCompare(vb) * sortDir;
    }
  });

  // Build status badge HTML helper
  function statusBadge(doc) {
    if (!hasStatuses) return '';
    const st = doc.status || 'draft';
    const info = statusList.find(s => s.id === st) || { label: st, color: '#6B7280' };
    return '<span style="display:inline-block;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:600;background:' + info.color + '20;color:' + info.color + ';">' + escapeHtml(info.label) + '</span>';
  }

  // Unique jobs used in docs for filter dropdown
  const usedJobIds = [...new Set((type === 'estimate' ? getEstimates() : getDocuments(type)).map(d => d.jobId).filter(Boolean))];

  main.innerHTML = `
    <div class="page-header">
      <h1>${titles[type]}</h1>
      <div class="page-header-actions">
        ${type !== 'estimate' ? `<button class="btn btn-secondary" onclick="exportDashboardTemplate('${type}')" title="Download a blank JSON template for importing ${titles[type]}">\u2193 Template</button>` : ''}
        ${type !== 'estimate' ? `<button class="btn btn-secondary" onclick="importDocuments('${type}')" title="Import ${titles[type]} from JSON files (single or batch)">\u2191 Import</button>` : ''}
        <button class="btn btn-primary" onclick="createNewDocument('${type}')">+ New ${titles[type].replace(/s$/, '')}</button>
      </div>
    </div>
    <div class="card" style="margin-bottom:12px;">
      <div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;">
        <input class="form-input" style="width:200px;" placeholder="Search..." value="${escapeHtml(prefs.searchQuery || '')}" oninput="updateDocListPref('${type}','searchQuery',this.value)">
        ${hasStatuses ? `<select class="form-select" style="width:140px;" onchange="updateDocListPref('${type}','filterStatus',this.value)">
          <option value="all">All Statuses</option>
          ${statusList.map(s => '<option value="' + s.id + '"' + (prefs.filterStatus === s.id ? ' selected' : '') + '>' + s.label + '</option>').join('')}
        </select>` : ''}
        ${usedJobIds.length > 0 ? `<select class="form-select" style="width:180px;" onchange="updateDocListPref('${type}','filterJob',this.value)">
          <option value="all">All Jobs</option>
          ${usedJobIds.map(jid => { const j = getJobById(jid); return j ? '<option value="' + jid + '"' + (prefs.filterJob === jid ? ' selected' : '') + '>' + escapeHtml(j.jobNumber) + '</option>' : ''; }).join('')}
        </select>` : ''}
        <select class="form-select" style="width:140px;" onchange="updateDocListPref('${type}','sortBy',this.value)">
          <option value="date" ${prefs.sortBy==='date'?'selected':''}>Sort by Date</option>
          <option value="number" ${prefs.sortBy==='number'?'selected':''}>Sort by Number</option>
          <option value="name" ${prefs.sortBy==='name'?'selected':''}>Sort by Name</option>
          <option value="total" ${prefs.sortBy==='total'?'selected':''}>Sort by Total</option>
          ${hasStatuses ? '<option value="status"' + (prefs.sortBy==='status'?' selected':'') + '>Sort by Status</option>' : ''}
        </select>
        <button class="btn btn-secondary btn-sm" onclick="toggleDocListSortDir('${type}')" title="Toggle sort direction">${prefs.sortDir === 'asc' ? '\u25b2 Asc' : '\u25bc Desc'}</button>
      </div>
    </div>
    ${docs.length === 0 ? `<p class="intro-text">No ${titles[type].toLowerCase()} found.</p>` : ''}
    ${docs.map(doc => {
      const num = doc.docNumber || doc.estimateNumber || '';
      const name = doc.customerName || doc.vendorName || doc.recipientName || '';
      const date = doc.date || '';
      const total = doc.total || doc.totalCustomerPrice || 0;
      const jobLabel = doc.jobId ? (() => { const j = getJobById(doc.jobId); return j ? j.jobNumber : ''; })() : '';
      return `
      <div class="doc-row" onclick="${type === 'estimate' ? `editEstimate('${doc.id}')` : `editDocument('${type}','${doc.id}')`}">
        <div class="doc-row-info">
          <div class="doc-row-number">${escapeHtml(num)} ${statusBadge(doc)}</div>
          <div class="doc-row-meta">${escapeHtml(name)} \u00b7 ${formatDate(date)}${jobLabel ? ` \u00b7 ${escapeHtml(jobLabel)}` : ''}</div>
        </div>
        <div class="doc-row-actions">
          <span class="doc-row-total">${formatCurrency(total)}</span>
          ${type !== 'estimate' ? `<button class="btn-icon" onclick="event.stopPropagation(); exportSingleDoc('${type}','${doc.id}')" title="Export JSON">\u2197</button>` : ''}
          <button class="btn-icon" onclick="event.stopPropagation(); confirmDelete('${type === 'estimate' ? 'estimates' : type}','${doc.id}','${escapeHtml(num)}')" title="Delete">\ud83d\uddd1</button>
        </div>
      </div>`;
    }).join('')}
  `;
}

function updateDocListPref(type, key, value) {
  const prefs = getDashboardPrefs(type);
  prefs[key] = value;
  saveDashboardPrefs(type, prefs);
  if (type === 'jobs') { renderJobsList(); }
  else if (type === 'timesheets') { renderTimesheetsList(); }
  else { renderDocumentList(type); }
}

function toggleDocListSortDir(type) {
  const prefs = getDashboardPrefs(type);
  prefs.sortDir = prefs.sortDir === 'asc' ? 'desc' : 'asc';
  saveDashboardPrefs(type, prefs);
  if (type === 'jobs') { renderJobsList(); }
  else if (type === 'timesheets') { renderTimesheetsList(); }
  else { renderDocumentList(type); }
}

function createNewDocument(type) {
  editingDocId = null;
  switch(type) {
    case 'quote': renderQuoteEditor(getDefaultQuote()); break;
    case 'invoice': renderInvoiceEditor(getDefaultInvoice()); break;
    case 'po': renderPOEditor(getDefaultPO()); break;
    case 'letterhead': renderLetterheadEditor(getDefaultLetterhead()); break;
    case 'estimate': renderEstimateEditor(getDefaultEstimate()); break;
    case 'workorder': renderWorkOrderEditor(getDefaultWorkOrder()); break;
    case 'changeorder': renderChangeOrderEditor(getDefaultChangeOrder()); break;
    case 'proposal': renderProposalEditor(getDefaultProposal()); break;
    case 'contracts': renderContractEditor(getDefaultContract()); break;
    case 'creditmemo': renderCreditMemoEditor(getDefaultCreditMemo()); break;
    case 'paymentreceipt': renderPaymentReceiptEditor(getDefaultPaymentReceipt()); break;
    case 'statements': renderStatementEditor(getDefaultStatement()); break;
    case 'certificates': renderCertificateEditor(getDefaultCertificate()); break;
    case 'assettransfers': renderAssetTransferEditor(getDefaultAssetTransfer()); break;
    case 'safetyreports': renderSafetyReportEditor(getDefaultSafetyReport()); break;
  }
}

function editDocument(type, id) {
  editingDocId = id;
  const doc = getDocuments(type).find(d => d.id === id);
  if (!doc) return;
  switch(type) {
    case 'quote': renderQuoteEditor(doc); break;
    case 'invoice': renderInvoiceEditor(doc); break;
    case 'po': renderPOEditor(doc); break;
    case 'letterhead': renderLetterheadEditor(doc); break;
    case 'workorder': renderWorkOrderEditor(doc); break;
    case 'changeorder': renderChangeOrderEditor(doc); break;
    case 'proposal': renderProposalEditor(doc); break;
    case 'contracts': renderContractEditor(doc); break;
    case 'creditmemo': renderCreditMemoEditor(doc); break;
    case 'paymentreceipt': renderPaymentReceiptEditor(doc); break;
    case 'statements': renderStatementEditor(doc); break;
    case 'certificates': renderCertificateEditor(doc); break;
    case 'assettransfers': renderAssetTransferEditor(doc); break;
    case 'safetyreports': renderSafetyReportEditor(doc); break;
  }
}

function confirmDelete(type, id, name) {
  if (confirm('Are you sure you want to delete "' + name + '"? This action cannot be undone.')) {
    deleteDocument(type, id);
    renderPage();
    showToast('Deleted!');
  }
}

function confirmDeleteJob(jobId, jobName) {
  // Step 1: Explain consequences clearly
  const job = getJobById(jobId);
  if (!job) { showToast('Job not found', 'error'); return; }

  // Count all associated documents
  const estimates = getEstimates().filter(e => e.jobId === jobId);
  const quotes = getDocuments('quote').filter(q => q.jobId === jobId);
  const invoices = getDocuments('invoice').filter(i => i.jobId === jobId);
  const pos = getDocuments('po').filter(p => p.jobId === jobId);
  const timesheets = getTimesheets().filter(t => t.jobId === jobId);
  const travel = getTravelEntries().filter(t => t.jobId === jobId);
  const receipts = getReceipts().filter(r => r.jobId === jobId);
  const testReports = getTestReports().filter(t => t.jobId === jobId);
  const pnl = getPnlStatements().filter(p => p.jobId === jobId);
  const workorders = getDocuments('workorder').filter(d => d.jobId === jobId);
  const changeorders = getDocuments('changeorder').filter(d => d.jobId === jobId);
  const proposals = getDocuments('proposal').filter(d => d.jobId === jobId);
  const contracts = getDocuments('contracts').filter(d => d.jobId === jobId);
  const creditmemos = getDocuments('creditmemo').filter(d => d.jobId === jobId);
  const paymentreceipts = getDocuments('paymentreceipt').filter(d => d.jobId === jobId);
  const statements = getDocuments('statements').filter(d => d.jobId === jobId);
  const certificates = getDocuments('certificates').filter(d => d.jobId === jobId);
  const assettransfers = getDocuments('assettransfers').filter(d => d.jobId === jobId);
  const safetyreports = getDocuments('safetyreports').filter(d => d.jobId === jobId);

  const totalDocs = estimates.length + quotes.length + invoices.length + pos.length + timesheets.length + travel.length + receipts.length + testReports.length + pnl.length + workorders.length + changeorders.length + proposals.length + contracts.length + creditmemos.length + paymentreceipts.length + statements.length + certificates.length + assettransfers.length + safetyreports.length;

  let warningMsg = 'WARNING: You are about to delete the job "' + jobName + '" and ALL of its associated data.\n\n';
  warningMsg += 'This will permanently delete:\n';
  if (estimates.length > 0) warningMsg += '  • ' + estimates.length + ' Estimate(s)\n';
  if (quotes.length > 0) warningMsg += '  • ' + quotes.length + ' Quote(s)\n';
  if (invoices.length > 0) warningMsg += '  • ' + invoices.length + ' Invoice(s)\n';
  if (pos.length > 0) warningMsg += '  • ' + pos.length + ' Purchase Order(s)\n';
  if (timesheets.length > 0) warningMsg += '  • ' + timesheets.length + ' Timesheet(s)\n';
  if (travel.length > 0) warningMsg += '  • ' + travel.length + ' Travel/Mileage Entry(ies)\n';
  if (receipts.length > 0) warningMsg += '  \u2022 ' + receipts.length + ' Receipt(s)\n';
  if (testReports.length > 0) warningMsg += '  \u2022 ' + testReports.length + ' Test Report(s)\n';
  if (pnl.length > 0) warningMsg += '  \u2022 ' + pnl.length + ' Profit & Loss Statement(s)\n';
  if (workorders.length > 0) warningMsg += '  \u2022 ' + workorders.length + ' Work Order(s)\n';
  if (changeorders.length > 0) warningMsg += '  \u2022 ' + changeorders.length + ' Change Order(s)\n';
  if (proposals.length > 0) warningMsg += '  \u2022 ' + proposals.length + ' Proposal(s)\n';
  if (contracts.length > 0) warningMsg += '  \u2022 ' + contracts.length + ' Contract(s)\n';
  if (creditmemos.length > 0) warningMsg += '  \u2022 ' + creditmemos.length + ' Credit Memo(s)\n';
  if (paymentreceipts.length > 0) warningMsg += '  \u2022 ' + paymentreceipts.length + ' Payment Receipt(s)\n';
  if (statements.length > 0) warningMsg += '  \u2022 ' + statements.length + ' Statement(s)\n';
  if (certificates.length > 0) warningMsg += '  \u2022 ' + certificates.length + ' Certificate(s)\n';
  if (assettransfers.length > 0) warningMsg += '  \u2022 ' + assettransfers.length + ' Asset Transfer(s)\n';
  if (safetyreports.length > 0) warningMsg += '  \u2022 ' + safetyreports.length + ' Safety Report(s)\n';
  if (totalDocs === 0) warningMsg += '  (No associated documents found)\n';
  warningMsg += '\nThis action CANNOT be undone. All data will be permanently lost.\n\nDo you want to continue?';

  if (!confirm(warningMsg)) return;

  // Step 2: Final confirmation
  if (!confirm('FINAL CONFIRMATION: Are you absolutely sure you want to delete "' + jobName + '" and all ' + totalDocs + ' associated document(s)? Click OK to permanently delete everything.')) return;

  // Perform cascade delete
  estimates.forEach(e => deleteDocument('estimates', e.id));
  quotes.forEach(q => deleteDocument('quote', q.id));
  invoices.forEach(i => deleteDocument('invoice', i.id));
  pos.forEach(p => deleteDocument('po', p.id));
  timesheets.forEach(t => deleteDocument('timesheets', t.id));
  travel.forEach(t => deleteDocument('travel', t.id));
  receipts.forEach(r => deleteDocument('receipts', r.id));
  testReports.forEach(t => { const all = getTestReports().filter(x => x.id !== t.id); localStorage.setItem('psva_testreports', JSON.stringify(all)); });
  pnl.forEach(p => deleteDocument('pnl', p.id));
  workorders.forEach(d => deleteDocument('workorder', d.id));
  changeorders.forEach(d => deleteDocument('changeorder', d.id));
  proposals.forEach(d => deleteDocument('proposal', d.id));
  contracts.forEach(d => deleteDocument('contracts', d.id));
  creditmemos.forEach(d => deleteDocument('creditmemo', d.id));
  paymentreceipts.forEach(d => deleteDocument('paymentreceipt', d.id));
  statements.forEach(d => deleteDocument('statements', d.id));
  certificates.forEach(d => deleteDocument('certificates', d.id));
  assettransfers.forEach(d => deleteDocument('assettransfers', d.id));
  safetyreports.forEach(d => deleteDocument('safetyreports', d.id));
  deleteDocument('jobs', jobId);

  currentJobId = null;
  showPage('jobs');
  showToast('Job "' + jobName + '" and all associated data deleted.');
}

function exportSingleDoc(type, id) {
  const doc = getDocuments(type).find(d => d.id === id);
  if (!doc) return;
  const blob = new Blob([JSON.stringify(doc, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = `${doc.docNumber || 'document'}.json`; a.click();
  URL.revokeObjectURL(url);
}

function importDocuments(type) {
  const input = document.createElement('input');
  input.type = 'file'; input.accept = '.json'; input.multiple = true;
  input.onchange = (e) => {
    const files = Array.from(e.target.files);
    if (files.length === 0) return;
    let allDocs = [];
    let totalErrors = 0;
    let filesProcessed = 0;
    files.forEach(file => {
      const reader = new FileReader();
      reader.onload = (ev) => {
        try {
          let data;
          try {
            data = JSON.parse(ev.target.result);
          } catch(parseErr) {
            totalErrors++;
            filesProcessed++;
            if (filesProcessed === files.length) processAllDocs();
            return;
          }
          // Remove template markers if present
          if (data._isTemplate) { delete data._isTemplate; delete data._instructions; }
          // Support single doc, array of docs, or wrapped {documents: [...]}
          let docs = Array.isArray(data) ? data : (data.id ? [data] : (data.documents ? data.documents : []));
          // Also support full backup files — extract the relevant type
          if (docs.length === 0 && data.version) {
            const typeKeyMap = { quote: 'quotes', invoice: 'invoices', po: 'po', letterhead: 'letterheads', workorder: 'workorders', changeorder: 'changeorders', proposal: 'proposals', contracts: 'contracts', creditmemo: 'creditmemos', paymentreceipt: 'paymentreceipts', statements: 'statements', certificates: 'certificates', assettransfers: 'assettransfers', safetyreports: 'safetyreports' };
            const key = typeKeyMap[type];
            if (key && data[key] && Array.isArray(data[key])) {
              docs = data[key];
            }
          }
          allDocs = allDocs.concat(docs);
          if (docs.length === 0) {
            totalErrors++;
            console.warn('[PS-VA Import] No valid documents found in file:', file.name);
          }
        } catch(err) {
          totalErrors++;
          console.error('[PS-VA Import] Error processing file:', file.name, err);
        }
        filesProcessed++;
        if (filesProcessed === files.length) processAllDocs();
      };
      reader.readAsText(file);
    });

    function processAllDocs() {
      if (allDocs.length === 0) {
        showToast('No valid documents found in the selected file(s).' + (totalErrors > 0 ? ' ' + totalErrors + ' file(s) had errors.' : ''), 'error');
        return;
      }

      // Validate all docs and check for issues
      const docsWithIssues = [];
      const cleanDocs = [];
      allDocs.forEach(doc => {
        const result = validateDocument({...doc}, type);
        if (!result.valid) {
          docsWithIssues.push({ doc: doc, issues: result.issues, include: false });
          return;
        }
        const editableIssues = result.issues.filter(i => i.severity === 'warning' || i.severity === 'error');
        if (editableIssues.length > 0) {
          docsWithIssues.push({ doc: result.doc, issues: result.issues, include: true });
        } else {
          cleanDocs.push(result.doc);
        }
      });

      // If there are issues, show a review modal for just these documents
      if (docsWithIssues.length > 0) {
        showDocImportReviewModal(type, cleanDocs, docsWithIssues, totalErrors);
      } else {
        // All clean — import directly
        cleanDocs.forEach(doc => {
          if (doc.id === 'TEMPLATE' || !doc.id) {
            doc.id = type + '-' + Date.now() + '-' + Math.random().toString(36).substr(2, 6);
          }
          saveDocument(type, doc);
        });
        renderPage();
        showToast(cleanDocs.length + ' document(s) imported successfully.', 'success');
      }
    }
  };
  input.click();
}

// Simplified review modal for per-dashboard document imports
function showDocImportReviewModal(type, cleanDocs, docsWithIssues, totalErrors) {
  const typeLabels = { quote: 'Quote', invoice: 'Invoice', po: 'Purchase Order', letterhead: 'Letterhead', workorder: 'Work Order', changeorder: 'Change Order', proposal: 'Proposal', contracts: 'Contract', creditmemo: 'Credit Memo', paymentreceipt: 'Payment Receipt', statements: 'Statement', certificates: 'Certificate', assettransfers: 'Asset Transfer', safetyreports: 'Safety Report', estimate: 'Estimate', timesheets: 'Timesheet' };
  const typeLabel = typeLabels[type] || type;

  const overlay = document.createElement('div');
  overlay.id = 'doc-import-review-overlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.85);z-index:10000;display:flex;align-items:center;justify-content:center;padding:20px;';

  const modal = document.createElement('div');
  modal.style.cssText = 'background:var(--bg-primary,#1a1a2e);color:var(--text-primary,#e0e0e0);border-radius:12px;max-width:800px;width:100%;max-height:85vh;display:flex;flex-direction:column;box-shadow:0 20px 60px rgba(0,0,0,0.5);border:1px solid var(--border-color,#333);';

  // Header
  const header = document.createElement('div');
  header.style.cssText = 'padding:20px 24px;border-bottom:1px solid var(--border-color,#333);flex-shrink:0;';
  header.innerHTML = `
    <h2 style="margin:0 0 8px 0;font-size:20px;">${typeLabel} Import Review</h2>
    <div style="font-size:13px;color:var(--text-secondary,#888);">
      <strong>${cleanDocs.length}</strong> clean record(s) ready \u00b7 <strong style="color:#f59e0b;">${docsWithIssues.length}</strong> record(s) need review
      ${totalErrors > 0 ? ' \u00b7 <strong style="color:#ef4444;">' + totalErrors + '</strong> file error(s)' : ''}
    </div>
    <div style="font-size:12px;color:var(--text-secondary,#888);margin-top:6px;">Review the flagged fields below. Correct values, skip records, or cancel the entire import.</div>
  `;
  modal.appendChild(header);

  // Body
  const body = document.createElement('div');
  body.style.cssText = 'flex:1;overflow-y:auto;padding:16px 24px;';

  docsWithIssues.forEach((record, rIdx) => {
    const card = document.createElement('div');
    card.style.cssText = 'padding:12px 16px;border:1px solid var(--border-color,#333);border-radius:8px;margin-bottom:8px;' + (!record.include ? 'opacity:0.4;' : '');
    card.setAttribute('data-ridx', rIdx);

    const docLabel = record.doc.docNumber || record.doc.estimateNumber || record.doc.employeeName || record.doc.name || record.doc.id?.substring(0, 12) || 'Record';
    const editableIssues = record.issues.filter(i => i.severity !== 'info');
    const infoIssues = record.issues.filter(i => i.severity === 'info');

    let html = `
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:${editableIssues.length > 0 ? '8' : '0'}px;">
        <div style="display:flex;align-items:center;gap:8px;">
          <span style="font-weight:500;">${escapeHtml(docLabel)}</span>
          ${record.doc.date ? '<span style="font-size:12px;color:var(--text-secondary,#888);">' + record.doc.date + '</span>' : ''}
        </div>
        <label style="display:flex;align-items:center;gap:6px;font-size:12px;cursor:pointer;">
          <input type="checkbox" ${record.include ? 'checked' : ''} onchange="window._docImportToggle(${rIdx}, this.checked)" style="cursor:pointer;">
          Include
        </label>
      </div>
    `;

    if (editableIssues.length > 0) {
      html += '<table style="width:100%;font-size:12px;border-collapse:collapse;">';
      html += '<tr style="color:var(--text-secondary,#888);"><td style="padding:2px 8px;width:25%;">Field</td><td style="padding:2px 8px;width:40%;">Issue</td><td style="padding:2px 8px;width:35%;">Value</td></tr>';
      editableIssues.forEach((issue, iIdx) => {
        const sevColor = issue.severity === 'error' ? '#ef4444' : '#f59e0b';
        let inputHtml = '';
        if (issue.editable) {
          const inputId = 'dir-' + rIdx + '-' + iIdx;
          if (issue.inputType === 'select' && issue.options) {
            inputHtml = '<select id="' + inputId + '" style="background:var(--bg-primary,#1a1a2e);color:var(--text-primary,#e0e0e0);border:1px solid var(--border-color,#333);border-radius:4px;padding:2px 6px;font-size:12px;width:100%;">';
            inputHtml += '<option value="">(select)</option>';
            issue.options.forEach(opt => { inputHtml += '<option value="' + escapeHtml(opt) + '"' + (issue.defaultValue === opt ? ' selected' : '') + '>' + escapeHtml(opt) + '</option>'; });
            inputHtml += '</select>';
          } else if (issue.inputType === 'number') {
            inputHtml = '<input type="number" id="' + inputId + '" value="' + (issue.defaultValue || '0') + '" step="0.01" style="background:var(--bg-primary,#1a1a2e);color:var(--text-primary,#e0e0e0);border:1px solid var(--border-color,#333);border-radius:4px;padding:2px 6px;font-size:12px;width:100%;">';
          } else if (issue.inputType === 'date') {
            inputHtml = '<input type="date" id="' + inputId + '" value="' + (issue.defaultValue || '') + '" style="background:var(--bg-primary,#1a1a2e);color:var(--text-primary,#e0e0e0);border:1px solid var(--border-color,#333);border-radius:4px;padding:2px 6px;font-size:12px;width:100%;">';
          } else {
            inputHtml = '<input type="text" id="' + inputId + '" value="' + escapeHtml(issue.defaultValue || '') + '" placeholder="Enter value" style="background:var(--bg-primary,#1a1a2e);color:var(--text-primary,#e0e0e0);border:1px solid var(--border-color,#333);border-radius:4px;padding:2px 6px;font-size:12px;width:100%;">';
          }
        } else {
          inputHtml = '<span style="font-size:11px;color:var(--text-secondary,#888);">' + escapeHtml(String(issue.defaultValue || 'auto')) + '</span>';
        }
        html += '<tr><td style="padding:4px 8px;border-top:1px solid var(--border-color,#222);">' + escapeHtml(issue.field) + '</td><td style="padding:4px 8px;border-top:1px solid var(--border-color,#222);color:' + sevColor + ';">' + escapeHtml(issue.message) + '</td><td style="padding:4px 8px;border-top:1px solid var(--border-color,#222);">' + inputHtml + '</td></tr>';
      });
      html += '</table>';
    }
    if (infoIssues.length > 0) {
      html += '<div style="font-size:11px;color:var(--text-secondary,#666);margin-top:4px;">\u2139 ' + infoIssues.map(i => escapeHtml(i.message)).join(' \u00b7 ') + '</div>';
    }

    card.innerHTML = html;
    body.appendChild(card);
  });

  modal.appendChild(body);

  // Footer
  const footer = document.createElement('div');
  footer.style.cssText = 'padding:16px 24px;border-top:1px solid var(--border-color,#333);display:flex;justify-content:space-between;align-items:center;flex-shrink:0;flex-wrap:wrap;gap:8px;';
  footer.innerHTML = `
    <button id="dir-cancel" class="btn btn-secondary" style="min-width:140px;">Cancel Import</button>
    <div style="display:flex;gap:8px;flex-wrap:wrap;">
      <button id="dir-accept" class="btn btn-secondary" style="min-width:160px;">Accept All Defaults</button>
      <button id="dir-proceed" class="btn btn-primary" style="min-width:180px;">Proceed with Corrections</button>
    </div>
  `;
  modal.appendChild(footer);
  overlay.appendChild(modal);
  document.body.appendChild(overlay);

  // Toggle handler
  window._docImportToggle = (rIdx, checked) => {
    docsWithIssues[rIdx].include = checked;
    const card = body.querySelector('[data-ridx="' + rIdx + '"]');
    if (card) card.style.opacity = checked ? '1' : '0.4';
  };

  // Collect corrections
  function collectDocCorrections() {
    docsWithIssues.forEach((record, rIdx) => {
      if (!record.include) return;
      const editableIssues = record.issues.filter(i => i.severity !== 'info' && i.editable);
      editableIssues.forEach((issue, iIdx) => {
        const el = document.getElementById('dir-' + rIdx + '-' + iIdx);
        if (!el) return;
        const val = el.value;
        if (val === '' || val === issue.defaultValue) return;
        applyFieldCorrection(record.doc, issue.field, val, type);
      });
    });
  }

  function finishImport(applyCorrections) {
    if (applyCorrections) collectDocCorrections();
    overlay.remove();
    delete window._docImportToggle;

    let imported = 0;
    let skipped = 0;

    // Import clean docs
    cleanDocs.forEach(doc => {
      if (doc.id === 'TEMPLATE' || !doc.id) doc.id = type + '-' + Date.now() + '-' + Math.random().toString(36).substr(2, 6);
      saveDocument(type, doc);
      imported++;
    });

    // Import reviewed docs (only included ones)
    docsWithIssues.forEach(record => {
      if (!record.include) { skipped++; return; }
      const doc = record.doc;
      if (doc.id === 'TEMPLATE' || !doc.id) doc.id = type + '-' + Date.now() + '-' + Math.random().toString(36).substr(2, 6);
      saveDocument(type, doc);
      imported++;
    });

    renderPage();
    let msg = imported + ' ' + typeLabel.toLowerCase() + '(s) imported.';
    if (skipped > 0) msg += ' ' + skipped + ' skipped.';
    showToast(msg, skipped > 0 ? 'warning' : 'success');
  }

  document.getElementById('dir-cancel').onclick = () => {
    overlay.remove();
    delete window._docImportToggle;
    showToast('Import cancelled.', 'info');
  };
  document.getElementById('dir-accept').onclick = () => finishImport(false);
  document.getElementById('dir-proceed').onclick = () => finishImport(true);
}

function exportDashboardTemplate(type) {
  const titles = { quote: 'Quote', invoice: 'Invoice', po: 'Purchase Order', letterhead: 'Letterhead', estimate: 'Estimate', workorder: 'Work Order', changeorder: 'Change Order', proposal: 'Proposal', contracts: 'Contract', creditmemo: 'Credit Memo', paymentreceipt: 'Payment Receipt', statements: 'Statement', certificates: 'Certificate', assettransfers: 'Asset Transfer', safetyreports: 'Safety Report' };
  let template;
  switch(type) {
    case 'quote': template = getDefaultQuote(); break;
    case 'invoice': template = getDefaultInvoice(); break;
    case 'po': template = getDefaultPO(); break;
    case 'letterhead': template = getDefaultLetterhead(); break;
    case 'workorder': template = getDefaultWorkOrder(); break;
    case 'changeorder': template = getDefaultChangeOrder(); break;
    case 'proposal': template = getDefaultProposal(); break;
    case 'contracts': template = getDefaultContract(); break;
    case 'creditmemo': template = getDefaultCreditMemo(); break;
    case 'paymentreceipt': template = getDefaultPaymentReceipt(); break;
    case 'statements': template = getDefaultStatement(); break;
    case 'certificates': template = getDefaultCertificate(); break;
    case 'assettransfers': template = getDefaultAssetTransfer(); break;
    case 'safetyreports': template = getDefaultSafetyReport(); break;
    default: template = { id: 'TEMPLATE', docNumber: 'TEMPLATE-001', date: todayStr() };
  }
  template._isTemplate = true;
  template._instructions = 'Fill in the fields and remove this _instructions and _isTemplate field before importing. The id field will be auto-generated if set to TEMPLATE.';
  const blob = new Blob([JSON.stringify(template, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = `${type}-template.json`; a.click();
  URL.revokeObjectURL(url);
  showToast((titles[type] || type) + ' template exported!');
}

// ============================================================
// QUOTE EDITOR
// ============================================================
function getDefaultQuote() {
  const company = getCompany();
  return {
    id: generateId(), docNumber: generateNumber('Q'), date: todayStr(), validUntil: '',
    status: 'draft',
    jobId: '', projectName: '',
    customerName: '', customerCompany: '', customerPhone: '', customerEmail: '', customerAddress: '',
    introText: 'Thank you for allowing Power Services of Virginia LLC to provide pricing for the specified work.',
    lineItems: (function() {
      const rs = getRateSheet();
      const straightRate = (rs.laborRates.find(r => r.id === 'straight') || {}).rate || 150;
      const minHrs = rs.minimumHours || 4;
      return [
        { item: 1, description: minHrs + '-Hour Minimum Charge (Straight Time)', quantity: minHrs, unit: 'Hours', unitPrice: straightRate, taxable: false },
        { item: 2, description: '', quantity: 1, unit: 'Labor', unitPrice: 0, taxable: false }
      ];
    })(),
    taxRate: company.taxRate, subtotal: 0, taxAmount: 0, total: 0,
    terms: ['NET 30 payment terms.', 'Late payments subject to 1.5% monthly interest charge.'],
  };
}

function renderQuoteEditor(quote) {
  window._currentQuote = quote;
  window._quoteLineItems = quote.lineItems.map(li => ({...li}));
  window._quoteTerms = [...(quote.terms || [])];
  const main = document.querySelector('.main-content');
  const backAction = quote.jobId ? `openJobDashboard('${quote.jobId}')` : `showPage('quotes')`;

  main.innerHTML = `
    <div class="page-header">
      <div style="display:flex;align-items:center;gap:12px;">
        <button class="btn-icon" onclick="${backAction}" title="Back">←</button>
        <h1>Edit Quote</h1>
      </div>
      <div class="page-header-actions">
        <button class="btn btn-secondary" onclick="saveCurrentQuote()">Save Draft</button>
        <button class="btn btn-primary" onclick="exportQuotePDF()">Export PDF</button>
        <button class="btn btn-success" onclick="convertQuoteToInvoice()">Create Invoice</button>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Document Information</div>
      <div class="form-grid">
        <div class="form-group"><label class="form-label">Quote Number</label><input class="form-input" id="q-docNumber" value="${escapeHtml(quote.docNumber)}"></div>
        <div class="form-group"><label class="form-label">Date</label><input class="form-input" type="date" id="q-date" value="${quote.date}"></div>
        <div class="form-group"><label class="form-label">Valid Until</label><input class="form-input" type="date" id="q-validUntil" value="${quote.validUntil}"></div>
        <div class="form-group"><label class="form-label">Status</label>
          <select class="form-select" id="q-status">
            ${QUOTE_STATUSES.map(s => '<option value="' + s.id + '"' + (quote.status === s.id ? ' selected' : '') + '>' + s.label + '</option>').join('')}
          </select>
        </div>
        <div class="form-group"><label class="form-label">Job</label>${buildJobSelector('q-job', quote.jobId, true)}</div>
        <div class="form-group"><label class="form-label">Project Name</label><input class="form-input" id="q-projectName" value="${escapeHtml(quote.projectName)}"></div>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Customer Information</div>
      <div class="form-grid">
        <div class="form-group"><label class="form-label">Contact Name</label><input class="form-input" id="q-customerName" value="${escapeHtml(quote.customerName)}"></div>
        <div class="form-group"><label class="form-label">Company</label><input class="form-input" id="q-customerCompany" value="${escapeHtml(quote.customerCompany)}"></div>
        <div class="form-group"><label class="form-label">Phone</label><input class="form-input" id="q-customerPhone" value="${escapeHtml(quote.customerPhone)}"></div>
        <div class="form-group"><label class="form-label">Email</label><input class="form-input" id="q-customerEmail" value="${escapeHtml(quote.customerEmail)}"></div>
        <div class="form-group full-width"><label class="form-label">Address</label><input class="form-input" id="q-customerAddress" value="${escapeHtml(quote.customerAddress)}"></div>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Introduction</div>
      <textarea class="form-textarea" id="q-introText" rows="2">${escapeHtml(quote.introText)}</textarea>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Line Items</div>
      <div class="table-scroll">
        <table class="line-items-table"><thead><tr>
          <th class="col-item">#</th><th class="col-desc">Description</th><th class="col-qty">Qty</th><th class="col-unit">Unit</th><th class="col-price">Unit Price</th><th class="col-tax">Tax</th><th class="col-ext">Extended</th><th class="col-actions"></th>
        </tr></thead><tbody id="q-line-items"></tbody></table>
      </div>
      <button class="btn btn-secondary btn-sm" style="margin-top:12px;" onclick="addQuoteLineItem()">+ Add Line Item</button>
      <div class="tax-rate-input" style="margin-top:12px;"><label class="form-label">Tax Rate:</label><input class="form-input" id="q-taxRate" type="number" value="${quote.taxRate}" min="0" step="0.1" onchange="recalcQuote()"><span>%</span></div>
    </div>
    <div class="totals-section">
      <div class="totals-table">
        <div class="totals-row"><span class="label">Subtotal:</span><span class="value" id="q-subtotal">$0.00</span></div>
        <div class="totals-row"><span class="label">Sales Tax:</span><span class="value" id="q-taxAmount">$0.00</span></div>
        <div class="totals-row total"><span class="label">Total:</span><span class="value" id="q-total">$0.00</span></div>
      </div>
    </div>
    <div class="card" style="margin-top:20px;">
      <div class="card-title"><div class="accent-bar"></div>Terms & Conditions</div>
      <div id="q-terms-list" class="terms-list"></div>
      <div style="margin-top:12px;display:flex;gap:8px;flex-wrap:wrap;">
        <button class="btn btn-secondary btn-sm" onclick="addQuoteTerm()">+ Add Term</button>
        <button class="btn btn-secondary btn-sm" onclick="loadDefaultQuoteTerms()">Load Default Terms</button>
        <button class="btn btn-secondary btn-sm" onclick="saveAsDefaultQuoteTerms()">Save as Default Terms</button>
      </div>
    </div>
  `;
  renderQuoteLineItems();
  renderQuoteTerms();
  recalcQuote();
}

function renderQuoteLineItems() {
  const tbody = document.getElementById('q-line-items');
  if (!tbody) return;
  tbody.innerHTML = window._quoteLineItems.map((li, idx) => `
    <tr>
      <td><input class="form-input" type="text" value="${escapeHtml(String(li.item))}" onchange="window._quoteLineItems[${idx}].item=this.value;"></td>
      <td><input class="form-input" type="text" value="${escapeHtml(li.description)}" onchange="window._quoteLineItems[${idx}].description=this.value;"></td>
      <td><input class="form-input" type="number" value="${li.quantity}" min="0" step="1" onchange="window._quoteLineItems[${idx}].quantity=parseFloat(this.value)||0; recalcQuote();"></td>
      <td><select class="form-select" onchange="window._quoteLineItems[${idx}].unit=this.value;">
        ${['Labor','Material','Equipment','Rental Equipment','Service','Each','Lot','LF','Day'].map(u => `<option ${li.unit===u?'selected':''}>${u}</option>`).join('')}
      </select></td>
      <td><input class="form-input" type="number" value="${li.unitPrice}" min="0" step="0.01" onchange="window._quoteLineItems[${idx}].unitPrice=parseFloat(this.value)||0; recalcQuote();"></td>
      <td style="text-align:center;"><input type="checkbox" class="tax-checkbox" ${li.taxable?'checked':''} onchange="window._quoteLineItems[${idx}].taxable=this.checked; recalcQuote();"></td>
      <td style="text-align:right;font-weight:600;" id="q-ext-${idx}">$0.00</td>
      <td><button class="delete-btn" onclick="removeQuoteLineItem(${idx})" title="Remove">✕</button></td>
    </tr>
  `).join('');
}

function addQuoteLineItem() {
  window._quoteLineItems.push({ item: window._quoteLineItems.length + 1, description: '', quantity: 1, unit: 'Labor', unitPrice: 0, taxable: false });
  renderQuoteLineItems(); recalcQuote();
}

function removeQuoteLineItem(idx) { window._quoteLineItems.splice(idx, 1); renderQuoteLineItems(); recalcQuote(); }

function recalcQuote() {
  let subtotal = 0, taxable = 0;
  const taxRate = parseFloat(document.getElementById('q-taxRate')?.value || 0);
  window._quoteLineItems.forEach((li, idx) => {
    const ext = (li.quantity || 0) * (li.unitPrice || 0);
    subtotal += ext;
    if (li.taxable) taxable += ext;
    const el = document.getElementById('q-ext-' + idx);
    if (el) el.textContent = formatCurrency(ext);
  });
  const tax = taxable * (taxRate / 100);
  document.getElementById('q-subtotal').textContent = formatCurrency(subtotal);
  document.getElementById('q-taxAmount').textContent = formatCurrency(tax);
  document.getElementById('q-total').textContent = formatCurrency(subtotal + tax);
}

function renderQuoteTerms() {
  const container = document.getElementById('q-terms-list');
  if (!container) return;
  container.innerHTML = window._quoteTerms.map((term, idx) => `
    <div class="term-item">
      <input class="form-input" type="text" value="${escapeHtml(term)}" onchange="window._quoteTerms[${idx}]=this.value;">
      <button class="delete-btn" onclick="window._quoteTerms.splice(${idx},1); renderQuoteTerms();">✕</button>
    </div>
  `).join('');
}

function addQuoteTerm() { window._quoteTerms.push(''); renderQuoteTerms(); }

function loadDefaultQuoteTerms() {
  const defaults = getSavedQuoteTermsTemplate();
  if (window._quoteTerms.length > 0 && !confirm('Replace current terms with default terms? This will overwrite existing terms.')) return;
  window._quoteTerms = [...defaults];
  renderQuoteTerms();
  showToast('Default terms loaded', 'success');
}

function saveAsDefaultQuoteTerms() {
  saveQuoteTermsTemplate([...window._quoteTerms]);
  showToast('Current terms saved as default template', 'success');
}

function collectQuoteData() {
  const q = window._currentQuote;
  q.docNumber = document.getElementById('q-docNumber').value;
  q.date = document.getElementById('q-date').value;
  q.validUntil = document.getElementById('q-validUntil').value;
  q.status = document.getElementById('q-status')?.value || 'draft';
  q.projectName = document.getElementById('q-projectName').value;
  // Resolve job selector (may auto-create a job)
  q.jobId = resolveJobId('q-job', 'Quote', q);
  q.customerName = document.getElementById('q-customerName').value;
  q.customerCompany = document.getElementById('q-customerCompany').value;
  q.customerPhone = document.getElementById('q-customerPhone').value;
  q.customerEmail = document.getElementById('q-customerEmail').value;
  q.customerAddress = document.getElementById('q-customerAddress').value;
  q.introText = document.getElementById('q-introText').value;
  q.lineItems = window._quoteLineItems;
  q.taxRate = parseFloat(document.getElementById('q-taxRate').value) || 0;
  q.terms = window._quoteTerms;
  let sub = 0, taxable = 0;
  q.lineItems.forEach(li => { const e = (li.quantity||0)*(li.unitPrice||0); sub += e; if(li.taxable) taxable += e; });
  q.subtotal = sub; q.taxAmount = taxable * (q.taxRate / 100); q.total = sub + q.taxAmount;
  return q;
}

function saveCurrentQuote() {
  const doc = collectQuoteData();
  saveDocument('quote', doc);
  editingDocId = doc.id;
  showToast('Quote saved!');
}

function convertQuoteToInvoice() {
  const q = collectQuoteData();
  saveDocument('quote', q);
  const inv = getDefaultInvoice();
  inv.jobId = q.jobId || '';
  inv.projectName = q.projectName;
  inv.customerName = q.customerName; inv.customerCompany = q.customerCompany;
  inv.customerPhone = q.customerPhone; inv.customerEmail = q.customerEmail; inv.customerAddress = q.customerAddress;
  inv.lineItems = q.lineItems.map(li => ({...li}));
  inv.taxRate = q.taxRate; inv.subtotal = q.subtotal; inv.taxAmount = q.taxAmount; inv.total = q.total;
  inv.terms = [...q.terms];
  inv.quoteRef = q.docNumber;
  editingDocId = null;
  renderInvoiceEditor(inv);
  showToast('Invoice created from quote!');
}

