function renderInvoiceLineItems() {
  const tbody = document.getElementById('i-line-items');
  if (!tbody) return;
  tbody.innerHTML = window._invoiceLineItems.map((li, idx) => `
    <tr>
      <td><input class="form-input" type="text" value="${escapeHtml(String(li.item))}" onchange="window._invoiceLineItems[${idx}].item=this.value;"></td>
      <td><input class="form-input" type="text" value="${escapeHtml(li.description)}" onchange="window._invoiceLineItems[${idx}].description=this.value;"></td>
      <td><input class="form-input" type="number" value="${li.quantity}" min="0" onchange="window._invoiceLineItems[${idx}].quantity=parseFloat(this.value)||0; recalcInvoice();"></td>
      <td><select class="form-select" onchange="window._invoiceLineItems[${idx}].unit=this.value;">
        ${['Labor','Material','Equipment','Rental Equipment','Service','Each','Lot','LF','Day'].map(u => `<option ${li.unit===u?'selected':''}>${u}</option>`).join('')}
      </select></td>
      <td><input class="form-input" type="number" value="${li.unitPrice}" min="0" step="0.01" onchange="window._invoiceLineItems[${idx}].unitPrice=parseFloat(this.value)||0; recalcInvoice();"></td>
      <td style="text-align:center;"><input type="checkbox" class="tax-checkbox" ${li.taxable?'checked':''} onchange="window._invoiceLineItems[${idx}].taxable=this.checked; recalcInvoice();"></td>
      <td style="text-align:right;font-weight:600;" id="i-ext-${idx}">$0.00</td>
      <td><button class="delete-btn" onclick="removeInvoiceLineItem(${idx})">✕</button></td>
    </tr>
  `).join('');
}

function addInvoiceLineItem() { window._invoiceLineItems.push({item:window._invoiceLineItems.length+1,description:'',quantity:1,unit:'Labor',unitPrice:0,taxable:false}); renderInvoiceLineItems(); recalcInvoice(); }
function removeInvoiceLineItem(idx) { window._invoiceLineItems.splice(idx,1); renderInvoiceLineItems(); recalcInvoice(); }

function recalcInvoice() {
  let sub=0, taxable=0;
  const rate = parseFloat(document.getElementById('i-taxRate')?.value||0);
  window._invoiceLineItems.forEach((li,idx) => {
    const ext=(li.quantity||0)*(li.unitPrice||0); sub+=ext; if(li.taxable) taxable+=ext;
    const el=document.getElementById('i-ext-'+idx); if(el) el.textContent=formatCurrency(ext);
  });
  const tax=taxable*(rate/100);
  document.getElementById('i-subtotal').textContent=formatCurrency(sub);
  document.getElementById('i-taxAmount').textContent=formatCurrency(tax);
  document.getElementById('i-total').textContent=formatCurrency(sub+tax);
}

function renderInvoiceTerms() {
  const c=document.getElementById('i-terms-list'); if(!c) return;
  c.innerHTML=window._invoiceTerms.map((t,i)=>`<div class="term-item"><input class="form-input" value="${escapeHtml(t)}" onchange="window._invoiceTerms[${i}]=this.value;"><button class="delete-btn" onclick="window._invoiceTerms.splice(${i},1);renderInvoiceTerms();">✕</button></div>`).join('');
}
function addInvoiceTerm() { window._invoiceTerms.push(''); renderInvoiceTerms(); }

function collectInvoiceData() {
  const inv=window._currentInvoice;
  inv.docNumber=document.getElementById('i-docNumber').value;
  inv.date=document.getElementById('i-date').value;
  inv.status=document.getElementById('i-status')?.value || 'draft';
  inv.netTerms=document.getElementById('i-netTerms').value;
  inv.dueDate=document.getElementById('i-dueDate').value;
  inv.quoteRef=document.getElementById('i-quoteRef').value;
  inv.projectName=document.getElementById('i-projectName').value;
  // Resolve job selector (may auto-create a job)
  inv.jobId = resolveJobId('i-job', 'Invoice', inv);
  inv.customerName=document.getElementById('i-customerName').value;
  inv.customerCompany=document.getElementById('i-customerCompany').value;
  inv.customerPhone=document.getElementById('i-customerPhone').value;
  inv.customerEmail=document.getElementById('i-customerEmail').value;
  inv.customerAddress=document.getElementById('i-customerAddress').value;
  inv.lineItems=window._invoiceLineItems;
  inv.taxRate=parseFloat(document.getElementById('i-taxRate').value)||0;
  inv.terms=window._invoiceTerms;
  let sub=0,taxable=0;
  inv.lineItems.forEach(li=>{const e=(li.quantity||0)*(li.unitPrice||0);sub+=e;if(li.taxable)taxable+=e;});
  inv.subtotal=sub; inv.taxAmount=taxable*(inv.taxRate/100); inv.total=sub+inv.taxAmount;
  return inv;
}

function saveCurrentInvoice() { const doc=collectInvoiceData(); saveDocument('invoice',doc); editingDocId=doc.id; showToast('Invoice saved!'); }

