function recalcTravel() {
  const mi = parseFloat(document.getElementById('tr-mileage')?.value) || 0;
  const rate = parseFloat(document.getElementById('tr-rate')?.value) || 0;
  document.getElementById('tr-total').textContent = formatCurrency(mi * rate);
}

function saveCurrentTravel() {
  const t = window._currentTravel;
  t.date = document.getElementById('tr-date').value;
  t.jobId = document.getElementById('tr-job').value;
  t.fromLocation = document.getElementById('tr-from').value;
  t.toLocation = document.getElementById('tr-to').value;
  t.mileage = parseFloat(document.getElementById('tr-mileage').value) || 0;
  t.mileageRate = parseFloat(document.getElementById('tr-rate').value) || 0;
  t.totalCost = t.mileage * t.mileageRate;
  t.purpose = document.getElementById('tr-purpose').value;
  t.notes = document.getElementById('tr-notes').value;
  saveDocument('travel', t);
  editingDocId = t.id;
  showToast('Travel entry saved!');
}

