function renderReceiptEditor(receipt) {
  window._currentReceipt = receipt;
  const main = document.querySelector('.main-content');
  const jobs = getJobs();
  const backAction = receipt.jobId ? `openJobDashboard('${receipt.jobId}')` : `showPage('receipts')`;

  main.innerHTML = `
    <div class="page-header">
      <div style="display:flex;align-items:center;gap:12px;">
        <button class="btn-icon" onclick="${backAction}" title="Back">←</button>
        <h1>Receipt</h1>
      </div>
      <div class="page-header-actions">
        <button class="btn btn-secondary" onclick="saveCurrentReceipt()">Save Receipt</button>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Receipt Details</div>
      <div class="form-grid">
        <div class="form-group"><label class="form-label">Date</label><input class="form-input" type="date" id="rc-date" value="${receipt.date}"></div>
        <div class="form-group"><label class="form-label">Vendor</label><input class="form-input" id="rc-vendor" value="${escapeHtml(receipt.vendor)}"></div>
        <div class="form-group"><label class="form-label">Amount</label><input class="form-input" type="number" id="rc-amount" value="${receipt.amount}" min="0" step="0.01"></div>
        <div class="form-group"><label class="form-label">Category</label>
          <select class="form-select" id="rc-category">
            ${RECEIPT_CATEGORIES.map(c => `<option ${receipt.category === c ? 'selected' : ''}>${c}</option>`).join('')}
          </select>
        </div>
        <div class="form-group"><label class="form-label">Job</label>
          <select class="form-select" id="rc-job">
            <option value="">— No Job —</option>
            ${jobs.map(j => `<option value="${j.id}" ${receipt.jobId === j.id ? 'selected' : ''}>${escapeHtml(j.jobNumber)} — ${escapeHtml(j.name)}</option>`).join('')}
          </select>
        </div>
        <div class="form-group"><label class="form-label" style="display:flex;align-items:center;gap:8px;">
          <input type="checkbox" id="rc-taxDeductible" ${receipt.taxDeductible ? 'checked' : ''}> Tax Deductible
        </label></div>
        <div class="form-group full-width"><label class="form-label">Description</label><input class="form-input" id="rc-desc" value="${escapeHtml(receipt.description)}"></div>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Receipt Image / File</div>
      <div style="display:flex;gap:12px;align-items:center;">
        <input type="file" id="rc-file" accept="image/*,.pdf" onchange="handleReceiptUpload(event)" style="display:none;">
        <button class="btn btn-secondary" onclick="document.getElementById('rc-file').click()">Upload Receipt</button>
        ${receipt.fileData ? `<span style="color:var(--text-secondary);">📎 ${escapeHtml(receipt.fileName)}</span>
          <button class="btn btn-sm btn-secondary" onclick="viewReceiptFile()">View</button>
          <button class="btn btn-sm btn-secondary" onclick="clearReceiptFile()">Remove</button>` : '<span style="color:var(--text-secondary);">No file attached</span>'}
      </div>
      ${receipt.fileData && receipt.fileType?.startsWith('image/') ? `<div style="margin-top:12px;"><img src="${receipt.fileData}" style="max-width:400px;max-height:300px;border-radius:8px;border:1px solid var(--border);"></div>` : ''}
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Notes</div>
      <textarea class="form-textarea" id="rc-notes" rows="3">${escapeHtml(receipt.notes)}</textarea>
    </div>
  `;
}

function handleReceiptUpload(event) {
  const file = event.target.files[0];
  if (!file) return;
  if (file.size > 5 * 1024 * 1024) { showToast('File too large (max 5MB)', 'error'); return; }
  const reader = new FileReader();
  reader.onload = (e) => {
    window._currentReceipt.fileData = e.target.result;
    window._currentReceipt.fileName = file.name;
    window._currentReceipt.fileType = file.type;
    renderReceiptEditor(window._currentReceipt);
    showToast('Receipt file attached!');
  };
  reader.readAsDataURL(file);
}

function viewReceiptFile() {
  const r = window._currentReceipt;
  if (!r.fileData) return;
  const win = window.open();
  if (r.fileType?.startsWith('image/')) {
    win.document.write(`<img src="${r.fileData}" style="max-width:100%;">`);
  } else {
    win.document.write(`<iframe src="${r.fileData}" style="width:100%;height:100vh;border:none;"></iframe>`);
  }
}

function clearReceiptFile() {
  window._currentReceipt.fileData = null;
  window._currentReceipt.fileName = '';
  window._currentReceipt.fileType = '';
  renderReceiptEditor(window._currentReceipt);
}

function saveCurrentReceipt() {
  const r = window._currentReceipt;
  r.date = document.getElementById('rc-date').value;
  r.vendor = document.getElementById('rc-vendor').value;
  r.amount = parseFloat(document.getElementById('rc-amount').value) || 0;
  r.category = document.getElementById('rc-category').value;
  r.jobId = document.getElementById('rc-job').value;
  r.taxDeductible = document.getElementById('rc-taxDeductible').checked;
  r.description = document.getElementById('rc-desc').value;
  r.notes = document.getElementById('rc-notes').value;
  saveDocument('receipts', r);
  editingDocId = r.id;
  showToast('Receipt saved!');
}


