// EQUIPMENT REGISTER WITH CALIBRATION TRACKING
// ============================================================
const CALIBRATION_FREQUENCIES = [
  { id: 'none', label: 'N/A — No Calibration Required' },
  { id: '6months', label: 'Every 6 Months' },
  { id: '1year', label: 'Every 1 Year' },
  { id: '2years', label: 'Every 2 Years' },
];

function getDefaultEquipment() {
  return {
    id: generateId(), description: '', manufacturer: '', modelNumber: '', serialNumber: '',
    category: 'Test Equipment', purchaseDate: '', purchaseCost: 0, usefulLifeYears: 7, condition: 'Good',
    calibrationRequired: true, calibrationFrequency: '1year',
    lastCalibrated: '', nextCalibrationDue: '', calibrationVendor: '',
    certificateNumber: '', notes: '',
    // ROI fields
    annualMaintenanceCost: 0,
    targetRoiPercent: 15,
    estimatedJobsPerYear: 50,
    roiRecoveryMethod: 'per-job', // 'per-job' or 'percentage'
    totalJobsUsed: 0,
    totalRevenueRecovered: 0,
  };
}

const EQUIPMENT_CATEGORIES = ['Test Equipment', 'Metering', 'Power Tools', 'Safety Equipment', 'Diagnostic', 'Communication', 'Lifting', 'Other'];
const EQUIPMENT_CONDITIONS = ['New', 'Good', 'Fair', 'Needs Repair', 'Out of Service'];

function getCalibrationStatus(equip) {
  if (!equip.calibrationRequired || equip.calibrationFrequency === 'none') return { status: 'na', label: 'N/A', color: '#6B7280' };
  if (!equip.nextCalibrationDue) return { status: 'unknown', label: 'Not Set', color: '#F59E0B' };
  const today = new Date();
  const due = new Date(equip.nextCalibrationDue + 'T00:00:00');
  const daysUntil = Math.ceil((due - today) / (1000 * 60 * 60 * 24));
  if (daysUntil < 0) return { status: 'overdue', label: 'OVERDUE', color: '#DC2626' };
  if (daysUntil <= 30) return { status: 'due-soon', label: 'Due Soon', color: '#F59E0B' };
  return { status: 'current', label: 'Current', color: '#22C55E' };
}

function calcNextCalDate(lastDate, frequency) {
  if (!lastDate || frequency === 'none') return '';
  const d = new Date(lastDate + 'T00:00:00');
  switch(frequency) {
    case '6months': d.setMonth(d.getMonth() + 6); break;
    case '1year': d.setFullYear(d.getFullYear() + 1); break;
    case '2years': d.setFullYear(d.getFullYear() + 2); break;
  }
  return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
}

function renderEquipmentList() {
  const main = document.querySelector('.main-content');
  const equipment = getDocuments('equipment');
  const overdueCount = equipment.filter(e => getCalibrationStatus(e).status === 'overdue').length;
  const dueSoonCount = equipment.filter(e => getCalibrationStatus(e).status === 'due-soon').length;

  main.innerHTML = `
    <div class="page-header">
      <h1>Equipment Register</h1>
      <div class="page-header-actions">
        <button class="btn btn-secondary" onclick="showEquipmentCertSelector()">📄 Equipment Cert PDF</button>
        <button class="btn btn-primary" onclick="createNewEquipment()">+ Add Equipment</button>
      </div>
    </div>
    ${overdueCount > 0 ? `<div class="alert alert-danger">⚠ ${overdueCount} piece(s) of equipment have OVERDUE calibration.</div>` : ''}
    ${dueSoonCount > 0 ? `<div class="alert alert-warning">⏰ ${dueSoonCount} piece(s) of equipment have calibration due within 30 days.</div>` : ''}
    ${equipment.length === 0 ? '<p class="intro-text">No equipment registered yet.</p>' : `
    <div class="table-scroll">
      <table class="data-table">
        <thead><tr>
          <th style="width:40px;"><input type="checkbox" id="equip-select-all" onchange="toggleAllEquipment(this.checked)"></th>
          <th>Description</th><th>Model</th><th>Serial #</th><th>Category</th><th>Cal. Status</th><th>Next Due</th><th>Actions</th>
        </tr></thead>
        <tbody>
          ${equipment.map(eq => {
            const calStatus = getCalibrationStatus(eq);
            return `<tr onclick="editEquipment('${eq.id}')" style="cursor:pointer;">
              <td onclick="event.stopPropagation();"><input type="checkbox" class="equip-checkbox" value="${eq.id}" onchange="updateEquipmentSelection()"></td>
              <td><strong>${escapeHtml(eq.description)}</strong><br><span style="font-size:12px;color:var(--text-secondary);">${escapeHtml(eq.manufacturer)}</span></td>
              <td>${escapeHtml(eq.modelNumber)}</td>
              <td>${escapeHtml(eq.serialNumber)}</td>
              <td>${escapeHtml(eq.category)}</td>
              <td><span class="status-badge" style="background:${calStatus.color}20;color:${calStatus.color};border:1px solid ${calStatus.color}40;">${calStatus.label}</span></td>
              <td>${eq.nextCalibrationDue ? formatDateShort(eq.nextCalibrationDue) : '—'}</td>
              <td><button class="btn-icon" onclick="event.stopPropagation(); confirmDelete('equipment','${eq.id}','${escapeHtml(eq.description)}')" title="Delete">🗑</button></td>
            </tr>`;
          }).join('')}
        </tbody>
      </table>
    </div>
    <div id="equip-selection-bar" class="selection-bar" style="display:none;">
      <span id="equip-selected-count">0</span> selected
      <button class="btn btn-primary btn-sm" onclick="generateEquipmentCertPDF()">Generate Equipment Certificate PDF</button>
    </div>
    `}
  `;
}

function toggleAllEquipment(checked) {
  document.querySelectorAll('.equip-checkbox').forEach(cb => cb.checked = checked);
  updateEquipmentSelection();
}

function updateEquipmentSelection() {
  const checked = document.querySelectorAll('.equip-checkbox:checked');
  const bar = document.getElementById('equip-selection-bar');
  const count = document.getElementById('equip-selected-count');
  if (bar) bar.style.display = checked.length > 0 ? 'flex' : 'none';
  if (count) count.textContent = checked.length;
}

function getSelectedEquipmentIds() {
  return Array.from(document.querySelectorAll('.equip-checkbox:checked')).map(cb => cb.value);
}

function showEquipmentCertSelector() {
  // If no checkboxes are checked, show a prompt
  const ids = getSelectedEquipmentIds();
  if (ids.length === 0) {
    showToast('Select equipment using the checkboxes first, then click Generate.', 'error');
    return;
  }
  generateEquipmentCertPDF();
}

