function updateRoiPreview() {
  const preview = document.getElementById('roi-preview');
  if (!preview) return;
  const cost = parseFloat(document.getElementById('eq-purchaseCost')?.value) || 0;
  const life = parseInt(document.getElementById('eq-usefulLife')?.value) || 7;
  const maint = parseFloat(document.getElementById('eq-annualMaint')?.value) || 0;
  const roi = parseFloat(document.getElementById('eq-targetRoi')?.value) || 15;
  const jobsYr = parseInt(document.getElementById('eq-jobsPerYear')?.value) || 50;
  const method = document.getElementById('eq-roiMethod')?.value || 'per-job';

  const totalLifetimeCost = cost + (maint * life);
  const targetRevenue = totalLifetimeCost * (1 + roi / 100);
  const annualRecovery = targetRevenue / life;
  const perJobCost = annualRecovery / jobsYr;
  const markupEquiv = cost > 0 ? ((targetRevenue - totalLifetimeCost) / totalLifetimeCost * 100) : 0;

  preview.innerHTML = `
    <div class="stat-card"><div class="stat-label">Lifetime Cost</div><div class="stat-value">${formatCurrency(totalLifetimeCost)}</div></div>
    <div class="stat-card"><div class="stat-label">Target Revenue</div><div class="stat-value">${formatCurrency(targetRevenue)}</div></div>
    <div class="stat-card"><div class="stat-label">Annual Recovery</div><div class="stat-value">${formatCurrency(annualRecovery)}</div></div>
    <div class="stat-card"><div class="stat-label">${method === 'per-job' ? 'Per-Job Charge' : 'Markup %'}</div><div class="stat-value" style="color:var(--accent);">${method === 'per-job' ? formatCurrency(perJobCost) : roi.toFixed(1) + '%'}</div></div>
  `;
}

function updateRecoveryProgress() {
  const el = document.getElementById('recovery-progress');
  if (!el) return;
  const cost = parseFloat(document.getElementById('eq-purchaseCost')?.value) || 0;
  const life = parseInt(document.getElementById('eq-usefulLife')?.value) || 7;
  const maint = parseFloat(document.getElementById('eq-annualMaint')?.value) || 0;
  const roi = parseFloat(document.getElementById('eq-targetRoi')?.value) || 15;
  const recovered = parseFloat(document.getElementById('eq-totalRecovered')?.value) || 0;
  const totalJobs = parseInt(document.getElementById('eq-totalJobs')?.value) || 0;

  const totalLifetimeCost = cost + (maint * life);
  const targetRevenue = totalLifetimeCost * (1 + roi / 100);
  const pct = targetRevenue > 0 ? Math.min((recovered / targetRevenue) * 100, 100) : 0;
  const remaining = Math.max(targetRevenue - recovered, 0);

  el.innerHTML = `
    <div style="display:flex;justify-content:space-between;font-size:13px;margin-bottom:6px;">
      <span>Recovery Progress: ${pct.toFixed(1)}%</span>
      <span>${formatCurrency(recovered)} / ${formatCurrency(targetRevenue)}</span>
    </div>
    <div style="background:var(--bg-secondary);border-radius:8px;height:20px;overflow:hidden;">
      <div style="background:${pct >= 100 ? 'var(--success)' : 'var(--accent)'};height:100%;width:${pct}%;border-radius:8px;transition:width 0.3s;"></div>
    </div>
    <div style="font-size:12px;color:var(--text-secondary);margin-top:6px;">
      Used on ${totalJobs} job${totalJobs !== 1 ? 's' : ''} · ${formatCurrency(remaining)} remaining to target
    </div>
  `;
}

function toggleCalFields() {
  // Visual toggle only — all fields remain accessible
}

function autoCalcNextDue() {
  const lastCal = document.getElementById('eq-lastCal').value;
  const freq = document.getElementById('eq-calFreq').value;
  if (lastCal && freq !== 'none') {
    const next = calcNextCalDate(lastCal, freq);
    document.getElementById('eq-nextCal').value = next;
  }
}

function saveCurrentEquipment() {
  const eq = window._currentEquipment;
  eq.description = document.getElementById('eq-desc').value;
  eq.manufacturer = document.getElementById('eq-manufacturer').value;
  eq.modelNumber = document.getElementById('eq-model').value;
  eq.serialNumber = document.getElementById('eq-serial').value;
  eq.category = document.getElementById('eq-category').value;
  eq.purchaseDate = document.getElementById('eq-purchaseDate').value;
  eq.purchaseCost = parseFloat(document.getElementById('eq-purchaseCost').value) || 0;
  eq.usefulLifeYears = parseInt(document.getElementById('eq-usefulLife').value) || 7;
  eq.condition = document.getElementById('eq-condition').value;
  eq.calibrationRequired = document.getElementById('eq-calRequired').checked;
  eq.calibrationFrequency = document.getElementById('eq-calFreq').value;
  eq.lastCalibrated = document.getElementById('eq-lastCal').value;
  eq.nextCalibrationDue = document.getElementById('eq-nextCal').value;
  eq.calibrationVendor = document.getElementById('eq-calVendor').value;
  eq.certificateNumber = document.getElementById('eq-certNum').value;
  eq.notes = document.getElementById('eq-notes').value;
  // ROI fields
  eq.annualMaintenanceCost = parseFloat(document.getElementById('eq-annualMaint')?.value) || 0;
  eq.targetRoiPercent = parseFloat(document.getElementById('eq-targetRoi')?.value) || 15;
  eq.estimatedJobsPerYear = parseInt(document.getElementById('eq-jobsPerYear')?.value) || 50;
  eq.roiRecoveryMethod = document.getElementById('eq-roiMethod')?.value || 'per-job';
  eq.totalJobsUsed = parseInt(document.getElementById('eq-totalJobs')?.value) || 0;
  eq.totalRevenueRecovered = parseFloat(document.getElementById('eq-totalRecovered')?.value) || 0;
  saveDocument('equipment', eq);
  editingDocId = eq.id;
  showToast('Equipment saved!');
}


