// NETA Testing Standards Data
const NETA_IR_TABLE = [
  { maxVoltage: 250, testVoltage: 500, minIR: 25 },
  { maxVoltage: 600, testVoltage: 1000, minIR: 100 },
  { maxVoltage: 1000, testVoltage: 1000, minIR: 100 },
  { maxVoltage: 2500, testVoltage: 1000, minIR: 500 },
  { maxVoltage: 5000, testVoltage: 2500, minIR: 1500 },
  { maxVoltage: 8000, testVoltage: 2500, minIR: 2500 },
  { maxVoltage: 15000, testVoltage: 2500, minIR: 5000 },
  { maxVoltage: 25000, testVoltage: 5000, minIR: 10000 },
  { maxVoltage: 34500, testVoltage: 5000, minIR: 100000 },
  { maxVoltage: 999999, testVoltage: 5000, minIR: 100000 },
];

const NETA_STANDARDS = {
  insulation_resistance: {
    acceptance: 'Per ANSI/NETA ATS Table 100.1: Min IR based on voltage class. Values must meet or exceed minimum.',
    maintenance: 'Per ANSI/NETA MTS Table 100.1: Compare to baseline. Should not decrease >25% from previous test.',
    evaluate: function(measuredValue, acceptableMin) {
      const val = parseFloat(measuredValue);
      if (isNaN(val)) return '';
      if (val >= acceptableMin) return 'pass';
      if (val >= acceptableMin * 0.75) return 'investigate';
      return 'fail';
    }
  },
  contact_resistance: {
    acceptance: 'Per ANSI/NETA ATS: Compare to manufacturer published data. Phase-to-phase deviation should not exceed 50%.',
    maintenance: 'Per ANSI/NETA MTS: Compare to baseline and manufacturer data. Deviation >50% from baseline warrants investigation.',
  },
  turns_ratio: {
    acceptance: 'Per ANSI/NETA ATS: Turns ratio shall be within +/- 0.5% of calculated ratio from nameplate.',
    maintenance: 'Per ANSI/NETA MTS: Turns ratio shall be within +/- 0.5% of calculated ratio or previous test results.',
    evaluate: function(measuredValue, nameplate) {
      var val = parseFloat(measuredValue);
      var np = parseFloat(nameplate);
      if (isNaN(val) || isNaN(np) || np === 0) return '';
      var deviation = Math.abs((val - np) / np) * 100;
      if (deviation <= 0.5) return 'pass';
      if (deviation <= 2.0) return 'investigate';
      return 'fail';
    }
  },
  winding_resistance: {
    acceptance: 'Per ANSI/NETA ATS: Winding resistance phase-to-phase deviation shall not exceed 2% from average.',
    maintenance: 'Per ANSI/NETA MTS: Winding resistance shall not deviate more than 2% from average or previous results.',
  },
  power_factor: {
    acceptance: 'Per ANSI/NETA ATS: New equipment typically < 1.0%. Values > 2.0% indicate deterioration.',
    maintenance: 'Per ANSI/NETA MTS: Compare to nameplate/baseline. Increase >25% from baseline warrants investigation.',
    evaluate: function(measuredValue, isAcceptance) {
      const val = parseFloat(measuredValue);
      if (isNaN(val)) return '';
      if (isAcceptance) {
        if (val <= 1.0) return 'pass';
        if (val <= 2.0) return 'investigate';
        return 'fail';
      } else {
        if (val <= 2.0) return 'pass';
        if (val <= 3.0) return 'investigate';
        return 'fail';
      }
    }
  },

};

