function getCustomThemeColors() {
  try {
    const saved = localStorage.getItem('psva_custom_theme_colors');
    if (saved) return JSON.parse(saved);
  } catch(e) {}
  // Default: start from the currently selected theme's colors
  const current = PDF_THEMES.find(t => t.id === selectedThemeId) || PDF_THEMES[0];
  return { ...current.colors };
}

function saveCustomThemeColors(colors) {
  localStorage.setItem('psva_custom_theme_colors', JSON.stringify(colors));
}

function updateCustomThemeColor(key, value) {
  // Validate hex color
  if (!/^#[0-9A-Fa-f]{6}$/.test(value)) return;
  const colors = getCustomThemeColors();
  colors[key] = value.toUpperCase();
  saveCustomThemeColors(colors);
  // Sync both inputs
  const colorInput = document.getElementById('cp-' + key);
  const hexInput = document.getElementById('cp-hex-' + key);
  if (colorInput) colorInput.value = value;
  if (hexInput) hexInput.value = value.toUpperCase();
  // Update live preview only (don't re-render entire page)
  const previewEl = document.getElementById('custom-theme-preview');
  if (previewEl) previewEl.innerHTML = buildCustomThemePreview();
}

function loadBaseThemeColors(themeId) {
  if (!themeId) return;
  const base = PDF_THEMES.find(t => t.id === themeId);
  if (!base) return;
  const colors = { ...base.colors };
  saveCustomThemeColors(colors);
  // Update all color pickers
  Object.keys(colors).forEach(key => {
    const colorInput = document.getElementById('cp-' + key);
    const hexInput = document.getElementById('cp-hex-' + key);
    if (colorInput) colorInput.value = colors[key];
    if (hexInput) hexInput.value = colors[key];
  });
  // Update live preview
  const previewEl = document.getElementById('custom-theme-preview');
  if (previewEl) previewEl.innerHTML = buildCustomThemePreview();
  showToast('Loaded ' + base.name + ' as base — customize away!', 'success');
}

function applyCustomTheme() {
  selectedThemeId = 'custom';
  localStorage.setItem('psva_pdf_theme', 'custom');
  renderThemes();
  showToast('Custom theme applied! All PDF exports will use your colors.', 'success');
}

function resetCustomThemeColors() {
  if (!confirm('Reset custom colors to the Classic Dark defaults?')) return;
  localStorage.removeItem('psva_custom_theme_colors');
  renderThemes();
}

