// ============================================================
// TEST REPORT PDF EXPORT
// ============================================================
function sanitizePdfText(text) {
  if (!text) return text;
  return text
    .replace(/\u2265/g, '>=')
    .replace(/\u2264/g, '<=')
    .replace(/\u03BCOhm/g, 'uOhm')
    .replace(/MOhm/g, 'MOhm')
    .replace(/\u03A9/g, 'Ohm')
    .replace(/\u03BC/g, 'u')
    .replace(/\u00B0/g, ' deg');
}

async function exportTestReportPDF() {
  const report = collectTestReportData();
  saveCurrentTestReport();

  const { jsPDF } = window.jspdf;
  const doc = new jsPDF('p', 'mm', 'letter');
  const theme = getActiveTheme();
  const company = getCompany();
  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();

  function addPageBg() {
    doc.setFillColor(...hexToRgb(theme.colors.bg));
    doc.rect(0, 0, pageWidth, pageHeight, 'F');
  }

  function addFooter(pageNum, totalPages) {
    const footerY = pageHeight - 12;
    doc.setDrawColor(...hexToRgb(theme.colors.accent));
    doc.setLineWidth(0.4);
    doc.line(15, footerY, pageWidth - 15, footerY);
    doc.setFontSize(7);
    doc.setTextColor(...hexToRgb(theme.colors.textSecondary));
    doc.text(company.name + ' | ' + report.reportNumber, 15, footerY + 4);
    doc.text('Page ' + pageNum + ' of ' + totalPages, pageWidth - 15, footerY + 4, { align: 'right' });
  }

  function checkNewPage(neededHeight) {
    if (y + neededHeight > pageHeight - 20) {
      doc.addPage();
      addPageBg();
      y = 20;
      return true;
    }
    return false;
  }

  addPageBg();
  let y = pdfAddHeader(doc, theme, company, 'TEST REPORT', report.reportNumber, pageWidth);

  const leftCol = 15;
  const labelColor = hexToRgb(theme.colors.textSecondary);
  const textColor = hexToRgb(theme.colors.text);
  const accentColor = hexToRgb(theme.colors.accent);

  // Report Details
  doc.setDrawColor(...accentColor);
  doc.setLineWidth(0.6);
  doc.line(leftCol, y, leftCol + 10, y);
  y += 3;
  doc.setFontSize(9);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(...accentColor);
  doc.text('REPORT DETAILS', leftCol, y);
  y += 5;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(8);

  let overallText = 'PASS';
  let overallColor = pdfDarkMode ? [34, 197, 94] : [22, 163, 74];
  if (report.overallResult === 'fail') { overallText = 'FAIL'; overallColor = pdfDarkMode ? [239, 68, 68] : [220, 38, 38]; }
  else if (report.overallResult === 'investigate') { overallText = 'INVESTIGATE'; overallColor = pdfDarkMode ? [245, 158, 11] : [180, 110, 0]; }

  const infoRows = [
    ['Title:', report.title],
    ['Date:', formatDate(report.date)],
    ['Technician:', report.technician],
    ['Test Standard:', report.testStandard === 'acceptance' ? 'Acceptance Testing (ANSI/NETA ATS)' : 'Maintenance Testing (ANSI/NETA MTS)'],
    ['NETA Standards:', report.useNeta ? 'Applied' : 'Not Applied'],
  ];
  infoRows.forEach(function(pair) {
    doc.setTextColor(...labelColor);
    doc.text(pair[0], leftCol, y);
    doc.setTextColor(...textColor);
    doc.text(sanitizePdfText(pair[1] || ''), leftCol + 30, y);
    y += 4;
  });
  doc.setTextColor(...labelColor);
  doc.text('Overall Result:', leftCol, y);
  doc.setTextColor(...overallColor);
  doc.setFont('helvetica', 'bold');
  doc.text(overallText, leftCol + 30, y);
  doc.setFont('helvetica', 'normal');
  y += 4;

  if (report.jobId) {
    const job = getJobById(report.jobId);
    if (job) {
      doc.setTextColor(...labelColor);
      doc.text('Job:', leftCol, y);
      doc.setTextColor(...textColor);
      doc.text(sanitizePdfText(job.jobNumber + ' - ' + (job.name || '')), leftCol + 30, y);
      y += 4;
    }
  }
  y += 3;

  // Equipment Under Test
  doc.setDrawColor(...accentColor);
  doc.line(leftCol, y, leftCol + 10, y);
  y += 3;
  doc.setFontSize(9);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(...accentColor);
  doc.text('EQUIPMENT UNDER TEST', leftCol, y);
  y += 5;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(8);
  const eqRows = [
    ['Equipment:', report.equipmentTested],
    ['Manufacturer:', report.equipmentManufacturer],
    ['Model:', report.equipmentModel],
    ['Serial Number:', report.equipmentSerial],
    ['Location:', report.location],
    ['Temperature:', report.temperature ? report.temperature + ' F' : ''],
    ['Humidity:', report.humidity ? report.humidity + '%' : ''],
  ];
  eqRows.forEach(function(pair) {
    if (pair[1]) {
      doc.setTextColor(...labelColor);
      doc.text(pair[0], leftCol, y);
      doc.setTextColor(...textColor);
      doc.text(sanitizePdfText(pair[1]), leftCol + 30, y);
      y += 4;
    }
  });
  y += 5;

  // Enabled test sections
  const enabledSections = TEST_SECTIONS.filter(function(sec) { return report.sections[sec.id] && report.sections[sec.id].enabled; });

  enabledSections.forEach(function(sec) {
    const sectionData = report.sections[sec.id];
    if (!sectionData || sectionData.params.length === 0) return;

    const estimatedHeight = 20 + sectionData.params.length * 7 + (sectionData.comment ? 15 : 0);
    checkNewPage(estimatedHeight);

    doc.setDrawColor(...accentColor);
    doc.setLineWidth(0.6);
    doc.line(leftCol, y, leftCol + 10, y);
    y += 3;
    doc.setFontSize(9);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...accentColor);
    var unitLabel = sectionData.unit ? ' (' + sectionData.unit + ')' : '';
    var sectionTitle = sec.label.toUpperCase() + unitLabel;
    if (sec.id === 'contact_resistance') {
      var devType = report.contactResistanceDeviceType || 'circuit_breaker';
      var devLabel = devType === 'circuit_breaker' ? 'Circuit Breaker' : devType === 'bus' ? 'Bus' : (report.contactResistanceDeviceTypeCustom || 'Other');
      sectionTitle += ' - ' + devLabel;
    }
    doc.text(sanitizePdfText(sectionTitle), leftCol, y);

    if (report.useNeta && sec.netaApplicable) {
      var badgeX = leftCol + doc.getTextWidth(sanitizePdfText(sectionTitle)) + 3;
      doc.setFontSize(6);
      doc.setTextColor(...accentColor);
      doc.text('[NETA]', badgeX, y);
    }
    y += 4;

    const tableData = sectionData.params.map(function(p) {
      let resultText = '';
      if (p.passFail === 'pass') resultText = 'PASS';
      else if (p.passFail === 'fail') resultText = 'FAIL';
      else if (p.passFail === 'investigate') resultText = 'INVESTIGATE';
      else if (p.passFail === 'na') resultText = 'N/A';
      return [sanitizePdfText(p.name), sanitizePdfText(p.measuredValue), sanitizePdfText(p.acceptableRange), resultText];
    });

    doc.autoTable({
      startY: y,
      head: [['Parameter', 'Measured Value', 'Acceptable Range', 'Result']],
      body: tableData,
      margin: { left: leftCol, right: 15 },
      styles: {
        fontSize: 7.5,
        cellPadding: 2,
        textColor: textColor,
        lineColor: hexToRgb(theme.colors.border || theme.colors.textSecondary),
        lineWidth: 0.2,
      },
      headStyles: {
        fillColor: hexToRgb(theme.colors.tableAlt || theme.colors.bg),
        textColor: accentColor,
        fontStyle: 'bold',
        lineWidth: 0,
      },
      bodyStyles: { fillColor: hexToRgb(theme.colors.tableBg || theme.colors.bg) },
      alternateRowStyles: {
        fillColor: hexToRgb(theme.colors.tableAlt || (pdfDarkMode ? '#32323a' : '#F5F5F8')),
      },
      columnStyles: {
        0: { cellWidth: 'auto' },
        3: { cellWidth: 25, halign: 'center' },
      },
      didParseCell: function(data) {
        if (data.section === 'body' && data.column.index === 3) {
          if (data.cell.raw === 'PASS') data.cell.styles.textColor = [34, 197, 94];
          else if (data.cell.raw === 'FAIL') data.cell.styles.textColor = [239, 68, 68];
          else if (data.cell.raw === 'INVESTIGATE') data.cell.styles.textColor = [245, 158, 11];
        }
      },
      theme: 'plain',
      didDrawPage: pdfAutoTablePageHook(theme),
    });

    y = doc.lastAutoTable.finalY + 3;

    // Section comment (only if not blank)
    if (sectionData.comment && sectionData.comment.trim()) {
      checkNewPage(15);
      doc.setFontSize(7);
      doc.setFont('helvetica', 'italic');
      doc.setTextColor(...labelColor);
      doc.text('Comment:', leftCol, y + 2);
      doc.setFont('helvetica', 'normal');
      doc.setTextColor(...textColor);
      const commentLines = doc.splitTextToSize(sanitizePdfText(sectionData.comment), pageWidth - 45);
      doc.text(commentLines, leftCol + 18, y + 2);
      y += commentLines.length * 3.5 + 4;
    }

    y += 5;
  });

  // Notes
  if (report.notes) {
    checkNewPage(25);
    doc.setDrawColor(...accentColor);
    doc.setLineWidth(0.6);
    doc.line(leftCol, y, leftCol + 10, y);
    y += 3;
    doc.setFontSize(9);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...accentColor);
    doc.text('NOTES / COMMENTS', leftCol, y);
    y += 5;
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.setTextColor(...textColor);
    const noteLines = doc.splitTextToSize(sanitizePdfText(report.notes), pageWidth - 30);
    doc.text(noteLines, leftCol, y);
    y += noteLines.length * 3.5 + 5;
  }

  // Signature line
  checkNewPage(30);
  y += 10;
  doc.setDrawColor(...hexToRgb(theme.colors.textSecondary));
  doc.setLineWidth(0.3);
  doc.line(leftCol, y + 8, leftCol + 70, y + 8);
  doc.line(pageWidth / 2 + 5, y + 8, pageWidth - 15, y + 8);
  doc.setFontSize(7);
  doc.setTextColor(...labelColor);
  doc.text('Technician Signature', leftCol, y + 12);
  doc.text('Date', pageWidth / 2 + 5, y + 12);

  // Add footers to all pages
  const totalPages = doc.internal.getNumberOfPages();
  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i);
    addFooter(i, totalPages);
  }

  doc.save(report.reportNumber + '.pdf');
  showToast('Test report PDF exported!');
}


// ============================================================
// COMPILED TEST REPORTS PDF (ALL REPORTS FOR A JOB)
// ============================================================
async function exportCompiledTestReportsPDF(jobId) {
  const job = getJobById(jobId);
  if (!job) { showToast('Job not found.', 'error'); return; }
  const allReports = getTestReports().filter(r => r.jobId === jobId);
  if (allReports.length === 0) { showToast('No test reports for this job.', 'error'); return; }

  const { jsPDF } = window.jspdf;
  const doc = new jsPDF('p', 'mm', 'letter');
  const theme = getActiveTheme();
  const company = getCompany();
  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();
  const colors = theme.colors;
  const leftCol = 15;
  const labelColor = hexToRgb(theme.colors.textSecondary);
  const textColor = hexToRgb(theme.colors.text);
  const accentColor = hexToRgb(theme.colors.accent);

  function addPageBg() {
    doc.setFillColor(...hexToRgb(theme.colors.bg));
    doc.rect(0, 0, pageWidth, pageHeight, 'F');
  }

  function checkNewPage(neededHeight) {
    if (y + neededHeight > pageHeight - 20) {
      doc.addPage();
      addPageBg();
      y = 20;
      return true;
    }
    return false;
  }

  // === COVER PAGE ===
  addPageBg();
  let y = pdfAddHeader(doc, theme, company, 'TEST REPORT COMPILATION', job.jobNumber, pageWidth);

  // Job info section
  doc.setDrawColor(...accentColor);
  doc.setLineWidth(0.6);
  doc.line(leftCol, y, leftCol + 10, y);
  y += 3;
  doc.setFontSize(9); doc.setFont('helvetica', 'bold'); doc.setTextColor(...accentColor);
  doc.text('JOB INFORMATION', leftCol, y); y += 5;
  doc.setFont('helvetica', 'normal'); doc.setFontSize(8);
  const jobInfoRows = [
    ['Job Number:', job.jobNumber],
    ['Job Name:', job.name || ''],
    ['Customer:', (job.customer.company || '') + (job.customer.name ? ' (' + job.customer.name + ')' : '')],
    ['Status:', (job.status || '').replace(/_/g, ' ').toUpperCase()],
    ['Start Date:', job.startDate ? formatDate(job.startDate) : ''],
    ['End Date:', job.endDate ? formatDate(job.endDate) : ''],
  ];
  jobInfoRows.forEach(function(pair) {
    if (pair[1]) {
      doc.setTextColor(...labelColor); doc.text(pair[0], leftCol, y);
      doc.setTextColor(...textColor); doc.text(sanitizePdfText(pair[1]), leftCol + 30, y);
      y += 4;
    }
  });
  y += 5;

  // Table of contents
  doc.setDrawColor(...accentColor);
  doc.line(leftCol, y, leftCol + 10, y);
  y += 3;
  doc.setFontSize(9); doc.setFont('helvetica', 'bold'); doc.setTextColor(...accentColor);
  doc.text('TABLE OF CONTENTS — ' + allReports.length + ' REPORT' + (allReports.length !== 1 ? 'S' : ''), leftCol, y); y += 5;

  doc.setFont('helvetica', 'normal'); doc.setFontSize(8);
  allReports.forEach(function(r, idx) {
    let resultText = 'PASS', resultColor = pdfDarkMode ? [34, 197, 94] : [22, 163, 74];
    if (r.overallResult === 'fail') { resultText = 'FAIL'; resultColor = pdfDarkMode ? [239, 68, 68] : [220, 38, 38]; }
    else if (r.overallResult === 'investigate') { resultText = 'INVESTIGATE'; resultColor = pdfDarkMode ? [245, 158, 11] : [180, 110, 0]; }
    doc.setTextColor(...textColor);
    doc.text((idx + 1) + '.  ' + sanitizePdfText(r.reportNumber) + ' — ' + sanitizePdfText(r.title || r.equipmentTested || 'Untitled'), leftCol, y);
    doc.setTextColor(...resultColor);
    doc.text(resultText, pageWidth - 15, y, { align: 'right' });
    y += 5;
    if (y > pageHeight - 25) { doc.addPage(); addPageBg(); y = 20; }
  });

  // === INDIVIDUAL REPORTS ===
  allReports.forEach(function(report, reportIdx) {
    // Start each report on a new page
    doc.addPage();
    addPageBg();
    y = pdfAddHeader(doc, theme, company, 'TEST REPORT', report.reportNumber, pageWidth);

    // Report details
    doc.setDrawColor(...accentColor); doc.setLineWidth(0.6);
    doc.line(leftCol, y, leftCol + 10, y); y += 3;
    doc.setFontSize(9); doc.setFont('helvetica', 'bold'); doc.setTextColor(...accentColor);
    doc.text('REPORT DETAILS', leftCol, y); y += 5;
    doc.setFont('helvetica', 'normal'); doc.setFontSize(8);

    let overallText = 'PASS', overallColor = pdfDarkMode ? [34, 197, 94] : [22, 163, 74];
    if (report.overallResult === 'fail') { overallText = 'FAIL'; overallColor = pdfDarkMode ? [239, 68, 68] : [220, 38, 38]; }
    else if (report.overallResult === 'investigate') { overallText = 'INVESTIGATE'; overallColor = pdfDarkMode ? [245, 158, 11] : [180, 110, 0]; }

    const infoRows = [
      ['Title:', report.title],
      ['Date:', formatDate(report.date)],
      ['Technician:', report.technician],
      ['Test Standard:', report.testStandard === 'acceptance' ? 'Acceptance Testing (ANSI/NETA ATS)' : 'Maintenance Testing (ANSI/NETA MTS)'],
      ['NETA Standards:', report.useNeta ? 'Applied' : 'Not Applied'],
    ];
    infoRows.forEach(function(pair) {
      doc.setTextColor(...labelColor); doc.text(pair[0], leftCol, y);
      doc.setTextColor(...textColor); doc.text(sanitizePdfText(pair[1] || ''), leftCol + 30, y);
      y += 4;
    });
    doc.setTextColor(...labelColor); doc.text('Overall Result:', leftCol, y);
    doc.setTextColor(...overallColor); doc.setFont('helvetica', 'bold');
    doc.text(overallText, leftCol + 30, y);
    doc.setFont('helvetica', 'normal'); y += 7;

    // Equipment Under Test
    doc.setDrawColor(...accentColor); doc.line(leftCol, y, leftCol + 10, y); y += 3;
    doc.setFontSize(9); doc.setFont('helvetica', 'bold'); doc.setTextColor(...accentColor);
    doc.text('EQUIPMENT UNDER TEST', leftCol, y); y += 5;
    doc.setFont('helvetica', 'normal'); doc.setFontSize(8);
    const eqRows = [
      ['Equipment:', report.equipmentTested],
      ['Manufacturer:', report.equipmentManufacturer],
      ['Model:', report.equipmentModel],
      ['Serial Number:', report.equipmentSerial],
      ['Location:', report.location],
      ['Temperature:', report.temperature ? report.temperature + ' F' : ''],
      ['Humidity:', report.humidity ? report.humidity + '%' : ''],
    ];
    eqRows.forEach(function(pair) {
      if (pair[1]) {
        doc.setTextColor(...labelColor); doc.text(pair[0], leftCol, y);
        doc.setTextColor(...textColor); doc.text(sanitizePdfText(pair[1]), leftCol + 30, y);
        y += 4;
      }
    });
    y += 5;

    // Test sections
    const enabledSections = TEST_SECTIONS.filter(function(sec) { return report.sections[sec.id] && report.sections[sec.id].enabled; });
    enabledSections.forEach(function(sec) {
      const sectionData = report.sections[sec.id];
      if (!sectionData || sectionData.params.length === 0) return;

      const estimatedHeight = 20 + sectionData.params.length * 7 + (sectionData.comment ? 15 : 0);
      checkNewPage(estimatedHeight);

      doc.setDrawColor(...accentColor); doc.setLineWidth(0.6);
      doc.line(leftCol, y, leftCol + 10, y); y += 3;
      doc.setFontSize(9); doc.setFont('helvetica', 'bold'); doc.setTextColor(...accentColor);
      var unitLabel = sectionData.unit ? ' (' + sectionData.unit + ')' : '';
      var sectionTitle = sec.label.toUpperCase() + unitLabel;
      if (sec.id === 'contact_resistance') {
        var devType = report.contactResistanceDeviceType || 'circuit_breaker';
        var devLabel = devType === 'circuit_breaker' ? 'Circuit Breaker' : devType === 'bus' ? 'Bus' : (report.contactResistanceDeviceTypeCustom || 'Other');
        sectionTitle += ' - ' + devLabel;
      }
      doc.text(sanitizePdfText(sectionTitle), leftCol, y);
      if (report.useNeta && sec.netaApplicable) {
        var badgeX = leftCol + doc.getTextWidth(sanitizePdfText(sectionTitle)) + 3;
        doc.setFontSize(6); doc.setTextColor(...accentColor);
        doc.text('[NETA]', badgeX, y);
      }
      y += 4;

      const tableData = sectionData.params.map(function(p) {
        let resultText = '';
        if (p.passFail === 'pass') resultText = 'PASS';
        else if (p.passFail === 'fail') resultText = 'FAIL';
        else if (p.passFail === 'investigate') resultText = 'INVESTIGATE';
        else if (p.passFail === 'na') resultText = 'N/A';
        return [sanitizePdfText(p.name), sanitizePdfText(p.measuredValue), sanitizePdfText(p.acceptableRange), resultText];
      });

      doc.autoTable({
        startY: y,
        head: [['Parameter', 'Measured Value', 'Acceptable Range', 'Result']],
        body: tableData,
        margin: { left: leftCol, right: 15 },
        styles: { fontSize: 7.5, cellPadding: 2, textColor: textColor, lineColor: hexToRgb(colors.border || colors.textSecondary), lineWidth: 0.2 },
        headStyles: { fillColor: hexToRgb(colors.tableAlt || colors.bg), textColor: accentColor, fontStyle: 'bold', lineWidth: 0 },
        bodyStyles: { fillColor: hexToRgb(colors.tableBg || colors.bg) },
        alternateRowStyles: { fillColor: hexToRgb(colors.tableAlt || (pdfDarkMode ? '#32323a' : '#F5F5F8')) },
        columnStyles: { 0: { cellWidth: 'auto' }, 3: { cellWidth: 25, halign: 'center' } },
        didParseCell: function(data) {
          if (data.section === 'body' && data.column.index === 3) {
            if (data.cell.raw === 'PASS') data.cell.styles.textColor = [34, 197, 94];
            else if (data.cell.raw === 'FAIL') data.cell.styles.textColor = [239, 68, 68];
            else if (data.cell.raw === 'INVESTIGATE') data.cell.styles.textColor = [245, 158, 11];
          }
        },
        theme: 'plain',
        didDrawPage: pdfAutoTablePageHook(theme),
      });
      y = doc.lastAutoTable.finalY + 3;

      if (sectionData.comment && sectionData.comment.trim()) {
        checkNewPage(15);
        doc.setFontSize(7); doc.setFont('helvetica', 'italic'); doc.setTextColor(...labelColor);
        doc.text('Comment:', leftCol, y + 2);
        doc.setFont('helvetica', 'normal'); doc.setTextColor(...textColor);
        const commentLines = doc.splitTextToSize(sanitizePdfText(sectionData.comment), pageWidth - 45);
        doc.text(commentLines, leftCol + 18, y + 2);
        y += commentLines.length * 3.5 + 4;
      }
      y += 5;
    });

    // Notes
    if (report.notes) {
      checkNewPage(25);
      doc.setDrawColor(...accentColor); doc.setLineWidth(0.6);
      doc.line(leftCol, y, leftCol + 10, y); y += 3;
      doc.setFontSize(9); doc.setFont('helvetica', 'bold'); doc.setTextColor(...accentColor);
      doc.text('NOTES / COMMENTS', leftCol, y); y += 5;
      doc.setFont('helvetica', 'normal'); doc.setFontSize(8); doc.setTextColor(...textColor);
      const noteLines = doc.splitTextToSize(sanitizePdfText(report.notes), pageWidth - 30);
      doc.text(noteLines, leftCol, y);
      y += noteLines.length * 3.5 + 5;
    }

    // Signature line
    checkNewPage(30);
    y += 10;
    doc.setDrawColor(...hexToRgb(theme.colors.textSecondary)); doc.setLineWidth(0.3);
    doc.line(leftCol, y + 8, leftCol + 70, y + 8);
    doc.line(pageWidth / 2 + 5, y + 8, pageWidth - 15, y + 8);
    doc.setFontSize(7); doc.setTextColor(...labelColor);
    doc.text('Technician Signature', leftCol, y + 12);
    doc.text('Date', pageWidth / 2 + 5, y + 12);
  });

  // Add footers to all pages
  const totalPages = doc.internal.getNumberOfPages();
  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i);
    const footerY = pageHeight - 12;
    doc.setDrawColor(...accentColor); doc.setLineWidth(0.4);
    doc.line(15, footerY, pageWidth - 15, footerY);
    doc.setFontSize(7); doc.setTextColor(...labelColor);
    doc.text(company.name + ' | ' + job.jobNumber + ' — Compiled Test Reports', 15, footerY + 4);
    doc.text('Page ' + i + ' of ' + totalPages, pageWidth - 15, footerY + 4, { align: 'right' });
  }

  doc.save(job.jobNumber + '-Test-Reports-Compiled.pdf');
  showToast('Compiled test report PDF exported! (' + allReports.length + ' reports)');
}



// ============================================================
// EQUIPMENT ROI PICKER FOR ESTIMATES
// ============================================================
function showEquipmentRoiPicker() {
  const equipment = getDocuments('equipment');
  if (equipment.length === 0) {
    showToast('No equipment in register. Add equipment first.', 'error');
    return;
  }
  const modal = document.createElement('div');
  modal.className = 'modal-overlay';
  modal.innerHTML = `
    <div class="modal" style="max-width:600px;">
      <div class="modal-header">
        <h3>Add Equipment Cost Recovery</h3>
        <button class="btn-icon" onclick="this.closest('.modal-overlay').remove()">✕</button>
      </div>
      <div class="modal-body" style="max-height:400px;overflow-y:auto;">
        ${equipment.map(eq => {
          const cost = eq.purchaseCost || 0;
          const life = eq.usefulLifeYears || 7;
          const maint = eq.annualMaintenanceCost || 0;
          const roi = eq.targetRoiPercent || 15;
          const jobsYr = eq.estimatedJobsPerYear || 50;
          const totalCost = cost + (maint * life);
          const targetRev = totalCost * (1 + roi / 100);
          const perJob = targetRev / life / jobsYr;
          return `
          <div class="mini-row" style="cursor:pointer;padding:12px;" onclick="addEquipmentToEstimate('${eq.id}'); this.closest('.modal-overlay').remove();">
            <div style="flex:1;">
              <div style="font-weight:600;">${escapeHtml(eq.description || eq.modelNumber || 'Unknown')}</div>
              <div style="font-size:12px;color:var(--text-secondary);">${escapeHtml(eq.manufacturer)} ${escapeHtml(eq.modelNumber)} · S/N: ${escapeHtml(eq.serialNumber)}</div>
            </div>
            <div style="text-align:right;">
              <div style="font-weight:600;color:var(--accent);">${formatCurrency(perJob)}/job</div>
              <div style="font-size:12px;color:var(--text-secondary);">ROI: ${roi}%</div>
            </div>
          </div>`;
        }).join('')}
      </div>
    </div>
  `;
  document.body.appendChild(modal);
  modal.addEventListener('click', (e) => { if (e.target === modal) modal.remove(); });
}

function addEquipmentToEstimate(eqId) {
  const eq = getDocuments('equipment').find(e => e.id === eqId);
  if (!eq) return;
  const cost = eq.purchaseCost || 0;
  const life = eq.usefulLifeYears || 7;
  const maint = eq.annualMaintenanceCost || 0;
  const roi = eq.targetRoiPercent || 15;
  const jobsYr = eq.estimatedJobsPerYear || 50;
  const totalCost = cost + (maint * life);
  const targetRev = totalCost * (1 + roi / 100);
  const perJob = targetRev / life / jobsYr;

  window._estLineItems.push({
    id: generateId(),
    category: 'equipment',
    description: `${eq.description || eq.modelNumber} (S/N: ${eq.serialNumber}) — Cost Recovery`,
    quantity: 1,
    unit: 'Each',
    unitCost: Math.round(perJob * 100) / 100,
    markupPercent: 0,
    equipmentId: eq.id,
  });
  renderEstLineItems();
  recalcEstimate();
  showToast(`Added ${eq.description || eq.modelNumber} at ${formatCurrency(perJob)}/job`);
}


// ============================================================
// CUSTOMER MANAGEMENT / CRM
// ============================================================
function getCustomers() {
  const data = localStorage.getItem('psva_customers');
  return data ? JSON.parse(data) : [];
}

function saveCustomers(customers) {
  localStorage.setItem('psva_customers', JSON.stringify(customers));
}

function saveCustomer(customer) {
  const customers = getCustomers();
  const idx = customers.findIndex(c => c.id === customer.id);
  if (idx >= 0) customers[idx] = customer;
  else customers.push(customer);
  saveCustomers(customers);
}

function getDefaultCustomer() {
  return {
    id: generateId(),
    name: '',
    company: '',
    phone: '',
    email: '',
    address: '',
    notes: '',
    createdAt: new Date().toISOString(),
  };
}


// ============================================================
// CONTACT CSV IMPORT / EXPORT
// ============================================================

// CSV helper: properly escape a field for CSV output
function csvEscapeField(val) {
  const s = String(val || '').replace(/\r\n/g, '\n');
  if (s.includes(',') || s.includes('"') || s.includes('\n')) {
    return '"' + s.replace(/"/g, '""') + '"';
  }
  return s;
}

// CSV helper: parse a CSV string into rows of arrays
function parseCSV(text) {
  const rows = [];
  let current = [];
  let field = '';
  let inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const ch = text[i];
    if (inQuotes) {
      if (ch === '"') {
        if (i + 1 < text.length && text[i + 1] === '"') {
          field += '"';
          i++;
        } else {
          inQuotes = false;
        }
      } else {
        field += ch;
      }
    } else {
      if (ch === '"') {
        inQuotes = true;
      } else if (ch === ',') {
        current.push(field);
        field = '';
      } else if (ch === '\n' || ch === '\r') {
        if (ch === '\r' && i + 1 < text.length && text[i + 1] === '\n') i++;
        current.push(field);
        field = '';
        if (current.length > 1 || current[0] !== '') rows.push(current);
        current = [];
      } else {
        field += ch;
      }
    }
  }
  current.push(field);
  if (current.length > 1 || current[0] !== '') rows.push(current);
  return rows;
}

// Export customers to CSV file download
function exportContactsCSV() {
  const customers = getCustomers();
  if (customers.length === 0) {
    showToast('No customers to export.', 'error');
    return;
  }
  const header = ['Company', 'Contact Name', 'Phone', 'Email', 'Address', 'Notes'];
  let csv = header.join(',') + '\n';
  customers.forEach(c => {
    csv += [
      csvEscapeField(c.company),
      csvEscapeField(c.name),
      csvEscapeField(c.phone),
      csvEscapeField(c.email),
      csvEscapeField(c.address),
      csvEscapeField(c.notes)
    ].join(',') + '\n';
  });
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'PS-VA_Contacts_' + new Date().toISOString().slice(0, 10) + '.csv';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
  showToast(customers.length + ' contacts exported to CSV.', 'success');
}

// Download a blank CSV template for importing contacts
function downloadCSVTemplate() {
  const header = 'Company,Contact Name,Phone,Email,Address,Notes';
  const example1 = 'Acme Corp,John Smith,(555) 123-4567,john@acme.com,123 Main St,Preferred vendor';
  const example2 = 'Beta Industries,Jane Doe,(555) 987-6543,jane@beta.com,456 Oak Ave,Net 30 terms';
  const csv = header + '\n' + example1 + '\n' + example2 + '\n';
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'PS-VA_Customer_Import_Template.csv';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
  showToast('CSV template downloaded. Fill it in and use Import CSV to load your contacts.', 'success');
}

// Clear all contacts with safety prompts
function clearAllContacts() {
  const customers = getCustomers();
  if (customers.length === 0) {
    showToast('No contacts to clear.', 'error');
    return;
  }
  _openClearAllModal(customers.length);
}

function _openClearAllModal(count) {
  const overlay = document.createElement('div');
  overlay.id = 'clear-all-modal-overlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;z-index:9999;';

  const modal = document.createElement('div');
  modal.style.cssText = 'background:var(--bg-secondary);border:1px solid var(--border);border-radius:12px;padding:24px;width:420px;max-width:90vw;color:var(--text-primary);box-shadow:0 8px 32px var(--shadow);';

  modal.innerHTML = `
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">
      <h2 style="margin:0;font-size:1.2em;color:#ff6b6b;">⚠️ Clear All Contacts</h2>
      <button onclick="document.getElementById('clear-all-modal-overlay').remove();" style="background:none;border:none;font-size:22px;cursor:pointer;color:var(--text-secondary);padding:4px 8px;">&times;</button>
    </div>
    <div style="display:flex;flex-direction:column;gap:14px;">
      <p style="margin:0;font-size:0.95em;color:var(--text-secondary);line-height:1.5;">
        This will permanently delete all <strong style="color:var(--text-primary,#eee);">${count}</strong> contacts. This action cannot be undone.
      </p>
      <div style="padding:10px 12px;border-radius:6px;background:rgba(255,107,107,0.1);border:1px solid rgba(255,107,107,0.25);">
        <label style="display:flex;align-items:center;gap:8px;cursor:pointer;font-size:0.9em;">
          <input type="checkbox" id="clear-all-export-check" checked style="width:16px;height:16px;accent-color:var(--accent,#c0392b);cursor:pointer;" />
          <span>Export contacts to CSV before deleting</span>
        </label>
      </div>
      <div>
        <label style="display:block;font-size:0.85em;color:var(--text-secondary);margin-bottom:4px;">Type <strong style="color:#ff6b6b;">DELETE</strong> to confirm</label>
        <input id="clear-all-confirm-input" type="text" placeholder="Type DELETE here" autocomplete="off" style="width:100%;padding:8px 10px;border-radius:6px;border:1px solid var(--border);background:var(--bg-input);color:var(--text-primary);font-size:0.95em;box-sizing:border-box;" />
      </div>
      <div style="display:flex;gap:10px;justify-content:flex-end;margin-top:4px;">
        <button onclick="document.getElementById('clear-all-modal-overlay').remove();" class="btn btn-secondary">Cancel</button>
        <button onclick="_executeClearAll();" class="btn btn-danger" id="clear-all-confirm-btn">Delete All Contacts</button>
      </div>
    </div>
  `;

  overlay.appendChild(modal);
  overlay.addEventListener('click', function(e) { if (e.target === overlay) overlay.remove(); });
  document.body.appendChild(overlay);

  // Focus the input and enable Enter key to submit
  const inp = document.getElementById('clear-all-confirm-input');
  setTimeout(function() { inp.focus(); }, 100);
  inp.addEventListener('keydown', function(e) {
    if (e.key === 'Enter') _executeClearAll();
  });
}

function _executeClearAll() {
  const inp = document.getElementById('clear-all-confirm-input');
  if (!inp || inp.value.trim() !== 'DELETE') {
    showToast('You must type exactly "DELETE" to confirm.', 'error');
    inp && inp.focus();
    return;
  }
  // Export first if checkbox is checked
  const exportCheck = document.getElementById('clear-all-export-check');
  if (exportCheck && exportCheck.checked) {
    exportContactsCSV();
  }
  const count = getCustomers().length;
  saveCustomers([]);
  document.getElementById('clear-all-modal-overlay').remove();
  renderCustomersList();
  showToast('All ' + count + ' contacts have been deleted.', 'success');
}

// Import customers from a CSV file
function importContactsCSV() {
  const input = document.createElement('input');
  input.type = 'file';
  input.accept = '.csv';
  input.onchange = function(e) {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = function(ev) {
      try {
        const text = ev.target.result;
        const rows = parseCSV(text);
        if (rows.length < 2) {
          showToast('CSV file is empty or has no data rows.', 'error');
          return;
        }
        // Parse header to find column indices
        const header = rows[0].map(h => h.trim().toLowerCase());
        const colMap = {
          company: header.findIndex(h => h.includes('company') || h.includes('organization')),
          name: header.findIndex(h => h.includes('contact') || h.includes('name')),
          phone: header.findIndex(h => h.includes('phone') || h.includes('tel')),
          email: header.findIndex(h => h.includes('email') || h.includes('e-mail')),
          address: header.findIndex(h => h.includes('address') || h.includes('location')),
          notes: header.findIndex(h => h.includes('note') || h.includes('comment') || h.includes('title'))
        };
        // At minimum need company or name
        if (colMap.company < 0 && colMap.name < 0) {
          showToast('CSV must have a "Company" or "Contact Name" column header.', 'error');
          return;
        }
        const existing = getCustomers();
        const existingKeys = new Set();
        existing.forEach(c => {
          const key = ((c.company || '') + '|' + (c.name || '')).toLowerCase().trim();
          existingKeys.add(key);
          if (c.email) existingKeys.add(c.email.toLowerCase().trim());
        });
        let imported = 0;
        let skipped = 0;
        for (let i = 1; i < rows.length; i++) {
          const row = rows[i];
          const company = (colMap.company >= 0 && row[colMap.company]) ? row[colMap.company].trim() : '';
          const name = (colMap.name >= 0 && row[colMap.name]) ? row[colMap.name].trim() : '';
          const phone = (colMap.phone >= 0 && row[colMap.phone]) ? row[colMap.phone].trim() : '';
          const email = (colMap.email >= 0 && row[colMap.email]) ? row[colMap.email].trim() : '';
          const address = (colMap.address >= 0 && row[colMap.address]) ? row[colMap.address].trim() : '';
          const notes = (colMap.notes >= 0 && row[colMap.notes]) ? row[colMap.notes].trim() : '';
          if (!company && !name) continue; // skip blank rows
          const key = (company + '|' + name).toLowerCase().trim();
          const emailKey = email.toLowerCase().trim();
          if (existingKeys.has(key) || (emailKey && existingKeys.has(emailKey))) {
            // Merge missing info
            const existIdx = existing.findIndex(c => {
              const ck = ((c.company || '') + '|' + (c.name || '')).toLowerCase().trim();
              const ce = (c.email || '').toLowerCase().trim();
              return ck === key || (emailKey && ce === emailKey);
            });
            if (existIdx >= 0) {
              const ex = existing[existIdx];
              if (!ex.phone && phone) ex.phone = phone;
              if (!ex.email && email) ex.email = email;
              if (!ex.address && address) ex.address = address;
              if (notes && !ex.notes) ex.notes = notes;
              else if (notes && ex.notes && !ex.notes.includes(notes.substring(0, 50))) {
                ex.notes = ex.notes + '\n---\n' + notes;
              }
            }
            skipped++;
          } else {
            existing.push({
              id: generateId(),
              company: company,
              name: name,
              phone: phone,
              email: email,
              address: address,
              notes: notes,
              createdAt: new Date().toISOString().slice(0, 10),
            });
            existingKeys.add(key);
            if (emailKey) existingKeys.add(emailKey);
            imported++;
          }
        }
        saveCustomers(existing);
        showToast(imported + ' contacts imported, ' + skipped + ' duplicates merged.', 'success');
        renderCustomersList();
      } catch (err) {
        showToast('Error reading CSV: ' + err.message, 'error');
      }
    };
    reader.readAsText(file);
  };
  input.click();
}

function clearImportedContacts() {
  if (!confirm('This will remove ALL customers. Are you sure?')) return;
  if (!confirm('This cannot be undone. Confirm deletion of all customers?')) return;
  saveCustomers([]);
  showToast('All customers cleared.', 'success');
  renderCustomersList();
}

function renderCustomersList() {
  const main = document.querySelector('.main-content');
  const customers = getCustomers();
  const jobs = getJobs();

  // Auto-populate customers from jobs if empty
  if (customers.length === 0 && jobs.length > 0) {
    const seen = new Set();
    jobs.forEach(j => {
      const key = (j.customer.company || j.customer.name || '').toLowerCase().trim();
      if (key && !seen.has(key)) {
        seen.add(key);
        const c = getDefaultCustomer();
        c.name = j.customer.name;
        c.company = j.customer.company;
        c.phone = j.customer.phone;
        c.email = j.customer.email;
        c.address = j.customer.address;
        customers.push(c);
      }
    });
    if (customers.length > 0) saveCustomers(customers);
  }

  main.innerHTML = `
    <div class="page-header">
      <h1>Customers <span style="font-size:0.5em;font-weight:400;opacity:0.6;vertical-align:middle;">(${customers.length} contact${customers.length !== 1 ? 's' : ''})</span></h1>
      <div class="page-header-actions" style="flex-wrap:wrap;gap:6px;">
        <button class="btn btn-secondary" onclick="importContactsCSV()" title="Import contacts from a CSV file">📥 Import CSV</button>
        <button class="btn btn-secondary" onclick="exportContactsCSV()" title="Export all contacts to a CSV file">📤 Export CSV</button>
        <button class="btn btn-secondary" onclick="downloadCSVTemplate()" title="Download a blank CSV template for importing contacts">📋 CSV Template</button>
        ${customers.length > 0 ? '<button class="btn btn-danger" onclick="clearAllContacts()" title="Delete all contacts">🗑 Clear All</button>' : ''}
        <button class="btn btn-primary" onclick="createNewCustomer()">+ New Customer</button>
      </div>
    </div>
    ${customers.length === 0 ? '<p class="intro-text">No customers yet. Add your first customer or they will be auto-imported from jobs.</p>' : ''}
    <div class="table-scroll">
      <table class="data-table">
        <thead><tr>
          <th>Company</th><th>Contact</th><th>Phone</th><th>Email</th><th>Jobs</th><th>Revenue</th><th></th>
        </tr></thead>
        <tbody>
          ${customers.map(c => {
            const custJobs = jobs.filter(j => {
              const jKey = (j.customer.company || j.customer.name || '').toLowerCase().trim();
              const cKey = (c.company || c.name || '').toLowerCase().trim();
              return jKey === cKey;
            });
            const totalRev = custJobs.reduce((s, j) => {
              const ests = getEstimates().filter(e => e.jobId === j.id);
              return s + ests.reduce((ss, e) => ss + (e.totalCustomerPrice || 0), 0);
            }, 0);
            return `
            <tr onclick="editCustomer('${c.id}')" style="cursor:pointer;">
              <td><strong>${escapeHtml(c.company || '—')}</strong></td>
              <td>${escapeHtml(c.name)}</td>
              <td>${escapeHtml(c.phone)}</td>
              <td>${escapeHtml(c.email)}</td>
              <td>${custJobs.length}</td>
              <td>${formatCurrency(totalRev)}</td>
              <td><button class="delete-btn" onclick="event.stopPropagation(); deleteCustomer('${c.id}','${escapeHtml(c.company || c.name)}')" title="Delete">✕</button></td>
            </tr>`;
          }).join('')}
        </tbody>
      </table>
    </div>
  `;
}

function createNewCustomer() {
  editingDocId = null;
  renderCustomerEditor(getDefaultCustomer());
}

function editCustomer(id) {
  const c = getCustomers().find(x => x.id === id);
  if (!c) return;
  editingDocId = id;
  renderCustomerEditor(c);
}

function renderCustomerEditor(customer) {
  window._currentCustomer = customer;
  const main = document.querySelector('.main-content');
  const jobs = getJobs();
  const custJobs = jobs.filter(j => {
    const jKey = (j.customer.company || j.customer.name || '').toLowerCase().trim();
    const cKey = (customer.company || customer.name || '').toLowerCase().trim();
    return cKey && jKey === cKey;
  });

  main.innerHTML = `
    <div class="page-header">
      <div style="display:flex;align-items:center;gap:12px;">
        <button class="btn-icon" onclick="_rememberCustNotesHeight(); editingDocId=null; showPage('customers')" title="Back">←</button>
        <h1>${editingDocId ? 'Edit' : 'New'} Customer</h1>
      </div>
      <div class="page-header-actions">
        ${editingDocId ? '<button class="btn btn-danger" onclick="deleteCustomerFromEditor()" title="Delete this customer">Delete Customer</button>' : ''}
        <button class="btn btn-secondary" onclick="saveCurrentCustomer()">Save Customer</button>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Customer Information</div>
      <div class="form-grid">
        <div class="form-group"><label class="form-label">Company Name</label><input class="form-input" id="cust-company" value="${escapeHtml(customer.company)}"></div>
        <div class="form-group"><label class="form-label">Contact Name</label><input class="form-input" id="cust-name" value="${escapeHtml(customer.name)}"></div>
        <div class="form-group"><label class="form-label">Phone</label><input class="form-input" id="cust-phone" value="${escapeHtml(customer.phone)}"></div>
        <div class="form-group"><label class="form-label">Email</label><input class="form-input" id="cust-email" value="${escapeHtml(customer.email)}"></div>
        <div class="form-group full-width"><label class="form-label">Address</label><input class="form-input" id="cust-address" value="${escapeHtml(customer.address)}"></div>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>General Notes</div>
      <textarea class="form-textarea" id="cust-notes" rows="3" style="min-height:${window._custNotesHeight || 80}px;height:${window._custNotesHeight || 80}px;resize:vertical;">${escapeHtml(customer.notes || '')}</textarea>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Job History (${custJobs.length} jobs)</div>
      ${custJobs.length === 0 ? '<p class="intro-text">No jobs linked to this customer yet.</p>' :
        custJobs.map(j => {
          const jobNotes = j.notes || '';
          return `
          <div style="border:1px solid var(--border);border-radius:8px;padding:12px;margin-bottom:8px;">
            <div style="display:flex;justify-content:space-between;align-items:center;">
              <div>
                <strong style="cursor:pointer;color:var(--accent);" onclick="openJobDashboard('${j.id}')">${escapeHtml(j.jobNumber)} — ${escapeHtml(j.name || 'Untitled')}</strong>
                <div style="font-size:12px;color:var(--text-secondary);margin-top:2px;">${formatDateShort(j.startDate)} ${j.endDate ? '→ ' + formatDateShort(j.endDate) : ''} · ${getStatusBadge(j.status)}</div>
              </div>
            </div>
            ${jobNotes ? '<div style="margin-top:8px;padding:8px;background:var(--bg-secondary);border-radius:6px;font-size:13px;white-space:pre-wrap;">' + escapeHtml(jobNotes) + '</div>' : ''}
          </div>`;
        }).join('')
      }
    </div>
  `;
}

function saveCurrentCustomer() {
  _rememberCustNotesHeight();
  const c = window._currentCustomer;
  c.company = document.getElementById('cust-company').value;
  c.name = document.getElementById('cust-name').value;
  c.phone = document.getElementById('cust-phone').value;
  c.email = document.getElementById('cust-email').value;
  c.address = document.getElementById('cust-address').value;
  c.notes = document.getElementById('cust-notes').value;
  saveCustomer(c);
  editingDocId = c.id;
  showToast('Customer saved!');
}

// Remember the notes textarea height when navigating away
function _rememberCustNotesHeight() {
  const ta = document.getElementById('cust-notes');
  if (ta) {
    window._custNotesHeight = ta.offsetHeight;
    try { localStorage.setItem('psva_custNotesHeight', ta.offsetHeight); } catch(e) {}
  }
}

// Restore saved height on load
try {
  const savedH = localStorage.getItem('psva_custNotesHeight');
  if (savedH && parseInt(savedH) > 60) window._custNotesHeight = parseInt(savedH);
} catch(e) {}

function deleteCustomerFromEditor() {
  const c = window._currentCustomer;
  if (!c || !c.id) return;
  const label = c.company || c.name || 'this customer';
  if (!confirm('Delete customer "' + label + '"? This cannot be undone.')) return;
  const customers = getCustomers().filter(x => x.id !== c.id);
  saveCustomers(customers);
  showToast('Customer deleted');
  showPage('customers');
}

function deleteCustomer(id, name) {
  if (!confirm('Delete customer "' + name + '"?')) return;
  const customers = getCustomers().filter(c => c.id !== id);
  saveCustomers(customers);
  renderCustomersList();
  showToast('Customer deleted');
}


// ============================================================
// TECHNICIAN CERTIFICATIONS & TRAINING TRACKER
// ============================================================
function getTechnicians() {
  const data = localStorage.getItem('psva_technicians');
  return data ? JSON.parse(data) : [];
}

function saveTechnicians(techs) {
  localStorage.setItem('psva_technicians', JSON.stringify(techs));
}

function saveTechnician(tech) {
  const techs = getTechnicians();
  const idx = techs.findIndex(t => t.id === tech.id);
  if (idx >= 0) techs[idx] = tech;
  else techs.push(tech);
  saveTechnicians(techs);
}

function getDefaultTechnician() {
  return {
    id: generateId(),
    name: '',
    title: '',
    phone: '',
    email: '',
    hireDate: '',
    certifications: [],
    notes: '',
  };
}

function getDefaultCertification() {
  return {
    id: generateId(),
    name: '',
    issuingBody: '',
    certNumber: '',
    issueDate: '',
    expirationDate: '',
    documentData: '', // base64 of uploaded doc
    documentName: '',
  };
}

function getCertStatus(cert) {
  if (!cert.expirationDate) return { status: 'no-expiry', label: 'No Expiry', color: '#6B7280' };
  const today = new Date();
  const exp = new Date(cert.expirationDate + 'T00:00:00');
  const daysUntil = Math.ceil((exp - today) / (1000 * 60 * 60 * 24));
  if (daysUntil < 0) return { status: 'expired', label: 'EXPIRED', color: '#DC2626' };
  if (daysUntil <= 90) return { status: 'expiring-soon', label: `Expires in ${daysUntil}d`, color: '#F59E0B' };
  return { status: 'active', label: 'Active', color: '#22C55E' };
}

function renderTechniciansList() {
  const main = document.querySelector('.main-content');
  const techs = getTechnicians();

  const allCerts = techs.flatMap(t => (t.certifications || []).map(c => ({...c, techName: t.name})));
  const expiredCount = allCerts.filter(c => getCertStatus(c).status === 'expired').length;
  const expiringCount = allCerts.filter(c => getCertStatus(c).status === 'expiring-soon').length;

  main.innerHTML = `
    <div class="page-header">
      <h1>Technicians & Certifications</h1>
      <div class="page-header-actions">
        <button class="btn btn-secondary" onclick="exportCompliancePackagePDF()">Export Compliance Package</button>
        <button class="btn btn-primary" onclick="createNewTechnician()">+ New Technician</button>
      </div>
    </div>
    ${(expiredCount > 0 || expiringCount > 0) ? `
    <div class="alert-banner" style="display:flex;gap:16px;padding:12px 16px;background:${expiredCount > 0 ? '#DC262615' : '#F59E0B15'};border:1px solid ${expiredCount > 0 ? '#DC262640' : '#F59E0B40'};border-radius:8px;margin-bottom:16px;">
      ${expiredCount > 0 ? '<span style="color:#DC2626;font-weight:600;">⚠ ' + expiredCount + ' expired certification' + (expiredCount !== 1 ? 's' : '') + '</span>' : ''}
      ${expiringCount > 0 ? '<span style="color:#F59E0B;font-weight:600;">⏰ ' + expiringCount + ' expiring within 90 days</span>' : ''}
    </div>` : ''}
    <div class="page-header" style="margin-bottom:12px;">
      <div style="display:flex;gap:8px;">
        <select class="form-select" id="cert-filter" onchange="filterTechView()" style="width:auto;">
          <option value="all">All Technicians</option>
          <option value="expiring">Expiring Soon (90 days)</option>
          <option value="expired">Expired Only</option>
          <option value="active">Active/Compliant Only</option>
        </select>
      </div>
    </div>
    <div id="tech-list-body">
      ${renderTechCards(techs, 'all')}
    </div>
  `;
}

function renderTechCards(techs, filter) {
  return techs.map(t => {
    const certs = t.certifications || [];
    const certStatuses = certs.map(c => getCertStatus(c));
    const hasExpired = certStatuses.some(s => s.status === 'expired');
    const hasExpiring = certStatuses.some(s => s.status === 'expiring-soon');

    if (filter === 'expired' && !hasExpired) return '';
    if (filter === 'expiring' && !hasExpiring && !hasExpired) return '';
    if (filter === 'active' && (hasExpired || hasExpiring)) return '';

    return `
    <div class="card" style="cursor:pointer;" onclick="editTechnician('${t.id}')">
      <div class="card-title">
        <div class="accent-bar"></div>
        <div>
          <div>${escapeHtml(t.name || 'Unnamed')}</div>
          <div style="font-size:12px;color:var(--text-secondary);font-weight:400;">${escapeHtml(t.title || '')}</div>
        </div>
        <div style="margin-left:auto;display:flex;gap:6px;">
          ${hasExpired ? '<span class="status-badge" style="background:#DC262620;color:#DC2626;">EXPIRED</span>' : ''}
          ${hasExpiring ? '<span class="status-badge" style="background:#F59E0B20;color:#F59E0B;">EXPIRING</span>' : ''}
          ${!hasExpired && !hasExpiring && certs.length > 0 ? '<span class="status-badge" style="background:#22C55E20;color:#22C55E;">COMPLIANT</span>' : ''}
        </div>
      </div>
      ${certs.length > 0 ? `
      <div class="mini-table" style="margin-top:8px;">
        ${certs.map(c => {
          const st = getCertStatus(c);
          return `
          <div class="mini-row" style="padding:6px 0;">
            <span class="mini-primary">${escapeHtml(c.name)}</span>
            <span class="mini-secondary">${escapeHtml(c.issuingBody)} ${c.expirationDate ? '· Exp: ' + formatDateShort(c.expirationDate) : ''}</span>
            <span class="status-badge" style="background:${st.color}20;color:${st.color};font-size:11px;">${st.label}</span>
          </div>`;
        }).join('')}
      </div>` : '<p class="intro-text" style="margin-top:8px;">No certifications added yet.</p>'}
    </div>`;
  }).join('');
}

function filterTechView() {
  const filter = document.getElementById('cert-filter')?.value || 'all';
  const body = document.getElementById('tech-list-body');
  if (body) body.innerHTML = renderTechCards(getTechnicians(), filter);
}

function createNewTechnician() {
  editingDocId = null;
  renderTechnicianEditor(getDefaultTechnician());
}

function editTechnician(id) {
  const t = getTechnicians().find(x => x.id === id);
  if (!t) return;
  editingDocId = id;
  renderTechnicianEditor(t);
}

function renderTechnicianEditor(tech) {
  window._currentTechnician = tech;
  window._techCerts = (tech.certifications || []).map(c => ({...c}));
  const main = document.querySelector('.main-content');

  main.innerHTML = `
    <div class="page-header">
      <div style="display:flex;align-items:center;gap:12px;">
        <button class="btn-icon" onclick="showPage('technicians')" title="Back">←</button>
        <h1>${editingDocId ? 'Edit' : 'New'} Technician</h1>
      </div>
      <div class="page-header-actions">
        <button class="btn btn-secondary" onclick="saveCurrentTechnician()">Save</button>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Technician Information</div>
      <div class="form-grid">
        <div class="form-group"><label class="form-label">Full Name</label><input class="form-input" id="tech-name" value="${escapeHtml(tech.name)}"></div>
        <div class="form-group"><label class="form-label">Title / Role</label><input class="form-input" id="tech-title" value="${escapeHtml(tech.title)}"></div>
        <div class="form-group"><label class="form-label">Phone</label><input class="form-input" id="tech-phone" value="${escapeHtml(tech.phone)}"></div>
        <div class="form-group"><label class="form-label">Email</label><input class="form-input" id="tech-email" value="${escapeHtml(tech.email)}"></div>
        <div class="form-group"><label class="form-label">Hire Date</label><input class="form-input" type="date" id="tech-hireDate" value="${tech.hireDate}"></div>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Certifications & Training
        <button class="btn btn-sm btn-primary" style="margin-left:auto;" onclick="addTechCert()">+ Add Certification</button>
      </div>
      <div id="tech-certs-list"></div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Notes</div>
      <textarea class="form-textarea" id="tech-notes" rows="3">${escapeHtml(tech.notes || '')}</textarea>
    </div>
  `;
  renderTechCerts();
}

function renderTechCerts() {
  const container = document.getElementById('tech-certs-list');
  if (!container) return;
  if (window._techCerts.length === 0) {
    container.innerHTML = '<p class="intro-text">No certifications added. Click "+ Add Certification" above.</p>';
    return;
  }
  container.innerHTML = window._techCerts.map((c, idx) => {
    const st = getCertStatus(c);
    return `
    <div style="border:1px solid var(--border);border-radius:8px;padding:12px;margin-bottom:8px;">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">
        <span class="status-badge" style="background:${st.color}20;color:${st.color};">${st.label}</span>
        <button class="delete-btn" onclick="removeTechCert(${idx})" title="Remove">✕</button>
      </div>
      <div class="form-grid">
        <div class="form-group"><label class="form-label">Certification Name</label><input class="form-input" value="${escapeHtml(c.name)}" onchange="window._techCerts[${idx}].name=this.value;"></div>
        <div class="form-group"><label class="form-label">Issuing Body</label><input class="form-input" value="${escapeHtml(c.issuingBody)}" onchange="window._techCerts[${idx}].issuingBody=this.value;"></div>
        <div class="form-group"><label class="form-label">Cert/License Number</label><input class="form-input" value="${escapeHtml(c.certNumber)}" onchange="window._techCerts[${idx}].certNumber=this.value;"></div>
        <div class="form-group"><label class="form-label">Issue Date</label><input class="form-input" type="date" value="${c.issueDate}" onchange="window._techCerts[${idx}].issueDate=this.value;"></div>
        <div class="form-group"><label class="form-label">Expiration Date</label><input class="form-input" type="date" value="${c.expirationDate}" onchange="window._techCerts[${idx}].expirationDate=this.value; renderTechCerts();"></div>
        <div class="form-group"><label class="form-label">Document</label>
          ${c.documentName ? `<div style="font-size:13px;margin-bottom:4px;">📄 ${escapeHtml(c.documentName)} <button class="btn btn-sm btn-secondary" onclick="removeCertDoc(${idx})">Remove</button></div>` : ''}
          <input type="file" accept=".pdf,.jpg,.jpeg,.png,.doc,.docx" onchange="uploadCertDoc(${idx}, this)" style="font-size:13px;">
        </div>
      </div>
    </div>`;
  }).join('');
}

function addTechCert() {
  window._techCerts.push(getDefaultCertification());
  renderTechCerts();
}

function removeTechCert(idx) {
  window._techCerts.splice(idx, 1);
  renderTechCerts();
}

function uploadCertDoc(idx, input) {
  const file = input.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = (e) => {
    window._techCerts[idx].documentData = e.target.result;
    window._techCerts[idx].documentName = file.name;
    renderTechCerts();
  };
  reader.readAsDataURL(file);
}

function removeCertDoc(idx) {
  window._techCerts[idx].documentData = '';
  window._techCerts[idx].documentName = '';
  renderTechCerts();
}

function saveCurrentTechnician() {
  const t = window._currentTechnician;
  t.name = document.getElementById('tech-name').value;
  t.title = document.getElementById('tech-title').value;
  t.phone = document.getElementById('tech-phone').value;
  t.email = document.getElementById('tech-email').value;
  t.hireDate = document.getElementById('tech-hireDate').value;
  t.certifications = window._techCerts;
  t.notes = document.getElementById('tech-notes').value;
  saveTechnician(t);
  editingDocId = t.id;
  showToast('Technician saved!');
}

function exportCompliancePackagePDF() {
  const techs = getTechnicians();
  const activeCerts = [];
  techs.forEach(t => {
    (t.certifications || []).forEach(c => {
      const st = getCertStatus(c);
      if (st.status !== 'expired') {
        activeCerts.push({ ...c, techName: t.name, techTitle: t.title, status: st });
      }
    });
  });

  if (activeCerts.length === 0) {
    showToast('No active certifications to export.', 'error');
    return;
  }

  const { jsPDF } = window.jspdf;
  const doc = new jsPDF('p', 'mm', 'letter');
  const pageWidth = doc.internal.pageSize.getWidth();
  const company = getCompany();
  const theme = getPdfTheme();

  let y = pdfAddHeader(doc, theme, company, 'COMPLIANCE PACKAGE', 'Active Certifications', pageWidth);
  y += 5;

  doc.setFontSize(10);
  doc.setTextColor(...hexToRgb(colors.textSecondary));
  doc.text('Generated: ' + new Date().toLocaleDateString(), 15, y);
  doc.text('Total Active Certifications: ' + activeCerts.length, pageWidth - 15, y, { align: 'right' });
  y += 8;

  // Table header
  const cols = [15, 55, 85, 115, 145, pageWidth - 15];
  doc.setFillColor(...hexToRgb(colors.accent));
  doc.rect(15, y, pageWidth - 30, 8, 'F');
  doc.setFontSize(8);
  doc.setTextColor(...(isLightColor(colors.accent) ? [30, 30, 30] : [255, 255, 255]));
  doc.text('Technician', 17, y + 5.5);
  doc.text('Certification', 57, y + 5.5);
  doc.text('Issuing Body', 87, y + 5.5);
  doc.text('Cert #', 117, y + 5.5);
  doc.text('Expiration', 147, y + 5.5);
  doc.text('Status', pageWidth - 17, y + 5.5, { align: 'right' });
  y += 10;

  doc.setTextColor(...hexToRgb(colors.text));
  activeCerts.forEach((c, i) => {
    if (y > 250) {
      pdfDrawFooter(doc, theme, company);
      doc.addPage();
      doc.setFillColor(...hexToRgb(colors.bg));
      doc.rect(0, 0, pageWidth, pageHeight, 'F');
      y = 20;
    }
    if (i % 2 === 0) {
      doc.setFillColor(...hexToRgb(colors.tableAlt));
      doc.rect(15, y - 3, pageWidth - 30, 7, 'F');
    }
    doc.setFontSize(8);
    doc.setTextColor(...hexToRgb(colors.text));
    doc.text(c.techName.substring(0, 20), 17, y + 1);
    doc.text(c.name.substring(0, 15), 57, y + 1);
    doc.text((c.issuingBody || '').substring(0, 15), 87, y + 1);
    doc.text((c.certNumber || '').substring(0, 15), 117, y + 1);
    doc.text(c.expirationDate ? formatDateShort(c.expirationDate) : 'No Expiry', 147, y + 1);
    const stColor = c.status.status === 'expiring-soon' ? (pdfDarkMode ? [245, 158, 11] : [180, 110, 0]) : (pdfDarkMode ? [34, 197, 94] : [22, 163, 74]);
    doc.setTextColor(stColor[0], stColor[1], stColor[2]);
    doc.text(c.status.label, pageWidth - 17, y + 1, { align: 'right' });
    doc.setTextColor(...hexToRgb(colors.text));
    y += 7;
  });

  pdfDrawFooter(doc, theme, company);

  doc.save('Compliance-Package-' + new Date().toISOString().split('T')[0] + '.pdf');
  showToast('Compliance package exported!');
}


