let calendarDate = new Date();


// ============================================================
// CUSTOM CALENDAR EVENTS

// ============================================================
// RATE SHEET & COMPANY RATES
// ============================================================
function getDefaultRateSheet() {
  return {
    year: new Date().getFullYear(),
    laborRates: [
      { id: 'straight', name: 'Straight Time', description: 'Regular hours (Mon-Fri, 8 am - 5 pm) for scheduled labor', rate: 150, unit: 'hr', multiplier: 1 },
      { id: 'overtime', name: 'Overtime', description: 'After 8 hrs/day or outside straight time hours for scheduled labor', rate: 225, unit: 'hr', multiplier: 1.5 },
      { id: 'doubletime', name: 'Double Time', description: 'After 12hrs/day and Sundays', rate: 300, unit: 'hr', multiplier: 2 },
      { id: 'holiday', name: 'Major Company Holidays (non-emergency)', description: 'All observed major company holidays', rate: 375, unit: 'hr', multiplier: 2.5 },
      { id: 'emergency', name: 'Emergency Callout (All hours)', description: 'Emergency Services for days, nights, weekends, holidays; billed at a 4-hour minimum', rate: 350, unit: 'hr', multiplier: 2.333, dualRate: true, multiplier2: 3, rate2: 450, dualRateThresholdHrs: 2, dualRateLabel1: 'First 2 hrs', dualRateLabel2: 'After 2 hrs' },
      { id: 'portal', name: 'Portal-to-Portal (Emergency)', description: 'Time starts when a technician is dispatched for emergency services', rate: 0, unit: 'hr', multiplier: 0, note: 'See Emergency Callout for specific pricing' },
      { id: 'travel', name: 'Travel After First 30 min (non-emergency)', description: 'Travel time commences after the first 30 min. from closest office', rate: 150, unit: 'hr', multiplier: 1 },
      { id: 'oncall', name: 'On-call Services', description: 'On-call time will be assessed on an as needed basis for waiting time, standby time, and on-call services requested', rate: 150, unit: 'hr', multiplier: 1 },
    ],
    specialtyServices: [
      { id: 'engineering', name: 'Engineering & Commissioning Studies', rate: 300, unit: 'hr' },
      { id: 'supervision', name: 'On-Site Supervision & Reporting', rate: 150, rateMax: 225, unit: 'hr', note: '$150-225/hr (based on certification)' },
    ],
    billingTerms: [
      { id: 'net30', text: 'NET 30: Payment due within 30 days unless otherwise pre-negotiated.' },
      { id: 'tm', text: 'Time & Material: Labor billed at standard hourly labor rates; minimum 15% markup on all supplied materials.' },
      { id: 'perdiem', text: 'Per Diem: $250/day per person for overnight travel-related expenses.' },
      { id: 'minimum', text: 'Minimum Charge: All requests for field services will incur a 4-hour minimum charge per site visit at applicable hourly labor rates.' },
      { id: 'permits', text: 'Permit Fees: Permits are billed at cost with applicable time and material charges for handling.' },
      { id: 'change', text: 'All rates and terms are subject to change. Clients will be notified in advance of any adjustments.' },
    ],
    maintenanceWarranty: [
      { id: 'warranty', text: 'Warranty Clause: 30-day workmanship guarantee\u2014any requested retests will be billed as time and material.' },
      { id: 'maintenance', text: 'Annual Maintenance Contracts: Prepaid service blocks (e.g., 20 hrs.) available at 10% discount.' },
    ],
    perDiem: 250,
    materialMarkupMin: 15,
    minimumHours: 4,
    warrantyDays: 30,
    maintenanceDiscount: 10,
    updatedAt: new Date().toISOString(),
  };
}

function getRateSheet() {
  const data = localStorage.getItem('psva_rate_sheet');
  if (!data) return getDefaultRateSheet();
  let rs;
  try { rs = JSON.parse(data); } catch(e) { return getDefaultRateSheet(); }
  if (!rs || typeof rs !== 'object') return getDefaultRateSheet();
  // Ensure all required arrays/properties exist by merging from defaults
  const defaults = getDefaultRateSheet();
  if (!rs.laborRates || !Array.isArray(rs.laborRates)) rs.laborRates = defaults.laborRates;
  if (!rs.specialtyServices || !Array.isArray(rs.specialtyServices)) rs.specialtyServices = defaults.specialtyServices;
  if (!rs.billingTerms || !Array.isArray(rs.billingTerms)) rs.billingTerms = defaults.billingTerms;
  if (!rs.maintenanceWarranty || !Array.isArray(rs.maintenanceWarranty)) rs.maintenanceWarranty = defaults.maintenanceWarranty;
  if (!rs.year) rs.year = defaults.year;
  if (!rs.updatedAt) rs.updatedAt = defaults.updatedAt || new Date().toISOString();
  if (!rs.straightTimeRate && rs.straightTimeRate !== 0) rs.straightTimeRate = defaults.straightTimeRate;
  if (!rs.holidays || !Array.isArray(rs.holidays) || rs.holidays.length === 0) rs.holidays = getDefaultHolidayList(rs.year || new Date().getFullYear());
  // Migrate old string multipliers (e.g. '1.5x' or '') to numeric format
  let migrated = false;
  if (rs.laborRates) {
    // Migrate hidden emergency_after into dual-rate on emergency row
    const emergencyAfter = rs.laborRates.find(r => r.id === 'emergency_after');
    const emergency = rs.laborRates.find(r => r.id === 'emergency');
    if (emergencyAfter && emergency && !emergency.dualRate) {
      emergency.dualRate = true;
      emergency.multiplier2 = parseMultiplierValue(emergencyAfter.multiplier) || 3;
      emergency.rate2 = emergencyAfter.rate || 450;
      emergency.dualRateThresholdHrs = 2;
      emergency.dualRateLabel1 = 'First 2 hrs';
      emergency.dualRateLabel2 = 'After 2 hrs';
      rs.laborRates = rs.laborRates.filter(r => r.id !== 'emergency_after');
      migrated = true;
    }
    // Default multipliers for known rate IDs (used during migration from old format)
    const defaultMultipliers = { straight: 1, overtime: 1.5, doubletime: 2, holiday: 2.5, emergency: 2.333, travel: 1, oncall: 1, portal: 0 };
    rs.laborRates.forEach(r => {
      if (typeof r.multiplier === 'string') {
        r.multiplier = parseMultiplierValue(r.multiplier);
        migrated = true;
      }
      if (r.multiplier === undefined || r.multiplier === null) {
        r.multiplier = 0;
        migrated = true;
      }
      // Fix known rate IDs that got migrated to 0 from old format
      if (r.multiplier === 0 && defaultMultipliers[r.id] !== undefined && defaultMultipliers[r.id] > 0) {
        r.multiplier = defaultMultipliers[r.id];
        migrated = true;
      }
      // Ensure dual-rate fields exist if dualRate is true
      if (r.dualRate) {
        if (typeof r.multiplier2 === 'string') { r.multiplier2 = parseMultiplierValue(r.multiplier2); migrated = true; }
        if (r.multiplier2 === undefined || r.multiplier2 === 0) {
          // Set default multiplier2 for emergency
          if (r.id === 'emergency') { r.multiplier2 = 3; migrated = true; }
          else if (r.multiplier2 === undefined) { r.multiplier2 = 0; migrated = true; }
        }
        if (r.rate2 === undefined) { r.rate2 = 0; migrated = true; }
        if (!r.dualRateThresholdHrs) { r.dualRateThresholdHrs = 2; migrated = true; }
        if (!r.dualRateLabel1) { r.dualRateLabel1 = 'First ' + r.dualRateThresholdHrs + ' hrs'; migrated = true; }
        if (!r.dualRateLabel2) { r.dualRateLabel2 = 'After ' + r.dualRateThresholdHrs + ' hrs'; migrated = true; }
      }
    });
  }
  if (migrated) saveRateSheet(rs);
  return rs;
}

// Parse old multiplier strings like '1.5x', '2x', '' to numeric values
function parseMultiplierValue(val) {
  if (typeof val === 'number') return val;
  if (!val || val === '') return 0;
  const cleaned = String(val).replace(/[x×]/gi, '').trim();
  const num = parseFloat(cleaned);
  return isNaN(num) ? 0 : num;
}

function saveRateSheet(rs) {
  rs.updatedAt = new Date().toISOString();
  localStorage.setItem('psva_rate_sheet', JSON.stringify(rs));
}

function getLaborRate(rateId) {
  const rs = getRateSheet();
  const r = rs.laborRates.find(lr => lr.id === rateId);
  return r ? r.rate : 150;
}

// ============================================================
// COMPANY HOLIDAYS
// ============================================================
function getCompanyHolidays(year) {
  // Returns array of { date: 'YYYY-MM-DD', name: '...', multiplier: '2.5x' }
  // First check if custom holidays are stored in rate sheet
  const rs = getRateSheet();
  if (rs.holidays && rs.holidays.length > 0) {
    // Recalculate floating holiday dates for the requested year
    return rs.holidays.map(h => {
      if (h.floating) {
        const d = calcFloatingHoliday(h.floating, year);
        return { ...h, date: formatDateISO(d) };
      } else {
        // Fixed date - just update the year
        return { ...h, date: year + h.date.substring(4) };
      }
    });
  }
  // Default holidays if none stored
  return getDefaultHolidayList(year);
}

function getDefaultHolidayList(year) {
  const holidays = [];
  holidays.push({ id: 'newyear', date: year + '-01-01', name: "New Year's Day", multiplier: 2.5, fixed: true });
  
  let d = new Date(year, 0, 1);
  let mondays = 0;
  while (mondays < 3) { if (d.getDay() === 1) mondays++; if (mondays < 3) d.setDate(d.getDate() + 1); }
  holidays.push({ id: 'mlk', date: formatDateISO(d), name: 'Martin Luther King Jr. Day', multiplier: 2.5, floating: { month: 0, weekday: 1, nth: 3 } });
  
  d = new Date(year, 1, 1);
  mondays = 0;
  while (mondays < 3) { if (d.getDay() === 1) mondays++; if (mondays < 3) d.setDate(d.getDate() + 1); }
  holidays.push({ id: 'presidents', date: formatDateISO(d), name: "Presidents' Day", multiplier: 2.5, floating: { month: 1, weekday: 1, nth: 3 } });
  
  d = new Date(year, 4, 31);
  while (d.getDay() !== 1) d.setDate(d.getDate() - 1);
  holidays.push({ id: 'memorial', date: formatDateISO(d), name: 'Memorial Day', multiplier: 2.5, floating: { month: 4, weekday: 1, nth: -1 } });
  
  holidays.push({ id: 'juneteenth', date: year + '-06-19', name: 'Juneteenth', multiplier: 2.5, fixed: true });
  holidays.push({ id: 'july4', date: year + '-07-04', name: 'Independence Day', multiplier: 2.5, fixed: true });
  
  d = new Date(year, 8, 1);
  while (d.getDay() !== 1) d.setDate(d.getDate() + 1);
  holidays.push({ id: 'labor', date: formatDateISO(d), name: 'Labor Day', multiplier: 2.5, floating: { month: 8, weekday: 1, nth: 1 } });
  
  d = new Date(year, 10, 1);
  let thursdays = 0;
  while (thursdays < 4) { if (d.getDay() === 4) thursdays++; if (thursdays < 4) d.setDate(d.getDate() + 1); }
  holidays.push({ id: 'thanksgiving', date: formatDateISO(d), name: 'Thanksgiving Day', multiplier: 2.5, floating: { month: 10, weekday: 4, nth: 4 } });
  const dayAfter = new Date(d);
  dayAfter.setDate(dayAfter.getDate() + 1);
  holidays.push({ id: 'dayafterthanks', date: formatDateISO(dayAfter), name: 'Day After Thanksgiving', multiplier: 2.5, floating: { month: 10, weekday: 5, nth: 4 } });
  
  holidays.push({ id: 'xmaseve', date: year + '-12-24', name: 'Christmas Eve', multiplier: 2.5, fixed: true });
  holidays.push({ id: 'xmas', date: year + '-12-25', name: 'Christmas Day', multiplier: 2.5, fixed: true });
  holidays.push({ id: 'nyeve', date: year + '-12-31', name: "New Year's Eve", multiplier: 2.5, fixed: true });
  
  return holidays;
}

function calcFloatingHoliday(rule, year) {
  if (rule.nth === -1) {
    // Last occurrence (e.g., last Monday in May)
    const d = new Date(year, rule.month + 1, 0); // last day of month
    while (d.getDay() !== rule.weekday) d.setDate(d.getDate() - 1);
    return d;
  }
  const d = new Date(year, rule.month, 1);
  let count = 0;
  while (count < rule.nth) {
    if (d.getDay() === rule.weekday) count++;
    if (count < rule.nth) d.setDate(d.getDate() + 1);
  }
  return d;
}

function initHolidaysInRateSheet() {
  const rs = getRateSheet();
  if (!rs.holidays) {
    rs.holidays = getDefaultHolidayList(rs.year || new Date().getFullYear());
    saveRateSheet(rs);
  }
  return rs;
}

function addCompanyHoliday() {
  _openHolidayModal(null, -1);
}

function editCompanyHoliday(idx) {
  const rs = getRateSheet();
  if (!rs.holidays) return;
  const h = rs.holidays[idx];
  if (!h) return;
  _openHolidayModal(h, idx);
}

function _openHolidayModal(existing, idx) {
  const isEdit = existing !== null;
  const year = getRateSheet().year || new Date().getFullYear();
  const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const dayNames = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  const nthLabels = ['1st','2nd','3rd','4th','Last'];
  const nthValues = [1, 2, 3, 4, -1];

  // Defaults
  const defName = existing ? existing.name : '';
  const defMult = existing ? (existing.multiplier || 2.5) : 2.5;
  const defType = (existing && existing.floating) ? 'float' : 'fixed';
  const defMonth = existing ? (existing.floating ? existing.floating.month : parseInt((existing.date || '').substring(5,7)) - 1) : 0;
  const defDay = existing ? (existing.date || '').substring(8,10) : '01';
  const defWeekday = (existing && existing.floating) ? existing.floating.weekday : 1;
  const defNth = (existing && existing.floating) ? existing.floating.nth : 1;

  const overlay = document.createElement('div');
  overlay.id = 'holiday-modal-overlay';
  overlay.className = 'modal-overlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;z-index:9999;';

  const modal = document.createElement('div');
  modal.style.cssText = 'background:var(--bg-secondary);border:1px solid var(--border);border-radius:12px;padding:24px;width:420px;max-width:90vw;color:var(--text-primary);box-shadow:0 8px 32px var(--shadow);';

  // Build month options
  const monthOpts = monthNames.map((m, i) => `<option value="${i}" ${i === defMonth ? 'selected' : ''}>${m}</option>`).join('');
  // Build weekday options
  const weekdayOpts = dayNames.map((d, i) => `<option value="${i}" ${i === defWeekday ? 'selected' : ''}>${d}</option>`).join('');
  // Build nth options
  const nthOpts = nthLabels.map((l, i) => `<option value="${nthValues[i]}" ${nthValues[i] === defNth ? 'selected' : ''}>${l}</option>`).join('');
  // Build day-of-month options
  let dayOpts = '';
  for (let d = 1; d <= 31; d++) {
    const ds = String(d).padStart(2, '0');
    dayOpts += `<option value="${ds}" ${ds === defDay ? 'selected' : ''}>${d}</option>`;
  }

  modal.innerHTML = `
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:20px;">
      <h2 style="margin:0;font-size:1.2em;">${isEdit ? 'Edit' : 'Add'} Holiday</h2>
      <button onclick="document.getElementById('holiday-modal-overlay').remove();" style="background:none;border:none;font-size:22px;cursor:pointer;color:var(--text-secondary);padding:4px 8px;">&times;</button>
    </div>
    <div style="display:flex;flex-direction:column;gap:14px;">
      <div>
        <label style="display:block;font-size:0.85em;color:var(--text-secondary);margin-bottom:4px;">Holiday Name</label>
        <input id="hol-name" type="text" value="${escapeHtml(defName)}" placeholder="e.g. Memorial Day" style="width:100%;padding:8px 10px;border-radius:6px;border:1px solid var(--border);background:var(--bg-input);color:var(--text-primary);font-size:0.95em;box-sizing:border-box;" />
      </div>
      <div>
        <label style="display:block;font-size:0.85em;color:var(--text-secondary);margin-bottom:4px;">Holiday Type</label>
        <div style="display:flex;gap:0;border-radius:6px;overflow:hidden;border:1px solid var(--border);">
          <button id="hol-type-fixed" onclick="_holSetType('fixed')" style="flex:1;padding:8px;border:none;cursor:pointer;font-size:0.9em;font-weight:600;transition:all 0.2s;${defType==='fixed' ? 'background:var(--accent);color:#fff;' : 'background:var(--bg-input);color:var(--text-secondary);'}">Fixed Date</button>
          <button id="hol-type-float" onclick="_holSetType('float')" style="flex:1;padding:8px;border:none;border-left:1px solid var(--border);cursor:pointer;font-size:0.9em;font-weight:600;transition:all 0.2s;${defType==='float' ? 'background:var(--accent);color:#fff;' : 'background:var(--bg-input);color:var(--text-secondary);'}">Floating</button>
        </div>
      </div>
      <div id="hol-fixed-fields" style="display:${defType==='fixed' ? 'flex' : 'none'};gap:10px;">
        <div style="flex:1;">
          <label style="display:block;font-size:0.85em;color:var(--text-secondary);margin-bottom:4px;">Month</label>
          <select id="hol-fixed-month" style="width:100%;padding:8px;border-radius:6px;border:1px solid var(--border);background:var(--bg-input);color:var(--text-primary);font-size:0.9em;">${monthOpts}</select>
        </div>
        <div style="flex:0 0 80px;">
          <label style="display:block;font-size:0.85em;color:var(--text-secondary);margin-bottom:4px;">Day</label>
          <select id="hol-fixed-day" style="width:100%;padding:8px;border-radius:6px;border:1px solid var(--border);background:var(--bg-input);color:var(--text-primary);font-size:0.9em;">${dayOpts}</select>
        </div>
      </div>
      <div id="hol-float-fields" style="display:${defType==='float' ? 'flex' : 'none'};flex-direction:column;gap:10px;">
        <div style="display:flex;gap:10px;">
          <div style="flex:1;">
            <label style="display:block;font-size:0.85em;color:var(--text-secondary);margin-bottom:4px;">Occurrence</label>
            <select id="hol-float-nth" style="width:100%;padding:8px;border-radius:6px;border:1px solid var(--border);background:var(--bg-input);color:var(--text-primary);font-size:0.9em;">${nthOpts}</select>
          </div>
          <div style="flex:1;">
            <label style="display:block;font-size:0.85em;color:var(--text-secondary);margin-bottom:4px;">Day of Week</label>
            <select id="hol-float-weekday" style="width:100%;padding:8px;border-radius:6px;border:1px solid var(--border);background:var(--bg-input);color:var(--text-primary);font-size:0.9em;">${weekdayOpts}</select>
          </div>
        </div>
        <div>
          <label style="display:block;font-size:0.85em;color:var(--text-secondary);margin-bottom:4px;">Month</label>
          <select id="hol-float-month" style="width:100%;padding:8px;border-radius:6px;border:1px solid var(--border);background:var(--bg-input);color:var(--text-primary);font-size:0.9em;">${monthOpts}</select>
        </div>
        <div style="padding:8px 10px;border-radius:6px;background:var(--bg-input);border:1px solid var(--border);font-size:0.85em;color:var(--text-secondary);">
          <span id="hol-float-preview">Preview: calculating...</span>
        </div>
      </div>
      <div>
        <label style="display:block;font-size:0.85em;color:var(--text-secondary);margin-bottom:4px;">Rate Multiplier</label>
        <div style="display:flex;align-items:center;gap:8px;">
          <input id="hol-mult" type="number" step="0.1" min="1" value="${defMult}" style="width:80px;padding:8px 10px;border-radius:6px;border:1px solid var(--border);background:var(--bg-input);color:var(--text-primary);font-size:0.95em;" />
          <span style="font-size:0.85em;color:var(--text-secondary);">x pay (e.g. 2.5 = time and a half + regular)</span>
        </div>
      </div>
      <div style="display:flex;gap:10px;justify-content:flex-end;margin-top:6px;">
        <button onclick="document.getElementById('holiday-modal-overlay').remove();" class="btn btn-secondary">Cancel</button>
        <button onclick="_holSave(${idx});" class="btn btn-primary">${isEdit ? 'Update' : 'Add'} Holiday</button>
      </div>
    </div>
  `;

  overlay.appendChild(modal);
  overlay.addEventListener('click', function(e) { if (e.target === overlay) overlay.remove(); });
  document.body.appendChild(overlay);

  // Set up float preview updates
  _holUpdateFloatPreview();
  document.getElementById('hol-float-nth').addEventListener('change', _holUpdateFloatPreview);
  document.getElementById('hol-float-weekday').addEventListener('change', _holUpdateFloatPreview);
  document.getElementById('hol-float-month').addEventListener('change', _holUpdateFloatPreview);
}

function _holSetType(type) {
  const fixedBtn = document.getElementById('hol-type-fixed');
  const floatBtn = document.getElementById('hol-type-float');
  const fixedFields = document.getElementById('hol-fixed-fields');
  const floatFields = document.getElementById('hol-float-fields');
  if (type === 'fixed') {
    fixedBtn.style.background = 'var(--accent)'; fixedBtn.style.color = '#fff';
    floatBtn.style.background = 'var(--bg-input)'; floatBtn.style.color = 'var(--text-secondary)';
    fixedFields.style.display = 'flex';
    floatFields.style.display = 'none';
  } else {
    floatBtn.style.background = 'var(--accent)'; floatBtn.style.color = '#fff';
    fixedBtn.style.background = 'var(--bg-input)'; fixedBtn.style.color = 'var(--text-secondary)';
    fixedFields.style.display = 'none';
    floatFields.style.display = 'flex';
    _holUpdateFloatPreview();
  }
}

function _holUpdateFloatPreview() {
  const nthEl = document.getElementById('hol-float-nth');
  const wdEl = document.getElementById('hol-float-weekday');
  const moEl = document.getElementById('hol-float-month');
  const prevEl = document.getElementById('hol-float-preview');
  if (!nthEl || !wdEl || !moEl || !prevEl) return;
  const nth = parseInt(nthEl.value);
  const weekday = parseInt(wdEl.value);
  const month = parseInt(moEl.value);
  const year = getRateSheet().year || new Date().getFullYear();
  const d = calcFloatingHoliday({ month, weekday, nth }, year);
  const dayNames = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const nthLabel = nth === -1 ? 'Last' : ['','1st','2nd','3rd','4th'][nth];
  prevEl.textContent = 'Preview: ' + nthLabel + ' ' + dayNames[weekday] + ' of ' + monthNames[month] + ' ' + year + ' = ' + monthNames[d.getMonth()] + ' ' + d.getDate() + ', ' + year;
}

function _holSave(idx) {
  const name = document.getElementById('hol-name').value.trim();
  if (!name) { showToast('Please enter a holiday name.', 'error'); return; }
  const mult = parseFloat(document.getElementById('hol-mult').value) || 2.5;
  const isFloat = document.getElementById('hol-type-float').style.background.includes('var(--accent') || document.getElementById('hol-float-fields').style.display !== 'none';
  const year = getRateSheet().year || new Date().getFullYear();

  const rs = getRateSheet();
  if (!rs.holidays) rs.holidays = getDefaultHolidayList(rs.year);

  let holiday;
  if (isFloat) {
    const month = parseInt(document.getElementById('hol-float-month').value);
    const weekday = parseInt(document.getElementById('hol-float-weekday').value);
    const nth = parseInt(document.getElementById('hol-float-nth').value);
    const d = calcFloatingHoliday({ month, weekday, nth }, year);
    holiday = {
      id: idx >= 0 ? rs.holidays[idx].id : 'custom_' + Date.now(),
      date: formatDateISO(d),
      name: name,
      multiplier: mult,
      floating: { month, weekday, nth },
      custom: true
    };
  } else {
    const month = parseInt(document.getElementById('hol-fixed-month').value);
    const day = document.getElementById('hol-fixed-day').value;
    holiday = {
      id: idx >= 0 ? rs.holidays[idx].id : 'custom_' + Date.now(),
      date: year + '-' + String(month + 1).padStart(2, '0') + '-' + day,
      name: name,
      multiplier: mult,
      fixed: true,
      custom: true
    };
  }

  if (idx >= 0) {
    rs.holidays[idx] = holiday;
  } else {
    rs.holidays.push(holiday);
  }
  rs.holidays.sort((a, b) => a.date.localeCompare(b.date));
  saveRateSheet(rs);
  document.getElementById('holiday-modal-overlay').remove();
  renderRateSheetPage();
  showToast(idx >= 0 ? 'Holiday updated!' : 'Holiday added!', 'success');
}

function deleteCompanyHoliday(idx) {
  if (!confirm('Remove this holiday?')) return;
  const rs = getRateSheet();
  if (!rs.holidays) return;
  rs.holidays.splice(idx, 1);
  saveRateSheet(rs);
  renderRateSheetPage();
  showToast('Holiday removed.');
}

function formatDateISO(d) {
  return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
}

function isCompanyHoliday(dateStr) {
  if (!dateStr) return null;
  const year = parseInt(dateStr.substring(0, 4));
  const holidays = getCompanyHolidays(year);
  const found = holidays.find(h => h.date === dateStr);
  return found || null;
}

function getHolidayRateWarning(dateStr) {
  const holiday = isCompanyHoliday(dateStr);
  if (holiday) {
    const rs = getRateSheet();
    const holidayRate = rs.laborRates.find(r => r.id === 'holiday');
    return { holiday: holiday.name, rate: holidayRate ? holidayRate.rate : 375 };
  }
  // Check if it's a weekend (Sunday)
  const d = new Date(dateStr + 'T12:00:00');
  if (d.getDay() === 0) {
    const rs = getRateSheet();
    const dtRate = rs.laborRates.find(r => r.id === 'doubletime');
    return { holiday: 'Sunday (Double Time)', rate: dtRate ? dtRate.rate : 300 };
  }
  return null;
}

// ============================================================
// DEFAULT QUOTE TERMS (Industry-specific for electrical testing)
// ============================================================
function getDefaultQuoteTerms() {
  return [
    'Payment Terms: NET 30 from date of invoice unless otherwise agreed upon in writing.',
    'Scope of Work: This quote covers only the services and materials explicitly described herein. Any additional work requested will be quoted separately or billed on a time and material basis.',
    'Validity: This quote is valid for 30 days from the date of issue. After this period, pricing may be subject to revision.',
    'Scheduling: Work will be scheduled upon receipt of a signed purchase order or written authorization. Scheduling is subject to technician and equipment availability.',
    'Site Access & Conditions: Customer shall provide safe, unobstructed access to all equipment to be tested. All circuits must be de-energized, isolated, and locked out/tagged out (LOTO) prior to testing unless otherwise specified.',
    'Minimum Charge: A minimum charge of 4 hours at the applicable hourly labor rate applies to all field service visits.',
    'Travel: Travel time beyond the first 30 minutes from our nearest office will be billed at the standard hourly rate. Per diem of $250/day per person applies for overnight travel.',
    'Materials Markup: All materials and consumables supplied will be billed at cost plus a minimum 15% markup.',
    'Emergency & After-Hours: Work performed outside normal business hours (Mon-Fri, 8 AM - 5 PM), on weekends, or holidays will be billed at the applicable overtime, double-time, or holiday rate per our current rate schedule.',
    'Warranty: Power Services of VA, LLC provides a 30-day workmanship guarantee on all testing services. Any requested retests within this period due to our workmanship will be performed at no charge; all other retests will be billed as time and material.',
    'Liability Limitation: Power Services of VA, LLC liability shall not exceed the total contract value. We are not responsible for pre-existing equipment defects, latent conditions, or damage caused by others.',
    'Insurance: Power Services of VA, LLC maintains General Liability, Workers Compensation, and Professional Liability insurance. Certificates of Insurance are available upon request.',
    'Cancellation: Cancellations made less than 48 hours before the scheduled start date may incur a cancellation fee equal to 4 hours at the applicable labor rate.',
    'Test Reports: Detailed test reports will be provided within 10 business days of project completion unless expedited delivery is requested.',
    'Permits & Fees: Any required permits or inspection fees are the responsibility of the customer unless explicitly included in this quote.',
    'Change Orders: Any changes to the scope of work must be documented in writing and may result in adjusted pricing and schedule.',
  ];
}

function getSavedQuoteTermsTemplate() {
  const data = localStorage.getItem('psva_quote_terms_template');
  return data ? JSON.parse(data) : getDefaultQuoteTerms();
}

function saveQuoteTermsTemplate(terms) {
  localStorage.setItem('psva_quote_terms_template', JSON.stringify(terms));
}

// ============================================================
// RENDER RATE SHEET PAGE
// ============================================================
function renderRateSheetPage() {
  const rs = getRateSheet();
  const main = document.querySelector('.main-content');
  
  // Build the actual index mapping for visible labor rates (accounting for hidden ones)
  let visibleLaborIdx = 0;
  let laborHtml = rs.laborRates.map((r, realIdx) => {
    if (r.hidden) return '';
    const mult = (r.multiplier !== undefined && r.multiplier !== null) ? r.multiplier : '';
    const multDisplay = (typeof mult === 'number' && mult > 0) ? mult : '';
    // Build dual-rate sub-row if enabled
    let dualRateHtml = '';
    if (r.dualRate) {
      dualRateHtml = `
      <tr style="background:var(--bg-primary);">
        <td colspan="2" style="padding-left:32px;font-size:12px;">
          <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
            <span style="color:var(--text-secondary);">┗ Split Rate:</span>
            <label style="font-size:11px;">Label 1:</label>
            <input class="form-input" value="${escapeHtml(r.dualRateLabel1 || 'First 2 hrs')}" style="width:100px;font-size:11px;padding:2px 6px;" onchange="updateRateField('laborRates', ${realIdx}, 'dualRateLabel1', this.value)">
            <label style="font-size:11px;">Mult:</label>
            <input class="form-input" type="number" value="${mult}" min="0" step="0.1" style="width:60px;font-size:11px;padding:2px 6px;" onchange="updateLaborMultiplier(${realIdx}, parseFloat(this.value)||0)">
            <span style="font-size:11px;color:var(--text-secondary);">= $${r.rate}/${r.unit}</span>
          </div>
          <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-top:4px;">
            <span style="color:var(--text-secondary);">┗ After threshold:</span>
            <label style="font-size:11px;">Label 2:</label>
            <input class="form-input" value="${escapeHtml(r.dualRateLabel2 || 'After 2 hrs')}" style="width:100px;font-size:11px;padding:2px 6px;" onchange="updateRateField('laborRates', ${realIdx}, 'dualRateLabel2', this.value)">
            <label style="font-size:11px;">Mult:</label>
            <input class="form-input" type="number" value="${r.multiplier2 || 0}" min="0" step="0.1" style="width:60px;font-size:11px;padding:2px 6px;" onchange="updateLaborMultiplier2(${realIdx}, parseFloat(this.value)||0)">
            <span style="font-size:11px;color:var(--text-secondary);">= $${r.rate2 || 0}/${r.unit}</span>
            <label style="font-size:11px;">Threshold (hrs):</label>
            <input class="form-input" type="number" value="${r.dualRateThresholdHrs || 2}" min="1" step="1" style="width:50px;font-size:11px;padding:2px 6px;" onchange="updateRateField('laborRates', ${realIdx}, 'dualRateThresholdHrs', parseInt(this.value)||2)">
          </div>
        </td>
        <td colspan="3"></td>
      </tr>`;
    }
    const html = `
    <tr>
      <td><input class="form-input" value="${escapeHtml(r.name)}" onchange="updateRateField('laborRates', ${realIdx}, 'name', this.value)"></td>
      <td><input class="form-input" value="${escapeHtml(r.description)}" onchange="updateRateField('laborRates', ${realIdx}, 'description', this.value)" style="font-size:12px;"></td>
      <td style="text-align:center;">
        <input class="form-input" type="number" value="${multDisplay}" min="0" step="0.1" style="width:70px;text-align:center;" 
          onchange="updateLaborMultiplier(${realIdx}, parseFloat(this.value)||0)" 
          title="Multiplier of base straight time rate">
      </td>
      <td><input class="form-input" type="number" value="${r.rate}" min="0" step="5" style="width:100px;" onchange="updateRateField('laborRates', ${realIdx}, 'rate', parseFloat(this.value)||0)"></td>
      <td style="font-size:11px;color:var(--text-secondary);white-space:nowrap;">${r.dualRate ? '$' + r.rate + '/' + r.unit + ' / $' + (r.rate2||0) + '/' + r.unit : '$' + r.rate + '/' + r.unit}</td>
      <td style="text-align:center;">
        <label style="font-size:11px;cursor:pointer;display:flex;align-items:center;gap:4px;justify-content:center;" title="Enable split/dual rate for this item">
          <input type="checkbox" ${r.dualRate ? 'checked' : ''} onchange="toggleDualRate(${realIdx}, this.checked)">
          <span>Split</span>
        </label>
      </td>
      <td style="width:40px;text-align:center;"><button onclick="removeLaborRate(${realIdx})" title="Delete this rate" style="color:#EF4444;background:none;border:none;cursor:pointer;font-size:16px;padding:4px 8px;">&#10005;</button></td>
    </tr>
    ${dualRateHtml}
  `;
    visibleLaborIdx++;
    return html;
  }).join('');
  
  // Determine straight time rate (stored in rate sheet or from the 'straight' labor rate)
  const straightTimeRate = rs.straightTimeRate || (rs.laborRates.find(r => r.id === 'straight')?.rate) || 0;
  
  // Build dynamic auto-calculate tooltip from actual multipliers
  const tooltipParts = rs.laborRates.filter(r => !r.hidden && r.multiplier > 0 && r.id !== 'straight').map(r => {
    let label = r.name.replace(/ \(.*\)/, '').trim();
    if (label.length > 30) label = label.substring(0, 28) + '..';
    if (r.dualRate) {
      return label + ' = ' + r.multiplier + '× (' + (r.dualRateLabel1||'first') + ') & ' + (r.multiplier2||0) + '× (' + (r.dualRateLabel2||'after') + ')';
    }
    return label + ' = ' + r.multiplier + '×';
  });
  const autoCalcTooltip = tooltipParts.length > 0 ? tooltipParts.join(', ') : 'Set multipliers on each row to enable auto-calculation';
  
  let specialtyHtml = rs.specialtyServices.map((s, idx) => `
    <tr>
      <td><input class="form-input" value="${escapeHtml(s.name)}" onchange="updateRateField('specialtyServices', ${idx}, 'name', this.value)"></td>
      <td><input class="form-input" type="number" value="${s.rate}" min="0" step="5" style="width:100px;" onchange="updateRateField('specialtyServices', ${idx}, 'rate', parseFloat(this.value)||0)"></td>
      <td>${s.note ? '<span style="font-size:11px;color:var(--text-secondary);">' + escapeHtml(s.note) + '</span>' : '$' + s.rate + '/' + s.unit}</td>
      <td style="width:50px;text-align:center;"><button class="delete-btn" onclick="removeSpecialtyService(${idx})" title="Delete this service" style="color:#EF4444;background:none;border:none;cursor:pointer;font-size:16px;padding:4px 8px;">&#10005;</button></td>
    </tr>
  `).join('');
  
  let billingHtml = rs.billingTerms.map((bt, idx) => `
    <div class="term-item">
      <input class="form-input" value="${escapeHtml(bt.text)}" onchange="updateRateField('billingTerms', ${idx}, 'text', this.value)">
      <button class="delete-btn" onclick="removeRateItem('billingTerms', ${idx})" title="Remove">&#10005;</button>
    </div>
  `).join('');
  
  let warrantyHtml = rs.maintenanceWarranty.map((mw, idx) => `
    <div class="term-item">
      <input class="form-input" value="${escapeHtml(mw.text)}" onchange="updateRateField('maintenanceWarranty', ${idx}, 'text', this.value)">
      <button class="delete-btn" onclick="removeRateItem('maintenanceWarranty', ${idx})" title="Remove">&#10005;</button>
    </div>
  `).join('');
  
  // Company holidays for current year - editable
  const currentYear = rs.year || new Date().getFullYear();
  initHolidaysInRateSheet();
  const rsUpdated = getRateSheet();
  const holidays = rsUpdated.holidays || getDefaultHolidayList(currentYear);
  let holidayHtml = `
    <div class="table-scroll">
      <table class="data-table">
        <thead><tr><th>Holiday</th><th>Date</th><th>Multiplier</th><th>Type</th><th style="width:80px;">Actions</th></tr></thead>
        <tbody>
          ${holidays.map((h, i) => `
            <tr>
              <td><span style="display:inline-block;width:10px;height:10px;border-radius:50%;background:#F59E0B;margin-right:8px;"></span>${escapeHtml(h.name)}</td>
              <td>${h.date}</td>
              <td>${h.multiplier || 2.5}x</td>
              <td><span style="font-size:11px;padding:2px 6px;border-radius:4px;background:${h.floating ? '#EFF6FF' : '#F0FDF4'};color:${h.floating ? '#2563EB' : '#16A34A'};">${h.floating ? 'Floating' : 'Fixed'}</span></td>
              <td>
                <button class="btn btn-secondary btn-sm" style="padding:2px 8px;font-size:11px;" onclick="editCompanyHoliday(${i})" title="Edit">\u270E</button>
                <button class="btn btn-secondary btn-sm" style="padding:2px 8px;font-size:11px;color:#EF4444;" onclick="deleteCompanyHoliday(${i})" title="Delete">\u2715</button>
              </td>
            </tr>
          `).join('')}
        </tbody>
      </table>
    </div>`;
  
  main.innerHTML = `
    <div class="page-header">
      <h1>Rate Sheet</h1>
      <div class="page-header-actions">
        <button class="btn btn-secondary" onclick="resetRateSheet()">Reset to Defaults</button>
        <button class="btn btn-primary" onclick="exportRateSheetPDF()">Export PDF</button>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Rate Sheet Year
        <span style="margin-left:auto;font-size:12px;color:var(--text-secondary);font-weight:400;">Last updated: ${new Date(rs.updatedAt).toLocaleDateString()}</span>
      </div>
      <div class="form-grid">
        <div class="form-group">
          <label class="form-label">Year</label>
          <input class="form-input" type="number" id="rs-year" value="${rs.year}" min="2020" max="2040" onchange="updateRateSheetYear(parseInt(this.value))">
        </div>
        <div class="form-group">
          <label class="form-label">Material Markup Minimum %</label>
          <input class="form-input" type="number" id="rs-markup" value="${rs.materialMarkupMin}" min="0" step="1" onchange="updateRateSheetField('materialMarkupMin', parseFloat(this.value)||0)">
        </div>
        <div class="form-group">
          <label class="form-label" style="position:relative;cursor:help;" title="The minimum number of hours billed per site visit. All field service requests are subject to this minimum charge at the applicable hourly labor rate, regardless of actual time spent on site.">Minimum Field Hours <span style="display:inline-block;width:16px;height:16px;border-radius:50%;background:var(--text-secondary);color:white;font-size:11px;text-align:center;line-height:16px;margin-left:4px;cursor:help;">?</span></label>
          <input class="form-input" type="number" id="rs-minhrs" value="${rs.minimumHours}" min="0" step="1" onchange="updateRateSheetField('minimumHours', parseFloat(this.value)||0)">
        </div>
        <div class="form-group">
          <label class="form-label">Per Diem ($/day)</label>
          <input class="form-input" type="number" id="rs-perdiem" value="${rs.perDiem}" min="0" step="10" onchange="updateRateSheetField('perDiem', parseFloat(this.value)||0)">
        </div>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Hourly Labor Rates</div>
      <div style="background:var(--bg-primary);border:1px solid var(--border-color);border-radius:8px;padding:16px;margin-bottom:16px;">
        <div style="display:flex;align-items:center;gap:16px;flex-wrap:wrap;">
          <div style="flex:0 0 auto;">
            <label class="form-label" style="margin-bottom:4px;font-weight:600;">Straight Time Base Rate ($/hr)</label>
            <input class="form-input" type="number" id="rs-straight-time" value="${straightTimeRate}" min="0" step="5" style="width:140px;font-size:16px;font-weight:600;" onchange="updateStraightTimeRate(parseFloat(this.value)||0)">
          </div>
          <div style="flex:1;font-size:12px;color:var(--text-secondary);padding-top:18px;">
            <strong>Auto-Calculate:</strong> When you change the base rate, all rows with a multiplier set will recalculate automatically.<br>
            <span style="font-size:11px;">${escapeHtml(autoCalcTooltip)}</span>
          </div>
        </div>
      </div>
      <div class="table-scroll">
        <table class="data-table">
          <thead><tr><th>Rate Type</th><th>Description</th><th style="text-align:center;width:80px;">Multiplier</th><th style="width:110px;">Rate ($)</th><th>Display</th><th style="width:60px;text-align:center;">Dual</th><th style="width:40px;"></th></tr></thead>
          <tbody>${laborHtml}</tbody>
        </table>
      </div>
      <div style="display:flex;gap:8px;align-items:center;margin-top:8px;">
        <button class="btn btn-secondary btn-sm" onclick="addLaborRate()">+ Add Labor Rate</button>
        <span style="font-size:11px;color:var(--text-secondary);">Tip: Check "Split" to create a dual-rate item (e.g., different rate after X hours)</span>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Specialty Services</div>
      <div class="table-scroll">
        <table class="data-table">
          <thead><tr><th>Service</th><th>Rate ($)</th><th>Display</th><th style="width:50px;"></th></tr></thead>
          <tbody>${specialtyHtml}</tbody>
        </table>
      </div>
      <button class="btn btn-secondary btn-sm" style="margin-top:8px;" onclick="addSpecialtyService()">+ Add Service</button>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Billing Terms & Fees</div>
      <div class="terms-list">${billingHtml}</div>
      <button class="btn btn-secondary btn-sm" style="margin-top:8px;" onclick="addRateItem('billingTerms')">+ Add Term</button>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Maintenance & Warranty</div>
      <div class="terms-list">${warrantyHtml}</div>
      <button class="btn btn-secondary btn-sm" style="margin-top:8px;" onclick="addRateItem('maintenanceWarranty')">+ Add Item</button>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Company Holidays (${currentYear})
        <span style="margin-left:auto;font-size:12px;color:var(--text-secondary);font-weight:400;">Holiday rate: $${rs.laborRates.find(r => r.id === 'holiday')?.rate || 375}/hr (default multiplier)</span>
      </div>
      ${holidayHtml}
      <div style="display:flex;gap:8px;align-items:center;margin-top:8px;">
        <button class="btn btn-secondary btn-sm" onclick="addCompanyHoliday()">+ Add Holiday</button>
        <p style="font-size:11px;color:var(--text-secondary);margin:0;">Holidays appear on the Calendar. Estimates on these dates show a rate reminder. Edit multiplier per holiday.</p>
      </div>
    </div>
  `;
}

function updateRateField(section, idx, field, value) {
  const rs = getRateSheet();
  if (rs[section] && rs[section][idx]) {
    rs[section][idx][field] = value;
    saveRateSheet(rs);
  }
}

function updateRateSheetYear(year) {
  const rs = getRateSheet();
  rs.year = year;
  saveRateSheet(rs);
}

function updateRateSheetField(field, value) {
  const rs = getRateSheet();
  rs[field] = value;
  saveRateSheet(rs);
}

function updateStraightTimeRate(baseRate) {
  const rs = getRateSheet();
  rs.straightTimeRate = baseRate;
  // Auto-calculate all rates using their per-row multiplier
  rs.laborRates.forEach(r => {
    if (r.hidden) return;
    const mult = parseFloat(r.multiplier);
    if (mult > 0) {
      r.rate = Math.round(baseRate * mult);
    }
    // Also recalculate dual-rate secondary rate
    if (r.dualRate) {
      const mult2 = parseFloat(r.multiplier2);
      if (mult2 > 0) {
        r.rate2 = Math.round(baseRate * mult2);
      }
    }
  });
  saveRateSheet(rs);
  renderRateSheetPage();
  showToast('All rates recalculated from $' + baseRate + '/hr base rate', 'success');
}

function updateLaborMultiplier(idx, newMult) {
  const rs = getRateSheet();
  const r = rs.laborRates[idx];
  if (!r) return;
  r.multiplier = newMult;
  // Auto-recalculate rate from straight time base if multiplier > 0
  const baseRate = rs.straightTimeRate || (rs.laborRates.find(lr => lr.id === 'straight')?.rate) || 0;
  if (newMult > 0 && baseRate > 0) {
    r.rate = Math.round(baseRate * newMult);
  }
  saveRateSheet(rs);
  renderRateSheetPage();
}

function updateLaborMultiplier2(idx, newMult2) {
  const rs = getRateSheet();
  const r = rs.laborRates[idx];
  if (!r || !r.dualRate) return;
  r.multiplier2 = newMult2;
  // Auto-recalculate rate2 from straight time base
  const baseRate = rs.straightTimeRate || (rs.laborRates.find(lr => lr.id === 'straight')?.rate) || 0;
  if (newMult2 > 0 && baseRate > 0) {
    r.rate2 = Math.round(baseRate * newMult2);
  }
  saveRateSheet(rs);
  renderRateSheetPage();
}

function toggleDualRate(idx, enabled) {
  const rs = getRateSheet();
  const r = rs.laborRates[idx];
  if (!r) return;
  r.dualRate = enabled;
  if (enabled) {
    // Initialize dual-rate defaults if not already set
    if (!r.multiplier2) r.multiplier2 = 0;
    if (!r.rate2) r.rate2 = 0;
    if (!r.dualRateThresholdHrs) r.dualRateThresholdHrs = 2;
    if (!r.dualRateLabel1) r.dualRateLabel1 = 'First ' + r.dualRateThresholdHrs + ' hrs';
    if (!r.dualRateLabel2) r.dualRateLabel2 = 'After ' + r.dualRateThresholdHrs + ' hrs';
  }
  saveRateSheet(rs);
  renderRateSheetPage();
}

function addLaborRate() {
  const rs = getRateSheet();
  rs.laborRates.push({ id: generateId(), name: 'New Rate', description: '', rate: 0, unit: 'hr', multiplier: 0, custom: true });
  saveRateSheet(rs);
  renderRateSheetPage();
}

function removeLaborRate(idx) {
  const rs = getRateSheet();
  const item = rs.laborRates[idx];
  if (!confirm('Delete "' + (item?.name || 'this rate') + '" from labor rates?')) return;
  rs.laborRates.splice(idx, 1);
  // Also remove the hidden companion if it was emergency
  if (item && item.id === 'emergency') {
    const afterIdx = rs.laborRates.findIndex(r => r.id === 'emergency_after');
    if (afterIdx >= 0) rs.laborRates.splice(afterIdx, 1);
  }
  saveRateSheet(rs);
  renderRateSheetPage();
}

function removeSpecialtyService(idx) {
  const rs = getRateSheet();
  const item = rs.specialtyServices[idx];
  if (!confirm('Delete "' + (item?.name || 'this service') + '" from specialty services?')) return;
  rs.specialtyServices.splice(idx, 1);
  saveRateSheet(rs);
  renderRateSheetPage();
}

function addSpecialtyService() {
  const rs = getRateSheet();
  rs.specialtyServices.push({ id: generateId(), name: 'New Service', rate: 0, unit: 'hr' });
  saveRateSheet(rs);
  renderRateSheetPage();
}

function addRateItem(section) {
  const rs = getRateSheet();
  rs[section].push({ id: generateId(), text: '' });
  saveRateSheet(rs);
  renderRateSheetPage();
}

function removeRateItem(section, idx) {
  const rs = getRateSheet();
  rs[section].splice(idx, 1);
  saveRateSheet(rs);
  renderRateSheetPage();
}

function resetRateSheet() {
  if (!confirm('Reset all rates to defaults? This cannot be undone.')) return;
  localStorage.removeItem('psva_rate_sheet');
  renderRateSheetPage();
  showToast('Rate sheet reset to defaults', 'success');
}

// ============================================================
// RATE SHEET PDF EXPORT
// ============================================================
function exportRateSheetPDF() {
  const rs = getRateSheet();
  const company = getCompany();
  const theme = getActiveTheme();
  const colors = theme.colors;
  const doc = new jspdf.jsPDF('p', 'mm', 'letter');
  const pageW = doc.internal.pageSize.getWidth();
  const pageH = doc.internal.pageSize.getHeight();
  const margin = 20;
  const contentW = pageW - margin * 2;
  
  // Page background
  doc.setFillColor(...hexToRgb(colors.bg));
  doc.rect(0, 0, pageW, pageH, 'F');
  
  // Header
  pdfAddHeader(doc, theme, company, rs.year + ' Rate Sheet', '', pageW);
  
  // Title
  let y = 48;
  doc.setFontSize(16);
  doc.setTextColor(...hexToRgb(colors.accent));
  doc.setFont('helvetica', 'bold');
  const title = company.name + ' \u2013 ' + rs.year + ' Rate Sheet';
  doc.text(title, pageW / 2, y, { align: 'center' });
  y += 12;
  
  // Company info
  doc.setFontSize(10);
  doc.setTextColor(...hexToRgb(colors.textSecondary));
  doc.setFont('helvetica', 'normal');
  if (company.address) { doc.text(company.address, margin, y); y += 5; }
  if (company.phone) { doc.text('Phone: ' + company.phone, margin, y); y += 5; }
  y += 5;
  
  // Section: Hourly Labor Rates
  doc.setFontSize(13);
  doc.setTextColor(...hexToRgb(colors.accent));
  doc.setFont('helvetica', 'bold');
  doc.text('Hourly Labor Rates', margin, y);
  y += 8;
  
  doc.setFontSize(9);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(...hexToRgb(colors.textSecondary));
  doc.text('Rate Type', margin, y);
  doc.text('Description', margin + 52, y);
  doc.text('Rate / Notes', margin + 112, y);
  y += 2;
  doc.setDrawColor(...hexToRgb(colors.border));
  doc.line(margin, y, pageW - margin, y);
  y += 5;
  
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(...hexToRgb(colors.text));
  rs.laborRates.filter(r => !r.hidden).forEach(r => {
    if (y > pageH - 40) { doc.addPage(); doc.setFillColor(...hexToRgb(colors.bg)); doc.rect(0, 0, pageW, pageH, 'F'); y = 30; }
    
    // Column widths: Name=50, Description=60, Rate=55 (right-aligned)
    const colName = margin;
    const colDesc = margin + 52;
    const colDescW = 58;
    const colRate = margin + 112;
    const colRateW = contentW - 112;
    
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(9);
    const nameLines = doc.splitTextToSize(r.name, 50);
    nameLines.forEach((line, i) => { doc.text(line, colName, y + i * 4); });
    
    doc.setFont('helvetica', 'normal');
    const descLines = doc.splitTextToSize(r.description, colDescW);
    descLines.forEach((line, i) => { doc.text(line, colDesc, y + i * 4); });
    
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8.5);
    let rateText;
    if (r.dualRate && r.rate2 > 0) {
      rateText = '$' + r.rate.toLocaleString() + '/hr (' + (r.dualRateLabel1 || 'first') + '), $' + r.rate2.toLocaleString() + '/hr (' + (r.dualRateLabel2 || 'after') + ')';
    } else {
      rateText = r.note || ('$' + r.rate.toLocaleString() + '/hr.');
    }
    const rateLines = doc.splitTextToSize(rateText, colRateW);
    rateLines.forEach((line, i) => { doc.text(line, colRate, y + i * 4); });
    doc.setFontSize(9);
    
    const maxLines = Math.max(nameLines.length, descLines.length, rateLines.length);
    y += maxLines * 4 + 4;
  });
  
  // Force page 2: Specialty Services always starts on new page
  doc.addPage();
  doc.setFillColor(...hexToRgb(colors.bg));
  doc.rect(0, 0, pageW, pageH, 'F');
  y = 30;
  
  doc.setFontSize(13);
  doc.setTextColor(...hexToRgb(colors.accent));
  doc.setFont('helvetica', 'bold');
  doc.text('Specialty Services, Rates, and Terms', pageW / 2, y, { align: 'center' });
  y += 10;
  
  doc.setFontSize(9);
  doc.setTextColor(...hexToRgb(colors.text));
  rs.specialtyServices.forEach(s => {
    doc.setFont('helvetica', 'normal');
    const text = '- ' + s.name + ': ' + (s.note || ('$' + s.rate + '/hr.'));
    const lines = doc.splitTextToSize(text, contentW);
    lines.forEach(line => { doc.text(line, margin, y); y += 4; });
    y += 2;
  });
  
  y += 5;
  
  // Billing Terms & Fees
  doc.setFontSize(13);
  doc.setTextColor(...hexToRgb(colors.accent));
  doc.setFont('helvetica', 'bold');
  doc.text('Billing Terms & Fees', margin, y);
  y += 8;
  
  doc.setFontSize(9);
  doc.setTextColor(...hexToRgb(colors.text));
  doc.setFont('helvetica', 'normal');
  rs.billingTerms.forEach(bt => {
    if (y > pageH - 30) { doc.addPage(); doc.setFillColor(...hexToRgb(colors.bg)); doc.rect(0, 0, pageW, pageH, 'F'); y = 30; }
    const lines = doc.splitTextToSize('- ' + bt.text, contentW);
    lines.forEach(line => { doc.text(line, margin, y); y += 4; });
    y += 3;
  });
  
  y += 5;
  
  // Maintenance & Warranty
  if (y > pageH - 40) { doc.addPage(); doc.setFillColor(...hexToRgb(colors.bg)); doc.rect(0, 0, pageW, pageH, 'F'); y = 30; }
  doc.setFontSize(13);
  doc.setTextColor(...hexToRgb(colors.accent));
  doc.setFont('helvetica', 'bold');
  doc.text('Maintenance & Warranty', margin, y);
  y += 8;
  
  doc.setFontSize(9);
  doc.setTextColor(...hexToRgb(colors.text));
  doc.setFont('helvetica', 'normal');
  rs.maintenanceWarranty.forEach(mw => {
    if (y > pageH - 30) { doc.addPage(); doc.setFillColor(...hexToRgb(colors.bg)); doc.rect(0, 0, pageW, pageH, 'F'); y = 30; }
    const lines = doc.splitTextToSize('- ' + mw.text, contentW);
    lines.forEach(line => { doc.text(line, margin, y); y += 4; });
    y += 3;
  });
  
  y += 5;
  
  // Disclosures - Company Holidays
  if (y > pageH - 50) { doc.addPage(); doc.setFillColor(...hexToRgb(colors.bg)); doc.rect(0, 0, pageW, pageH, 'F'); y = 30; }
  doc.setFontSize(13);
  doc.setTextColor(...hexToRgb(colors.accent));
  doc.setFont('helvetica', 'bold');
  doc.text('Disclosures', margin, y);
  y += 8;
  
  doc.setFontSize(9);
  doc.setTextColor(...hexToRgb(colors.text));
  doc.setFont('helvetica', 'normal');
  const holidays = getCompanyHolidays(rs.year);
  const holidayNames = holidays.map(h => h.name).join(', ');
  const holidayText = '- Company Identified Holidays: ' + holidayNames;
  const hLines = doc.splitTextToSize(holidayText, contentW);
  hLines.forEach(line => { doc.text(line, margin, y); y += 4; });
  
  // Footer with page numbers and accent line
  const totalPages = doc.internal.getNumberOfPages();
  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i);
    // Page background (for any addPage calls that didn't get it)
    // Accent line
    doc.setDrawColor(...hexToRgb(colors.accent));
    doc.setLineWidth(0.5);
    doc.line(margin, pageH - 18, pageW - margin, pageH - 18);
    // Page number
    doc.setFontSize(8);
    doc.setTextColor(...hexToRgb(colors.textSecondary));
    doc.text('Page ' + i + ' of ' + totalPages, pageW - margin, pageH - 12, { align: 'right' });
    // Company name in footer
    doc.text(company.name, margin, pageH - 12);
  }
  
  doc.save(company.name.replace(/[^a-zA-Z0-9]/g, '_') + '_Rate_Sheet_' + rs.year + '.pdf');
  showToast('Rate Sheet PDF exported!', 'success');
}


// ============================================================
function getCalendarCustomEvents() {
  const data = localStorage.getItem('psva_calendar_events');
  return data ? JSON.parse(data) : [];
}

function saveCalendarCustomEvents(events) {
  localStorage.setItem('psva_calendar_events', JSON.stringify(events));
}





// ---- CALENDAR PEOPLE / CONTACTS MANAGEMENT ----
function getCalendarPeople() {
  const data = localStorage.getItem('psva_calendar_people');
  return data ? JSON.parse(data) : [];
}

function saveCalendarPeople(people) {
  localStorage.setItem('psva_calendar_people', JSON.stringify(people));
}

function addPersonToCalendarList(name) {
  if (!name || !name.trim()) return;
  const people = getCalendarPeople();
  const trimmed = name.trim();
  if (!people.find(p => p.toLowerCase() === trimmed.toLowerCase())) {
    people.push(trimmed);
    people.sort((a, b) => a.toLowerCase().localeCompare(b.toLowerCase()));
    saveCalendarPeople(people);
  }
}

function removePersonFromCalendarList(name) {
  let people = getCalendarPeople();
  people = people.filter(p => p.toLowerCase() !== name.toLowerCase());
  saveCalendarPeople(people);
}

function cleanupCalendarPeople() {
  // Auto-remove names from the saved list that no longer appear on any calendar event
  // Names that were manually added (via Manage People) are preserved until explicitly removed
  var events = getCalendarCustomEvents();
  var namesInUse = new Set();
  events.forEach(function(e) {
    (e.people || []).forEach(function(p) { namesInUse.add(p.toLowerCase()); });
  });
  var peopleData = JSON.parse(localStorage.getItem('psva_calendar_people_data') || '{}');
  var people = getCalendarPeople();
  var cleaned = people.filter(function(p) {
    // Keep if the name is on an event OR was manually added
    return namesInUse.has(p.toLowerCase()) || (peopleData[p.toLowerCase()] && peopleData[p.toLowerCase()].manual);
  });
  if (cleaned.length !== people.length) {
    saveCalendarPeople(cleaned);
  }
  return cleaned;
}

function markPersonAsManual(name) {
  var data = JSON.parse(localStorage.getItem('psva_calendar_people_data') || '{}');
  data[name.trim().toLowerCase()] = { manual: true };
  localStorage.setItem('psva_calendar_people_data', JSON.stringify(data));
}

function unmarkPersonAsManual(name) {
  var data = JSON.parse(localStorage.getItem('psva_calendar_people_data') || '{}');
  delete data[name.trim().toLowerCase()];
  localStorage.setItem('psva_calendar_people_data', JSON.stringify(data));
}

// ---- CALENDAR EVENT MODAL ----
function openCalendarEventModal(dateStr, eventId) {
  let existingEvent = null;
  if (eventId) {
    const events = getCalendarCustomEvents();
    existingEvent = events.find(e => e.id === eventId);
    if (!existingEvent) return;
  }

  const isEdit = !!existingEvent;
  const title = isEdit ? existingEvent.title : '';
  const date = isEdit ? existingEvent.date : (dateStr || new Date().toISOString().split('T')[0]);
  const time = isEdit ? (existingEvent.time || '') : '';
  const description = isEdit ? (existingEvent.description || '') : '';
  const color = isEdit ? (existingEvent.color || '#3B82F6') : '#3B82F6';
  const people = isEdit ? (existingEvent.people || []) : [];

  const colors = [
    { value: '#3B82F6', name: 'Blue' },
    { value: '#10B981', name: 'Green' },
    { value: '#DC2626', name: 'Red' },
    { value: '#F59E0B', name: 'Orange' },
    { value: '#8B5CF6', name: 'Purple' },
    { value: '#EC4899', name: 'Pink' },
    { value: '#14B8A6', name: 'Teal' },
    { value: '#6B7280', name: 'Gray' },
  ];

  // Store the current people list for this modal session
  window._calModalPeople = [...people];

  const overlay = document.createElement('div');
  overlay.id = 'calendar-event-modal-overlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.5);z-index:10000;display:flex;align-items:center;justify-content:center;';
  overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };

  const modal = document.createElement('div');
  modal.style.cssText = 'background:var(--bg-secondary);color:var(--text-primary);border:1px solid var(--border);border-radius:12px;padding:24px;width:460px;max-width:92vw;max-height:90vh;overflow-y:auto;box-shadow:0 20px 60px var(--shadow);';

  const colorSwatches = colors.map(c => 
    '<div onclick="document.querySelectorAll(\'#cal-modal-colors .cal-color-swatch\').forEach(s=>s.style.outline=\'none\'); this.style.outline=\'3px solid var(--text-primary)\'; document.getElementById(\'cal-modal-color-value\').value=\'' + c.value + '\';" class="cal-color-swatch" style="width:32px;height:32px;border-radius:8px;background:' + c.value + ';cursor:pointer;transition:transform 0.15s;' + (c.value === color ? 'outline:3px solid var(--text-primary);' : '') + '" title="' + c.name + '"></div>'
  ).join('');

  const peopleTags = people.map((p, i) => 
    '<span style="display:inline-flex;align-items:center;gap:4px;background:var(--accent-light);color:var(--accent);padding:4px 10px;border-radius:16px;font-size:12px;font-weight:500;">' + escapeHtml(p) + ' <button onclick="calModalRemovePerson(' + i + ')" style="background:none;border:none;cursor:pointer;color:inherit;font-size:14px;padding:0 2px;line-height:1;">&times;</button></span>'
  ).join('');

  modal.innerHTML = 
    '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:20px;">' +
      '<h3 style="margin:0;font-size:18px;font-weight:600;">' + (isEdit ? 'Edit Event' : 'New Event') + '</h3>' +
      '<button onclick="document.getElementById(\'calendar-event-modal-overlay\').remove();" style="background:none;border:none;font-size:22px;cursor:pointer;color:var(--text-secondary);padding:4px 8px;">&times;</button>' +
    '</div>' +
    '<div style="display:flex;flex-direction:column;gap:14px;">' +
      '<div>' +
        '<label style="display:block;font-size:13px;font-weight:600;margin-bottom:4px;color:var(--text-secondary);">Event Title <span style="color:#DC2626;">*</span></label>' +
        '<input id="cal-modal-title" type="text" class="form-input" placeholder="e.g. Site Survey - Dominion Power" value="' + escapeHtml(title) + '" style="width:100%;">' +
      '</div>' +
      '<div style="display:flex;gap:12px;">' +
        '<div style="flex:1;">' +
          '<label style="display:block;font-size:13px;font-weight:600;margin-bottom:4px;color:var(--text-secondary);">Date</label>' +
          '<input id="cal-modal-date" type="date" class="form-input" value="' + date + '" style="width:100%;">' +
        '</div>' +
        '<div style="flex:1;">' +
          '<label style="display:block;font-size:13px;font-weight:600;margin-bottom:4px;color:var(--text-secondary);">Time (optional)</label>' +
          '<input id="cal-modal-time" type="text" class="form-input" placeholder="e.g. 9:00 AM" value="' + escapeHtml(time) + '" style="width:100%;">' +
        '</div>' +
      '</div>' +
      '<div>' +
        '<label style="display:block;font-size:13px;font-weight:600;margin-bottom:4px;color:var(--text-secondary);">Description (optional)</label>' +
        '<textarea id="cal-modal-desc" class="form-input" rows="2" placeholder="Add details about this event..." style="width:100%;resize:vertical;">' + escapeHtml(description) + '</textarea>' +
      '</div>' +
      '<div>' +
        '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;">' +
          '<label style="font-size:13px;font-weight:600;color:var(--text-secondary);">People</label>' +
          '<button onclick="openManagePeoplePanel();" style="background:none;border:none;font-size:11px;color:var(--accent,#3B82F6);cursor:pointer;text-decoration:underline;">Manage Names</button>' +
        '</div>' +
        '<div id="cal-modal-people-tags" style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:8px;min-height:24px;">' + peopleTags + '</div>' +
        '<div style="position:relative;">' +
          '<input id="cal-modal-person-input" type="text" class="form-input" placeholder="Type a name to add..." style="width:100%;" autocomplete="off" onkeydown="calModalPersonKeydown(event)" oninput="calModalPersonAutocomplete(this.value)" onblur="calModalPersonBlur()">' +
          '<div id="cal-modal-person-suggestions" style="display:none;position:absolute;top:100%;left:0;right:0;background:var(--bg-secondary);border:1px solid var(--border);border-radius:8px;box-shadow:0 4px 12px var(--shadow);max-height:150px;overflow-y:auto;z-index:10001;"></div>' +
        '</div>' +
      '</div>' +
      '<div>' +
        '<label style="display:block;font-size:13px;font-weight:600;margin-bottom:8px;color:var(--text-secondary);">Color</label>' +
        '<div id="cal-modal-colors" style="display:flex;gap:8px;flex-wrap:wrap;">' + colorSwatches + '</div>' +
        '<input type="hidden" id="cal-modal-color-value" value="' + color + '">' +
      '</div>' +
    '</div>' +
    '<div style="display:flex;justify-content:' + (isEdit ? 'space-between' : 'flex-end') + ';align-items:center;margin-top:24px;padding-top:16px;border-top:1px solid var(--border);">' +
      (isEdit ? '<button onclick="calendarModalDelete(\'' + eventId + '\');" style="background:#DC2626;color:#fff;border:none;padding:8px 16px;border-radius:8px;cursor:pointer;font-size:14px;font-weight:500;">Delete Event</button>' : '<div></div>') +
      '<div style="display:flex;gap:8px;">' +
        '<button onclick="document.getElementById(\'calendar-event-modal-overlay\').remove();" class="btn btn-secondary">Cancel</button>' +
        '<button onclick="calendarModalSave(' + (isEdit ? "'" + eventId + "'" : 'null') + ');" class="btn btn-primary">' + (isEdit ? 'Save Changes' : 'Add Event') + '</button>' +
      '</div>' +
    '</div>';

  overlay.appendChild(modal);
  document.body.appendChild(overlay);
  setTimeout(function() { var el = document.getElementById('cal-modal-title'); if (el) el.focus(); }, 100);
}

function calModalPersonKeydown(e) {
  if (e.key === 'Enter') {
    e.preventDefault();
    var input = document.getElementById('cal-modal-person-input');
    var name = input.value.trim();
    if (name) {
      calModalAddPerson(name);
      input.value = '';
      document.getElementById('cal-modal-person-suggestions').style.display = 'none';
    }
  }
}

function calModalPersonBlur() {
  // Small delay to allow clicking on suggestion items before blur fires
  setTimeout(function() {
    var input = document.getElementById('cal-modal-person-input');
    if (!input) return;
    var name = input.value.trim();
    if (name) {
      calModalAddPerson(name);
      input.value = '';
    }
    var sugBox = document.getElementById('cal-modal-person-suggestions');
    if (sugBox) sugBox.style.display = 'none';
  }, 200);
}

function calModalFlushPersonInput() {
  // Called before save to ensure any typed-but-not-submitted name is captured
  var input = document.getElementById('cal-modal-person-input');
  if (!input) return;
  var name = input.value.trim();
  if (name) {
    calModalAddPerson(name);
    input.value = '';
  }
}

function calModalAddPerson(name) {
  if (!name || !name.trim()) return;
  var trimmed = name.trim();
  if (window._calModalPeople.find(function(p) { return p.toLowerCase() === trimmed.toLowerCase(); })) return;
  window._calModalPeople.push(trimmed);
  addPersonToCalendarList(trimmed);
  calModalRenderPeopleTags();
}

function calModalRemovePerson(index) {
  window._calModalPeople.splice(index, 1);
  calModalRenderPeopleTags();
}

function calModalRenderPeopleTags() {
  var container = document.getElementById('cal-modal-people-tags');
  if (!container) return;
  container.innerHTML = window._calModalPeople.map(function(p, i) {
    return '<span style="display:inline-flex;align-items:center;gap:4px;background:var(--accent-light);color:var(--accent);padding:4px 10px;border-radius:16px;font-size:12px;font-weight:500;">' + escapeHtml(p) + ' <button onclick="calModalRemovePerson(' + i + ')" style="background:none;border:none;cursor:pointer;color:inherit;font-size:14px;padding:0 2px;line-height:1;">&times;</button></span>';
  }).join('');
}

function calModalPersonAutocomplete(query) {
  var sugBox = document.getElementById('cal-modal-person-suggestions');
  if (!sugBox) return;
  if (!query || !query.trim()) { sugBox.style.display = 'none'; return; }
  var q = query.trim().toLowerCase();
  var allPeople = getCalendarPeople();
  var currentPeople = window._calModalPeople.map(function(p) { return p.toLowerCase(); });
  var matches = allPeople.filter(function(p) {
    return p.toLowerCase().indexOf(q) !== -1 && currentPeople.indexOf(p.toLowerCase()) === -1;
  });
  if (matches.length === 0) { sugBox.style.display = 'none'; return; }
  sugBox.style.display = 'block';
  sugBox.innerHTML = matches.map(function(m) {
    return '<div onclick="calModalAddPerson(\'' + escapeHtml(m).replace(/'/g, "\\'") + '\'); document.getElementById(\'cal-modal-person-input\').value=\'\'; document.getElementById(\'cal-modal-person-suggestions\').style.display=\'none\';" style="padding:8px 12px;cursor:pointer;font-size:13px;border-bottom:1px solid var(--border);" onmouseover="this.style.background=\'var(--bg-tertiary)\'" onmouseout="this.style.background=\'none\'">' + escapeHtml(m) + '</div>';
  }).join('');
}

function openCalendarPeopleManager() {
  var people = getCalendarPeople();
  var overlay = document.createElement('div');
  overlay.id = 'cal-people-manager-overlay';
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:10001;display:flex;align-items:center;justify-content:center;';
  overlay.onclick = function(e) { if (e.target === overlay) overlay.remove(); };

  var modal = document.createElement('div');
  modal.style.cssText = 'background:var(--bg-secondary);color:var(--text-primary);border:1px solid var(--border);border-radius:12px;padding:24px;width:400px;max-height:70vh;overflow-y:auto;box-shadow:0 20px 60px var(--shadow);';

  function renderManagerContent() {
    people = getCalendarPeople();
    var html = '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">' +
      '<h4 style="margin:0;font-size:16px;font-weight:600;">Manage Calendar People</h4>' +
      '<button onclick="document.getElementById(\'cal-people-manager-overlay\').remove();" style="background:none;border:none;font-size:20px;cursor:pointer;color:var(--text-secondary);">&times;</button>' +
    '</div>' +
    '<p style="font-size:12px;color:var(--text-secondary);margin-bottom:12px;">Names are auto-added when you assign people to events. Manually added names persist until you remove them. Names only added via events are auto-cleaned when removed from all events.</p>' +
    '<div style="display:flex;gap:8px;margin-bottom:16px;">' +
      '<input id="cal-people-mgr-input" type="text" class="form-input" placeholder="Add a new name..." style="flex:1;" onkeydown="if(event.key===\'Enter\'){event.preventDefault();calPeopleMgrAdd();}">' +
      '<button class="btn btn-primary" style="padding:6px 14px;font-size:13px;white-space:nowrap;" onclick="calPeopleMgrAdd()">+ Add</button>' +
    '</div>';

    if (people.length === 0) {
      html += '<p style="font-size:13px;color:var(--text-secondary);text-align:center;padding:20px 0;">No saved names. Add people to calendar events and they will appear here automatically.</p>';
    } else {
      html += '<div style="display:flex;flex-direction:column;gap:6px;">';
      // Count events per person
      var events = getCalendarCustomEvents();
      people.forEach(function(p) {
        var eventCount = events.filter(function(e) { return (e.people || []).find(function(pp) { return pp.toLowerCase() === p.toLowerCase(); }); }).length;
        html += '<div style="display:flex;align-items:center;justify-content:space-between;padding:8px 12px;background:var(--bg-tertiary);border-radius:8px;">' +
          '<div style="display:flex;flex-direction:column;">' +
            '<span style="font-size:13px;font-weight:500;">' + escapeHtml(p) + '</span>' +
            '<span style="font-size:11px;color:var(--text-secondary);">' + eventCount + ' event' + (eventCount !== 1 ? 's' : '') + '</span>' +
          '</div>' +
          '<button onclick="calPeopleMgrRemove(\'' + escapeHtml(p).replace(/'/g, "\\'") + '\')" style="background:rgba(220,38,38,0.12);color:#DC2626;border:none;padding:4px 10px;border-radius:6px;cursor:pointer;font-size:12px;">Remove</button>' +
        '</div>';
      });
      html += '</div>';
    }

    html += '<div style="display:flex;justify-content:flex-end;margin-top:16px;">' +
      '<button class="btn btn-secondary" onclick="document.getElementById(\'cal-people-manager-overlay\').remove(); renderCalendarView();">Done</button>' +
    '</div>';

    modal.innerHTML = html;
    setTimeout(function() { var inp = document.getElementById('cal-people-mgr-input'); if (inp) inp.focus(); }, 50);
  }

  // Expose add/remove functions globally for onclick handlers
  window.calPeopleMgrAdd = function() {
    var input = document.getElementById('cal-people-mgr-input');
    if (!input) return;
    var name = input.value.trim();
    if (!name) { showToast('Please enter a name', 'error'); return; }
    addPersonToCalendarList(name);
    markPersonAsManual(name);
    input.value = '';
    renderManagerContent();
    showToast('Added: ' + name, 'success');
  };

  window.calPeopleMgrRemove = function(name) {
    // Also remove from all events
    var events = getCalendarCustomEvents();
    var removedFromEvents = 0;
    events.forEach(function(e) {
      if (e.people && e.people.length > 0) {
        var before = e.people.length;
        e.people = e.people.filter(function(p) { return p.toLowerCase() !== name.toLowerCase(); });
        if (e.people.length < before) removedFromEvents++;
      }
    });
    saveCalendarCustomEvents(events);
    removePersonFromCalendarList(name);
    unmarkPersonAsManual(name);
    renderManagerContent();
    var msg = 'Removed: ' + name;
    if (removedFromEvents > 0) msg += ' (from ' + removedFromEvents + ' event' + (removedFromEvents !== 1 ? 's' : '') + ')';
    showToast(msg, 'success');
  };

  renderManagerContent();
  overlay.appendChild(modal);
  document.body.appendChild(overlay);
}

function openManagePeoplePanel() {
  var people = getCalendarPeople();
  var panel = document.getElementById('cal-modal-manage-people');
  if (panel) { panel.remove(); return; }

  panel = document.createElement('div');
  panel.id = 'cal-modal-manage-people';
  panel.style.cssText = 'position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);background:var(--bg-secondary);color:var(--text-primary);border:1px solid var(--border);border-radius:12px;padding:20px;width:340px;max-height:70vh;overflow-y:auto;box-shadow:0 20px 60px var(--shadow);z-index:10002;';

  var html = '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">' +
    '<h4 style="margin:0;font-size:16px;font-weight:600;">Manage People</h4>' +
    '<button onclick="document.getElementById(\'cal-modal-manage-people\').remove();" style="background:none;border:none;font-size:20px;cursor:pointer;color:var(--text-secondary);">&times;</button>' +
  '</div>' +
  '<p style="font-size:12px;color:var(--text-secondary);margin-bottom:12px;">Removing a name here removes it from future suggestions only. Existing events are not affected.</p>';

  if (people.length === 0) {
    html += '<p style="font-size:13px;color:var(--text-secondary);text-align:center;padding:20px 0;">No saved names yet. Names are saved automatically when you add people to events.</p>';
  } else {
    html += '<div style="display:flex;flex-direction:column;gap:6px;">';
    people.forEach(function(p) {
      html += '<div style="display:flex;align-items:center;justify-content:space-between;padding:8px 12px;background:var(--bg-tertiary);border-radius:8px;">' +
        '<span style="font-size:13px;">' + escapeHtml(p) + '</span>' +
        '<button onclick="removePersonFromCalendarList(\'' + escapeHtml(p).replace(/'/g, "\\'") + '\'); document.getElementById(\'cal-modal-manage-people\').remove(); openManagePeoplePanel();" style="background:rgba(220,38,38,0.12);color:#DC2626;border:none;padding:4px 10px;border-radius:6px;cursor:pointer;font-size:12px;">Remove</button>' +
      '</div>';
    });
    html += '</div>';
  }

  panel.innerHTML = html;
  document.body.appendChild(panel);
}

function calendarModalSave(eventId) {
  // Flush any name typed in the person input but not yet added
  calModalFlushPersonInput();
  var title = document.getElementById('cal-modal-title').value.trim();
  var date = document.getElementById('cal-modal-date').value;
  var time = document.getElementById('cal-modal-time').value.trim();
  var desc = document.getElementById('cal-modal-desc').value.trim();
  var color = document.getElementById('cal-modal-color-value').value;
  var people = window._calModalPeople || [];

  if (!title) {
    showToast('Please enter an event title', 'error');
    document.getElementById('cal-modal-title').focus();
    return;
  }
  if (!date) {
    showToast('Please select a date', 'error');
    return;
  }

  var events = getCalendarCustomEvents();

  if (eventId) {
    var evt = events.find(function(e) { return e.id === eventId; });
    if (evt) {
      evt.title = title;
      evt.date = date;
      evt.time = time;
      evt.description = desc;
      evt.color = color;
      evt.people = people;
    }
    saveCalendarCustomEvents(events);
    showToast('Event updated', 'success');
  } else {
    events.push({
      id: generateId(),
      date: date,
      title: title,
      time: time,
      description: desc,
      color: color,
      people: people,
      type: 'custom',
      createdAt: new Date().toISOString(),
    });
    saveCalendarCustomEvents(events);
    showToast('Event added', 'success');
  }

  document.getElementById('calendar-event-modal-overlay').remove();
  renderCalendarView();
}

function calendarModalDelete(eventId) {
  if (!confirm('Are you sure you want to delete this event?')) return;
  var events = getCalendarCustomEvents();
  events = events.filter(function(e) { return e.id !== eventId; });
  saveCalendarCustomEvents(events);
  var overlay = document.getElementById('calendar-event-modal-overlay');
  if (overlay) overlay.remove();
  renderCalendarView();
  showToast('Event deleted', 'success');
}

// Legacy wrappers for onclick handlers in calendar grid
function addCalendarEvent(dateStr) {
  openCalendarEventModal(dateStr, null);
}

function editCalendarEvent(eventId) {
  openCalendarEventModal(null, eventId);
}

function deleteCalendarEvent(eventId) {
  calendarModalDelete(eventId);
}

function showDayEventsModal(dateStr) {
  // Rebuild events for this date (same logic as renderCalendarView)
  var showHolidays = localStorage.getItem('psva_cal_show_holidays') !== 'false';
  var jobs = getJobs();
  var equipment = getDocuments('equipment');
  var techs = getTechnicians();
  var events = [];
  jobs.forEach(function(j) {
    if (j.startDate) events.push({ date: j.startDate, type: 'job-start', label: j.jobNumber + ' Start', detail: j.name, color: '#3B82F6' });
    if (j.endDate) events.push({ date: j.endDate, type: 'job-end', label: j.jobNumber + ' End', detail: j.name, color: '#6B7280' });
  });
  equipment.forEach(function(eq) {
    if (eq.nextCalibrationDue) {
      var st = getCalibrationStatus(eq);
      events.push({ date: eq.nextCalibrationDue, type: 'calibration', label: 'Cal: ' + (eq.description || eq.modelNumber).substring(0, 20), detail: eq.serialNumber, color: st.color });
    }
  });
  techs.forEach(function(t) {
    (t.certifications || []).forEach(function(c) {
      if (c.expirationDate) {
        var st = getCertStatus(c);
        events.push({ date: c.expirationDate, type: 'cert-expiry', label: 'Cert: ' + c.name.substring(0, 20), detail: t.name, color: st.color });
      }
    });
  });
  var yr = parseInt(dateStr.split('-')[0]);
  var holidays = getCompanyHolidays(yr);
  if (showHolidays) {
    holidays.forEach(function(h) {
      events.push({ date: h.date, type: 'holiday', label: h.name, detail: 'Company Holiday \u2013 ' + (h.multiplier || 2.5) + '\u00d7 base rate applies', color: '#D97706' });
    });
  }
  var customEvents = getCalendarCustomEvents();
  customEvents.forEach(function(ce) {
    var peopleStr = (ce.people && ce.people.length > 0) ? ' [' + ce.people.join(', ') + ']' : '';
    events.push({
      date: ce.date, type: 'custom',
      label: (ce.time ? ce.time + ' ' : '') + ce.title,
      detail: (ce.description || 'Custom event') + peopleStr,
      color: ce.color || '#3B82F6', customId: ce.id, people: ce.people || [],
    });
  });

  var dayEvents = events.filter(function(e) { return e.date === dateStr; });
  if (dayEvents.length === 0) { addCalendarEvent(dateStr); return; }

  var d = new Date(dateStr + 'T00:00:00');
  var dayNames = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  var mNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  var dateLabel = dayNames[d.getDay()] + ', ' + mNames[d.getMonth()] + ' ' + d.getDate() + ', ' + d.getFullYear();

  var overlay = document.createElement('div');
  overlay.id = 'day-events-modal-overlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.5);z-index:10000;display:flex;align-items:center;justify-content:center;';
  overlay.onclick = function(e) { if (e.target === overlay) overlay.remove(); };

  var modal = document.createElement('div');
  modal.style.cssText = 'background:var(--bg-secondary);color:var(--text-primary);border:1px solid var(--border);border-radius:12px;padding:0;width:460px;max-width:92vw;max-height:80vh;overflow:hidden;box-shadow:0 20px 60px var(--shadow);display:flex;flex-direction:column;';

  var header = '<div style="display:flex;justify-content:space-between;align-items:center;padding:16px 20px;border-bottom:1px solid var(--border);">' +
    '<div>' +
      '<h3 style="margin:0;font-size:16px;font-weight:600;">' + dateLabel + '</h3>' +
      '<span style="font-size:12px;color:var(--text-secondary);">' + dayEvents.length + ' event' + (dayEvents.length !== 1 ? 's' : '') + '</span>' +
    '</div>' +
    '<button onclick="document.getElementById(\'day-events-modal-overlay\').remove();" style="background:none;border:none;font-size:22px;cursor:pointer;color:var(--text-secondary);padding:4px 8px;">&times;</button>' +
  '</div>';

  var body = '<div style="padding:12px 20px;overflow-y:auto;flex:1;">';
  dayEvents.forEach(function(e) {
    var peopleHint = (e.people && e.people.length > 0) ? '<div style="font-size:11px;color:var(--accent,#3B82F6);margin-top:2px;">\ud83d\udc64 ' + e.people.map(function(p){return escapeHtml(p);}).join(', ') + '</div>' : '';
    var isCustom = !!e.customId;
    var editBtn = isCustom ? ' onclick="document.getElementById(\'day-events-modal-overlay\').remove(); editCalendarEvent(\'' + e.customId + '\');"' : '';
    var cursorStyle = isCustom ? 'cursor:pointer;' : '';
    var typeLabel = '';
    if (e.type === 'holiday') typeLabel = 'Holiday';
    else if (e.type === 'job-start') typeLabel = 'Job Start';
    else if (e.type === 'job-end') typeLabel = 'Job End';
    else if (e.type === 'calibration') typeLabel = 'Calibration';
    else if (e.type === 'cert-expiry') typeLabel = 'Cert Expiry';
    else if (e.type === 'custom') typeLabel = 'Custom';
    // Convert hex color to rgba for proper transparency
    var _r = parseInt(e.color.slice(1,3),16), _g = parseInt(e.color.slice(3,5),16), _b = parseInt(e.color.slice(5,7),16);
    var bgRgba = 'rgba(' + _r + ',' + _g + ',' + _b + ',0.08)';
    var borderRgba = 'rgba(' + _r + ',' + _g + ',' + _b + ',0.2)';
    var badgeBgRgba = 'rgba(' + _r + ',' + _g + ',' + _b + ',0.15)';
    body += '<div style="display:flex;align-items:flex-start;gap:10px;padding:10px 12px;border-radius:8px;margin-bottom:6px;background:' + bgRgba + ';border:1px solid ' + borderRgba + ';' + cursorStyle + '"' + editBtn + '>' +
      '<div style="width:4px;min-height:36px;border-radius:2px;background:' + e.color + ';flex-shrink:0;margin-top:2px;"></div>' +
      '<div style="flex:1;min-width:0;">' +
        '<div style="display:flex;align-items:center;gap:6px;">' +
          '<span style="font-size:13px;font-weight:600;color:var(--text-primary);">' + escapeHtml(e.label) + '</span>' +
          '<span style="font-size:10px;padding:2px 6px;border-radius:4px;background:' + badgeBgRgba + ';color:' + e.color + ';font-weight:500;">' + typeLabel + '</span>' +
          (isCustom ? '<span style="font-size:10px;color:var(--text-secondary);margin-left:auto;">click to edit</span>' : '<span style="font-size:10px;color:var(--text-secondary);margin-left:auto;">auto</span>') +
        '</div>' +
        '<div style="font-size:12px;color:var(--text-secondary);margin-top:2px;">' + escapeHtml(e.detail.split(' [')[0]) + '</div>' +
        peopleHint +
      '</div>' +
    '</div>';
  });
  body += '</div>';

  var footer = '<div style="padding:12px 20px;border-top:1px solid var(--border);text-align:right;">' +
    '<button class="btn btn-primary" onclick="document.getElementById(\'day-events-modal-overlay\').remove(); addCalendarEvent(\'' + dateStr + '\');">+ Add Event</button>' +
  '</div>';

  modal.innerHTML = header + body + footer;
  overlay.appendChild(modal);
  document.body.appendChild(overlay);
}

function renderCalendarView() {
  var main = document.querySelector('.main-content');
  var year = calendarDate.getFullYear();
  var month = calendarDate.getMonth();
  var monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];

  var showHolidays = localStorage.getItem('psva_cal_show_holidays') !== 'false';
  var showUpcoming = localStorage.getItem('psva_cal_show_upcoming') !== 'false';

  var jobs = getJobs();
  var equipment = getDocuments('equipment');
  var techs = getTechnicians();

  var events = [];
  jobs.forEach(function(j) {
    if (j.startDate) events.push({ date: j.startDate, type: 'job-start', label: j.jobNumber + ' Start', detail: j.name, color: '#3B82F6' });
    if (j.endDate) events.push({ date: j.endDate, type: 'job-end', label: j.jobNumber + ' End', detail: j.name, color: '#6B7280' });
  });
  equipment.forEach(function(eq) {
    if (eq.nextCalibrationDue) {
      var st = getCalibrationStatus(eq);
      events.push({ date: eq.nextCalibrationDue, type: 'calibration', label: 'Cal: ' + (eq.description || eq.modelNumber).substring(0, 20), detail: eq.serialNumber, color: st.color });
    }
  });
  techs.forEach(function(t) {
    (t.certifications || []).forEach(function(c) {
      if (c.expirationDate) {
        var st = getCertStatus(c);
        events.push({ date: c.expirationDate, type: 'cert-expiry', label: 'Cert: ' + c.name.substring(0, 20), detail: t.name, color: st.color });
      }
    });
  });

  var holidays = getCompanyHolidays(year);
  if (showHolidays) {
    holidays.forEach(function(h) {
      events.push({ date: h.date, type: 'holiday', label: h.name, detail: 'Company Holiday \u2013 ' + (h.multiplier || 2.5) + '\u00d7 base rate applies', color: '#D97706' });
    });
  }

  var customEvents = getCalendarCustomEvents();
  customEvents.forEach(function(ce) {
    var peopleStr = (ce.people && ce.people.length > 0) ? ' [' + ce.people.join(', ') + ']' : '';
    events.push({
      date: ce.date,
      type: 'custom',
      label: (ce.time ? ce.time + ' ' : '') + ce.title,
      detail: (ce.description || 'Custom event') + peopleStr,
      color: ce.color || '#3B82F6',
      customId: ce.id,
      people: ce.people || [],
    });
  });

  var firstDay = new Date(year, month, 1).getDay();
  var daysInMonth = new Date(year, month + 1, 0).getDate();
  var today = new Date();
  var todayStr2 = today.getFullYear() + '-' + String(today.getMonth()+1).padStart(2,'0') + '-' + String(today.getDate()).padStart(2,'0');

  var calHtml = '<div class="calendar-grid">';
  ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].forEach(function(d) {
    calHtml += '<div class="calendar-header-cell">' + d + '</div>';
  });

  for (var i = 0; i < firstDay; i++) calHtml += '<div class="calendar-cell empty"></div>';

  for (var day = 1; day <= daysInMonth; day++) {
    var dateStr = year + '-' + String(month+1).padStart(2,'0') + '-' + String(day).padStart(2,'0');
    var dayEvents = events.filter(function(e) { return e.date === dateStr; });
    var isToday = dateStr === todayStr2;
    calHtml += '<div class="calendar-cell ' + (isToday ? 'today' : '') + ' ' + (dayEvents.length > 0 ? 'has-events' : '') + '" onclick="' + (dayEvents.length > 0 ? 'showDayEventsModal(\'' + dateStr + '\')' : 'addCalendarEvent(\'' + dateStr + '\')') + '" style="cursor:pointer;" title="' + (dayEvents.length > 0 ? 'Click to view ' + dayEvents.length + ' event(s)' : 'Click to add event') + '">';
    calHtml += '<div class="calendar-day-number">' + day + '</div>';
    dayEvents.slice(0, 3).forEach(function(e) {
      var peopleHint = (e.people && e.people.length > 0) ? ' | People: ' + e.people.join(', ') : '';
      if (e.customId) {
        calHtml += '<div class="calendar-event calendar-event-custom" style="background:' + e.color + '20;color:' + e.color + ';border-left:3px solid ' + e.color + ';" onclick="event.stopPropagation(); editCalendarEvent(\'' + e.customId + '\')" title="Click to edit: ' + escapeHtml(e.detail) + peopleHint + '">' + escapeHtml(e.label) + '</div>';
      } else {
        calHtml += '<div class="calendar-event" style="background:' + e.color + '20;color:' + e.color + ';border-left:3px solid ' + e.color + ';" onclick="event.stopPropagation();" title="' + escapeHtml(e.detail) + ' (auto)">' + escapeHtml(e.label) + '</div>';
      }
    });
    if (dayEvents.length > 3) calHtml += '<div class="calendar-event-more" onclick="event.stopPropagation(); showDayEventsModal(\'' + dateStr + '\')" style="cursor:pointer;" title="Click to see all ' + dayEvents.length + ' events">+' + (dayEvents.length - 3) + ' more</div>';
    calHtml += '</div>';
  }
  calHtml += '</div>';

  var upcoming = events.filter(function(e) { return e.date >= todayStr2; }).sort(function(a, b) { return a.date.localeCompare(b.date); }).slice(0, 15);

  var upcomingHtml = '';
  if (showUpcoming) {
    if (upcoming.length === 0) {
      upcomingHtml = '<div class="card" style="margin-top:16px;"><div class="card-title"><div class="accent-bar"></div>Upcoming Events</div><p class="intro-text">No upcoming events.</p></div>';
    } else {
      upcomingHtml = '<div class="card" style="margin-top:16px;"><div class="card-title"><div class="accent-bar"></div>Upcoming Events</div><div class="mini-table">';
      upcoming.forEach(function(e) {
        var peopleInfo = (e.people && e.people.length > 0) ? '<span style="font-size:11px;color:var(--accent,#3B82F6);margin-left:6px;">\ud83d\udc64 ' + e.people.join(', ') + '</span>' : '';
        upcomingHtml += '<div class="mini-row">' +
          '<span style="width:10px;height:10px;border-radius:50%;background:' + e.color + ';flex-shrink:0;"></span>' +
          '<span class="mini-primary">' + escapeHtml(e.label) + peopleInfo + '</span>' +
          '<span class="mini-secondary">' + escapeHtml(e.detail.split(' [')[0]) + '</span>' +
          '<span class="mini-secondary">' + formatDateShort(e.date) + '</span>' +
          (e.customId ? '<button class="delete-btn" onclick="editCalendarEvent(\'' + e.customId + '\')" title="Edit event" style="margin-left:auto;background:none;border:1px solid var(--border);padding:2px 8px;border-radius:4px;cursor:pointer;font-size:11px;">Edit</button>' : '<span style="font-size:10px;color:var(--text-secondary);margin-left:auto;">auto</span>') +
        '</div>';
      });
      upcomingHtml += '</div></div>';
    }
  }

  // Auto-cleanup people no longer on any event
  cleanupCalendarPeople();
  var activePeople = getCalendarPeople();
  var filterPerson = localStorage.getItem('psva_cal_filter_person') || 'all';
  // If the filtered person was cleaned up, reset to all
  if (filterPerson !== 'all' && !activePeople.find(function(p) { return p === filterPerson; })) {
    localStorage.setItem('psva_cal_filter_person', 'all');
    filterPerson = 'all';
  }

  // Build month selector options
  var monthOpts = monthNames.map(function(m, i) {
    return '<option value="' + i + '"' + (i === month ? ' selected' : '') + '>' + m + '</option>';
  }).join('');

  // Build year selector options (current year +/- 10)
  var yearOpts = '';
  for (var yi = year - 10; yi <= year + 10; yi++) {
    yearOpts += '<option value="' + yi + '"' + (yi === year ? ' selected' : '') + '>' + yi + '</option>';
  }

  // Build people filter/management section
  var peopleSection = '';
  if (activePeople.length > 0) {
    peopleSection = '<div style="display:flex;align-items:center;gap:8px;margin-left:auto;">' +
      '<select class="form-select" style="width:160px;" onchange="localStorage.setItem(\'psva_cal_filter_person\',this.value); renderCalendarView();">' +
        '<option value="all">All People</option>' +
        activePeople.map(function(p) { return '<option value="' + p + '"' + (filterPerson === p ? ' selected' : '') + '>' + escapeHtml(p) + '</option>'; }).join('') +
      '</select>' +
      '<button class="btn btn-secondary" style="padding:6px 10px;font-size:12px;" onclick="openCalendarPeopleManager()" title="Manage People">\u270E</button>' +
    '</div>';
  } else {
    peopleSection = '<div style="margin-left:auto;">' +
      '<button class="btn btn-secondary" style="padding:6px 10px;font-size:12px;" onclick="openCalendarPeopleManager()" title="Manage People">Manage People</button>' +
    '</div>';
  }

  main.innerHTML = 
    '<div class="page-header">' +
      '<h1>Calendar</h1>' +
      '<div class="page-header-actions">' +
        '<button class="btn btn-secondary" onclick="calendarDate.setMonth(calendarDate.getMonth()-1); renderCalendarView();">\u2190 Prev</button>' +
        '<button class="btn btn-secondary" onclick="calendarDate = new Date(); renderCalendarView();">Today</button>' +
        '<button class="btn btn-secondary" onclick="calendarDate.setMonth(calendarDate.getMonth()+1); renderCalendarView();">Next \u2192</button>' +
        '<button class="btn btn-primary" onclick="openCalendarEventModal(new Date().toISOString().split(\'T\')[0], null)">+ Add Event</button>' +
      '</div>' +
    '</div>' +
    '<div style="display:flex;align-items:center;justify-content:center;gap:12px;margin-bottom:16px;">' +
      '<select class="form-select" style="width:150px;text-align:center;font-size:15px;font-weight:600;" onchange="calendarDate.setMonth(parseInt(this.value)); renderCalendarView();">' + monthOpts + '</select>' +
      '<select class="form-select" style="width:100px;text-align:center;font-size:15px;font-weight:600;" onchange="calendarDate.setFullYear(parseInt(this.value)); renderCalendarView();">' + yearOpts + '</select>' +
    '</div>' +
    '<p style="text-align:center;font-size:12px;color:var(--text-secondary);margin-top:-8px;margin-bottom:12px;">Click any date to add an event. Click custom events to edit them. Auto-generated events (jobs, calibrations, certs) are read-only.</p>' +
    calHtml +
    '<div style="display:flex;gap:16px;align-items:center;margin-top:16px;padding:12px 16px;background:var(--bg-secondary);border-radius:8px;border:1px solid var(--border);flex-wrap:wrap;">' +
      '<span style="font-size:13px;font-weight:600;color:var(--text-secondary);margin-right:8px;">Display Options:</span>' +
      '<label style="display:flex;align-items:center;gap:6px;cursor:pointer;font-size:13px;">' +
        '<input type="checkbox" ' + (showHolidays ? 'checked' : '') + ' onchange="localStorage.setItem(\'psva_cal_show_holidays\', this.checked); renderCalendarView();" style="accent-color:#D97706;">' +
        '<span style="display:inline-flex;align-items:center;gap:4px;"><span style="width:10px;height:10px;border-radius:50%;background:#D97706;display:inline-block;"></span>Company Holidays</span>' +
      '</label>' +
      '<label style="display:flex;align-items:center;gap:6px;cursor:pointer;font-size:13px;">' +
        '<input type="checkbox" ' + (showUpcoming ? 'checked' : '') + ' onchange="localStorage.setItem(\'psva_cal_show_upcoming\', this.checked); renderCalendarView();" style="accent-color:#3B82F6;">' +
        '<span>Upcoming Events</span>' +
      '</label>' +
      peopleSection +
    '</div>' +
    upcomingHtml;
}

// ============================================================
// PHOTO DOCUMENTATION FOR TEST REPORTS
// ============================================================
function addTestReportPhoto() {
  const input = document.createElement('input');
  input.type = 'file';
  input.accept = 'image/*';
  input.multiple = true;
  input.onchange = (e) => {
    const files = Array.from(e.target.files);
    files.forEach(file => {
      const reader = new FileReader();
      reader.onload = (ev) => {
        if (!window._testReportPhotos) window._testReportPhotos = [];
        window._testReportPhotos.push({
          id: generateId(),
          name: file.name,
          data: ev.target.result,
          caption: '',
          timestamp: new Date().toISOString(),
        });
        renderTestReportPhotos();
      };
      reader.readAsDataURL(file);
    });
  };
  input.click();
}

function renderTestReportPhotos() {
  const container = document.getElementById('test-photos-container');
  if (!container) return;
  const photos = window._testReportPhotos || [];
  if (photos.length === 0) {
    container.innerHTML = '<p class="intro-text">No photos attached. Click "+ Add Photos" to document equipment conditions.</p>';
    return;
  }
  container.innerHTML = `
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:12px;">
      ${photos.map((p, idx) => `
        <div style="border:1px solid var(--border);border-radius:8px;overflow:hidden;">
          <img src="${p.data}" alt="${escapeHtml(p.name)}" style="width:100%;height:150px;object-fit:cover;cursor:pointer;" onclick="viewPhotoFull(${idx})">
          <div style="padding:8px;">
            <input class="form-input form-input-sm" placeholder="Caption..." value="${escapeHtml(p.caption)}" onchange="window._testReportPhotos[${idx}].caption=this.value;" style="margin-bottom:4px;">
            <div style="display:flex;justify-content:space-between;align-items:center;">
              <span style="font-size:11px;color:var(--text-secondary);">${escapeHtml(p.name)}</span>
              <button class="delete-btn" onclick="removeTestPhoto(${idx})" title="Remove">✕</button>
            </div>
          </div>
        </div>
      `).join('')}
    </div>
  `;
}

function removeTestPhoto(idx) {
  window._testReportPhotos.splice(idx, 1);
  renderTestReportPhotos();
}

function viewPhotoFull(idx) {
  const photo = window._testReportPhotos[idx];
  if (!photo) return;
  const modal = document.createElement('div');
  modal.className = 'modal-overlay';
  modal.style.zIndex = '10000';
  modal.innerHTML = `
    <div style="max-width:90vw;max-height:90vh;position:relative;">
      <button class="btn-icon" onclick="this.closest('.modal-overlay').remove()" style="position:absolute;top:10px;right:10px;background:rgba(0,0,0,0.7);color:white;z-index:1;">✕</button>
      <img src="${photo.data}" alt="${escapeHtml(photo.name)}" style="max-width:90vw;max-height:85vh;object-fit:contain;border-radius:8px;">
      ${photo.caption ? '<div style="text-align:center;color:white;margin-top:8px;font-size:14px;">' + escapeHtml(photo.caption) + '</div>' : ''}
    </div>
  `;
  document.body.appendChild(modal);
  modal.addEventListener('click', (e) => { if (e.target === modal) modal.remove(); });
}


// ============================================================
// KPI DASHBOARD
// ============================================================
function getKPITargets() {
  const defaults = {
    grossMarginMin: 65, grossMarginMax: 80,
    grossMarginWarn: 40,
    billableRateTarget: 100,
    materialCostMax: 20,
    utilizationTarget: 75,
    winRateTarget: 50,
    calComplianceGreen: 95, calComplianceWarn: 80,
    certComplianceGreen: 95, certComplianceWarn: 80,
    projectedMarginOverride: null,  // null = auto-calculated, number = manual override
    actualMarginOverride: null      // null = auto-calculated, number = manual override
  };
  try {
    const saved = localStorage.getItem('psva_kpi_targets');
    if (saved) {
      const parsed = JSON.parse(saved);
      return { ...defaults, ...parsed };
    }
  } catch(e) {}
  return defaults;
}

function saveKPITargets(targets) {
  localStorage.setItem('psva_kpi_targets', JSON.stringify(targets));
}

function openKPITargetsModal() {
  const t = getKPITargets();
  const overlay = document.createElement('div');
  overlay.id = 'kpi-targets-modal-overlay';
  overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.6);display:flex;align-items:center;justify-content:center;z-index:9999;';
  overlay.addEventListener('click', (e) => { if (e.target === overlay) overlay.remove(); });
  overlay.innerHTML = `
    <div style="background:var(--bg-secondary);border:1px solid var(--border);border-radius:12px;padding:28px;width:560px;max-width:92vw;max-height:85vh;overflow-y:auto;box-shadow:0 20px 60px var(--shadow);color:var(--text-primary);">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:20px;">
        <h2 style="margin:0;font-size:1.2rem;">KPI Dashboard Targets</h2>
        <button onclick="this.closest('#kpi-targets-modal-overlay').remove()" style="background:none;border:none;color:var(--text-secondary);font-size:20px;cursor:pointer;padding:4px 8px;">&times;</button>
      </div>
      <p style="font-size:12px;color:var(--text-secondary);margin-bottom:20px;">These targets control the green/yellow/red color indicators on the KPI Dashboard. Changes are saved immediately and apply to all periods.</p>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;">
        <div class="card" style="padding:16px;">
          <div style="font-weight:700;font-size:13px;margin-bottom:12px;color:var(--accent);">Financial Targets</div>
          <div class="form-group" style="margin-bottom:10px;"><label class="form-label" style="font-size:12px;">Gross Margin — Green (%)</label><input class="form-input" type="number" id="kpi-t-grossMarginMin" value="${t.grossMarginMin}" step="1" min="0" max="100"><span style="font-size:10px;opacity:0.5;">Green when margin &ge; this value</span></div>
          <div class="form-group" style="margin-bottom:10px;"><label class="form-label" style="font-size:12px;">Gross Margin — Yellow (%)</label><input class="form-input" type="number" id="kpi-t-grossMarginWarn" value="${t.grossMarginWarn}" step="1" min="0" max="100"><span style="font-size:10px;opacity:0.5;">Yellow when margin &ge; this but below green</span></div>
          <div class="form-group" style="margin-bottom:10px;"><label class="form-label" style="font-size:12px;">Gross Margin — Display Max (%)</label><input class="form-input" type="number" id="kpi-t-grossMarginMax" value="${t.grossMarginMax}" step="1" min="0" max="100"><span style="font-size:10px;opacity:0.5;">Shown in subtitle as range (e.g. 65-80%)</span></div>
          <div class="form-group" style="margin-bottom:10px;"><label class="form-label" style="font-size:12px;">Eff. Billable Rate Target ($/hr)</label><input class="form-input" type="number" id="kpi-t-billableRateTarget" value="${t.billableRateTarget}" step="1" min="0"></div>
          <div class="form-group"><label class="form-label" style="font-size:12px;">Material Cost Max (%)</label><input class="form-input" type="number" id="kpi-t-materialCostMax" value="${t.materialCostMax}" step="1" min="0" max="100"></div>
          <div style="font-weight:700;font-size:13px;margin:16px 0 12px;color:var(--accent);">Margin Overrides</div>
          <div class="form-group" style="margin-bottom:10px;"><label class="form-label" style="font-size:12px;">Projected Margin Override (%)</label><input class="form-input" type="number" id="kpi-t-projectedMarginOverride" value="${t.projectedMarginOverride !== null && t.projectedMarginOverride !== undefined ? t.projectedMarginOverride : ''}" step="0.1" min="-100" max="100" placeholder="Auto-calculated"><span style="font-size:10px;opacity:0.5;">Leave blank to auto-calculate from estimates</span></div>
          <div class="form-group"><label class="form-label" style="font-size:12px;">Actual Margin Override (%)</label><input class="form-input" type="number" id="kpi-t-actualMarginOverride" value="${t.actualMarginOverride !== null && t.actualMarginOverride !== undefined ? t.actualMarginOverride : ''}" step="0.1" min="-100" max="100" placeholder="Auto-calculated"><span style="font-size:10px;opacity:0.5;">Leave blank to auto-calculate from completed jobs</span></div>
        </div>
        <div class="card" style="padding:16px;">
          <div style="font-weight:700;font-size:13px;margin-bottom:12px;color:var(--accent);">Operational Targets</div>
          <div class="form-group" style="margin-bottom:10px;"><label class="form-label" style="font-size:12px;">Utilization Rate Target (%)</label><input class="form-input" type="number" id="kpi-t-utilizationTarget" value="${t.utilizationTarget}" step="1" min="0" max="100"><span style="font-size:10px;opacity:0.5;">Green when utilization &ge; this value</span></div>
          <div class="form-group" style="margin-bottom:10px;"><label class="form-label" style="font-size:12px;">Win Rate Target (%)</label><input class="form-input" type="number" id="kpi-t-winRateTarget" value="${t.winRateTarget}" step="1" min="0" max="100"><span style="font-size:10px;opacity:0.5;">Green when win rate &ge; this value</span></div>
          <div style="font-weight:700;font-size:13px;margin:16px 0 12px;color:var(--accent);">Compliance Targets</div>
          <div class="form-group" style="margin-bottom:10px;"><label class="form-label" style="font-size:12px;">Cal. Compliance — Green (%)</label><input class="form-input" type="number" id="kpi-t-calComplianceGreen" value="${t.calComplianceGreen}" step="1" min="0" max="100"></div>
          <div class="form-group" style="margin-bottom:10px;"><label class="form-label" style="font-size:12px;">Cal. Compliance — Yellow (%)</label><input class="form-input" type="number" id="kpi-t-calComplianceWarn" value="${t.calComplianceWarn}" step="1" min="0" max="100"></div>
          <div class="form-group" style="margin-bottom:10px;"><label class="form-label" style="font-size:12px;">Cert. Compliance — Green (%)</label><input class="form-input" type="number" id="kpi-t-certComplianceGreen" value="${t.certComplianceGreen}" step="1" min="0" max="100"></div>
          <div class="form-group"><label class="form-label" style="font-size:12px;">Cert. Compliance — Yellow (%)</label><input class="form-input" type="number" id="kpi-t-certComplianceWarn" value="${t.certComplianceWarn}" step="1" min="0" max="100"></div>
        </div>
      </div>
      <div style="display:flex;gap:12px;margin-top:20px;justify-content:flex-end;">
        <button class="btn btn-secondary" onclick="resetKPITargetsToDefaults()">Reset to Defaults</button>
        <button class="btn btn-primary" onclick="saveKPITargetsFromModal()">Save Targets</button>
      </div>
    </div>
  `;
  document.body.appendChild(overlay);
}

function saveKPITargetsFromModal() {
  const t = {
    grossMarginMin: parseFloat(document.getElementById('kpi-t-grossMarginMin')?.value) || 65,
    grossMarginMax: parseFloat(document.getElementById('kpi-t-grossMarginMax')?.value) || 80,
    grossMarginWarn: parseFloat(document.getElementById('kpi-t-grossMarginWarn')?.value) || 40,
    billableRateTarget: parseFloat(document.getElementById('kpi-t-billableRateTarget')?.value) || 100,
    materialCostMax: parseFloat(document.getElementById('kpi-t-materialCostMax')?.value) || 20,
    utilizationTarget: parseFloat(document.getElementById('kpi-t-utilizationTarget')?.value) || 75,
    winRateTarget: parseFloat(document.getElementById('kpi-t-winRateTarget')?.value) || 50,
    calComplianceGreen: parseFloat(document.getElementById('kpi-t-calComplianceGreen')?.value) || 95,
    calComplianceWarn: parseFloat(document.getElementById('kpi-t-calComplianceWarn')?.value) || 80,
    certComplianceGreen: parseFloat(document.getElementById('kpi-t-certComplianceGreen')?.value) || 95,
    certComplianceWarn: parseFloat(document.getElementById('kpi-t-certComplianceWarn')?.value) || 80,
    projectedMarginOverride: document.getElementById('kpi-t-projectedMarginOverride')?.value !== '' ? parseFloat(document.getElementById('kpi-t-projectedMarginOverride')?.value) : null,
    actualMarginOverride: document.getElementById('kpi-t-actualMarginOverride')?.value !== '' ? parseFloat(document.getElementById('kpi-t-actualMarginOverride')?.value) : null
  };
  saveKPITargets(t);
  const overlay = document.getElementById('kpi-targets-modal-overlay');
  if (overlay) overlay.remove();
  // Re-render if on KPI dashboard or Settings
  const currentPage = document.querySelector('.sidebar-item.active');
  if (currentPage) {
    const pageId = currentPage.getAttribute('onclick');
    if (pageId && pageId.includes('kpi-dashboard')) renderKPIDashboard();
    else if (pageId && pageId.includes('settings')) renderSettings();
  } else {
    renderKPIDashboard();
  }
  showToast('KPI targets saved!', 'success');
}

function resetKPITargetsToDefaults() {
  if (!confirm('Reset all KPI targets to default values?')) return;
  localStorage.removeItem('psva_kpi_targets');
  const overlay = document.getElementById('kpi-targets-modal-overlay');
  if (overlay) overlay.remove();
  openKPITargetsModal();
  showToast('KPI targets reset to defaults.', 'success');
}

function renderKPIDashboard() {
  const main = document.querySelector('.main-content');
  
  // Period state
  if (!window._kpiPeriod) {
    const now = new Date();
    window._kpiPeriod = { month: now.getMonth(), year: now.getFullYear() };
    window._kpiCompare = null;
    window._kpiShowCompare = false;
  }
  
  const pm = window._kpiPeriod.month;
  const py = window._kpiPeriod.year;
  
  const metrics = calculateKPIMetrics(pm, py);
  const compareMetrics = window._kpiCompare ? calculateKPIMetrics(window._kpiCompare.month, window._kpiCompare.year) : null;
  
  const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const monthOpts = monthNames.map((m, i) => '<option value="' + i + '"' + (i === pm ? ' selected' : '') + '>' + m + '</option>').join('');
  
  const currentYear = new Date().getFullYear();
  let yearOpts = '';
  for (let y = currentYear - 5; y <= currentYear + 1; y++) {
    yearOpts += '<option value="' + y + '"' + (y === py ? ' selected' : '') + '>' + y + '</option>';
  }
  
  let cMonthOpts = monthNames.map((m, i) => '<option value="' + i + '"' + (window._kpiCompare && i === window._kpiCompare.month ? ' selected' : '') + '>' + m + '</option>').join('');
  let cYearOpts = '';
  for (let y = currentYear - 5; y <= currentYear + 1; y++) {
    cYearOpts += '<option value="' + y + '"' + (window._kpiCompare && y === window._kpiCompare.year ? ' selected' : '') + '>' + y + '</option>';
  }
  
  const m = metrics;
  
  function statCard(label, value, tooltip, opts) {
    opts = opts || {};
    let compareHtml = '';
    if (compareMetrics && opts.compareKey) {
      const cv = compareMetrics[opts.compareKey];
      const pv = m[opts.compareKey];
      if (cv !== undefined && pv !== undefined && cv !== 0) {
        const pctChange = ((pv - cv) / Math.abs(cv) * 100);
        const arrow = pctChange > 0 ? '\u25b2' : pctChange < 0 ? '\u25bc' : '\u25ac';
        const color = (opts.invertColor ? pctChange < 0 : pctChange > 0) ? 'var(--success)' : pctChange === 0 ? 'var(--text-secondary)' : '#DC2626';
        compareHtml = '<div style="font-size:11px;color:' + color + ';font-weight:600;">' + arrow + ' ' + Math.abs(pctChange).toFixed(1) + '% vs compare</div>';
      }
    }
    const colorStyle = opts.color ? ' style="color:' + opts.color + ';"' : '';
    const subHtml = opts.sub ? '<div style="font-size:11px;color:var(--text-secondary);">' + opts.sub + '</div>' : '';
    return '<div class="stat-card kpi-tooltip-wrap" data-kpi-tooltip="' + escapeHtml(tooltip) + '"><div class="stat-label">' + label + '</div><div class="stat-value"' + colorStyle + '>' + value + '</div>' + subHtml + compareHtml + '</div>';
  }
  
  main.innerHTML = `
    <div class="page-header">
      <h1>KPI Dashboard</h1>
      <div class="page-header-actions">
        <button class="btn btn-secondary" onclick="openKPITargetsModal()" title="Edit KPI Targets" style="display:flex;align-items:center;gap:6px;"><span style="font-size:16px;">&#9881;</span> Targets</button>
        <button class="btn btn-secondary" onclick="exportKPItoCSV()">Export CSV</button>
        <button class="btn btn-secondary" onclick="exportKPIDashboardPDF()">Export PDF</button>
      </div>
    </div>
    
    <!-- Period Selector -->
    <div class="card" style="margin-bottom:16px;">
      <div style="display:flex;align-items:center;gap:16px;flex-wrap:wrap;">
        <div style="display:flex;align-items:center;gap:8px;">
          <label style="font-weight:600;font-size:13px;white-space:nowrap;">Viewing Period:</label>
          <select class="form-input" style="width:140px;" onchange="window._kpiPeriod.month=parseInt(this.value); renderKPIDashboard();">${monthOpts}</select>
          <select class="form-input" style="width:100px;" onchange="window._kpiPeriod.year=parseInt(this.value); renderKPIDashboard();">${yearOpts}</select>
        </div>
        <div style="display:flex;align-items:center;gap:8px;">
          <label style="font-size:13px;">
            <input type="checkbox" ${window._kpiShowCompare ? 'checked' : ''} onchange="window._kpiShowCompare=this.checked; if(!this.checked){window._kpiCompare=null;} else { window._kpiCompare={month:${pm > 0 ? pm - 1 : 11},year:${pm > 0 ? py : py - 1}}; } renderKPIDashboard();">
            Compare with:
          </label>
          ${window._kpiShowCompare ? '<select class="form-input" style="width:140px;" onchange="if(!window._kpiCompare)window._kpiCompare={month:0,year:' + (py-1) + '}; window._kpiCompare.month=parseInt(this.value); renderKPIDashboard();">' + cMonthOpts + '</select><select class="form-input" style="width:100px;" onchange="if(!window._kpiCompare)window._kpiCompare={month:0,year:' + (py-1) + '}; window._kpiCompare.year=parseInt(this.value); renderKPIDashboard();">' + cYearOpts + '</select>' : ''}
        </div>
        <button class="btn btn-secondary btn-sm" onclick="window._kpiPeriod={month:new Date().getMonth(),year:new Date().getFullYear()}; window._kpiCompare=null; window._kpiShowCompare=false; renderKPIDashboard();">Reset to Current</button>
      </div>
      <div style="margin-top:6px;font-size:12px;color:var(--text-secondary);">
        Showing: <strong>${monthNames[pm]} ${py}</strong>${compareMetrics ? ' vs <strong>' + monthNames[window._kpiCompare.month] + ' ' + window._kpiCompare.year + '</strong> (\u25b2 green = improvement, \u25bc red = decline)' : ''}
      </div>
    </div>

    <!-- Alerts -->
    ${(m.overdueCalCount > 0 || m.expiredCerts > 0 || m.expiringCerts > 0 || m.dueSoonCalCount > 0) ? `
    <div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:16px;">
      ${m.overdueCalCount > 0 ? '<div style="flex:1;min-width:200px;padding:10px 14px;background:#DC262615;border:1px solid #DC262640;border-radius:8px;color:#DC2626;font-weight:600;">\u26a0 ' + m.overdueCalCount + ' equipment overdue for calibration</div>' : ''}
      ${m.dueSoonCalCount > 0 ? '<div style="flex:1;min-width:200px;padding:10px 14px;background:#F59E0B15;border:1px solid #F59E0B40;border-radius:8px;color:#F59E0B;font-weight:600;">\u23f0 ' + m.dueSoonCalCount + ' calibration' + (m.dueSoonCalCount !== 1 ? 's' : '') + ' due soon</div>' : ''}
      ${m.expiredCerts > 0 ? '<div style="flex:1;min-width:200px;padding:10px 14px;background:#DC262615;border:1px solid #DC262640;border-radius:8px;color:#DC2626;font-weight:600;">\u26a0 ' + m.expiredCerts + ' expired certification' + (m.expiredCerts !== 1 ? 's' : '') + '</div>' : ''}
      ${m.expiringCerts > 0 ? '<div style="flex:1;min-width:200px;padding:10px 14px;background:#F59E0B15;border:1px solid #F59E0B40;border-radius:8px;color:#F59E0B;font-weight:600;">\u23f0 ' + m.expiringCerts + ' cert' + (m.expiringCerts !== 1 ? 's' : '') + ' expiring within 90 days</div>' : ''}
    </div>` : ''}

    <!-- Financial KPIs -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Financial Performance \u2014 ${monthNames[pm]} ${py}</div>
      <div class="dashboard-stats">
        ${statCard('Period Revenue', formatCurrency(m.periodRevenue), 'Revenue invoiced during the selected month. Compare across periods to spot trends.', {compareKey:'periodRevenue'})}
        ${statCard('YTD Revenue', formatCurrency(m.ytdRevenue), 'Year-to-Date Revenue: Total invoiced from January through the selected month of the selected year.', {compareKey:'ytdRevenue'})}
        ${(() => { const t = getKPITargets();
          const pColor = m.projectedMarginDisplay >= t.grossMarginMin ? 'var(--success)' : m.projectedMarginDisplay >= t.grossMarginWarn ? '#F59E0B' : 'var(--accent)';
          const aColor = m.actualMarginDisplay >= t.grossMarginMin ? 'var(--success)' : m.actualMarginDisplay >= t.grossMarginWarn ? '#F59E0B' : 'var(--accent)';
          const variance = m.actualMarginDisplay - m.projectedMarginDisplay;
          const varColor = variance >= 0 ? 'var(--success)' : 'var(--accent)';
          const pOverride = t.projectedMarginOverride !== null && t.projectedMarginOverride !== undefined && t.projectedMarginOverride !== '';
          const aOverride = t.actualMarginOverride !== null && t.actualMarginOverride !== undefined && t.actualMarginOverride !== '';
          return `<div class="stat-card kpi-tooltip-wrap" data-kpi-tooltip="Projected Margin is calculated from estimates (customer price vs internal cost). Actual Margin is calculated from completed jobs (invoiced revenue vs timesheet labor + receipt costs). Use the Targets modal to set manual overrides." style="grid-column:span 2;">
            <div class="stat-label" style="margin-bottom:8px;">Gross Margin Comparison</div>
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;">
              <div style="padding:10px 14px;border-radius:8px;background:var(--bg-secondary);border:1px solid var(--border);">
                <div style="font-size:11px;font-weight:600;opacity:0.6;margin-bottom:4px;">PROJECTED${pOverride ? ' (Override)' : ''}</div>
                <div style="font-size:24px;font-weight:800;color:${pColor};">${m.projectedMarginDisplay.toFixed(1)}%</div>
                <div style="font-size:11px;color:var(--text-secondary);margin-top:4px;">From estimates: ${formatCurrency(m.totalEstRevenue)} rev - ${formatCurrency(m.totalEstCost)} cost</div>
              </div>
              <div style="padding:10px 14px;border-radius:8px;background:var(--bg-secondary);border:1px solid var(--border);">
                <div style="font-size:11px;font-weight:600;opacity:0.6;margin-bottom:4px;">ACTUAL${aOverride ? ' (Override)' : ''}</div>
                <div style="font-size:24px;font-weight:800;color:${aColor};">${m.actualMarginDisplay.toFixed(1)}%</div>
                <div style="font-size:11px;color:var(--text-secondary);margin-top:4px;">Completed jobs: ${formatCurrency(m.actualRevenue)} rev - ${formatCurrency(m.actualTotalCost)} cost</div>
              </div>
            </div>
            <div style="display:flex;justify-content:space-between;align-items:center;margin-top:8px;padding-top:8px;border-top:1px solid var(--border);">
              <span style="font-size:12px;color:var(--text-secondary);">Variance: <strong style="color:${varColor};">${variance >= 0 ? '+' : ''}${variance.toFixed(1)}%</strong></span>
              <span style="font-size:11px;color:var(--text-secondary);">Target: ${t.grossMarginMin}-${t.grossMarginMax}%</span>
            </div>
          </div>`; })()}
        ${(() => { const t = getKPITargets(); return statCard('Eff. Billable Rate', formatCurrency(m.effectiveBillableRate) + '/hr', 'Effective Billable Rate: Revenue divided by billable hours for the period. Target: $' + t.billableRateTarget + '+/hr.', {compareKey:'effectiveBillableRate', sub:'Target: $' + t.billableRateTarget + '+'}); })()}
        ${statCard('Outstanding AR', formatCurrency(m.outstandingAmount), 'Outstanding Accounts Receivable: Total value of unpaid invoices as of the selected period.', {color: m.outstandingAmount > 0 ? '#F59E0B' : 'var(--success)', sub: m.outstandingCount + ' invoice' + (m.outstandingCount !== 1 ? 's' : '')})}
        ${(() => { const t = getKPITargets(); return statCard('Material Cost %', m.materialCostPct.toFixed(1) + '%', 'Material cost as percentage of revenue. Lower is better for service businesses. Target: under ' + t.materialCostMax + '%.', {compareKey:'materialCostPct', invertColor:true, sub:'Target: <' + t.materialCostMax + '%'}); })()}
      </div>
    </div>

    <!-- Operational KPIs -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Operational Metrics</div>
      <div class="dashboard-stats">
        ${(() => { const t = getKPITargets(); return statCard('Utilization Rate', m.utilizationRate.toFixed(1) + '%', 'Percentage of logged hours that are billable. Higher = more productive. Target: ' + t.utilizationTarget + '%+.', {color: m.utilizationRate >= t.utilizationTarget ? 'var(--success)' : '#F59E0B', compareKey:'utilizationRate', sub:'Target: ' + t.utilizationTarget + '%+'}); })()}
        ${statCard('Active Jobs', String(m.activeJobCount), 'Jobs currently In Progress or in Estimate status.')}
        ${statCard('Completed Jobs', String(m.completedJobCount), 'Jobs marked Completed or Closed.')}
        ${(() => { const t = getKPITargets(); return statCard('Win Rate', m.winRate.toFixed(1) + '%', 'Percentage of quotes accepted by customers. Target: ' + t.winRateTarget + '%+.', {color: m.winRate >= t.winRateTarget ? 'var(--success)' : '#F59E0B', compareKey:'winRate', sub: m.acceptedQuotes + '/' + m.totalQuotes + ' quotes | Target: ' + t.winRateTarget + '%+'}); })()}
        ${statCard('Period Hours', m.periodHours.toFixed(0), 'Total billable hours logged during the selected period.', {compareKey:'periodHours'})}
        ${statCard('Period Labor Cost', formatCurrency(m.periodLaborCost), 'Total labor cost for the selected period.', {compareKey:'periodLaborCost', invertColor:true})}
      </div>
    </div>

    <!-- Equipment & Compliance -->
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;">
      <div class="card">
        <div class="card-title"><div class="accent-bar"></div>Equipment & ROI</div>
        <div class="dashboard-stats">
          ${statCard('Total Equipment Value', formatCurrency(m.totalEquipValue), 'Sum of purchase costs for all equipment.')}
          ${(() => { const t = getKPITargets(); return statCard('Cal. Compliance', m.calCompliance.toFixed(0) + '%', 'Percentage of equipment NOT overdue for calibration. 100% = all current.', {color: m.calCompliance >= t.calComplianceGreen ? 'var(--success)' : m.calCompliance >= t.calComplianceWarn ? '#F59E0B' : '#DC2626'}); })()}
          ${statCard('ROI Recovery', m.overallRecoveryPct.toFixed(1) + '%', 'Percentage of target revenue recovered across all equipment.')}
          ${statCard('Total Recovered', formatCurrency(m.totalRecovered), 'Dollar amount recovered through job charges.')}
        </div>
      </div>
      <div class="card">
        <div class="card-title"><div class="accent-bar"></div>Safety & Compliance</div>
        <div class="dashboard-stats">
          ${(() => { const t = getKPITargets(); return statCard('Cert. Compliance', m.certCompliance.toFixed(0) + '%', 'Percentage of technician certifications that are NOT expired.', {color: m.certCompliance >= t.certComplianceGreen ? 'var(--success)' : m.certCompliance >= t.certComplianceWarn ? '#F59E0B' : '#DC2626'}); })()}
          ${statCard('Active Certs', String(m.activeCerts), 'Certifications currently valid.')}
          ${statCard('Technicians', String(m.techCount), 'Total registered technicians.')}
          ${statCard('Expired', String(m.expiredCerts), 'Certifications past expiration.', {color: m.expiredCerts > 0 ? '#DC2626' : 'var(--success)'})}
        </div>
      </div>
    </div>

    <!-- Forecasting -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Forecasting</div>
      <div class="dashboard-stats">
        ${statCard('Backlog Value', formatCurrency(m.backlogValue), 'Total estimated revenue from active/contracted jobs not yet complete.', {sub:'Contracted, not complete'})}
        ${statCard('Pipeline Value', formatCurrency(m.pipelineValue), 'Total value of outstanding quotes (draft or sent).', {sub:'Outstanding quotes'})}
        ${statCard('Projected Revenue', formatCurrency(m.projectedRevenue), 'Backlog + Pipeline weighted by Win Rate.', {color:'var(--accent)', sub:'Backlog + Pipeline \u00d7 Win Rate'})}
      </div>
    </div>

    <!-- Revenue Chart -->
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Monthly Revenue \u2014 ${py}${compareMetrics ? ' vs ' + window._kpiCompare.year : ''}</div>
      <div id="kpi-revenue-chart" style="height:220px;display:flex;align-items:flex-end;gap:6px;padding:20px 10px 30px;">
        ${(() => {
          const monthlyData = [];
          for (let i = 0; i < 12; i++) {
            const mKey = py + '-' + String(i+1).padStart(2,'0');
            const invoices = getDocuments('invoice');
            const mRev = invoices.filter(inv => (inv.date || '').startsWith(mKey)).reduce((s, inv) => s + (inv.total || 0), 0);
            let cRev = 0;
            if (compareMetrics && window._kpiCompare) {
              const cKey = window._kpiCompare.year + '-' + String(i+1).padStart(2,'0');
              cRev = invoices.filter(inv => (inv.date || '').startsWith(cKey)).reduce((s, inv) => s + (inv.total || 0), 0);
            }
            monthlyData.push({ label: monthNames[i].substring(0,3), value: mRev, compare: cRev });
          }
          const maxVal = Math.max(...monthlyData.map(d => Math.max(d.value, d.compare)), 1);
          return monthlyData.map((d, i) => {
            const h = Math.max((d.value / maxVal) * 170, 4);
            const ch = d.compare > 0 ? Math.max((d.compare / maxVal) * 170, 4) : 0;
            const isSelected = i === pm;
            const barColor = isSelected ? '#DC2626' : 'var(--accent)';
            let bars = '<div style="width:' + (compareMetrics ? '48%' : '100%') + ';height:' + h + 'px;background:' + barColor + ';border-radius:4px 4px 0 0;"></div>';
            if (compareMetrics) {
              bars += '<div style="width:48%;height:' + ch + 'px;background:#94A3B8;border-radius:4px 4px 0 0;opacity:0.6;"></div>';
            }
            return '<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:2px;">' +
              '<div style="font-size:9px;color:var(--text-secondary);">' + (d.value > 0 ? formatCurrency(d.value) : '') + '</div>' +
              '<div style="width:100%;display:flex;gap:2px;align-items:flex-end;justify-content:center;height:170px;">' + bars + '</div>' +
              '<div style="font-size:9px;color:' + (isSelected ? '#DC2626;font-weight:700' : 'var(--text-secondary)') + ';white-space:nowrap;">' + d.label + '</div></div>';
          }).join('');
        })()}
      </div>
      ${compareMetrics ? '<div style="display:flex;gap:16px;justify-content:center;font-size:11px;color:var(--text-secondary);"><span>\u25a0 <span style="color:var(--accent);">' + py + '</span></span><span>\u25a0 <span style="color:#94A3B8;">' + window._kpiCompare.year + '</span></span><span>\u25a0 <span style="color:#DC2626;">Selected month</span></span></div>' : ''}
    </div>

    <!-- Job Profitability -->
    ${m.jobProfitData.length > 0 ? `
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Job Profitability (Recent)</div>
      <div class="table-scroll">
        <table class="data-table">
          <thead><tr><th>Job</th><th style="text-align:right;">Profit</th><th style="text-align:right;">Margin</th></tr></thead>
          <tbody>
            ${m.jobProfitData.map(j => `
              <tr>
                <td>${escapeHtml(j.label)}</td>
                <td style="text-align:right;color:${j.profit >= 0 ? 'var(--success)' : '#DC2626'};font-weight:600;">${formatCurrency(j.profit)}</td>
                <td style="text-align:right;">${j.margin.toFixed(1)}%</td>
              </tr>`).join('')}
          </tbody>
        </table>
      </div>
    </div>` : ''}

    <!-- Employee KPIs -->
    <div class="card">
      <div class="card-title" style="display:flex;justify-content:space-between;align-items:center;">
        <div style="display:flex;align-items:center;gap:8px;"><div class="accent-bar"></div>Employee Performance</div>
        <button class="btn btn-secondary btn-sm" onclick="refreshKPIEmployeePerformance()" title="Refresh from active HR employees" style="font-size:11px;padding:4px 10px;">\u21BB Refresh</button>
      </div>
      <div id="kpi-emp-perf-filters"></div>
      <div id="kpi-emp-perf-content"></div>
    </div>
  `;
  // Initialize employee performance section
  refreshKPIEmployeePerformance();
}

function calculateKPIMetrics(month, year) {
  const jobs = getJobs();
  const estimates = getEstimates();
  const invoices = getDocuments('invoice');
  const timesheets = getTimesheets();
  const equipment = getDocuments('equipment');
  const techs = getTechnicians();
  const receipts = getReceipts();
  const quotes = getDocuments('quote');
  const pnls = getPnlStatements();
  
  const periodKey = year + '-' + String(month + 1).padStart(2, '0');
  
  const periodInvoices = invoices.filter(i => (i.date || '').startsWith(periodKey));
  const periodRevenue = periodInvoices.reduce((s, i) => s + (i.total || 0), 0);
  
  let ytdRevenue = 0;
  for (let m = 0; m <= month; m++) {
    const mKey = year + '-' + String(m + 1).padStart(2, '0');
    ytdRevenue += invoices.filter(i => (i.date || '').startsWith(mKey)).reduce((s, i) => s + (i.total || 0), 0);
  }
  
  const totalEstCost = estimates.reduce((s, e) => s + (e.totalCost || 0), 0);
  const totalEstRevenue = estimates.reduce((s, e) => s + (e.totalCustomerPrice || 0), 0);
  const grossMargin = totalEstRevenue > 0 ? ((totalEstRevenue - totalEstCost) / totalEstRevenue * 100) : 0;

  // Actual Margin: from completed jobs — invoiced revenue vs actual costs (timesheets + receipts)
  const completedJobIds = jobs.filter(j => j.status === 'completed' || j.status === 'closed').map(j => j.id);
  const completedInvoices = invoices.filter(i => completedJobIds.includes(i.jobId));
  const completedTimesheets = timesheets.filter(t => completedJobIds.includes(t.jobId));
  const completedReceipts = receipts.filter(r => completedJobIds.includes(r.jobId));
  const actualRevenue = completedInvoices.reduce((s, i) => s + (i.total || 0), 0);
  const actualLaborCost = completedTimesheets.reduce((s, t) => s + (t.totalCost || 0), 0);
  const actualMaterialCost = completedReceipts.reduce((s, r) => s + (r.amount || 0), 0);
  const actualTotalCost = actualLaborCost + actualMaterialCost;
  const actualGrossMargin = actualRevenue > 0 ? ((actualRevenue - actualTotalCost) / actualRevenue * 100) : 0;

  // Apply manual overrides if set
  const kpiT = getKPITargets();
  const projectedMarginDisplay = kpiT.projectedMarginOverride !== null && kpiT.projectedMarginOverride !== undefined && kpiT.projectedMarginOverride !== '' ? parseFloat(kpiT.projectedMarginOverride) : grossMargin;
  const actualMarginDisplay = kpiT.actualMarginOverride !== null && kpiT.actualMarginOverride !== undefined && kpiT.actualMarginOverride !== '' ? parseFloat(kpiT.actualMarginOverride) : actualGrossMargin;
  
  const periodTimesheets = timesheets.filter(t => (t.date || '').startsWith(periodKey));
  const periodHours = periodTimesheets.reduce((s, t) => s + getTimesheetTotalHours(t), 0);
  const periodLaborCost = periodTimesheets.reduce((s, t) => s + (t.totalCost || 0), 0);
  
  const totalBillableHours = timesheets.reduce((s, t) => s + getTimesheetTotalHours(t), 0);
  const totalRevenue = invoices.reduce((s, i) => s + (i.total || 0), 0);
  const effectiveBillableRate = totalBillableHours > 0 ? totalRevenue / totalBillableHours : 0;
  
  const periodReceipts = receipts.filter(r => (r.date || '').startsWith(periodKey));
  const periodReceiptsCost = periodReceipts.reduce((s, r) => s + (r.amount || 0), 0);
  const materialCostPct = periodRevenue > 0 ? (periodReceiptsCost / periodRevenue * 100) : 0;
  
  const outstandingInvoices = invoices.filter(i => i.status !== 'paid');
  const outstandingAmount = outstandingInvoices.reduce((s, i) => s + (i.total || 0), 0);
  const outstandingCount = outstandingInvoices.length;
  
  const totalAvailableHours = periodTimesheets.reduce((s, t) => s + getTimesheetTotalHours(t), 0);
  const utilizationRate = totalAvailableHours > 0 ? (periodHours / totalAvailableHours * 100) : 0;
  
  const activeJobs = jobs.filter(j => j.status === 'in-progress' || j.status === 'estimate');
  const completedJobs = jobs.filter(j => j.status === 'completed' || j.status === 'closed');
  
  const totalQuotes = quotes.length;
  const acceptedQuotes = quotes.filter(q => q.status === 'accepted' || q.status === 'approved').length;
  const winRate = totalQuotes > 0 ? (acceptedQuotes / totalQuotes * 100) : 0;
  
  const totalEquipValue = equipment.reduce((s, e) => s + (e.purchaseCost || 0), 0);
  const overdueCalCount = equipment.filter(e => getCalibrationStatus(e).status === 'overdue').length;
  const dueSoonCalCount = equipment.filter(e => getCalibrationStatus(e).status === 'due-soon').length;
  const calCompliance = equipment.length > 0 ? ((equipment.length - overdueCalCount) / equipment.length * 100) : 100;
  const totalRecovered = equipment.reduce((s, e) => s + (e.totalRevenueRecovered || 0), 0);
  const totalTargetRev = equipment.reduce((s, e) => {
    const cost = (e.purchaseCost || 0) + ((e.annualMaintenanceCost || 0) * (e.usefulLifeYears || 7));
    return s + cost * (1 + (e.targetRoiPercent || 15) / 100);
  }, 0);
  const overallRecoveryPct = totalTargetRev > 0 ? (totalRecovered / totalTargetRev * 100) : 0;
  
  const allCerts = techs.flatMap(t => (t.certifications || []));
  const expiredCerts = allCerts.filter(c => getCertStatus(c).status === 'expired').length;
  const expiringCerts = allCerts.filter(c => getCertStatus(c).status === 'expiring-soon').length;
  const certCompliance = allCerts.length > 0 ? ((allCerts.length - expiredCerts) / allCerts.length * 100) : 100;
  
  const backlogValue = activeJobs.reduce((s, j) => {
    const ests = estimates.filter(e => e.jobId === j.id);
    return s + ests.reduce((ss, e) => ss + (e.totalCustomerPrice || 0), 0);
  }, 0);
  const pipelineValue = quotes.filter(q => !q.status || q.status === 'draft' || q.status === 'sent').reduce((s, q) => s + (q.total || 0), 0);
  const projectedRevenue = backlogValue + (pipelineValue * (winRate / 100 || 0.5));
  
  const jobProfitData = completedJobs.slice(-10).map(j => {
    const pnl = pnls.find(p => p.jobId === j.id);
    return {
      label: j.jobNumber,
      profit: pnl ? (pnl.actualProfit || pnl.estimatedProfit || 0) : 0,
      margin: pnl ? ((pnl.profitMargin || 0) * 100) : 0,
    };
  });
  
  return {
    periodRevenue, ytdRevenue, grossMargin, effectiveBillableRate,
    actualGrossMargin, projectedMarginDisplay, actualMarginDisplay,
    actualRevenue, actualTotalCost, actualLaborCost, actualMaterialCost,
    totalEstRevenue, totalEstCost,
    outstandingAmount, outstandingCount, materialCostPct,
    utilizationRate, activeJobCount: activeJobs.length, completedJobCount: completedJobs.length,
    winRate, acceptedQuotes, totalQuotes, periodHours, periodLaborCost,
    totalEquipValue, calCompliance, overallRecoveryPct, totalRecovered,
    overdueCalCount, dueSoonCalCount,
    certCompliance, activeCerts: allCerts.length - expiredCerts, techCount: techs.length,
    expiredCerts, expiringCerts,
    backlogValue, pipelineValue, projectedRevenue,
    jobProfitData,
  };
}

function exportKPItoCSV() {
  if (!window._kpiPeriod) {
    const now = new Date();
    window._kpiPeriod = { month: now.getMonth(), year: now.getFullYear() };
  }
  const m = calculateKPIMetrics(window._kpiPeriod.month, window._kpiPeriod.year);
  const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const period = monthNames[window._kpiPeriod.month] + ' ' + window._kpiPeriod.year;
  
  let csv = 'KPI Dashboard Export - ' + period + '\n\n';
  csv += 'Category,Metric,Value\n';
  csv += 'Financial,Period Revenue,' + m.periodRevenue.toFixed(2) + '\n';
  csv += 'Financial,YTD Revenue,' + m.ytdRevenue.toFixed(2) + '\n';
  csv += 'Financial,Gross Margin (%),' + m.grossMargin.toFixed(1) + '\n';
  csv += 'Financial,Effective Billable Rate,' + m.effectiveBillableRate.toFixed(2) + '\n';
  csv += 'Financial,Outstanding AR,' + m.outstandingAmount.toFixed(2) + '\n';
  csv += 'Financial,Material Cost (%),' + m.materialCostPct.toFixed(1) + '\n';
  csv += 'Operational,Utilization Rate (%),' + m.utilizationRate.toFixed(1) + '\n';
  csv += 'Operational,Active Jobs,' + m.activeJobCount + '\n';
  csv += 'Operational,Completed Jobs,' + m.completedJobCount + '\n';
  csv += 'Operational,Win Rate (%),' + m.winRate.toFixed(1) + '\n';
  csv += 'Operational,Period Hours,' + m.periodHours.toFixed(0) + '\n';
  csv += 'Operational,Period Labor Cost,' + m.periodLaborCost.toFixed(2) + '\n';
  csv += 'Equipment,Total Equipment Value,' + m.totalEquipValue.toFixed(2) + '\n';
  csv += 'Equipment,Calibration Compliance (%),' + m.calCompliance.toFixed(0) + '\n';
  csv += 'Equipment,ROI Recovery (%),' + m.overallRecoveryPct.toFixed(1) + '\n';
  csv += 'Equipment,Total Recovered,' + m.totalRecovered.toFixed(2) + '\n';
  csv += 'Compliance,Certification Compliance (%),' + m.certCompliance.toFixed(0) + '\n';
  csv += 'Compliance,Active Certifications,' + m.activeCerts + '\n';
  csv += 'Compliance,Technicians,' + m.techCount + '\n';
  csv += 'Compliance,Expired Certifications,' + m.expiredCerts + '\n';
  csv += 'Forecasting,Backlog Value,' + m.backlogValue.toFixed(2) + '\n';
  csv += 'Forecasting,Pipeline Value,' + m.pipelineValue.toFixed(2) + '\n';
  csv += 'Forecasting,Projected Revenue,' + m.projectedRevenue.toFixed(2) + '\n';
  
  if (window._kpiCompare) {
    const cm = calculateKPIMetrics(window._kpiCompare.month, window._kpiCompare.year);
    const cPeriod = monthNames[window._kpiCompare.month] + ' ' + window._kpiCompare.year;
    csv += '\nComparison Period: ' + cPeriod + '\n';
    csv += 'Category,Metric,Compare Value,Change (%)\n';
    const pairs = [
      ['Financial','Period Revenue', cm.periodRevenue, m.periodRevenue],
      ['Financial','YTD Revenue', cm.ytdRevenue, m.ytdRevenue],
      ['Financial','Gross Margin', cm.grossMargin, m.grossMargin],
      ['Operational','Utilization Rate', cm.utilizationRate, m.utilizationRate],
      ['Operational','Win Rate', cm.winRate, m.winRate],
      ['Operational','Period Hours', cm.periodHours, m.periodHours],
    ];
    pairs.forEach(([cat, name, cv, pv]) => {
      const pct = cv !== 0 ? ((pv - cv) / Math.abs(cv) * 100).toFixed(1) : 'N/A';
      csv += cat + ',' + name + ',' + cv.toFixed(2) + ',' + pct + '\n';
    });
  }
  
  csv += '\nMonthly Revenue - ' + window._kpiPeriod.year + '\n';
  csv += 'Month,Revenue\n';
  const invoices = getDocuments('invoice');
  for (let i = 0; i < 12; i++) {
    const mKey = window._kpiPeriod.year + '-' + String(i+1).padStart(2,'0');
    const rev = invoices.filter(inv => (inv.date || '').startsWith(mKey)).reduce((s, inv) => s + (inv.total || 0), 0);
    csv += monthNames[i] + ',' + rev.toFixed(2) + '\n';
  }
  
  const blob = new Blob([csv], { type: 'text/csv' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'KPI_Dashboard_' + monthNames[window._kpiPeriod.month] + '_' + window._kpiPeriod.year + '.csv';
  a.click();
  URL.revokeObjectURL(url);
  showToast('KPI data exported to CSV', 'success');
}

function exportKPIDashboardPDF() {
  if (!window._kpiPeriod) {
    const now = new Date();
    window._kpiPeriod = { month: now.getMonth(), year: now.getFullYear() };
  }
  const m = calculateKPIMetrics(window._kpiPeriod.month, window._kpiPeriod.year);
  const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const period = monthNames[window._kpiPeriod.month] + ' ' + window._kpiPeriod.year;
  const company = getCompany();
  const theme = getActiveTheme();
  const doc = new jspdf.jsPDF('p', 'mm', 'letter');
  const pageW = doc.internal.pageSize.getWidth();
  const pageH = doc.internal.pageSize.getHeight();
  const margin = 20;
  
  const colors = theme.colors;
  doc.setFillColor(...hexToRgb(colors.bg));
  doc.rect(0, 0, pageW, pageH, 'F');
  pdfAddHeader(doc, theme, company, 'KPI DASHBOARD', period, pageW);
  
  let y = 50;
  
  function addSection(title, items) {
    if (y > pageH - 60) {
      doc.addPage();
      doc.setFillColor(...hexToRgb(colors.bg));
      doc.rect(0, 0, pageW, pageH, 'F');
      y = 30;
    }
    doc.setFontSize(12);
    doc.setTextColor(...hexToRgb(colors.accent));
    doc.setFont('helvetica', 'bold');
    doc.text(title, margin, y);
    y += 7;
    doc.setFontSize(9);
    doc.setTextColor(...hexToRgb(colors.text));
    doc.setFont('helvetica', 'normal');
    items.forEach(item => {
      if (y > pageH - 25) {
        doc.addPage();
        doc.setFillColor(...hexToRgb(colors.bg));
        doc.rect(0, 0, pageW, pageH, 'F');
        y = 30;
      }
      doc.text(item[0] + ':', margin, y);
      doc.setFont('helvetica', 'bold');
      doc.text(item[1], margin + 60, y);
      doc.setFont('helvetica', 'normal');
      y += 5;
    });
    y += 5;
  }
  
  addSection('Financial Performance', [
    ['Period Revenue', formatCurrency(m.periodRevenue)],
    ['YTD Revenue', formatCurrency(m.ytdRevenue)],
    ['Gross Margin', m.grossMargin.toFixed(1) + '%'],
    ['Eff. Billable Rate', formatCurrency(m.effectiveBillableRate) + '/hr'],
    ['Outstanding AR', formatCurrency(m.outstandingAmount)],
    ['Material Cost %', m.materialCostPct.toFixed(1) + '%'],
  ]);
  
  addSection('Operational Metrics', [
    ['Utilization Rate', m.utilizationRate.toFixed(1) + '%'],
    ['Active Jobs', String(m.activeJobCount)],
    ['Completed Jobs', String(m.completedJobCount)],
    ['Win Rate', m.winRate.toFixed(1) + '%'],
    ['Period Hours', m.periodHours.toFixed(0)],
    ['Period Labor Cost', formatCurrency(m.periodLaborCost)],
  ]);
  
  addSection('Equipment & ROI', [
    ['Total Equipment Value', formatCurrency(m.totalEquipValue)],
    ['Calibration Compliance', m.calCompliance.toFixed(0) + '%'],
    ['ROI Recovery', m.overallRecoveryPct.toFixed(1) + '%'],
    ['Total Recovered', formatCurrency(m.totalRecovered)],
  ]);
  
  addSection('Safety & Compliance', [
    ['Cert. Compliance', m.certCompliance.toFixed(0) + '%'],
    ['Active Certifications', String(m.activeCerts)],
    ['Expired', String(m.expiredCerts)],
  ]);
  
  addSection('Forecasting', [
    ['Backlog Value', formatCurrency(m.backlogValue)],
    ['Pipeline Value', formatCurrency(m.pipelineValue)],
    ['Projected Revenue', formatCurrency(m.projectedRevenue)],
  ]);
  
  // Footer on all pages
  const totalPages = doc.internal.getNumberOfPages();
  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i);
    doc.setDrawColor(...hexToRgb(colors.accent));
    doc.setLineWidth(0.5);
    doc.line(margin, pageH - 18, pageW - margin, pageH - 18);
    doc.setFontSize(8);
    doc.setTextColor(...hexToRgb(colors.textSecondary));
    doc.text('Page ' + i + ' of ' + totalPages, pageW - margin, pageH - 12, { align: 'right' });
    doc.text(company.name + ' | KPI Dashboard', margin, pageH - 12);
  }
  
  doc.save('KPI_Dashboard_' + monthNames[window._kpiPeriod.month] + '_' + window._kpiPeriod.year + '.pdf');
  showToast('KPI Dashboard PDF exported!', 'success');
}
// ============================================================
// SIDEBAR DRAG-TO-REORDER
// ============================================================
function initSidebarDragReorder() {
  const savedOrder = localStorage.getItem('psva_sidebar_order');
  if (savedOrder) {
    try {
      const order = JSON.parse(savedOrder);
      applySidebarOrder(order);
    } catch(e) {}
  }
  setupDragListeners();
}

function getSidebarGroups() {
  // Each group is defined by a nav-section-label followed by nav-items until the next label
  const nav = document.querySelector('.sidebar-nav');
  if (!nav) return [];
  const groups = [];
  let currentGroup = null;
  Array.from(nav.children).forEach(child => {
    if (child.classList.contains('nav-section-label')) {
      currentGroup = { label: child.textContent.trim(), labelEl: child, items: [] };
      groups.push(currentGroup);
    } else if (child.classList.contains('nav-item') && currentGroup) {
      currentGroup.items.push(child);
    }
  });
  return groups;
}

function applySidebarOrder(order) {
  const nav = document.querySelector('.sidebar-nav');
  if (!nav) return;
  const groups = getSidebarGroups();

  groups.forEach(group => {
    const groupOrder = order[group.label];
    if (!groupOrder || !Array.isArray(groupOrder)) return;

    // Sort items according to saved order
    const itemMap = {};
    group.items.forEach(item => {
      const page = item.getAttribute('data-page');
      if (page) itemMap[page] = item;
    });

    // Re-insert items in saved order after the label element
    let insertAfter = group.labelEl;
    groupOrder.forEach(page => {
      if (itemMap[page]) {
        insertAfter.after(itemMap[page]);
        insertAfter = itemMap[page];
        delete itemMap[page];
      }
    });
    // Append any remaining items not in saved order
    Object.values(itemMap).forEach(item => {
      insertAfter.after(item);
      insertAfter = item;
    });
  });
}

function saveSidebarOrder() {
  const groups = getSidebarGroups();
  const order = {};
  groups.forEach(group => {
    order[group.label] = group.items.map(item => item.getAttribute('data-page'));
  });
  localStorage.setItem('psva_sidebar_order', JSON.stringify(order));
}

let draggedItem = null;
let draggedGroup = null;

function setupDragListeners() {
  const nav = document.querySelector('.sidebar-nav');
  if (!nav) return;

  // Add drag handles and make items draggable
  const groups = getSidebarGroups();
  groups.forEach(group => {
    group.items.forEach(item => {
      item.setAttribute('draggable', 'true');

      // Add drag handle if not already present
      if (!item.querySelector('.drag-handle')) {
        const handle = document.createElement('span');
        handle.className = 'drag-handle';
        handle.innerHTML = '⠿';
        handle.title = 'Drag to reorder';
        item.insertBefore(handle, item.firstChild);
      }

      item.addEventListener('dragstart', (e) => {
        draggedItem = item;
        // Find which group this item belongs to
        draggedGroup = groups.find(g => g.items.includes(item));
        item.classList.add('dragging');
        e.dataTransfer.effectAllowed = 'move';
        e.dataTransfer.setData('text/plain', item.getAttribute('data-page'));
      });

      item.addEventListener('dragend', () => {
        item.classList.remove('dragging');
        document.querySelectorAll('.nav-item.drag-over').forEach(el => el.classList.remove('drag-over'));
        draggedItem = null;
        draggedGroup = null;
      });

      item.addEventListener('dragover', (e) => {
        e.preventDefault();
        if (!draggedItem || draggedItem === item) return;

        // Only allow reorder within the same group
        const targetGroup = groups.find(g => g.items.includes(item));
        if (!targetGroup || targetGroup !== draggedGroup) return;

        e.dataTransfer.dropEffect = 'move';
        item.classList.add('drag-over');
      });

      item.addEventListener('dragleave', () => {
        item.classList.remove('drag-over');
      });

      item.addEventListener('drop', (e) => {
        e.preventDefault();
        item.classList.remove('drag-over');
        if (!draggedItem || draggedItem === item) return;

        // Only allow reorder within the same group
        const targetGroup = groups.find(g => g.items.includes(item));
        if (!targetGroup || targetGroup !== draggedGroup) return;

        // Determine if we should insert before or after
        const rect = item.getBoundingClientRect();
        const midY = rect.top + rect.height / 2;
        if (e.clientY < midY) {
          item.parentNode.insertBefore(draggedItem, item);
        } else {
          item.parentNode.insertBefore(draggedItem, item.nextSibling);
        }

        // Update the group's items array
        targetGroup.items = Array.from(item.parentNode.querySelectorAll('.nav-item')).filter(el => {
          return targetGroup.items.includes(el) || el === draggedItem;
        });

        saveSidebarOrder();
        showToast('Sidebar order saved', 'success');
      });
    });
  });
}


// ============================================================
// INIT
// ============================================================
function init() {
  loadState();
preloadDefaultLogos();
  document.body.classList.toggle('light-mode', !isDarkMode);
  const toggle = document.getElementById('themeToggle');
  if (toggle) toggle.classList.toggle('active', !isDarkMode);
  updateSidebarLogo();

  // Set home page from settings
  const company = getCompany();
  currentPage = company.homePage || 'jobs';

  // Bind navigation
  document.querySelectorAll('.nav-item').forEach(el => {
    el.addEventListener('click', () => {
      const page = el.getAttribute('data-page');
      if (page) showPage(page);
    });
  });

  // Highlight current nav
  const navEl = document.querySelector(`.nav-item[data-page="${currentPage}"]`);
  if (navEl) navEl.classList.add('active');

  renderPage();
  initSidebarDragReorder();
}

