// WORK ORDERS
// ============================================================
function getWorkOrders() { return getDocuments('workorders'); }

function getDefaultWorkOrder(jobId) {
  const company = getCompany();
  const job = jobId ? getJobById(jobId) : null;
  return {
    id: generateId(), docNumber: generateNumber('WO'), date: todayStr(),
    jobId: jobId || '',
    customer: job ? { ...job.customer } : { name: '', company: '', phone: '', email: '', address: '' },
    description: '', projectName: job ? job.name : '',
    items: [{ item: 1, description: '', qty: 1, unit: 'Each', unitPrice: 0, taxable: false }],
    scheduledStart: '', scheduledEnd: '',
    assignedTech: '',
    priority: 'normal',
    status: 'draft',
    taxRate: company.taxRate || 0, subtotal: 0, taxAmount: 0, total: 0,
    notes: '',
  };
}

function renderWorkOrderEditor(wo) {
  window._currentWO = wo;
  window._woLineItems = wo.items.map(li => ({...li}));
  const main = document.querySelector('.main-content');
  const backAction = wo.jobId ? `openJobDashboard('${wo.jobId}')` : `showPage('work-orders')`;
  const techs = getDocuments('technicians');
  const techOptions = techs.map(t => `<option value="${escapeHtml(t.name)}" ${wo.assignedTech === t.name ? 'selected' : ''}>${escapeHtml(t.name)}</option>`).join('');

  main.innerHTML = `
    <div class="page-header">
      <div style="display:flex;align-items:center;gap:12px;">
        <button class="btn-icon" onclick="${backAction}" title="Back">←</button>
        <h1>Edit Work Order</h1>
      </div>
      <div class="page-header-actions">
        <button class="btn btn-secondary" onclick="saveCurrentWO()">Save Draft</button>
        <button class="btn btn-primary" onclick="exportWorkOrderPDF()">Export PDF</button>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Work Order Information</div>
      <div class="form-grid">
        <div class="form-group"><label class="form-label">WO Number</label><input class="form-input" id="wo-docNumber" value="${escapeHtml(wo.docNumber)}"></div>
        <div class="form-group"><label class="form-label">Date</label><input class="form-input" type="date" id="wo-date" value="${wo.date}"></div>
        <div class="form-group"><label class="form-label">Job</label>${buildJobSelector('wo-job', wo.jobId, true)}</div>
        <div class="form-group"><label class="form-label">Project Name</label><input class="form-input" id="wo-projectName" value="${escapeHtml(wo.projectName)}"></div>
        <div class="form-group"><label class="form-label">Priority</label>
          <select class="form-select" id="wo-priority">
            <option value="normal" ${wo.priority==='normal'?'selected':''}>Normal</option>
            <option value="high" ${wo.priority==='high'?'selected':''}>High</option>
            <option value="urgent" ${wo.priority==='urgent'?'selected':''}>Urgent</option>
          </select>
        </div>
        <div class="form-group"><label class="form-label">Status</label>
          <select class="form-select" id="wo-status">
            <option value="draft" ${wo.status==='draft'?'selected':''}>Draft</option>
            <option value="issued" ${wo.status==='issued'?'selected':''}>Issued</option>
            <option value="in-progress" ${wo.status==='in-progress'?'selected':''}>In Progress</option>
            <option value="completed" ${wo.status==='completed'?'selected':''}>Completed</option>
          </select>
        </div>
        <div class="form-group"><label class="form-label">Scheduled Start</label><input class="form-input" type="date" id="wo-scheduledStart" value="${wo.scheduledStart}"></div>
        <div class="form-group"><label class="form-label">Scheduled End</label><input class="form-input" type="date" id="wo-scheduledEnd" value="${wo.scheduledEnd}"></div>
        <div class="form-group"><label class="form-label">Assigned Technician</label>
          <select class="form-select" id="wo-assignedTech">
            <option value="">— Select —</option>
            ${techOptions}
          </select>
        </div>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Customer Information</div>
      <div class="form-grid">
        <div class="form-group"><label class="form-label">Contact Name</label><input class="form-input" id="wo-customerName" value="${escapeHtml(wo.customer.name)}"></div>
        <div class="form-group"><label class="form-label">Company</label><input class="form-input" id="wo-customerCompany" value="${escapeHtml(wo.customer.company)}"></div>
        <div class="form-group"><label class="form-label">Phone</label><input class="form-input" id="wo-customerPhone" value="${escapeHtml(wo.customer.phone)}"></div>
        <div class="form-group"><label class="form-label">Email</label><input class="form-input" id="wo-customerEmail" value="${escapeHtml(wo.customer.email)}"></div>
        <div class="form-group full-width"><label class="form-label">Address</label><input class="form-input" id="wo-customerAddress" value="${escapeHtml(wo.customer.address)}"></div>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Scope of Work</div>
      <textarea class="form-textarea" id="wo-description" rows="4" placeholder="Describe the work to be performed...">${escapeHtml(wo.description)}</textarea>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Line Items</div>
      <div class="table-scroll"><table class="line-items-table"><thead><tr>
        <th class="col-item">#</th><th class="col-desc">Description</th><th class="col-qty">Qty</th><th class="col-unit">Unit</th><th class="col-price">Unit Price</th><th class="col-tax">Tax</th><th class="col-ext">Extended</th><th class="col-actions"></th>
      </tr></thead><tbody id="wo-line-items"></tbody></table></div>
      <button class="btn btn-secondary btn-sm" style="margin-top:12px;" onclick="addWOLineItem()">+ Add Line Item</button>
      <div class="tax-rate-input" style="margin-top:12px;"><label class="form-label">Tax Rate:</label><input class="form-input" id="wo-taxRate" type="number" value="${wo.taxRate}" min="0" step="0.1" onchange="recalcWO()"><span>%</span></div>
    </div>
    <div class="totals-section">
      <div class="totals-table">
        <div class="totals-row"><span class="label">Subtotal:</span><span class="value" id="wo-subtotal">$0.00</span></div>
        <div class="totals-row"><span class="label">Sales Tax:</span><span class="value" id="wo-taxAmount">$0.00</span></div>
        <div class="totals-row total"><span class="label">Total:</span><span class="value" id="wo-total">$0.00</span></div>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Notes</div>
      <textarea class="form-textarea" id="wo-notes" rows="3">${escapeHtml(wo.notes)}</textarea>
    </div>
  `;
  renderWOLineItems();
}

function renderWOLineItems() {
  const tbody = document.getElementById('wo-line-items');
  if (!tbody) return;
  tbody.innerHTML = window._woLineItems.map((li, i) => `
    <tr>
      <td>${i + 1}</td>
      <td><input class="form-input" value="${escapeHtml(li.description)}" onchange="window._woLineItems[${i}].description=this.value"></td>
      <td><input class="form-input" type="number" value="${li.qty}" min="0" step="0.01" onchange="window._woLineItems[${i}].qty=parseFloat(this.value)||0;recalcWO()"></td>
      <td><input class="form-input" value="${escapeHtml(li.unit)}" onchange="window._woLineItems[${i}].unit=this.value"></td>
      <td><input class="form-input" type="number" value="${li.unitPrice}" min="0" step="0.01" onchange="window._woLineItems[${i}].unitPrice=parseFloat(this.value)||0;recalcWO()"></td>
      <td><input type="checkbox" ${li.taxable ? 'checked' : ''} onchange="window._woLineItems[${i}].taxable=this.checked;recalcWO()"></td>
      <td class="ext-price">${formatCurrency((li.qty || 0) * (li.unitPrice || 0))}</td>
      <td><button class="btn-icon" onclick="window._woLineItems.splice(${i},1);renderWOLineItems()">🗑</button></td>
    </tr>
  `).join('');
  recalcWO();
}

function addWOLineItem() {
  window._woLineItems.push({ item: window._woLineItems.length + 1, description: '', qty: 1, unit: 'Each', unitPrice: 0, taxable: false });
  renderWOLineItems();
}

function recalcWO() {
  const taxRate = parseFloat(document.getElementById('wo-taxRate')?.value) || 0;
  let subtotal = 0, taxable = 0;
  window._woLineItems.forEach(li => {
    const ext = (li.qty || 0) * (li.unitPrice || 0);
    subtotal += ext;
    if (li.taxable) taxable += ext;
  });
  const taxAmount = taxable * (taxRate / 100);
  const total = subtotal + taxAmount;
  const el = id => document.getElementById(id);
  if (el('wo-subtotal')) el('wo-subtotal').textContent = formatCurrency(subtotal);
  if (el('wo-taxAmount')) el('wo-taxAmount').textContent = formatCurrency(taxAmount);
  if (el('wo-total')) el('wo-total').textContent = formatCurrency(total);
}

function collectWOData() {
  const wo = { ...window._currentWO };
  wo.docNumber = document.getElementById('wo-docNumber')?.value || wo.docNumber;
  wo.date = document.getElementById('wo-date')?.value || wo.date;
  wo.jobId = resolveJobId('wo-job', 'Work Order', wo);
  wo.projectName = document.getElementById('wo-projectName')?.value || '';
  wo.priority = document.getElementById('wo-priority')?.value || 'normal';
  wo.status = document.getElementById('wo-status')?.value || 'draft';
  wo.scheduledStart = document.getElementById('wo-scheduledStart')?.value || '';
  wo.scheduledEnd = document.getElementById('wo-scheduledEnd')?.value || '';
  wo.assignedTech = document.getElementById('wo-assignedTech')?.value || '';
  wo.customer = {
    name: document.getElementById('wo-customerName')?.value || '',
    company: document.getElementById('wo-customerCompany')?.value || '',
    phone: document.getElementById('wo-customerPhone')?.value || '',
    email: document.getElementById('wo-customerEmail')?.value || '',
    address: document.getElementById('wo-customerAddress')?.value || '',
  };
  wo.description = document.getElementById('wo-description')?.value || '';
  wo.items = window._woLineItems.map((li, i) => ({ ...li, item: i + 1 }));
  wo.taxRate = parseFloat(document.getElementById('wo-taxRate')?.value) || 0;
  let subtotal = 0, taxable = 0;
  wo.items.forEach(li => { const ext = (li.qty||0)*(li.unitPrice||0); subtotal += ext; if (li.taxable) taxable += ext; });
  wo.subtotal = subtotal;
  wo.taxAmount = taxable * (wo.taxRate / 100);
  wo.total = subtotal + wo.taxAmount;
  wo.notes = document.getElementById('wo-notes')?.value || '';
  return wo;
}

function saveCurrentWO() {
  const wo = collectWOData();
  saveDocument('workorders', wo);
  editingDocId = wo.id;
  window._currentWO = wo;
  showToast('Work order saved!');
}

async function exportWorkOrderPDF() {
  const data = collectWOData();
  saveDocument('workorders', data);
  editingDocId = data.id;

  const { jsPDF } = window.jspdf;
  const theme = getActiveTheme();
  const colors = theme.colors;
  const company = getCompany();
  const doc = new jsPDF('p', 'mm', 'letter');
  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();

  doc.setFillColor(...hexToRgb(colors.bg));
  doc.rect(0, 0, pageWidth, pageHeight, 'F');

  let y = pdfAddHeader(doc, theme, company, 'WORK ORDER', data.docNumber, pageWidth);

  // Meta info
  doc.setFontSize(9); doc.setTextColor(...hexToRgb(colors.textSecondary));
  y = pdfDrawMeta(doc, [
    `Date: ${formatDate(data.date)}`,
    data.scheduledStart ? `Start: ${formatDate(data.scheduledStart)}` : '',
    data.scheduledEnd ? `End: ${formatDate(data.scheduledEnd)}` : '',
    data.assignedTech ? `Tech: ${data.assignedTech}` : ''
  ], 15, y, pageWidth - 30, theme);

  // Customer
  doc.setDrawColor(...hexToRgb(colors.accent)); doc.setLineWidth(0.4);
  doc.line(15, y, 25, y); y += 4;
  doc.setFontSize(8); doc.setFont('helvetica', 'bold');
  doc.setTextColor(...hexToRgb(colors.accent));
  doc.text('CUSTOMER', 15, y); y += 5;
  doc.setFont('helvetica', 'normal'); doc.setFontSize(9);
  doc.setTextColor(...hexToRgb(colors.text));
  if (data.customer.name) { doc.text(data.customer.name, 15, y); y += 4; }
  if (data.customer.company) { doc.text(data.customer.company, 15, y); y += 4; }
  if (data.customer.phone || data.customer.email) { doc.text([data.customer.phone, data.customer.email].filter(Boolean).join(' | '), 15, y); y += 4; }
  if (data.customer.address) { doc.text(data.customer.address, 15, y); y += 4; }
  y += 4;

  // Scope of work
  if (data.description) {
    doc.setDrawColor(...hexToRgb(colors.accent)); doc.setLineWidth(0.4);
    doc.line(15, y, 25, y); y += 4;
    doc.setFontSize(8); doc.setFont('helvetica', 'bold');
    doc.setTextColor(...hexToRgb(colors.accent));
    doc.text('SCOPE OF WORK', 15, y); y += 5;
    doc.setFont('helvetica', 'normal'); doc.setFontSize(9);
    doc.setTextColor(...hexToRgb(colors.text));
    const scopeLines = doc.splitTextToSize(data.description, pageWidth - 30);
    doc.text(scopeLines, 15, y); y += scopeLines.length * 4 + 4;
  }

  // Line items table
  if (data.items && data.items.length > 0) {
    const tableHead = [['#', 'Description', 'Qty', 'Unit', 'Unit Price', 'Extended']];
    const tableBody = data.items.map(li => [
      String(li.item), li.description, String(li.qty), li.unit,
      formatCurrency(li.unitPrice), formatCurrency((li.qty || 0) * (li.unitPrice || 0))
    ]);
    doc.autoTable({
      startY: y, head: tableHead, body: tableBody,
      margin: { left: 15, right: 15 },
      styles: { fontSize: 8, cellPadding: 2.5, textColor: hexToRgb(colors.text), lineColor: hexToRgb(colors.border), lineWidth: 0.2 },
      headStyles: { fillColor: hexToRgb(colors.tableAlt), textColor: hexToRgb(colors.accent), fontStyle: 'bold', lineWidth: 0 },
      alternateRowStyles: { fillColor: hexToRgb(colors.tableAlt) },
      bodyStyles: { fillColor: hexToRgb(colors.tableBg) },
      columnStyles: { 0: { cellWidth: 12 }, 4: { halign: 'right' }, 5: { halign: 'right' } },
      didDrawPage: pdfAutoTablePageHook(theme),
    });
    y = doc.lastAutoTable.finalY + 6;

    // Totals
    doc.setDrawColor(...hexToRgb(colors.accent)); doc.setLineWidth(0.4);
    doc.line(pageWidth - 80, y, pageWidth - 15, y); y += 5;
    doc.setFontSize(9); doc.setTextColor(...hexToRgb(colors.text));
    doc.text('Subtotal:', pageWidth - 80, y); doc.text(formatCurrency(data.subtotal), pageWidth - 15, y, { align: 'right' }); y += 5;
    if (data.taxAmount > 0) {
      doc.text(`Tax (${data.taxRate}%):`, pageWidth - 80, y); doc.text(formatCurrency(data.taxAmount), pageWidth - 15, y, { align: 'right' }); y += 5;
    }
    doc.setFont('helvetica', 'bold'); doc.setFontSize(11);
    doc.setTextColor(...hexToRgb(colors.accent));
    doc.text('TOTAL:', pageWidth - 80, y + 2); doc.text(formatCurrency(data.total), pageWidth - 15, y + 2, { align: 'right' });
    y += 12;
  }

  // Notes
  if (data.notes) {
    doc.setDrawColor(...hexToRgb(colors.accent)); doc.setLineWidth(0.4);
    doc.line(15, y, 25, y); y += 4;
    doc.setFontSize(8); doc.setFont('helvetica', 'bold');
    doc.setTextColor(...hexToRgb(colors.accent));
    doc.text('NOTES', 15, y); y += 5;
    doc.setFont('helvetica', 'normal'); doc.setFontSize(8);
    doc.setTextColor(...hexToRgb(colors.textSecondary));
    const noteLines = doc.splitTextToSize(data.notes, pageWidth - 30);
    doc.text(noteLines, 15, y);
  }

  // Footer
  pdfDrawFooter(doc, theme, company);

  doc.save(`${data.docNumber || 'WorkOrder'}.pdf`);
  showToast('Work order PDF exported!');
}

function editWorkOrder(id) {
  editingDocId = id;
  const wo = getWorkOrders().find(d => d.id === id);
  if (wo) renderWorkOrderEditor(wo);
}

function createWorkOrderForJob(jobId) {
  currentJobId = jobId;
  editingDocId = null;
  renderWorkOrderEditor(getDefaultWorkOrder(jobId));
}


// ============================================================
// CHANGE ORDERS
// ============================================================
function getChangeOrders() { return getDocuments('changeorders'); }

function getDefaultChangeOrder(jobId) {
  const job = jobId ? getJobById(jobId) : null;
  return {
    id: generateId(), docNumber: generateNumber('CO'), date: todayStr(),
    jobId: jobId || '',
    customer: job ? { ...job.customer } : { name: '', company: '', phone: '', email: '', address: '' },
    projectName: job ? job.name : '',
    originalScope: '',
    changeDescription: '',
    reason: '',
    items: [{ item: 1, description: '', qty: 1, unit: 'Each', unitPrice: 0 }],
    costImpact: 0,
    scheduleImpact: '',
    status: 'draft',
    approvedBy: '',
    approvedDate: '',
    notes: '',
  };
}

function renderChangeOrderEditor(co) {
  window._currentCO = co;
  window._coLineItems = (co.items || []).map(li => ({...li}));
  const main = document.querySelector('.main-content');
  const backAction = co.jobId ? `openJobDashboard('${co.jobId}')` : `showPage('change-orders')`;

  main.innerHTML = `
    <div class="page-header">
      <div style="display:flex;align-items:center;gap:12px;">
        <button class="btn-icon" onclick="${backAction}" title="Back">←</button>
        <h1>Edit Change Order</h1>
      </div>
      <div class="page-header-actions">
        <button class="btn btn-secondary" onclick="saveCurrentCO()">Save Draft</button>
        <button class="btn btn-primary" onclick="exportChangeOrderPDF()">Export PDF</button>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Change Order Information</div>
      <div class="form-grid">
        <div class="form-group"><label class="form-label">CO Number</label><input class="form-input" id="co-docNumber" value="${escapeHtml(co.docNumber)}"></div>
        <div class="form-group"><label class="form-label">Date</label><input class="form-input" type="date" id="co-date" value="${co.date}"></div>
        <div class="form-group"><label class="form-label">Job</label>${buildJobSelector('co-job', co.jobId, true)}</div>
        <div class="form-group"><label class="form-label">Project Name</label><input class="form-input" id="co-projectName" value="${escapeHtml(co.projectName)}"></div>
        <div class="form-group"><label class="form-label">Status</label>
          <select class="form-select" id="co-status">
            <option value="draft" ${co.status==='draft'?'selected':''}>Draft</option>
            <option value="pending-approval" ${co.status==='pending-approval'?'selected':''}>Pending Approval</option>
            <option value="approved" ${co.status==='approved'?'selected':''}>Approved</option>
            <option value="rejected" ${co.status==='rejected'?'selected':''}>Rejected</option>
          </select>
        </div>
        <div class="form-group"><label class="form-label">Schedule Impact</label><input class="form-input" id="co-scheduleImpact" value="${escapeHtml(co.scheduleImpact)}" placeholder="e.g. +3 days"></div>
        <div class="form-group"><label class="form-label">Approved By</label><input class="form-input" id="co-approvedBy" value="${escapeHtml(co.approvedBy)}"></div>
        <div class="form-group"><label class="form-label">Approval Date</label><input class="form-input" type="date" id="co-approvedDate" value="${co.approvedDate}"></div>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Customer Information</div>
      <div class="form-grid">
        <div class="form-group"><label class="form-label">Contact Name</label><input class="form-input" id="co-customerName" value="${escapeHtml(co.customer.name)}"></div>
        <div class="form-group"><label class="form-label">Company</label><input class="form-input" id="co-customerCompany" value="${escapeHtml(co.customer.company)}"></div>
        <div class="form-group"><label class="form-label">Phone</label><input class="form-input" id="co-customerPhone" value="${escapeHtml(co.customer.phone)}"></div>
        <div class="form-group"><label class="form-label">Email</label><input class="form-input" id="co-customerEmail" value="${escapeHtml(co.customer.email)}"></div>
        <div class="form-group full-width"><label class="form-label">Address</label><input class="form-input" id="co-customerAddress" value="${escapeHtml(co.customer.address)}"></div>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Original Scope Reference</div>
      <textarea class="form-textarea" id="co-originalScope" rows="3" placeholder="Reference the original work scope...">${escapeHtml(co.originalScope)}</textarea>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Change Description</div>
      <textarea class="form-textarea" id="co-changeDescription" rows="4" placeholder="Describe the changes to be made...">${escapeHtml(co.changeDescription)}</textarea>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Reason for Change</div>
      <textarea class="form-textarea" id="co-reason" rows="3" placeholder="Explain why this change is needed...">${escapeHtml(co.reason)}</textarea>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Cost Impact Items</div>
      <div class="table-scroll"><table class="line-items-table"><thead><tr>
        <th class="col-item">#</th><th class="col-desc">Description</th><th class="col-qty">Qty</th><th class="col-unit">Unit</th><th class="col-price">Unit Price</th><th class="col-ext">Extended</th><th class="col-actions"></th>
      </tr></thead><tbody id="co-line-items"></tbody></table></div>
      <button class="btn btn-secondary btn-sm" style="margin-top:12px;" onclick="addCOLineItem()">+ Add Item</button>
    </div>
    <div class="totals-section">
      <div class="totals-table">
        <div class="totals-row total"><span class="label">Cost Impact:</span><span class="value" id="co-costImpact">$0.00</span></div>
      </div>
    </div>
    <div class="card">
      <div class="card-title"><div class="accent-bar"></div>Notes</div>
      <textarea class="form-textarea" id="co-notes" rows="3">${escapeHtml(co.notes)}</textarea>
    </div>
  `;
  renderCOLineItems();
}

function renderCOLineItems() {
  const tbody = document.getElementById('co-line-items');
  if (!tbody) return;
  tbody.innerHTML = window._coLineItems.map((li, i) => `
    <tr>
      <td>${i + 1}</td>
      <td><input class="form-input" value="${escapeHtml(li.description)}" onchange="window._coLineItems[${i}].description=this.value"></td>
      <td><input class="form-input" type="number" value="${li.qty}" min="0" step="0.01" onchange="window._coLineItems[${i}].qty=parseFloat(this.value)||0;recalcCO()"></td>
      <td><input class="form-input" value="${escapeHtml(li.unit)}" onchange="window._coLineItems[${i}].unit=this.value"></td>
      <td><input class="form-input" type="number" value="${li.unitPrice}" step="0.01" onchange="window._coLineItems[${i}].unitPrice=parseFloat(this.value)||0;recalcCO()"></td>
      <td class="ext-price">${formatCurrency((li.qty || 0) * (li.unitPrice || 0))}</td>
      <td><button class="btn-icon" onclick="window._coLineItems.splice(${i},1);renderCOLineItems()">🗑</button></td>
    </tr>
  `).join('');
  recalcCO();
}

function addCOLineItem() {
  window._coLineItems.push({ item: window._coLineItems.length + 1, description: '', qty: 1, unit: 'Each', unitPrice: 0 });
  renderCOLineItems();
}

function recalcCO() {
  let total = 0;
  window._coLineItems.forEach(li => { total += (li.qty || 0) * (li.unitPrice || 0); });
  const el = document.getElementById('co-costImpact');
  if (el) el.textContent = (total >= 0 ? '+' : '') + formatCurrency(total);
}

function collectCOData() {
  const co = { ...window._currentCO };
  co.docNumber = document.getElementById('co-docNumber')?.value || co.docNumber;
  co.date = document.getElementById('co-date')?.value || co.date;
  co.jobId = resolveJobId('co-job', 'Change Order', co);
  co.projectName = document.getElementById('co-projectName')?.value || '';
  co.status = document.getElementById('co-status')?.value || 'draft';
  co.scheduleImpact = document.getElementById('co-scheduleImpact')?.value || '';
  co.approvedBy = document.getElementById('co-approvedBy')?.value || '';
  co.approvedDate = document.getElementById('co-approvedDate')?.value || '';
  co.customer = {
    name: document.getElementById('co-customerName')?.value || '',
    company: document.getElementById('co-customerCompany')?.value || '',
    phone: document.getElementById('co-customerPhone')?.value || '',
    email: document.getElementById('co-customerEmail')?.value || '',
    address: document.getElementById('co-customerAddress')?.value || '',
  };
  co.originalScope = document.getElementById('co-originalScope')?.value || '';
  co.changeDescription = document.getElementById('co-changeDescription')?.value || '';
  co.reason = document.getElementById('co-reason')?.value || '';
  co.items = window._coLineItems.map((li, i) => ({ ...li, item: i + 1 }));
  co.costImpact = co.items.reduce((s, li) => s + (li.qty||0)*(li.unitPrice||0), 0);
  co.notes = document.getElementById('co-notes')?.value || '';
  return co;
}

function saveCurrentCO() {
  const co = collectCOData();
  saveDocument('changeorders', co);
  editingDocId = co.id;
  window._currentCO = co;
  showToast('Change order saved!');
}

async function exportChangeOrderPDF() {
  const data = collectCOData();
  saveDocument('changeorders', data);
  editingDocId = data.id;

  const { jsPDF } = window.jspdf;
  const theme = getActiveTheme();
  const colors = theme.colors;
  const company = getCompany();
  const doc = new jsPDF('p', 'mm', 'letter');
  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();

  doc.setFillColor(...hexToRgb(colors.bg));
  doc.rect(0, 0, pageWidth, pageHeight, 'F');

  let y = pdfAddHeader(doc, theme, company, 'CHANGE ORDER', data.docNumber, pageWidth);

  // Meta
  doc.setFontSize(9); doc.setTextColor(...hexToRgb(colors.textSecondary));
  y = pdfDrawMeta(doc, [
    `Date: ${formatDate(data.date)}`,
    data.scheduleImpact ? `Schedule Impact: ${data.scheduleImpact}` : '',
    data.approvedBy ? `Approved By: ${data.approvedBy}` : ''
  ], 15, y, pageWidth - 30, theme);

  // Customer
  doc.setDrawColor(...hexToRgb(colors.accent)); doc.setLineWidth(0.4);
  doc.line(15, y, 25, y); y += 4;
  doc.setFontSize(8); doc.setFont('helvetica', 'bold');
  doc.setTextColor(...hexToRgb(colors.accent));
  doc.text('CUSTOMER', 15, y); y += 5;
  doc.setFont('helvetica', 'normal'); doc.setFontSize(9);
  doc.setTextColor(...hexToRgb(colors.text));
  if (data.customer.name) { doc.text(data.customer.name, 15, y); y += 4; }
  if (data.customer.company) { doc.text(data.customer.company, 15, y); y += 4; }
  if (data.customer.phone || data.customer.email) { doc.text([data.customer.phone, data.customer.email].filter(Boolean).join(' | '), 15, y); y += 4; }
  if (data.customer.address) { doc.text(data.customer.address, 15, y); y += 4; }
  y += 4;

  // Original scope
  if (data.originalScope) {
    doc.setDrawColor(...hexToRgb(colors.accent)); doc.setLineWidth(0.4);
    doc.line(15, y, 25, y); y += 4;
    doc.setFontSize(8); doc.setFont('helvetica', 'bold');
    doc.setTextColor(...hexToRgb(colors.accent));
    doc.text('ORIGINAL SCOPE REFERENCE', 15, y); y += 5;
    doc.setFont('helvetica', 'normal'); doc.setFontSize(9);
    doc.setTextColor(...hexToRgb(colors.text));
    const oLines = doc.splitTextToSize(data.originalScope, pageWidth - 30);
    doc.text(oLines, 15, y); y += oLines.length * 4 + 4;
  }

  // Change description
  if (data.changeDescription) {
    doc.setDrawColor(...hexToRgb(colors.accent)); doc.setLineWidth(0.4);
    doc.line(15, y, 25, y); y += 4;
    doc.setFontSize(8); doc.setFont('helvetica', 'bold');
    doc.setTextColor(...hexToRgb(colors.accent));
    doc.text('CHANGE DESCRIPTION', 15, y); y += 5;
    doc.setFont('helvetica', 'normal'); doc.setFontSize(9);
    doc.setTextColor(...hexToRgb(colors.text));
    const cLines = doc.splitTextToSize(data.changeDescription, pageWidth - 30);
    doc.text(cLines, 15, y); y += cLines.length * 4 + 4;
  }

  // Reason
  if (data.reason) {
    doc.setDrawColor(...hexToRgb(colors.accent)); doc.setLineWidth(0.4);
    doc.line(15, y, 25, y); y += 4;
    doc.setFontSize(8); doc.setFont('helvetica', 'bold');
    doc.setTextColor(...hexToRgb(colors.accent));
    doc.text('REASON FOR CHANGE', 15, y); y += 5;
    doc.setFont('helvetica', 'normal'); doc.setFontSize(9);
    doc.setTextColor(...hexToRgb(colors.text));
    const rLines = doc.splitTextToSize(data.reason, pageWidth - 30);
    doc.text(rLines, 15, y); y += rLines.length * 4 + 4;
  }

  // Cost impact items
  if (data.items && data.items.length > 0) {
    const tableHead = [['#', 'Description', 'Qty', 'Unit', 'Unit Price', 'Extended']];
    const tableBody = data.items.map(li => [
      String(li.item), li.description, String(li.qty), li.unit,
      formatCurrency(li.unitPrice), formatCurrency((li.qty || 0) * (li.unitPrice || 0))
    ]);
    doc.autoTable({
      startY: y, head: tableHead, body: tableBody,
      margin: { left: 15, right: 15 },
      styles: { fontSize: 8, cellPadding: 2.5, textColor: hexToRgb(colors.text), lineColor: hexToRgb(colors.border), lineWidth: 0.2 },
      headStyles: { fillColor: hexToRgb(colors.tableAlt), textColor: hexToRgb(colors.accent), fontStyle: 'bold', lineWidth: 0 },
      alternateRowStyles: { fillColor: hexToRgb(colors.tableAlt) },
      bodyStyles: { fillColor: hexToRgb(colors.tableBg) },
      columnStyles: { 0: { cellWidth: 12 }, 4: { halign: 'right' }, 5: { halign: 'right' } },
      didDrawPage: pdfAutoTablePageHook(theme),
    });
    y = doc.lastAutoTable.finalY + 6;

    // Cost impact total
    doc.setFont('helvetica', 'bold'); doc.setFontSize(11);
    doc.setTextColor(...hexToRgb(colors.accent));
    const impactStr = (data.costImpact >= 0 ? '+' : '') + formatCurrency(data.costImpact);
    doc.text('COST IMPACT:', pageWidth - 80, y + 2);
    doc.text(impactStr, pageWidth - 15, y + 2, { align: 'right' });
    y += 12;
  }

  // Signature lines
  doc.setDrawColor(...hexToRgb(colors.border)); doc.setLineWidth(0.3);
  y += 5;
  doc.setFontSize(8); doc.setFont('helvetica', 'normal');
  doc.setTextColor(...hexToRgb(colors.textSecondary));
  doc.text('Authorized Signature:', 15, y);
  doc.line(55, y, 120, y);
  doc.text('Date:', 130, y);
  doc.line(145, y, pageWidth - 15, y);
  y += 10;
  doc.text('Customer Approval:', 15, y);
  doc.line(55, y, 120, y);
  doc.text('Date:', 130, y);
  doc.line(145, y, pageWidth - 15, y);

  // Footer
  pdfDrawFooter(doc, theme, company);

  doc.save(`${data.docNumber || 'ChangeOrder'}.pdf`);
  showToast('Change order PDF exported!');
}

function editChangeOrder(id) {
  editingDocId = id;
  const co = getChangeOrders().find(d => d.id === id);
  if (co) renderChangeOrderEditor(co);
}

function createChangeOrderForJob(jobId) {
  currentJobId = jobId;
  editingDocId = null;
  renderChangeOrderEditor(getDefaultChangeOrder(jobId));
}


