function getProposals() { return getDocuments('proposals'); }

function getDefaultProposal(jobId) {
  const company = getCompany();
  const job = jobId ? getJobById(jobId) : null;
  return {
    id: generateId(), docNumber: generateNumber('PROP'), date: todayStr(),
    validUntil: '',
    jobId: jobId || '',
    customer: job ? { ...job.customer } : { name: '', company: '', phone: '', email: '', address: '' },
    projectName: job ? job.name : '',
    scopeOfWork: '',
    timeline: '',
    qualifications: company.name + ' is a full-service electrical testing and maintenance company providing high-quality power system services.',
    items: [{ item: 1, description: '', qty: 1, unit: 'Each', unitPrice: 0, taxable: false }],
    terms: ['NET 30 payment terms.', 'This proposal is valid for 30 days from the date above.'],
    taxRate: company.taxRate || 0, subtotal: 0, taxAmount: 0, total: 0,
    status: 'draft',
    notes: '',
  };
}

